# =========================================
# MIDDLEWARE DE LOG DE REQUISIÇÕES
# Loga method, path, status, duração, usuário (best-effort do JWT) e IP.
# Saída para stdout em uma linha; útil para diagnosticar túnel ngrok caído,
# 401 em massa por token expirado, queries lentas, etc.
# Persistência em tabela é opt-in: defina REQUEST_LOG_PERSIST = True.
# =========================================

import time as _time_mod
import logging as _logging

REQUEST_LOG_SKIP_PATHS = {"/health", "/docs", "/openapi.json", "/redoc", "/favicon.ico"}
REQUEST_LOG_PERSIST = False   # ative para gravar em dbo.USU_REQ_LOG
REQUEST_LOG_SLOW_MS = 1500    # threshold para marcar SLOW na linha de log

_request_logger = _logging.getLogger("erp.requests")
if not _request_logger.handlers:
    _h = _logging.StreamHandler()
    _h.setFormatter(_logging.Formatter("%(asctime)s [REQ] %(message)s",
                                       datefmt="%Y-%m-%d %H:%M:%S"))
    _request_logger.addHandler(_h)
    _request_logger.setLevel(_logging.INFO)
    _request_logger.propagate = False


def _extrair_usuario_jwt_silencioso(auth_header: Optional[str]) -> str:
    """Tenta extrair o `sub` do Bearer token sem levantar — só para log.
    Retorna '' se não houver, '?' se token presente mas inválido,
    'expired' se assinatura vencida."""
    if not auth_header or not auth_header.lower().startswith("bearer "):
        return ""
    token = auth_header[7:].strip()
    if not token:
        return ""
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return str(payload.get("sub") or "")
    except ExpiredSignatureError:
        return "expired"
    except JWTError:
        return "?"
    except Exception:
        return "?"


@app.middleware("http")
async def log_requisicoes_middleware(request, call_next):
    path = request.url.path or ""
    # Pula paths ruidosos (probes /health, swagger, etc.)
    if path in REQUEST_LOG_SKIP_PATHS:
        return await call_next(request)

    inicio = _time_mod.perf_counter()
    method = request.method
    query = str(request.url.query or "")
    if len(query) > 200:
        query = query[:197] + "..."
    cliente = request.client.host if request.client else ""
    usuario = _extrair_usuario_jwt_silencioso(request.headers.get("authorization"))

    status_code = 0
    erro_inesperado = None
    try:
        response = await call_next(request)
        status_code = response.status_code
        return response
    except Exception as exc:
        erro_inesperado = repr(exc)[:200]
        status_code = 500
        raise
    finally:
        dur_ms = int((_time_mod.perf_counter() - inicio) * 1000)
        slow = " SLOW" if dur_ms >= REQUEST_LOG_SLOW_MS else ""
        usuario_tag = f"user={usuario}" if usuario else "user=-"
        cliente_tag = f"ip={cliente}" if cliente else "ip=-"
        query_tag = f" q={query}" if query else ""
        erro_tag = f" err={erro_inesperado}" if erro_inesperado else ""
        _request_logger.info(
            f"{method} {path}{query_tag} -> {status_code} in {dur_ms}ms "
            f"{usuario_tag} {cliente_tag}{slow}{erro_tag}"
        )

        if REQUEST_LOG_PERSIST:
            try:
                _persistir_request_log(
                    method=method, path=path, query=query,
                    status=status_code, dur_ms=dur_ms,
                    usuario=usuario, ip=cliente, erro=erro_inesperado,
                )
            except Exception as exc:
                # Best-effort: nunca derruba a request por causa do log
                print(f"[REQ_LOG_DB] falha ao persistir: {exc}")


def _persistir_request_log(*, method, path, query, status, dur_ms,
                           usuario, ip, erro):
    """Insert best-effort em dbo.USU_REQ_LOG. Cria a tabela on-demand."""
    conn = get_connection()
    try:
        cursor = conn.cursor()
        cursor.execute("""
            IF OBJECT_ID('dbo.USU_REQ_LOG','U') IS NULL
            BEGIN
                CREATE TABLE dbo.USU_REQ_LOG (
                    ID_LOG    INT IDENTITY(1,1) PRIMARY KEY,
                    DATA_HORA DATETIME      NOT NULL DEFAULT GETDATE(),
                    METHOD    VARCHAR(10)   NOT NULL,
                    PATH_REQ  VARCHAR(500)  NOT NULL,
                    QUERY_REQ VARCHAR(2000) NULL,
                    STATUS_HTTP INT         NOT NULL,
                    DURATION_MS INT         NOT NULL,
                    USUARIO   VARCHAR(100)  NULL,
                    IP        VARCHAR(60)   NULL,
                    ERRO      VARCHAR(500)  NULL
                );
                CREATE INDEX IX_USU_REQ_LOG_DATA   ON dbo.USU_REQ_LOG (DATA_HORA);
                CREATE INDEX IX_USU_REQ_LOG_STATUS ON dbo.USU_REQ_LOG (STATUS_HTTP, DATA_HORA);
            END;
        """)
        cursor.execute("""
            INSERT INTO dbo.USU_REQ_LOG
                (METHOD, PATH_REQ, QUERY_REQ, STATUS_HTTP, DURATION_MS, USUARIO, IP, ERRO)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        """, [
            (method or "")[:10],
            (path or "")[:500],
            (query or "")[:2000],
            int(status or 0),
            int(dur_ms or 0),
            (usuario or "")[:100],
            (ip or "")[:60],
            (erro or "")[:500] if erro else None,
        ])
        conn.commit()
    finally:
        try:
            conn.close()
        except Exception:
            pass


