def get_connection():
    try:
        conn = pyodbc.connect(
            "DRIVER={ODBC Driver 17 for SQL Server};"
            "SERVER=172.16.137.100,1433;"
            "DATABASE=sapiens;"
            f"UID={SQL_USER};"
            f"PWD={SQL_PASSWORD};"
            "Encrypt=no;"
            "TrustServerCertificate=yes;",
            timeout=10
        )
        return conn
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erro conexão SQL: {e}")


