async def _log_login_diagnostico(request: Request, motivo: str, usuario_final: str):
    """Best-effort: registra **apenas as chaves** recebidas no body/query
    + IP + User-Agent + se Authorization estava presente. NUNCA loga senha."""
    try:
        raw = await request.json()
    except Exception:
        raw = None
    body_keys: list = []
    if isinstance(raw, dict):
        body_keys = list(raw.keys())[:20]
    elif raw is not None:
        body_keys = [f"<{type(raw).__name__}>"]

    query_keys = list(request.query_params.keys())[:20]
    has_auth = bool(request.headers.get("authorization"))
    ua = (request.headers.get("user-agent") or "")[:120]
    ip = request.client.host if request.client else "-"
    content_type = request.headers.get("content-type") or "-"

    print(
        f"[LOGIN_FAIL] motivo={motivo} usuario_recebido={usuario_final or '-'} "
        f"body_keys={body_keys} query_keys={query_keys} "
        f"content_type={content_type} has_auth={has_auth} ip={ip} ua={ua!r}"
    )


@app.post("/login")
async def login(
    request: Request,
    payload: Optional[LoginRequest] = Body(default=None),
    usuario: Optional[str] = Query(default=None),
    senha: Optional[str] = Query(default=None),
):
    """
    Aceita:
    1) JSON: { "usuario": "...", "senha": "..." }   (também aceita aliases:
       username/password, user/pass, email/pwd, login/...)
    2) Query string: /login?usuario=RENATO&senha=123

    Não usa Form(...) para evitar a dependência de python-multipart.

    Em qualquer falha (400 sem creds, 401 creds inválidas), registra no log
    apenas as CHAVES recebidas (nunca valores) — facilita diagnosticar
    integrações que mandam o body com campos errados.
    """
    usuario_final = ""
    senha_final = ""

    if payload:
        usuario_final = (payload.usuario or "").upper().strip()
        senha_final = (payload.senha or "").strip()
    else:
        usuario_final = (usuario or "").upper().strip()
        senha_final = (senha or "").strip()

    if not usuario_final or not senha_final:
        await _log_login_diagnostico(
            request,
            motivo="campos_ausentes",
            usuario_final=usuario_final,
        )
        raise HTTPException(
            status_code=400,
            detail={
                "message": "Usuário e senha são obrigatórios",
                "code": "LOGIN_MISSING_FIELDS",
                "expected_fields": ["usuario", "senha"],
                "accepted_aliases": {
                    "usuario": ["usuario", "username", "user", "email", "login"],
                    "senha": ["senha", "password", "pass", "pwd"],
                },
            },
        )

    if usuario_final in USERS and USERS[usuario_final] == senha_final:
        return {
            "access_token": gerar_token(usuario_final),
            "token_type": "bearer",
            "usuario": usuario_final,
        }

    await _log_login_diagnostico(
        request,
        motivo="credenciais_invalidas",
        usuario_final=usuario_final,
    )
    raise HTTPException(
        status_code=401,
        detail={"message": "Login inválido", "code": "LOGIN_INVALID"},
    )


def _float_or_zero(v):
    try:
        return float(v or 0)
    except Exception:
        return 0.0


def _calcular_status_min_max(saldo_atual: float, estoque_minimo: float, estoque_maximo: float):
    saldo_atual = _float_or_zero(saldo_atual)
    estoque_minimo = _float_or_zero(estoque_minimo)
    estoque_maximo = _float_or_zero(estoque_maximo)

    sugestao_minimo = 0.0
    sugestao_maximo = 0.0

    if estoque_minimo <= 0 and estoque_maximo <= 0:
        status = 'SEM_POLITICA'
    elif saldo_atual < estoque_minimo:
        status = 'ABAIXO_MINIMO'
        sugestao_minimo = max(1.0, estoque_minimo - saldo_atual)
        sugestao_maximo = max(estoque_maximo - saldo_atual, 0.0) if estoque_maximo > 0 else 0.0
    elif saldo_atual == estoque_minimo:
        status = 'NO_MINIMO'
        sugestao_maximo = max(estoque_maximo - saldo_atual, 0.0) if estoque_maximo > 0 else 0.0
    elif estoque_maximo > 0 and saldo_atual > estoque_maximo:
        status = 'ACIMA_MAXIMO'
    else:
        status = 'ENTRE_MIN_E_MAX'
        sugestao_maximo = max(estoque_maximo - saldo_atual, 0.0) if estoque_maximo > 0 else 0.0

    return {
        'status_politica': status,
        'sugestao_minimo': round(sugestao_minimo, 6),
        'sugestao_maximo': round(sugestao_maximo, 6),
    }


