@app.get("/api/familias")
def listar_familias(
    q: Optional[str] = None,
    limite: int = 200,
    usuario=Depends(validar_token)
):
    limite = max(1, min(limite, 500))

    conn = get_connection()
    cursor = conn.cursor()

    where_sql = """
        FROM E012FAM F
        WHERE F.CODEMP = ?
          AND EXISTS (
              SELECT 1
              FROM E075PRO P
              WHERE P.CODEMP = F.CODEMP
                AND P.CODFAM = F.CODFAM
          )
    """
    params = [EMPRESA_PADRAO]

    if q:
        where_sql += " AND (F.CODFAM LIKE ? OR F.DESFAM LIKE ?)"
        termo = f"%{q.strip()}%"
        params.extend([termo, termo])

    sql = f"""
        SELECT TOP {limite}
            F.CODFAM AS codigo,
            F.DESFAM AS descricao
        {where_sql}
        ORDER BY F.CODFAM
    """

    cursor.execute(sql, params)
    rows = cursor.fetchall()
    conn.close()

    resultado = []
    for row in rows:
        codigo = (row[0] or '').strip()
        descricao = (row[1] or '').strip()
        label = f"{codigo} - {descricao}" if descricao else codigo
        resultado.append({
            "codigo": codigo,
            "descricao": descricao,
            "value": codigo,
            "label": label
        })

    return resultado


