# =========================================
# API ESTOQUE COM PAGINAÇÃO
# =========================================

@app.get("/api/estoque")
def consultar_estoque(
    codpro: Optional[str] = None,
    despro: Optional[str] = None,
    codfam: Optional[str] = None,
    codori: Optional[str] = None,
    coddep: Optional[str] = None,
    situacao_cadastro: str = 'TODOS',
    somente_com_estoque: bool = True,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token)
):
    if pagina < 1:
        pagina = 1

    if tamanho_pagina < 1:
        tamanho_pagina = 100

    if tamanho_pagina > 100:
        tamanho_pagina = 100

    offset = (pagina - 1) * tamanho_pagina

    conn = get_connection()
    cursor = conn.cursor()

    where_sql = """
        FROM E210EST E
        INNER JOIN E075PRO P
            ON P.CODEMP = E.CODEMP
           AND P.CODPRO = E.CODPRO
        WHERE E.CODEMP = ?
    """

    params_where = [EMPRESA_PADRAO]

    if codpro:
        where_sql += " AND E.CODPRO LIKE ?"
        params_where.append(f"%{codpro}%")

    if despro:
        where_sql += " AND P.DESPRO LIKE ?"
        params_where.append(f"%{despro}%")

    if codfam:
        where_sql += " AND P.CODFAM = ?"
        params_where.append(codfam)

    if codori:
        where_sql += " AND P.CODORI = ?"
        params_where.append(codori)

    if coddep:
        where_sql += " AND E.CODDEP = ?"
        params_where.append(coddep)

    where_sql += clausula_sql_situacao_cadastro('P', situacao_cadastro)

    if somente_com_estoque:
        where_sql += " AND E.QTDEST > 0"

    sql_total = f"""
        SELECT COUNT(*)
        {where_sql}
    """

    cursor.execute(sql_total, params_where)
    total_registros = cursor.fetchone()[0]

    sql_dados = f"""
        SELECT
            E.CODPRO AS codigo,
            P.DESPRO AS descricao,
            P.CODFAM AS familia,
            P.CODORI AS origem,
            P.TIPPRO AS tipo,
            P.UNIMED AS unidade_medida,
            E.CODDER AS derivacao,
            E.CODDEP AS deposito,
            CAST(E.QTDEST AS FLOAT) AS saldo
        {where_sql}
        ORDER BY E.CODPRO, E.CODDER, E.CODDEP
        OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
    """

    params_dados = params_where + [offset, tamanho_pagina]

    cursor.execute(sql_dados, params_dados)
    rows = cursor.fetchall()
    columns = [col[0] for col in cursor.description]
    conn.close()

    resultado = []

    for row in rows:
        item = {}
        for i, col in enumerate(columns):
            item[col] = row[i]

        tipo = (item.get("tipo") or "").strip().upper()
        if tipo == "P":
            item["tipo_descricao"] = "Produzido"
        elif tipo == "C":
            item["tipo_descricao"] = "Comprado"
        else:
            item["tipo_descricao"] = item.get("tipo") or "Não informado"

        item["origem"] = (item.get("origem") or "").strip()
        item["unidade_medida"] = (item.get("unidade_medida") or "").strip()
        resultado.append(item)

    total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros > 0 else 1

    return {
        "pagina": pagina,
        "tamanho_pagina": tamanho_pagina,
        "total_registros": total_registros,
        "total_paginas": total_paginas,
        "dados": resultado
    }

