@app.get("/api/onde-usa")
def consultar_onde_usa(
    codcmp: Optional[str] = None,
    dercmp: Optional[str] = None,
    codmod: Optional[str] = None,
    situacao_cadastro: str = 'TODOS',
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token)
):
    if pagina < 1:
        pagina = 1

    if tamanho_pagina < 1:
        tamanho_pagina = 100

    if tamanho_pagina > 100:
        tamanho_pagina = 100

    offset = (pagina - 1) * tamanho_pagina

    conn = get_connection()
    cursor = conn.cursor()

    where_sql = """
        FROM E700CTM CT
        INNER JOIN E700MOD M
            ON M.CODEMP = CT.CODEMP
           AND M.CODMOD = CT.CODMOD
        LEFT JOIN E075PRO PC
            ON PC.CODEMP = CT.CODEMP
           AND PC.CODPRO = CT.CODCMP
        WHERE CT.CODEMP = ?
    """

    params_where = [EMPRESA_PADRAO]

    if codcmp:
        where_sql += " AND CT.CODCMP LIKE ?"
        params_where.append(f"%{codcmp}%")

    if dercmp:
        where_sql += " AND COALESCE(CT.DERCMP, '') LIKE ?"
        params_where.append(f"%{dercmp}%")

    if codmod:
        where_sql += " AND CT.CODMOD LIKE ?"
        params_where.append(f"%{codmod}%")

    where_sql += clausula_sql_situacao_cadastro('PC', situacao_cadastro)

    sql_total = f"""
        SELECT COUNT(*)
        {where_sql}
    """

    cursor.execute(sql_total, params_where)
    total_registros = cursor.fetchone()[0]

    sql_dados = f"""
        SELECT
            CT.CODCMP AS codigo_componente,
            COALESCE(PC.DESPRO, '') AS descricao_componente,
            COALESCE(PC.UNIMED, CT.UNIME2, '') AS unidade_componente,
            COALESCE(CT.DERCMP, '') AS derivacao_componente,
            CT.CODMOD AS codigo_modelo,
            M.DESMOD AS descricao_modelo,
            CT.CODDER AS derivacao_modelo,
            CT.CODETG AS estagio,
            CT.SEQMOD AS sequencia,
            CAST(CT.QTDUTI AS FLOAT) AS quantidade_utilizada,
            COALESCE(CT.UNIME2, '') AS unidade_utilizada,
            CAST(COALESCE(CT.PERPRD, 0) AS FLOAT) AS perda_percentual,
            CAST(COALESCE(CT.PRDQTD, 0) AS FLOAT) AS quantidade_perda
        {where_sql}
        ORDER BY CT.CODCMP, CT.CODMOD, CT.CODDER, CT.CODETG, CT.SEQMOD
        OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
    """

    params_dados = params_where + [offset, tamanho_pagina]

    cursor.execute(sql_dados, params_dados)
    rows = cursor.fetchall()
    columns = [col[0] for col in cursor.description]
    conn.close()

    resultado = []

    for row in rows:
        item = {}
        for i, col in enumerate(columns):
            item[col] = row[i]

        item["codigo_componente"] = (item.get("codigo_componente") or "").strip()
        item["descricao_componente"] = (item.get("descricao_componente") or "").strip()
        item["unidade_componente"] = (item.get("unidade_componente") or "").strip()
        item["derivacao_componente"] = (item.get("derivacao_componente") or "").strip()
        item["codigo_modelo"] = (item.get("codigo_modelo") or "").strip()
        item["descricao_modelo"] = (item.get("descricao_modelo") or "").strip()
        item["derivacao_modelo"] = (item.get("derivacao_modelo") or "").strip()
        item["unidade_utilizada"] = (item.get("unidade_utilizada") or "").strip()
        resultado.append(item)

    total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros > 0 else 1

    return {
        "pagina": pagina,
        "tamanho_pagina": tamanho_pagina,
        "total_registros": total_registros,
        "total_paginas": total_paginas,
        "dados": resultado
    }





def _fetch_children_bom(cursor, codemp: int, codmod: str, codder: Optional[str], situacao_cadastro: str = 'TODOS'):
    sql = """
        SELECT
            CT.CODMOD AS modelo_pai,
            COALESCE(M.DESMOD, '') AS descricao_modelo_pai,
            COALESCE(CT.CODDER, '') AS derivacao_modelo,
            CT.CODETG AS estagio,
            CT.SEQMOD AS sequencia,
            CT.CODCMP AS codigo_componente,
            COALESCE(CT.DERCMP, '') AS derivacao_componente,
            COALESCE(P.DESPRO, '') AS descricao_componente,
            COALESCE(P.UNIMED, '') AS unidade_medida,
            COALESCE(P.TIPPRO, '') AS tipo_produto,
            CAST(CT.QTDUTI AS FLOAT) AS quantidade_utilizada,
            CAST(COALESCE(CT.PERPRD, 0) AS FLOAT) AS perda_percentual,
            CAST(COALESCE(CT.PRDQTD, 0) AS FLOAT) AS quantidade_perda
        FROM E700CTM CT
        LEFT JOIN E700MOD M
            ON M.CODEMP = CT.CODEMP
           AND M.CODMOD = CT.CODMOD
        LEFT JOIN E075PRO P
            ON P.CODEMP = CT.CODEMP
           AND P.CODPRO = CT.CODCMP
        WHERE CT.CODEMP = ?
          AND CT.CODMOD = ?
    """
    params = [codemp, codmod]

    if codder:
        sql += " AND COALESCE(CT.CODDER, '') = ?"
        params.append(codder)

    sql += clausula_sql_situacao_cadastro('P', situacao_cadastro)
    sql += " ORDER BY CT.CODETG, CT.SEQMOD, CT.CODCMP, CT.DERCMP"
    cursor.execute(sql, params)
    rows = cursor.fetchall()
    cols = [col[0] for col in cursor.description]
    result = []
    for row in rows:
        item = {}
        for i, col in enumerate(cols):
            val = row[i]
            if isinstance(val, str):
                val = val.strip()
            item[col] = val
        result.append(item)
    return result


def _model_exists(cursor, codemp: int, codmod: str, cache: dict):
    key = (codemp, (codmod or '').strip())
    if key in cache:
        return cache[key]
    cursor.execute("SELECT TOP 1 1 FROM E700MOD WHERE CODEMP = ? AND CODMOD = ?", [codemp, key[1]])
    exists = cursor.fetchone() is not None
    cache[key] = exists
    return exists


def _model_description(cursor, codemp: int, codmod: str, cache: dict):
    key = (codemp, (codmod or '').strip())
    if key in cache:
        return cache[key]
    cursor.execute("SELECT TOP 1 COALESCE(DESMOD, '') FROM E700MOD WHERE CODEMP = ? AND CODMOD = ?", [codemp, key[1]])
    row = cursor.fetchone()
    desc = row[0].strip() if row and isinstance(row[0], str) else (row[0] or "") if row else ""
    cache[key] = desc
    return desc


def _build_bom_rows(cursor, codemp: int, codmod: str, codder: Optional[str], max_nivel: int, situacao_cadastro: str = 'TODOS'):
    rows = []
    exists_cache = {}
    desc_cache = {}
    max_rows = 5000

    def walk(modelo_atual: str, derivacao_atual: Optional[str], nivel: int, caminho: list):
        if nivel > max_nivel:
            return
        if len(rows) >= max_rows:
            return

        filhos = _fetch_children_bom(cursor, codemp, modelo_atual, derivacao_atual, situacao_cadastro)
        for item in filhos:
            comp = (item.get('codigo_componente') or '').strip()
            der_comp = (item.get('derivacao_componente') or '').strip()
            path_key = f"{comp}|{der_comp}"
            possui_filhos = False
            ciclo = False

            if comp:
                if path_key in caminho:
                    ciclo = True
                else:
                    possui_filhos = _model_exists(cursor, codemp, comp, exists_cache)

            item['nivel'] = nivel
            item['caminho'] = ' > '.join([x.split('|')[0] for x in caminho] + [comp]) if comp else ' > '.join([x.split('|')[0] for x in caminho])
            item['possui_filhos'] = possui_filhos
            item['ciclo_detectado'] = ciclo
            item['descricao_modelo_pai'] = item.get('descricao_modelo_pai') or _model_description(cursor, codemp, modelo_atual, desc_cache)
            rows.append(item)

            if possui_filhos and not ciclo and nivel < max_nivel and len(rows) < max_rows:
                novo_caminho = list(caminho)
                novo_caminho.append(path_key)
                walk(comp, der_comp or None, nivel + 1, novo_caminho)

    walk(codmod, codder or None, 1, [f"{codmod}|{codder or ''}"])
    return rows




