@app.get('/api/compras-produto')
def consultar_compras_produto(
    codpro: Optional[str] = None,
    despro: Optional[str] = None,
    codfam: Optional[str] = None,
    codori: Optional[str] = None,
    codder: Optional[str] = None,
    numero_projeto: Optional[str] = None,
    centro_custo: Optional[str] = None,
    situacao_cadastro: str = 'TODOS',
    somente_com_oc_aberta: bool = False,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token)
):
    if pagina < 1:
        pagina = 1

    if tamanho_pagina < 1:
        tamanho_pagina = 100

    if tamanho_pagina > 100:
        tamanho_pagina = 100

    offset = (pagina - 1) * tamanho_pagina

    conn = get_connection()
    cursor = conn.cursor()

    from_count_sql = """
        FROM E075PRO P
        LEFT JOIN E075DER D
            ON D.CODEMP = P.CODEMP
           AND D.CODPRO = P.CODPRO
        LEFT JOIN (
            SELECT
                E.CODEMP,
                E.CODPRO,
                COALESCE(E.CODDER, '') AS CODDER,
                SUM(CAST(E.QTDEST AS FLOAT)) AS SALDO_TOTAL
            FROM E210EST E
            GROUP BY E.CODEMP, E.CODPRO, COALESCE(E.CODDER, '')
        ) EST
            ON EST.CODEMP = P.CODEMP
           AND EST.CODPRO = P.CODPRO
           AND EST.CODDER = COALESCE(D.CODDER, '')
        WHERE P.CODEMP = ?
    """

    params_where = [EMPRESA_PADRAO]

    if codpro:
        from_count_sql += " AND P.CODPRO LIKE ?"
        params_where.append(f"%{codpro}%")

    if despro:
        from_count_sql += " AND P.DESPRO LIKE ?"
        params_where.append(f"%{despro}%")

    if codfam:
        from_count_sql += " AND P.CODFAM = ?"
        params_where.append(codfam)

    if codori:
        from_count_sql += " AND P.CODORI = ?"
        params_where.append(codori)

    if codder:
        from_count_sql += " AND COALESCE(D.CODDER, '') LIKE ?"
        params_where.append(f"%{codder}%")

    if numero_projeto:
        from_count_sql += """
            AND EXISTS (
                SELECT 1
                FROM (
                    SELECT X.CODEMP, X.CODPRO, COALESCE(X.CODDER, '') AS CODDER, CAST(COALESCE(X.NUMPRJ, 0) AS VARCHAR(20)) AS NUMPRJ, COALESCE(X.CODCCU, '') AS CODCCU
                    FROM E420IPO X
                    UNION ALL
                    SELECT Y.CODEMP, Y.CODPRO, COALESCE(Y.CODDER, '') AS CODDER, CAST(COALESCE(Y.NUMPRJ, 0) AS VARCHAR(20)) AS NUMPRJ, COALESCE(Y.CODCCU, '') AS CODCCU
                    FROM E440IPC Y
                ) F
                WHERE F.CODEMP = P.CODEMP
                  AND F.CODPRO = P.CODPRO
                  AND F.CODDER = COALESCE(D.CODDER, '')
                  AND F.NUMPRJ LIKE ?
            )
        """
        params_where.append(f"%{numero_projeto}%")

    if centro_custo:
        from_count_sql += """
            AND EXISTS (
                SELECT 1
                FROM (
                    SELECT X.CODEMP, X.CODPRO, COALESCE(X.CODDER, '') AS CODDER, CAST(COALESCE(X.NUMPRJ, 0) AS VARCHAR(20)) AS NUMPRJ, COALESCE(X.CODCCU, '') AS CODCCU
                    FROM E420IPO X
                    UNION ALL
                    SELECT Y.CODEMP, Y.CODPRO, COALESCE(Y.CODDER, '') AS CODDER, CAST(COALESCE(Y.NUMPRJ, 0) AS VARCHAR(20)) AS NUMPRJ, COALESCE(Y.CODCCU, '') AS CODCCU
                    FROM E440IPC Y
                ) F
                WHERE F.CODEMP = P.CODEMP
                  AND F.CODPRO = P.CODPRO
                  AND F.CODDER = COALESCE(D.CODDER, '')
                  AND F.CODCCU LIKE ?
            )
        """
        params_where.append(f"%{centro_custo}%")

    from_count_sql += clausula_sql_situacao_cadastro('P', situacao_cadastro)

    if somente_com_oc_aberta:
        from_count_sql += """
            AND EXISTS (
                SELECT 1
                FROM E420IPO I
                WHERE I.CODEMP = P.CODEMP
                  AND I.CODPRO = P.CODPRO
                  AND COALESCE(I.CODDER, '') = COALESCE(D.CODDER, '')
                  AND COALESCE(I.QTDABE, 0) > 0
            )
        """

    sql_total = f"""
        SELECT COUNT(*)
        {from_count_sql}
    """

    cursor.execute(sql_total, params_where)
    total_registros = cursor.fetchone()[0]

    from_data_sql = """
        FROM E075PRO P
        LEFT JOIN E075DER D
            ON D.CODEMP = P.CODEMP
           AND D.CODPRO = P.CODPRO
        LEFT JOIN (
            SELECT
                E.CODEMP,
                E.CODPRO,
                COALESCE(E.CODDER, '') AS CODDER,
                SUM(CAST(E.QTDEST AS FLOAT)) AS SALDO_TOTAL
            FROM E210EST E
            GROUP BY E.CODEMP, E.CODPRO, COALESCE(E.CODDER, '')
        ) EST
            ON EST.CODEMP = P.CODEMP
           AND EST.CODPRO = P.CODPRO
           AND EST.CODDER = COALESCE(D.CODDER, '')
        OUTER APPLY (
            SELECT TOP 1
                H.CODFIL AS FILIAL_ULTIMA_NF,
                H.NUMNFC AS NUMERO_NF_ULTIMA_COMPRA,
                H.CODSNF AS SERIE_NF_ULTIMA_COMPRA,
                H.CODFOR AS COD_FORNECEDOR_ULTIMA_COMPRA,
                COALESCE(F.APEFOR, F.NOMFOR, '') AS FORNECEDOR_ULTIMA_COMPRA,
                H.DATEMI AS DATA_EMISSAO_NF_ULTIMA_COMPRA,
                H.DATENT AS DATA_ENTRADA_NF_ULTIMA_COMPRA,
                CAST(I.QTDREC AS FLOAT) AS QTD_NF_ULTIMA_COMPRA,
                COALESCE(I.UNIMED, I.UNINFC, '') AS UNIDADE_NF_ULTIMA_COMPRA,
                CAST(I.PREUNI AS FLOAT) AS PRECO_NF_ULTIMA_COMPRA,
                CAST(I.PREEST AS FLOAT) AS PRECO_ESTOQUE_NF_ULTIMA_COMPRA,
                I.NUMOCP AS NUMERO_OC_ORIGEM_ULTIMA_COMPRA
            FROM E440IPC I
            INNER JOIN E440NFC H
                ON H.CODEMP = I.CODEMP
               AND H.CODFIL = I.CODFIL
               AND H.CODFOR = I.CODFOR
               AND H.NUMNFC = I.NUMNFC
               AND H.CODSNF = I.CODSNF
            LEFT JOIN E095FOR F
                ON F.CODFOR = H.CODFOR
            WHERE I.CODEMP = P.CODEMP
              AND I.CODPRO = P.CODPRO
              AND COALESCE(I.CODDER, '') = COALESCE(D.CODDER, '')
            ORDER BY COALESCE(H.DATENT, H.DATEMI) DESC, H.NUMNFC DESC, I.SEQIPC DESC
        ) ULTNF
        OUTER APPLY (
            SELECT
                COUNT(DISTINCT O.NUMOCP) AS QTDE_OCS_ABERTAS,
                SUM(CAST(I.QTDABE AS FLOAT)) AS QTD_OC_ABERTA_TOTAL
            FROM E420IPO I
            INNER JOIN E420OCP O
                ON O.CODEMP = I.CODEMP
               AND O.CODFIL = I.CODFIL
               AND O.NUMOCP = I.NUMOCP
            WHERE I.CODEMP = P.CODEMP
              AND I.CODPRO = P.CODPRO
              AND COALESCE(I.CODDER, '') = COALESCE(D.CODDER, '')
              AND COALESCE(I.QTDABE, 0) > 0
        ) OCA
        OUTER APPLY (
            SELECT TOP 1
                O.NUMOCP AS ULTIMA_OC_ABERTA,
                O.CODFIL AS FILIAL_ULTIMA_OC_ABERTA,
                O.CODFOR AS COD_FORNECEDOR_ULTIMA_OC_ABERTA,
                COALESCE(F.APEFOR, F.NOMFOR, '') AS FORNECEDOR_ULTIMA_OC_ABERTA,
                O.DATEMI AS DATA_ULTIMA_OC_ABERTA,
                CAST(I.QTDPED AS FLOAT) AS QTD_PEDIDA_ULTIMA_OC_ABERTA,
                CAST(I.QTDABE AS FLOAT) AS QTD_ABERTA_ULTIMA_OC_ABERTA,
                COALESCE(I.UNIMED, '') AS UNIDADE_ULTIMA_OC_ABERTA,
                CAST(I.PREUNI AS FLOAT) AS PRECO_ULTIMA_OC_ABERTA
            FROM E420IPO I
            INNER JOIN E420OCP O
                ON O.CODEMP = I.CODEMP
               AND O.CODFIL = I.CODFIL
               AND O.NUMOCP = I.NUMOCP
            LEFT JOIN E095FOR F
                ON F.CODFOR = O.CODFOR
            WHERE I.CODEMP = P.CODEMP
              AND I.CODPRO = P.CODPRO
              AND COALESCE(I.CODDER, '') = COALESCE(D.CODDER, '')
              AND COALESCE(I.QTDABE, 0) > 0
            ORDER BY O.DATEMI DESC, O.NUMOCP DESC, I.SEQIPO DESC
        ) ULTPO
        WHERE P.CODEMP = ?
    """

    if codpro:
        from_data_sql += " AND P.CODPRO LIKE ?"

    if despro:
        from_data_sql += " AND P.DESPRO LIKE ?"

    if codfam:
        from_data_sql += " AND P.CODFAM = ?"

    if codori:
        from_data_sql += " AND P.CODORI = ?"

    if codder:
        from_data_sql += " AND COALESCE(D.CODDER, '') LIKE ?"

    if numero_projeto:
        from_data_sql += """
            AND EXISTS (
                SELECT 1
                FROM (
                    SELECT X.CODEMP, X.CODPRO, COALESCE(X.CODDER, '') AS CODDER, CAST(COALESCE(X.NUMPRJ, 0) AS VARCHAR(20)) AS NUMPRJ, COALESCE(X.CODCCU, '') AS CODCCU
                    FROM E420IPO X
                    UNION ALL
                    SELECT Y.CODEMP, Y.CODPRO, COALESCE(Y.CODDER, '') AS CODDER, CAST(COALESCE(Y.NUMPRJ, 0) AS VARCHAR(20)) AS NUMPRJ, COALESCE(Y.CODCCU, '') AS CODCCU
                    FROM E440IPC Y
                ) F
                WHERE F.CODEMP = P.CODEMP
                  AND F.CODPRO = P.CODPRO
                  AND F.CODDER = COALESCE(D.CODDER, '')
                  AND F.NUMPRJ LIKE ?
            )
        """

    if centro_custo:
        from_data_sql += """
            AND EXISTS (
                SELECT 1
                FROM (
                    SELECT X.CODEMP, X.CODPRO, COALESCE(X.CODDER, '') AS CODDER, CAST(COALESCE(X.NUMPRJ, 0) AS VARCHAR(20)) AS NUMPRJ, COALESCE(X.CODCCU, '') AS CODCCU
                    FROM E420IPO X
                    UNION ALL
                    SELECT Y.CODEMP, Y.CODPRO, COALESCE(Y.CODDER, '') AS CODDER, CAST(COALESCE(Y.NUMPRJ, 0) AS VARCHAR(20)) AS NUMPRJ, COALESCE(Y.CODCCU, '') AS CODCCU
                    FROM E440IPC Y
                ) F
                WHERE F.CODEMP = P.CODEMP
                  AND F.CODPRO = P.CODPRO
                  AND F.CODDER = COALESCE(D.CODDER, '')
                  AND F.CODCCU LIKE ?
            )
        """

    from_data_sql += clausula_sql_situacao_cadastro('P', situacao_cadastro)

    if somente_com_oc_aberta:
        from_data_sql += """
            AND EXISTS (
                SELECT 1
                FROM E420IPO I
                WHERE I.CODEMP = P.CODEMP
                  AND I.CODPRO = P.CODPRO
                  AND COALESCE(I.CODDER, '') = COALESCE(D.CODDER, '')
                  AND COALESCE(I.QTDABE, 0) > 0
            )
        """

    sql_dados = f"""
        SELECT
            P.CODPRO AS codigo,
            P.DESPRO AS descricao,
            P.CODFAM AS familia,
            P.CODORI AS origem,
            P.TIPPRO AS tipo,
            P.UNIMED AS unidade_medida,
            COALESCE(D.CODDER, '') AS derivacao,
            CAST(COALESCE(EST.SALDO_TOTAL, 0) AS FLOAT) AS saldo_total,
            CAST(COALESCE(D.PREMED, 0) AS FLOAT) AS preco_medio,
            D.DATMED AS data_preco_medio,
            CAST(COALESCE(D.PREUEN, 0) AS FLOAT) AS preco_ultima_entrada_cadastro,
            D.DATUEN AS data_ultima_entrada_cadastro,
            CAST(COALESCE(D.PRECUS, 0) AS FLOAT) AS custo_calculado,
            D.DATCUS AS data_custo_calculado,
            COALESCE(D.HORCUS, 0) AS hora_custo_calculado,
            COALESCE(D.ORICUS, '') AS origem_custo,
            COALESCE(D.INFCUS, '') AS informacao_custo,
            CAST(COALESCE(D.QTDCUS, 0) AS FLOAT) AS quantidade_base_custo,
            CAST(COALESCE(D.CUSSAL, 0) AS FLOAT) AS custo_salarial,
            CAST(COALESCE(D.CUSENC, 0) AS FLOAT) AS custo_encargos,
            ULTNF.NUMERO_NF_ULTIMA_COMPRA AS numero_nf_ultima_compra,
            COALESCE(ULTNF.SERIE_NF_ULTIMA_COMPRA, '') AS serie_nf_ultima_compra,
            ULTNF.DATA_EMISSAO_NF_ULTIMA_COMPRA AS data_emissao_nf_ultima_compra,
            ULTNF.DATA_ENTRADA_NF_ULTIMA_COMPRA AS data_entrada_nf_ultima_compra,
            COALESCE(ULTNF.FORNECEDOR_ULTIMA_COMPRA, '') AS fornecedor_ultima_compra,
            CAST(COALESCE(ULTNF.PRECO_NF_ULTIMA_COMPRA, 0) AS FLOAT) AS preco_nf_ultima_compra,
            CAST(COALESCE(ULTNF.PRECO_ESTOQUE_NF_ULTIMA_COMPRA, 0) AS FLOAT) AS preco_estoque_nf_ultima_compra,
            CAST(COALESCE(ULTNF.QTD_NF_ULTIMA_COMPRA, 0) AS FLOAT) AS quantidade_nf_ultima_compra,
            COALESCE(ULTNF.UNIDADE_NF_ULTIMA_COMPRA, '') AS unidade_nf_ultima_compra,
            COALESCE(ULTNF.NUMERO_OC_ORIGEM_ULTIMA_COMPRA, 0) AS numero_oc_origem_ultima_compra,
            CAST(
                COALESCE(
                    NULLIF(ULTPO.ULTIMA_OC_ABERTA, 0),
                    NULLIF(ULTNF.NUMERO_OC_ORIGEM_ULTIMA_COMPRA, 0),
                    0
                ) AS INT
            ) AS numero_oc_ultima,
            CASE WHEN COALESCE(OCA.QTD_OC_ABERTA_TOTAL, 0) > 0 THEN 'Sim' ELSE 'Não' END AS possui_oc_aberta,
            CAST(COALESCE(OCA.QTD_OC_ABERTA_TOTAL, 0) AS FLOAT) AS quantidade_oc_aberta,
            COALESCE(OCA.QTDE_OCS_ABERTAS, 0) AS quantidade_ocs_abertas,
            COALESCE(ULTPO.ULTIMA_OC_ABERTA, 0) AS ultima_oc_aberta,
            ULTPO.DATA_ULTIMA_OC_ABERTA AS data_ultima_oc_aberta,
            COALESCE(ULTPO.FORNECEDOR_ULTIMA_OC_ABERTA, '') AS fornecedor_ultima_oc_aberta,
            CAST(COALESCE(ULTPO.QTD_PEDIDA_ULTIMA_OC_ABERTA, 0) AS FLOAT) AS qtd_pedida_ultima_oc_aberta,
            CAST(COALESCE(ULTPO.QTD_ABERTA_ULTIMA_OC_ABERTA, 0) AS FLOAT) AS qtd_aberta_ultima_oc_aberta,
            COALESCE(ULTPO.UNIDADE_ULTIMA_OC_ABERTA, '') AS unidade_ultima_oc_aberta,
            CAST(COALESCE(ULTPO.PRECO_ULTIMA_OC_ABERTA, 0) AS FLOAT) AS preco_ultima_oc_aberta
        {from_data_sql}
        ORDER BY P.CODPRO, COALESCE(D.CODDER, '')
        OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
    """

    params_dados = params_where + [offset, tamanho_pagina]

    cursor.execute(sql_dados, params_dados)
    rows = cursor.fetchall()
    columns = [col[0] for col in cursor.description]
    conn.close()

    resultado = []

    for row in rows:
        item = {}
        for i, col in enumerate(columns):
            item[col] = row[i]

        tipo = (item.get('tipo') or '').strip().upper()
        if tipo == 'P':
            item['tipo_descricao'] = 'Produzido'
        elif tipo == 'C':
            item['tipo_descricao'] = 'Comprado'
        else:
            item['tipo_descricao'] = item.get('tipo') or 'Não informado'

        for campo_texto in [
            'descricao', 'familia', 'origem', 'unidade_medida', 'derivacao',
            'serie_nf_ultima_compra', 'fornecedor_ultima_compra', 'fornecedor_ultima_oc_aberta',
            'unidade_nf_ultima_compra', 'unidade_ultima_oc_aberta', 'origem_custo', 'informacao_custo'
        ]:
            item[campo_texto] = (item.get(campo_texto) or '').strip()

        item['numero_oc_ultima'] = (
            item.get('numero_oc_ultima')
            or item.get('ultima_oc_aberta')
            or item.get('numero_oc_origem_ultima_compra')
            or 0
        )

        resultado.append(item)

    total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros > 0 else 1

    return {
        'pagina': pagina,
        'tamanho_pagina': tamanho_pagina,
        'total_registros': total_registros,
        'total_paginas': total_paginas,
        'dados': resultado
    }


@app.get('/api/bom')
def consultar_bom(
    codmod: str,
    codder: Optional[str] = None,
    situacao_cadastro: str = 'TODOS',
    max_nivel: int = 10,
    usuario=Depends(validar_token)
):
    codmod = (codmod or '').strip()
    codder = (codder or '').strip() or None

    if not codmod:
        raise HTTPException(status_code=400, detail='Informe o código do produto / modelo para consultar a estrutura.')

    if max_nivel < 1:
        max_nivel = 1
    if max_nivel > 15:
        max_nivel = 15

    situacao_cadastro = normalizar_situacao_cadastro(situacao_cadastro)

    conn = get_connection()
    cursor = conn.cursor()

    raiz_existe = _model_exists(cursor, EMPRESA_PADRAO, codmod, {})
    if not raiz_existe:
        conn.close()
        raise HTTPException(status_code=404, detail='Modelo não encontrado na E700MOD para o código informado.')

    descricao_raiz = _model_description(cursor, EMPRESA_PADRAO, codmod, {})
    cursor.execute("SELECT TOP 1 COALESCE(UNIMED, '') FROM E075PRO WHERE CODEMP = ? AND CODPRO = ?", [EMPRESA_PADRAO, codmod])
    row_um = cursor.fetchone()
    unidade_raiz = row_um[0].strip() if row_um and isinstance(row_um[0], str) else (row_um[0] or '') if row_um else ''
    dados = _build_bom_rows(cursor, EMPRESA_PADRAO, codmod, codder, max_nivel, situacao_cadastro)
    conn.close()

    total_itens = len(dados)
    total_niveis = max([item.get('nivel', 0) for item in dados], default=0)
    total_modelos_filhos = len({item.get('codigo_componente') for item in dados if item.get('possui_filhos')})

    return {
        'cabecalho': {
            'codigo_modelo': codmod,
            'descricao_modelo': descricao_raiz,
            'derivacao_modelo': codder or '',
            'unidade_modelo': unidade_raiz,
            'max_nivel': max_nivel,
        },
        'total_itens': total_itens,
        'total_niveis': total_niveis,
        'total_modelos_filhos': total_modelos_filhos,
        'dados': dados,
    }






@app.get('/api/notas-recebimento')
def consultar_notas_recebimento(
    fornecedor: Optional[str] = None,
    situacao_nf: Optional[str] = None,
    numero_nf: Optional[str] = None,
    numero_nf_exato: bool = True,
    serie_nf: Optional[str] = None,
    codigo_filial: Optional[str] = None,
    codigo_item: Optional[str] = None,
    descricao_item: Optional[str] = None,
    centro_custo: Optional[str] = None,
    numero_projeto: Optional[str] = None,
    transacao: Optional[str] = None,
    origem_material: Optional[str] = None,
    familia: Optional[str] = None,
    deposito: Optional[str] = None,
    numero_oc_origem: Optional[str] = None,
    situacao_cadastro: str = 'TODOS',
    data_emissao_ini: Optional[str] = None,
    data_emissao_fim: Optional[str] = None,
    data_recebimento_ini: Optional[str] = None,
    data_recebimento_fim: Optional[str] = None,
    tipo_item: str = 'TODOS',
    valor_min: Optional[float] = None,
    valor_max: Optional[float] = None,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token)
):
    if pagina < 1:
        pagina = 1

    if tamanho_pagina < 1:
        tamanho_pagina = 100

    if tamanho_pagina > 100:
        tamanho_pagina = 100

    offset = (pagina - 1) * tamanho_pagina

    conn = get_connection()
    cursor = conn.cursor()

    base_union = """
        SELECT
            H.CodEmp AS codigo_empresa,
            H.CodFil AS codigo_filial,
            H.NumNfc AS numero_nf,
            H.CodSnf AS serie_nf,
            H.CodFor AS codigo_fornecedor,
            COALESCE(F.NomFor, '') AS nome_fornecedor,
            COALESCE(F.ApeFor, '') AS fantasia_fornecedor,
            H.DatEmi AS data_emissao,
            H.DatEnt AS data_recebimento,
            CASE
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '1' THEN 'DIGITADA'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '2' THEN 'FECHADA'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '3' THEN 'CANCELADA'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '4' THEN 'DOCUMENTO FISCAL EMITIDO (SAÍDA)'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '5' THEN 'AGUARDANDO FECHAMENTO (PÓS-SAÍDA)'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '6' THEN 'AGUARDANDO INTEGRAÇÃO WMS'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '7' THEN 'DIGITADA INTEGRAÇÃO'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '8' THEN 'AGRUPADA'
            WHEN COALESCE(CAST(H.SitNfc AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
            ELSE UPPER(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))
        END AS situacao_nf,
            'PRODUTO' AS tipo_item,
            CAST(I.SeqIpc AS INT) AS sequencia_item,
            COALESCE(I.CodPro, '') AS codigo_item,
            COALESCE(I.CplIpc, '') AS descricao_lancamento,
            COALESCE(P.DesPro, '') AS descricao_cadastro_produto_servico,
            COALESCE(P.DesPro, I.CplIpc, '') AS descricao_item,
            COALESCE(I.CodDer, '') AS derivacao,
            COALESCE(I.UniMed, P.UniMed, '') AS unidade_medida,
            COALESCE(I.TnsPro, '') AS transacao,
            COALESCE(I.CodDep, '') AS deposito,
            COALESCE(I.CodCcu, '') AS codigo_centro_custo,
            COALESCE(CC.DesCcu, '') AS descricao_centro_custo,
            CAST(COALESCE(I.NumPrj, 0) AS INT) AS numero_projeto,
            COALESCE(PRJ.NomPrj, '') AS nome_projeto,
            CAST(COALESCE(I.CodFpj, 0) AS INT) AS codigo_fase_projeto,
            COALESCE(FPJ.DesFpj, '') AS descricao_fase_projeto,
            COALESCE(I.CodFam, P.CodFam, '') AS codigo_familia,
            COALESCE(P.CodOri, '') AS origem_material,
            COALESCE(P.SitPro, '') AS situacao_cadastro_produto,
            CAST(COALESCE(I.QtdRec, 0) AS FLOAT) AS quantidade_recebida,
            CAST(COALESCE(I.PreUni, 0) AS FLOAT) AS preco_unitario,
            CAST(COALESCE(I.VlrBru, 0) AS FLOAT) AS valor_bruto,
            CAST(COALESCE(I.VlrLiq, 0) AS FLOAT) AS valor_liquido,
            CAST(COALESCE(NULLIF(O.VlrFin, 0), NULLIF(O.VlrLiq, 0), NULLIF(O.VlrOri, 0), 0) AS FLOAT) AS valor_total_oc_cabecalho,
            CAST(COALESCE(I.VlrIpi, 0) AS FLOAT) AS valor_ipi,
            CAST(COALESCE(I.VlrIcm, 0) AS FLOAT) AS valor_icms,
            CAST(COALESCE(I.VlrIcs, 0) AS FLOAT) AS valor_icms_st,
            CAST(COALESCE(I.VlrPis, 0) AS FLOAT) AS valor_pis,
            CAST(COALESCE(I.VlrCor, 0) AS FLOAT) AS valor_cofins,
            CAST(0 AS FLOAT) AS valor_iss,
            CAST(COALESCE(I.NumOcp, 0) AS INT) AS numero_oc_origem
        FROM E440NFC H
        INNER JOIN E440IPC I
            ON I.CodEmp = H.CodEmp
           AND I.CodFil = H.CodFil
           AND I.CodFor = H.CodFor
           AND I.NumNfc = H.NumNfc
           AND I.CodSnf = H.CodSnf
        LEFT JOIN E095FOR F
            ON F.CodFor = H.CodFor
        LEFT JOIN E075PRO P
            ON P.CodEmp = I.CodEmp
           AND P.CodPro = I.CodPro
        LEFT JOIN E044CCU CC
            ON CC.CodEmp = I.CodEmp
           AND CC.CodCcu = I.CodCcu
        LEFT JOIN E615PRJ PRJ
            ON PRJ.CodEmp = I.CodEmp
           AND PRJ.NumPrj = I.NumPrj
        LEFT JOIN E615FPJ FPJ
            ON FPJ.CodEmp = I.CodEmp
           AND FPJ.NumPrj = I.NumPrj
           AND FPJ.CodFpj = I.CodFpj
        LEFT JOIN E420OCP O
            ON O.CodEmp = I.CodEmp
           AND O.CodFil = I.CodFil
           AND O.NumOcp = I.NumOcp

        UNION ALL

        SELECT
            H.CodEmp AS codigo_empresa,
            H.CodFil AS codigo_filial,
            H.NumNfc AS numero_nf,
            H.CodSnf AS serie_nf,
            H.CodFor AS codigo_fornecedor,
            COALESCE(F.NomFor, '') AS nome_fornecedor,
            COALESCE(F.ApeFor, '') AS fantasia_fornecedor,
            H.DatEmi AS data_emissao,
            H.DatEnt AS data_recebimento,
            CASE
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '1' THEN 'DIGITADA'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '2' THEN 'FECHADA'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '3' THEN 'CANCELADA'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '4' THEN 'DOCUMENTO FISCAL EMITIDO (SAÍDA)'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '5' THEN 'AGUARDANDO FECHAMENTO (PÓS-SAÍDA)'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '6' THEN 'AGUARDANDO INTEGRAÇÃO WMS'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '7' THEN 'DIGITADA INTEGRAÇÃO'
            WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))) = '8' THEN 'AGRUPADA'
            WHEN COALESCE(CAST(H.SitNfc AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
            ELSE UPPER(CAST(COALESCE(H.SitNfc, '') AS VARCHAR(40)))
        END AS situacao_nf,
            'SERVIÇO' AS tipo_item,
            CAST(SI.SeqIsc AS INT) AS sequencia_item,
            COALESCE(SI.CodSer, '') AS codigo_item,
            COALESCE(SI.CplIsc, '') AS descricao_lancamento,
            COALESCE(S.DesSer, '') AS descricao_cadastro_produto_servico,
            COALESCE(S.DesSer, SI.CplIsc, '') AS descricao_item,
            '' AS derivacao,
            COALESCE(SI.UniMed, S.UniMed, '') AS unidade_medida,
            COALESCE(SI.TnsSer, '') AS transacao,
            '' AS deposito,
            COALESCE(SI.CodCcu, '') AS codigo_centro_custo,
            COALESCE(CC.DesCcu, '') AS descricao_centro_custo,
            CAST(COALESCE(SI.NumPrj, 0) AS INT) AS numero_projeto,
            COALESCE(PRJ.NomPrj, '') AS nome_projeto,
            CAST(COALESCE(SI.CodFpj, 0) AS INT) AS codigo_fase_projeto,
            COALESCE(FPJ.DesFpj, '') AS descricao_fase_projeto,
            COALESCE(SI.CodFam, S.CodFam, '') AS codigo_familia,
            COALESCE(S.OriMer, '') AS origem_material,
            '' AS situacao_cadastro_produto,
            CAST(COALESCE(SI.QtdRec, 0) AS FLOAT) AS quantidade_recebida,
            CAST(COALESCE(SI.PreUni, 0) AS FLOAT) AS preco_unitario,
            CAST(COALESCE(SI.VlrBru, 0) AS FLOAT) AS valor_bruto,
            CAST(COALESCE(SI.VlrLiq, 0) AS FLOAT) AS valor_liquido,
            CAST(COALESCE(NULLIF(O.VlrFin, 0), NULLIF(O.VlrLiq, 0), NULLIF(O.VlrOri, 0), 0) AS FLOAT) AS valor_total_oc_cabecalho,
            CAST(COALESCE(SI.VlrIpi, 0) AS FLOAT) AS valor_ipi,
            CAST(COALESCE(SI.VlrIcm, 0) AS FLOAT) AS valor_icms,
            CAST(COALESCE(SI.VlrIcs, 0) AS FLOAT) AS valor_icms_st,
            CAST(COALESCE(SI.VlrPis, 0) AS FLOAT) AS valor_pis,
            CAST(COALESCE(SI.VlrCor, 0) AS FLOAT) AS valor_cofins,
            CAST(COALESCE(SI.VlrIss, 0) AS FLOAT) AS valor_iss,
            CAST(COALESCE(SI.NumOcp, 0) AS INT) AS numero_oc_origem
        FROM E440NFC H
        INNER JOIN E440ISC SI
            ON SI.CodEmp = H.CodEmp
           AND SI.CodFil = H.CodFil
           AND SI.CodFor = H.CodFor
           AND SI.NumNfc = H.NumNfc
           AND SI.CodSnf = H.CodSnf
        LEFT JOIN E095FOR F
            ON F.CodFor = H.CodFor
        LEFT JOIN E080SER S
            ON S.CodEmp = SI.CodEmp
           AND S.CodSer = SI.CodSer
        LEFT JOIN E044CCU CC
            ON CC.CodEmp = SI.CodEmp
           AND CC.CodCcu = SI.CodCcu
        LEFT JOIN E615PRJ PRJ
            ON PRJ.CodEmp = SI.CodEmp
           AND PRJ.NumPrj = SI.NumPrj
        LEFT JOIN E615FPJ FPJ
            ON FPJ.CodEmp = SI.CodEmp
           AND FPJ.NumPrj = SI.NumPrj
           AND FPJ.CodFpj = SI.CodFpj
        LEFT JOIN E420OCP O
            ON O.CodEmp = SI.CodEmp
           AND O.CodFil = SI.CodFil
           AND O.NumOcp = SI.NumOcp
    """

    cte_sql = f"""
        WITH BASE AS (
            {base_union}
        )
    """

    where_parts = ["BASE.codigo_empresa = ?"]
    params_where = [EMPRESA_PADRAO]

    tipo_item = (tipo_item or 'TODOS').strip().upper()
    situacao_nf = (situacao_nf or '').strip()
    numero_nf = (numero_nf or '').strip()
    serie_nf = (serie_nf or '').strip()
    codigo_filial = (codigo_filial or '').strip()
    codigo_item = (codigo_item or '').strip()
    descricao_item = (descricao_item or '').strip()
    centro_custo = (centro_custo or '').strip()
    numero_projeto = (numero_projeto or '').strip()
    transacao = (transacao or '').strip()
    origem_material = (origem_material or '').strip()
    familia = (familia or '').strip()
    deposito = (deposito or '').strip()
    numero_oc_origem = (numero_oc_origem or '').strip()
    fornecedor = (fornecedor or '').strip()

    if fornecedor:
        fornecedor_like = f"%{fornecedor}%"
        where_parts.append("""
            (
                CAST(BASE.codigo_fornecedor AS VARCHAR(20)) LIKE ?
                OR BASE.nome_fornecedor LIKE ?
                OR BASE.fantasia_fornecedor LIKE ?
            )
        """)
        params_where.extend([fornecedor_like, fornecedor_like, fornecedor_like])

    if codigo_filial:
        if codigo_filial.isdigit():
            where_parts.append("BASE.codigo_filial = ?")
            params_where.append(int(codigo_filial))
        else:
            where_parts.append("CAST(BASE.codigo_filial AS VARCHAR(20)) LIKE ?")
            params_where.append(f"%{codigo_filial}%")

    if numero_nf:
        if numero_nf_exato and numero_nf.isdigit():
            where_parts.append("BASE.numero_nf = ?")
            params_where.append(int(numero_nf))
        else:
            where_parts.append("CAST(BASE.numero_nf AS VARCHAR(20)) LIKE ?")
            params_where.append(f"%{numero_nf}%")

    if situacao_nf:
        where_parts.append("UPPER(CAST(COALESCE(BASE.situacao_nf, '') AS VARCHAR(20))) LIKE ?")
        params_where.append(f"%{situacao_nf.upper()}%")

    if serie_nf:
        where_parts.append("BASE.serie_nf LIKE ?")
        params_where.append(f"%{serie_nf}%")

    if codigo_item:
        where_parts.append("BASE.codigo_item LIKE ?")
        params_where.append(f"%{codigo_item}%")

    if descricao_item:
        where_parts.append("BASE.descricao_item LIKE ?")
        params_where.append(f"%{descricao_item}%")

    if centro_custo:
        centro_like = f"%{centro_custo}%"
        where_parts.append("(BASE.codigo_centro_custo LIKE ? OR BASE.descricao_centro_custo LIKE ?)")
        params_where.extend([centro_like, centro_like])

    if numero_projeto:
        where_parts.append("CAST(BASE.numero_projeto AS VARCHAR(20)) LIKE ?")
        params_where.append(f"%{numero_projeto}%")

    if transacao:
        where_parts.append("BASE.transacao LIKE ?")
        params_where.append(f"%{transacao}%")

    if origem_material:
        where_parts.append("BASE.origem_material LIKE ?")
        params_where.append(f"%{origem_material}%")

    if familia:
        where_parts.append("BASE.codigo_familia LIKE ?")
        params_where.append(f"%{familia}%")

    if deposito:
        where_parts.append("BASE.deposito LIKE ?")
        params_where.append(f"%{deposito}%")

    if numero_oc_origem:
        if numero_oc_origem.isdigit():
            where_parts.append("BASE.numero_oc_origem = ?")
            params_where.append(int(numero_oc_origem))
        else:
            where_parts.append("CAST(BASE.numero_oc_origem AS VARCHAR(20)) LIKE ?")
            params_where.append(f"%{numero_oc_origem}%")

    situacao_cadastro = normalizar_situacao_cadastro(situacao_cadastro)
    if situacao_cadastro == 'ATIVO':
        where_parts.append("(BASE.tipo_item <> 'PRODUTO' OR COALESCE(BASE.situacao_cadastro_produto, 'A') = 'A')")
    elif situacao_cadastro == 'INATIVO':
        where_parts.append("(BASE.tipo_item <> 'PRODUTO' OR COALESCE(BASE.situacao_cadastro_produto, 'A') = 'I')")

    if data_emissao_ini:
        where_parts.append("CAST(BASE.data_emissao AS DATE) >= ?")
        params_where.append(data_emissao_ini)

    if data_emissao_fim:
        where_parts.append("CAST(BASE.data_emissao AS DATE) <= ?")
        params_where.append(data_emissao_fim)

    if data_recebimento_ini:
        where_parts.append("CAST(BASE.data_recebimento AS DATE) >= ?")
        params_where.append(data_recebimento_ini)

    if data_recebimento_fim:
        where_parts.append("CAST(BASE.data_recebimento AS DATE) <= ?")
        params_where.append(data_recebimento_fim)

    if tipo_item in ('PRODUTO', 'SERVIÇO'):
        where_parts.append("BASE.tipo_item = ?")
        params_where.append(tipo_item)

    if valor_min is not None:
        where_parts.append("COALESCE(BASE.valor_liquido, 0) >= ?")
        params_where.append(valor_min)

    if valor_max is not None:
        where_parts.append("COALESCE(BASE.valor_liquido, 0) <= ?")
        params_where.append(valor_max)

    where_sql = " AND ".join(where_parts)

    sql_total = cte_sql + f"""
        SELECT COUNT(*)
        FROM BASE
        WHERE {where_sql}
    """

    sql_dados = cte_sql + f"""
        SELECT *
        FROM BASE
        WHERE {where_sql}
        ORDER BY
            BASE.data_recebimento DESC,
            BASE.data_emissao DESC,
            BASE.numero_nf DESC,
            BASE.sequencia_item ASC
        OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
    """

    try:
        cursor.execute(sql_total, params_where)
        total_registros = cursor.fetchone()[0]

        cursor.execute(sql_dados, params_where + [offset, tamanho_pagina])
        rows = cursor.fetchall()
        columns = [col[0] for col in cursor.description]
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erro SQL em Notas de Recebimento: {str(e)}")
    finally:
        conn.close()

    dados = []
    for row in rows:
        item = {}
        for i, col in enumerate(columns):
            valor = row[i]
            if isinstance(valor, str):
                valor = valor.strip()
            item[col] = valor
        # Enriquece com classificação de movimento (bruto/devolução/estorno/líquido)
        try:
            item = _enriquecer_item_movimento_nf(item)
        except Exception as exc:
            # Best-effort — nunca derruba a request
            print(f"[notas-recebimento] falha ao classificar movimento: {exc}")
        dados.append(item)

    total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros > 0 else 1

    # KPIs agregados de movimento (úteis para o dashboard)
    kpis_movimento = {
        "valor_recebido_bruto": 0.0,
        "valor_devolucao": 0.0,
        "valor_estorno": 0.0,
        "valor_recebido_liquido": 0.0,
        "qtd_recebimentos": 0,
        "qtd_devolucoes": 0,
        "qtd_estornos": 0,
        "qtd_cancelamentos": 0,
    }
    for it in dados:
        kpis_movimento["valor_recebido_bruto"] += float(it.get("valor_recebido_bruto") or 0)
        kpis_movimento["valor_devolucao"] += float(it.get("valor_devolucao") or 0)
        kpis_movimento["valor_estorno"] += float(it.get("valor_estorno") or 0)
        kpis_movimento["valor_recebido_liquido"] += float(it.get("valor_recebido_liquido") or 0)
        tipo = str(it.get("tipo_movimento_nf") or "").upper()
        if tipo == "RECEBIMENTO" or tipo == "OUTROS":
            kpis_movimento["qtd_recebimentos"] += 1
        elif tipo == "DEVOLUCAO":
            kpis_movimento["qtd_devolucoes"] += 1
        elif tipo == "ESTORNO":
            kpis_movimento["qtd_estornos"] += 1
        elif tipo == "CANCELAMENTO":
            kpis_movimento["qtd_cancelamentos"] += 1
    for k in ("valor_recebido_bruto", "valor_devolucao", "valor_estorno", "valor_recebido_liquido"):
        kpis_movimento[k] = round(kpis_movimento[k], 2)

    return {
        'pagina': pagina,
        'tamanho_pagina': tamanho_pagina,
        'total_registros': total_registros,
        'total_paginas': total_paginas,
        'dados': dados,
        'kpis_movimento': kpis_movimento,
    }


@app.post('/api/notas-recebimento/recarregar-tipo-movimento')
def recarregar_tipo_movimento_nf_endpoint(usuario=Depends(validar_token)):
    """Força recarga do cache de USU_BI_TIPO_MOVIMENTO_NF — útil após
    um INSERT/UPDATE manual na tabela sem reiniciar o uvicorn."""
    return recarregar_tipo_movimento_nf()


@app.get('/api/notas-edocs-conciliacao')
def consultar_notas_edocs_conciliacao(
    tipo_nota: str = 'TODOS',  # TODOS | ENTRADA | SAIDA
    numero_nf: Optional[str] = None,
    serie_nf: Optional[str] = None,
    codigo_filial: Optional[str] = None,
    codigo_pessoa: Optional[str] = None,
    nome_pessoa: Optional[str] = None,
    numero_lote: Optional[str] = None,
    situacao_erp: Optional[str] = None,
    situacao_edocs: Optional[str] = None,
    status_conciliacao: str = 'TODOS',
    data_ini: Optional[str] = None,
    data_fim: Optional[str] = None,
    somente_divergencia: bool = False,
    somente_sem_edocs: bool = False,
    somente_com_erro: bool = False,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token)
):
    if pagina < 1:
        pagina = 1

    if tamanho_pagina < 1:
        tamanho_pagina = 100

    if tamanho_pagina > 100:
        tamanho_pagina = 100

    tipo_nota = (tipo_nota or 'TODOS').strip().upper()
    if tipo_nota not in ('TODOS', 'ENTRADA', 'SAIDA'):
        tipo_nota = 'TODOS'

    status_conciliacao = (status_conciliacao or 'TODOS').strip().upper()
    status_validos = (
        'TODOS', 'OK', 'SEM_EDOCS', 'ERRO_EDOCS', 'DIVERGENCIA_SITUACAO',
        'CHAVE_DIVERGENTE', 'NUMERO_DIVERGENTE', 'SERIE_DIVERGENTE'
    )
    if status_conciliacao not in status_validos:
        status_conciliacao = 'TODOS'

    offset = (pagina - 1) * tamanho_pagina

    conn = get_connection()
    cursor = conn.cursor()

    cte_sql = """
        WITH BASE AS (
            SELECT
                ERP.codigo_empresa,
                ERP.codigo_filial,
                ERP.tipo_nota,
                ERP.serie_nf,
                ERP.numero_nf,
                ERP.situacao_erp,
                ERP.situacao_erp_normalizada,
                ERP.integracao_erp,
                ERP.data_documento,
                ERP.numero_lote,
                ERP.codigo_pessoa,
                ERP.nome_pessoa,
                ERP.valor_liquido,
                ERP.valor_final,
                ERP.chave_nota,
                ERP.erp_qtd_itens,
                ERP.edocs_ideuni_ponte,
                ERP.edocs_numero_nf,
                ERP.edocs_serie_nf,
                ERP.edocs_tipo_nota,
                ERP.edocs_data_emissao,
                ERP.edocs_data_entrada,
                ERP.edocs_chave_acesso,
                ERP.situacao_edocs,
                ERP.situacao_edocs_normalizada,
                ERP.mensagem_edocs,
                ERP.indicador_exportacao_edocs,
                ERP.data_exportacao_edocs,
                ERP.hora_exportacao_edocs,
                ERP.registro_integracao_edocs,
                ERP.versao_registro_edocs,
                ERP.id_requisicao_edocs,
                ERP.chave_requisicao_edocs,
                ERP.data_requisicao_edocs,
                ERP.hora_requisicao_edocs,
                ERP.tipo_evento_edocs,
                ERP.codigo_motivo_edocs,
                ERP.descricao_motivo_edocs,
                ERP.data_evento_edocs,
                ERP.hora_evento_edocs,
                ERP.codint_edocs,
                ERP.ideint_edocs,
                ERP.status_conciliacao,
                ERP.observacao_conciliacao
            FROM (
                SELECT
                    H.CodEmp AS codigo_empresa,
                    H.CodFil AS codigo_filial,
                    'SAIDA' AS tipo_nota,
                    H.CodSnf AS serie_nf,
                    H.NumNfv AS numero_nf,
                    CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)) AS situacao_erp,
                    CASE
                        WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%CANCEL%' THEN 'CANCELADA'
                        WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%REJEIT%' THEN 'REJEITADA'
                        WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%DENEG%' THEN 'DENEGADA'
                        WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                        WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%PEND%' THEN 'PENDENTE'
                        WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                        WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%EMIT%' THEN 'AUTORIZADA'
                        WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))) IN ('1') THEN 'AUTORIZADA'
                        WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))) IN ('2') THEN 'CANCELADA'
                        WHEN COALESCE(CAST(H.SitNfv AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
                        ELSE UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))
                    END AS situacao_erp_normalizada,
                    CAST(COALESCE(H.IntImp, '') AS VARCHAR(20)) AS integracao_erp,
                    COALESCE(H.DatEmi, H.DatGer) AS data_documento,
                    CAST(COALESCE(H.NumLot, 0) AS INT) AS numero_lote,
                    CAST(H.CodCli AS INT) AS codigo_pessoa,
                    COALESCE(C.ApeCli, C.NomCli, '') AS nome_pessoa,
                    CAST(COALESCE(H.VlrLiq, 0) AS FLOAT) AS valor_liquido,
                    CAST(COALESCE(H.VlrFin, 0) AS FLOAT) AS valor_final,
                    CAST('' AS VARCHAR(50)) AS chave_nota,
                    CAST(0 AS INT) AS erp_qtd_itens,
                    CAST('' AS VARCHAR(50)) AS edocs_ideuni_ponte,
                    CAST(0 AS INT) AS edocs_numero_nf,
                    CAST('' AS VARCHAR(10)) AS edocs_serie_nf,
                    CAST('' AS VARCHAR(20)) AS edocs_tipo_nota,
                    CAST(NULL AS DATETIME) AS edocs_data_emissao,
                    CAST(NULL AS DATETIME) AS edocs_data_entrada,
                    CAST('' AS VARCHAR(60)) AS edocs_chave_acesso,
                    COALESCE(CIX.sitiex, '') AS situacao_edocs,
                    CASE
                        WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%CANCEL%' THEN 'CANCELADA'
                        WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%REJEIT%' THEN 'REJEITADA'
                        WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%DENEG%' THEN 'DENEGADA'
                        WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                        WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%PEND%' THEN 'PENDENTE'
                        WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                        WHEN COALESCE(CIX.sitiex, '') = '' THEN 'SEM_STATUS'
                        ELSE UPPER(COALESCE(CIX.sitiex, ''))
                    END AS situacao_edocs_normalizada,
                    COALESCE(CIX.msgerr, '') AS mensagem_edocs,
                    COALESCE(CIX.indexp, '') AS indicador_exportacao_edocs,
                    CIX.datexp AS data_exportacao_edocs,
                    CIX.horexp AS hora_exportacao_edocs,
                    COALESCE(CIX.regint, '') AS registro_integracao_edocs,
                    COALESCE(CIX.verreg, 0) AS versao_registro_edocs,
                    COALESCE(CIM.idtreq, '') AS id_requisicao_edocs,
                    COALESCE(CIM.chvreq, '') AS chave_requisicao_edocs,
                    CIM.datreq AS data_requisicao_edocs,
                    CIM.horreq AS hora_requisicao_edocs,
                    COALESCE(CAST(EIS.tipeis AS VARCHAR(20)), '') AS tipo_evento_edocs,
                    COALESCE(CAST(EIS.codmot AS VARCHAR(20)), '') AS codigo_motivo_edocs,
                    COALESCE(EIS.desmot, '') AS descricao_motivo_edocs,
                    EIS.datger AS data_evento_edocs,
                    EIS.horger AS hora_evento_edocs,
                    CAST(COALESCE(CIX.CODINT, '') AS VARCHAR(20)) AS codint_edocs,
                    CAST(COALESCE(CIX.IDEINT, '') AS VARCHAR(50)) AS ideint_edocs,
                    CASE
                        WHEN COALESCE(CIX.sitiex, '') = ''
                         AND COALESCE(CIM.idtreq, '') = ''
                         AND COALESCE(EIS.desmot, '') = ''
                        THEN 'SEM_EDOCS'
                        WHEN COALESCE(CIX.msgerr, '') <> ''
                          OR COALESCE(CAST(EIS.codmot AS VARCHAR(20)), '') <> ''
                          OR COALESCE(EIS.desmot, '') <> ''
                        THEN 'ERRO_EDOCS'
                        WHEN (
                                CASE
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%CANCEL%' THEN 'CANCELADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%REJEIT%' THEN 'REJEITADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%DENEG%' THEN 'DENEGADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%PEND%' THEN 'PENDENTE'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%EMIT%' THEN 'AUTORIZADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))) IN ('1') THEN 'AUTORIZADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))) IN ('2') THEN 'CANCELADA'
                                    WHEN COALESCE(CAST(H.SitNfv AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
                                    ELSE UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))
                                END
                             ) <> (
                                CASE
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%CANCEL%' THEN 'CANCELADA'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%REJEIT%' THEN 'REJEITADA'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%DENEG%' THEN 'DENEGADA'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%PEND%' THEN 'PENDENTE'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                                    WHEN COALESCE(CIX.sitiex, '') = '' THEN 'SEM_STATUS'
                                    ELSE UPPER(COALESCE(CIX.sitiex, ''))
                                END
                             )
                         AND COALESCE(CIX.sitiex, '') <> ''
                        THEN 'DIVERGENCIA_SITUACAO'
                        ELSE 'OK'
                    END AS status_conciliacao,
                    CASE
                        WHEN COALESCE(CIX.sitiex, '') = ''
                         AND COALESCE(CIM.idtreq, '') = ''
                         AND COALESCE(EIS.desmot, '') = ''
                        THEN 'Nota localizada no ERP, mas sem registro correspondente no EDocs'
                        WHEN COALESCE(CIX.msgerr, '') <> ''
                        THEN 'Erro no EDocs: ' + COALESCE(CIX.msgerr, '')
                        WHEN COALESCE(EIS.desmot, '') <> ''
                        THEN 'Evento/erro EDocs: ' + COALESCE(EIS.desmot, '')
                        WHEN (
                                CASE
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%CANCEL%' THEN 'CANCELADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%REJEIT%' THEN 'REJEITADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%DENEG%' THEN 'DENEGADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%PEND%' THEN 'PENDENTE'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                                    WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%EMIT%' THEN 'AUTORIZADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))) IN ('1') THEN 'AUTORIZADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))) IN ('2') THEN 'CANCELADA'
                                    WHEN COALESCE(CAST(H.SitNfv AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
                                    ELSE UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))
                                END
                             ) <> (
                                CASE
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%CANCEL%' THEN 'CANCELADA'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%REJEIT%' THEN 'REJEITADA'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%DENEG%' THEN 'DENEGADA'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%PEND%' THEN 'PENDENTE'
                                    WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                                    WHEN COALESCE(CIX.sitiex, '') = '' THEN 'SEM_STATUS'
                                    ELSE UPPER(COALESCE(CIX.sitiex, ''))
                                END
                             )
                         AND COALESCE(CIX.sitiex, '') <> ''
                        THEN 'Situação ERP=' +
                             CASE
                                WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%CANCEL%' THEN 'CANCELADA'
                                WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%REJEIT%' THEN 'REJEITADA'
                                WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%DENEG%' THEN 'DENEGADA'
                                WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                                WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%PEND%' THEN 'PENDENTE'
                                WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                                WHEN UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40))) LIKE '%EMIT%' THEN 'AUTORIZADA'
                                WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))) IN ('1') THEN 'AUTORIZADA'
                                WHEN LTRIM(RTRIM(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))) IN ('2') THEN 'CANCELADA'
                                WHEN COALESCE(CAST(H.SitNfv AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
                                ELSE UPPER(CAST(COALESCE(H.SitNfv, '') AS VARCHAR(40)))
                             END
                             + ' x EDocs=' +
                             CASE
                                WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%CANCEL%' THEN 'CANCELADA'
                                WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%REJEIT%' THEN 'REJEITADA'
                                WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%DENEG%' THEN 'DENEGADA'
                                WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                                WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%PEND%' THEN 'PENDENTE'
                                WHEN UPPER(COALESCE(CIX.sitiex, '')) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                                WHEN COALESCE(CIX.sitiex, '') = '' THEN 'SEM_STATUS'
                                ELSE UPPER(COALESCE(CIX.sitiex, ''))
                             END
                        ELSE 'Conciliação ok'
                    END AS observacao_conciliacao
                FROM E140NFV H
                LEFT JOIN E085CLI C
                    ON C.CodCli = H.CodCli
                OUTER APPLY (
                    SELECT TOP 1
                        X.numlot,
                        COALESCE(X.sitiex, '') AS sitiex,
                        COALESCE(X.msgerr, '') AS msgerr,
                        COALESCE(X.indexp, '') AS indexp,
                        X.datexp,
                        X.horexp,
                        COALESCE(CAST(X.regint AS VARCHAR(50)), '') AS regint,
                        COALESCE(X.verreg, 0) AS verreg,
                        X.CODINT,
                        X.IDEINT
                    FROM E000CIX X
                    WHERE COALESCE(H.NumLot, 0) > 0
                      AND X.numlot = H.NumLot
                    ORDER BY
                        COALESCE(X.datalt, X.datexp) DESC,
                        COALESCE(X.horalt, X.horexp) DESC,
                        X.numlot DESC
                ) CIX
                OUTER APPLY (
                    SELECT TOP 1
                        COALESCE(M.idtreq, '') AS idtreq,
                        COALESCE(M.chvreq, '') AS chvreq,
                        M.datreq,
                        M.horreq
                    FROM E000CIM M
                    WHERE 1 = 0
                ) CIM
                OUTER APPLY (
                    SELECT TOP 1
                        E.tipeis,
                        E.codmot,
                        COALESCE(E.desmot, '') AS desmot,
                        E.datger,
                        E.horger
                    FROM E000EIS E
                    WHERE
                        (COALESCE(CIM.idtreq, '') <> '' AND COALESCE(E.idtreq, '') = COALESCE(CIM.idtreq, ''))
                        OR (COALESCE(CIM.idtreq, '') = '' AND COALESCE(CIX.regint, '') <> '' AND COALESCE(E.idtreg, '') = COALESCE(CIX.regint, ''))
                    ORDER BY E.datger DESC, E.horger DESC
                ) EIS

                UNION ALL

                SELECT
                    nfc.CODEMP AS codigo_empresa,
                    nfc.CODFIL AS codigo_filial,
                    'ENTRADA' AS tipo_nota,
                    nfc.CODSNF AS serie_nf,
                    nfc.NUMNFC AS numero_nf,
                    CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)) AS situacao_erp,
                    CASE
                        WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '1' THEN 'DIGITADA'
                        WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '2' THEN 'FECHADA'
                        WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '3' THEN 'CANCELADA'
                        WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '4' THEN 'DOCUMENTO FISCAL EMITIDO (SAÍDA)'
                        WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '5' THEN 'AGUARDANDO FECHAMENTO (PÓS-SAÍDA)'
                        WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '6' THEN 'AGUARDANDO INTEGRAÇÃO WMS'
                        WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '7' THEN 'DIGITADA INTEGRAÇÃO'
                        WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '8' THEN 'AGRUPADA'
                        WHEN COALESCE(CAST(nfc.SITNFC AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
                        ELSE UPPER(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))
                    END AS situacao_erp_normalizada,
                    CAST(COALESCE(nfc.INTIMP, '') AS VARCHAR(20)) AS integracao_erp,
                    COALESCE(nfc.DATENT, nfc.DATEMI, nfc.DATGER) AS data_documento,
                    CAST(COALESCE(nfc.NUMLOT, 0) AS INT) AS numero_lote,
                    CAST(nfc.CODFOR AS INT) AS codigo_pessoa,
                    COALESCE(forx.APEFOR, forx.NOMFOR, '') AS nome_pessoa,
                    CAST(COALESCE(nfc.VLRLIQ, 0) AS FLOAT) AS valor_liquido,
                    CAST(COALESCE(nfc.VLRFIN, 0) AS FLOAT) AS valor_final,
                    COALESCE(nfc.CHVNEL, '') AS chave_nota,
                    COUNT(DISTINCT ipc.SEQIPC) AS erp_qtd_itens,
                    CAST(COALESCE(nex.IDEUNI, '') AS VARCHAR(50)) AS edocs_ideuni_ponte,
                    CAST(COALESCE(edc.NUMNFC, 0) AS INT) AS edocs_numero_nf,
                    COALESCE(edc.CODSNF, '') AS edocs_serie_nf,
                    CAST(COALESCE(edc.TIPNFE, '') AS VARCHAR(20)) AS edocs_tipo_nota,
                    edc.DATEMI AS edocs_data_emissao,
                    edc.DATENT AS edocs_data_entrada,
                    COALESCE(edc.CHVNEL, '') AS edocs_chave_acesso,
                    COALESCE(cix.SITIEX, '') AS situacao_edocs,
                    CASE
                        WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%CANCEL%' THEN 'CANCELADA'
                        WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%REJEIT%' THEN 'REJEITADA'
                        WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%DENEG%' THEN 'DENEGADA'
                        WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                        WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%PEND%' THEN 'PENDENTE'
                        WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                        WHEN COALESCE(cix.SITIEX, '') = '' THEN 'SEM_STATUS'
                        ELSE UPPER(COALESCE(cix.SITIEX, ''))
                    END AS situacao_edocs_normalizada,
                    COALESCE(cix.MSGERR, '') AS mensagem_edocs,
                    COALESCE(cix.INDEXP, '') AS indicador_exportacao_edocs,
                    cix.DATEXP AS data_exportacao_edocs,
                    cix.HOREXP AS hora_exportacao_edocs,
                    COALESCE(CAST(cix.REGINT AS VARCHAR(50)), '') AS registro_integracao_edocs,
                    COALESCE(cix.VERREG, 0) AS versao_registro_edocs,
                    COALESCE(cim.IDTREQ, '') AS id_requisicao_edocs,
                    COALESCE(cim.CHVREQ, '') AS chave_requisicao_edocs,
                    cim.DATREQ AS data_requisicao_edocs,
                    cim.HORREQ AS hora_requisicao_edocs,
                    COALESCE(CAST(eis.TIPEIS AS VARCHAR(20)), '') AS tipo_evento_edocs,
                    COALESCE(CAST(eis.CODMOT AS VARCHAR(20)), '') AS codigo_motivo_edocs,
                    COALESCE(eis.DESMOT, '') AS descricao_motivo_edocs,
                    eis.DATGER AS data_evento_edocs,
                    eis.HORGER AS hora_evento_edocs,
                    CAST(COALESCE(cix.CODINT, '') AS VARCHAR(20)) AS codint_edocs,
                    CAST(COALESCE(cix.IDEINT, '') AS VARCHAR(50)) AS ideint_edocs,
                    CASE
                        WHEN COALESCE(cix.MSGERR, '') <> ''
                          OR COALESCE(eis.DESMOT, '') <> ''
                          OR COALESCE(CAST(eis.CODMOT AS VARCHAR(20)), '') <> ''
                        THEN 'ERRO_EDOCS'
                        WHEN COALESCE(nex.IDEUNI, '') = ''
                         AND COALESCE(edc.CHVNEL, '') = ''
                         AND COALESCE(CAST(edc.NUMNFC AS VARCHAR(20)), '') = ''
                        THEN 'SEM_EDOCS'
                        WHEN ISNULL(NULLIF(LTRIM(RTRIM(nfc.CHVNEL)), ''), 'SEM_CHAVE') <> ISNULL(NULLIF(LTRIM(RTRIM(edc.CHVNEL)), ''), 'SEM_CHAVE')
                        THEN 'CHAVE_DIVERGENTE'
                        WHEN nfc.NUMNFC <> edc.NUMNFC
                        THEN 'NUMERO_DIVERGENTE'
                        WHEN ISNULL(LTRIM(RTRIM(nfc.CODSNF)), '') <> ISNULL(LTRIM(RTRIM(edc.CODSNF)), '')
                        THEN 'SERIE_DIVERGENTE'
                        WHEN (
                                CASE
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '1' THEN 'DIGITADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '2' THEN 'FECHADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '3' THEN 'CANCELADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '4' THEN 'DOCUMENTO FISCAL EMITIDO (SAÍDA)'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '5' THEN 'AGUARDANDO FECHAMENTO (PÓS-SAÍDA)'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '6' THEN 'AGUARDANDO INTEGRAÇÃO WMS'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '7' THEN 'DIGITADA INTEGRAÇÃO'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '8' THEN 'AGRUPADA'
                                    WHEN COALESCE(CAST(nfc.SITNFC AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
                                    ELSE UPPER(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))
                                END
                             ) <> (
                                CASE
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%CANCEL%' THEN 'CANCELADA'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%REJEIT%' THEN 'REJEITADA'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%DENEG%' THEN 'DENEGADA'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%PEND%' THEN 'PENDENTE'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                                    WHEN COALESCE(cix.SITIEX, '') = '' THEN 'SEM_STATUS'
                                    ELSE UPPER(COALESCE(cix.SITIEX, ''))
                                END
                             )
                         AND COALESCE(cix.SITIEX, '') <> ''
                        THEN 'DIVERGENCIA_SITUACAO'
                        ELSE 'OK'
                    END AS status_conciliacao,
                    CASE
                        WHEN COALESCE(cix.MSGERR, '') <> '' THEN 'Erro no EDocs: ' + COALESCE(cix.MSGERR, '')
                        WHEN COALESCE(eis.DESMOT, '') <> '' THEN 'Evento/erro EDocs: ' + COALESCE(eis.DESMOT, '')
                        WHEN COALESCE(nex.IDEUNI, '') = ''
                         AND COALESCE(edc.CHVNEL, '') = ''
                         AND COALESCE(CAST(edc.NUMNFC AS VARCHAR(20)), '') = ''
                        THEN 'Nota localizada no ERP, mas sem registro correspondente no EDocs'
                        WHEN ISNULL(NULLIF(LTRIM(RTRIM(nfc.CHVNEL)), ''), 'SEM_CHAVE') <> ISNULL(NULLIF(LTRIM(RTRIM(edc.CHVNEL)), ''), 'SEM_CHAVE')
                        THEN 'Chave ERP=' + ISNULL(NULLIF(LTRIM(RTRIM(nfc.CHVNEL)), ''), 'SEM_CHAVE') + ' x EDocs=' + ISNULL(NULLIF(LTRIM(RTRIM(edc.CHVNEL)), ''), 'SEM_CHAVE')
                        WHEN nfc.NUMNFC <> edc.NUMNFC
                        THEN 'Número ERP=' + CAST(nfc.NUMNFC AS VARCHAR(20)) + ' x EDocs=' + CAST(edc.NUMNFC AS VARCHAR(20))
                        WHEN ISNULL(LTRIM(RTRIM(nfc.CODSNF)), '') <> ISNULL(LTRIM(RTRIM(edc.CODSNF)), '')
                        THEN 'Série ERP=' + ISNULL(LTRIM(RTRIM(nfc.CODSNF)), '') + ' x EDocs=' + ISNULL(LTRIM(RTRIM(edc.CODSNF)), '')
                        WHEN (
                                CASE
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '1' THEN 'DIGITADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '2' THEN 'FECHADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '3' THEN 'CANCELADA'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '4' THEN 'DOCUMENTO FISCAL EMITIDO (SAÍDA)'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '5' THEN 'AGUARDANDO FECHAMENTO (PÓS-SAÍDA)'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '6' THEN 'AGUARDANDO INTEGRAÇÃO WMS'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '7' THEN 'DIGITADA INTEGRAÇÃO'
                                    WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '8' THEN 'AGRUPADA'
                                    WHEN COALESCE(CAST(nfc.SITNFC AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
                                    ELSE UPPER(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))
                                END
                             ) <> (
                                CASE
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%CANCEL%' THEN 'CANCELADA'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%REJEIT%' THEN 'REJEITADA'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%DENEG%' THEN 'DENEGADA'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%PEND%' THEN 'PENDENTE'
                                    WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                                    WHEN COALESCE(cix.SITIEX, '') = '' THEN 'SEM_STATUS'
                                    ELSE UPPER(COALESCE(cix.SITIEX, ''))
                                END
                             )
                         AND COALESCE(cix.SITIEX, '') <> ''
                        THEN 'Situação ERP=' +
                             CASE
                                WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '1' THEN 'DIGITADA'
                                WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '2' THEN 'FECHADA'
                                WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '3' THEN 'CANCELADA'
                                WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '4' THEN 'DOCUMENTO FISCAL EMITIDO (SAÍDA)'
                                WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '5' THEN 'AGUARDANDO FECHAMENTO (PÓS-SAÍDA)'
                                WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '6' THEN 'AGUARDANDO INTEGRAÇÃO WMS'
                                WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '7' THEN 'DIGITADA INTEGRAÇÃO'
                                WHEN LTRIM(RTRIM(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))) = '8' THEN 'AGRUPADA'
                                WHEN COALESCE(CAST(nfc.SITNFC AS VARCHAR(40)), '') = '' THEN 'SEM_STATUS'
                                ELSE UPPER(CAST(COALESCE(nfc.SITNFC, '') AS VARCHAR(40)))
                             END
                             + ' x EDocs=' +
                             CASE
                                WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%CANCEL%' THEN 'CANCELADA'
                                WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%REJEIT%' THEN 'REJEITADA'
                                WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%DENEG%' THEN 'DENEGADA'
                                WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%INUTIL%' THEN 'INUTILIZADA'
                                WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%PEND%' THEN 'PENDENTE'
                                WHEN UPPER(COALESCE(cix.SITIEX, '')) LIKE '%AUTORIZ%' THEN 'AUTORIZADA'
                                WHEN COALESCE(cix.SITIEX, '') = '' THEN 'SEM_STATUS'
                                ELSE UPPER(COALESCE(cix.SITIEX, ''))
                             END
                        ELSE 'Conciliação ok'
                    END AS observacao_conciliacao
                FROM E440NFC nfc
                LEFT JOIN E095FOR forx
                    ON forx.CODFOR = nfc.CODFOR
                LEFT JOIN E440IPC ipc
                    ON ipc.CODEMP = nfc.CODEMP
                   AND ipc.CODFIL = nfc.CODFIL
                   AND ipc.CODFOR = nfc.CODFOR
                   AND ipc.NUMNFC = nfc.NUMNFC
                   AND ipc.CODSNF = nfc.CODSNF
                LEFT JOIN E000NEX nex
                    ON nex.CODEMP = nfc.CODEMP
                   AND nex.CODFIL = nfc.CODFIL
                   AND nex.CODFOR = nfc.CODFOR
                   AND nex.NUMNFC = nfc.NUMNFC
                   AND ISNULL(LTRIM(RTRIM(nex.CODSNF)), '') = ISNULL(LTRIM(RTRIM(nfc.CODSNF)), '')
                LEFT JOIN E000NFC edc
                    ON (
                           NULLIF(LTRIM(RTRIM(edc.CHVNEL)), '') IS NOT NULL
                       AND NULLIF(LTRIM(RTRIM(nfc.CHVNEL)), '') IS NOT NULL
                       AND LTRIM(RTRIM(edc.CHVNEL)) = LTRIM(RTRIM(nfc.CHVNEL))
                       )
                    OR (
                           edc.CHVNEL IS NULL
                       AND nex.IDEUNI IS NOT NULL
                       AND edc.NUMNFC = nfc.NUMNFC
                       AND ISNULL(LTRIM(RTRIM(edc.CODSNF)), '') = ISNULL(LTRIM(RTRIM(nfc.CODSNF)), '')
                       )
                LEFT JOIN E000CIX cix
                    ON cix.IDEINT = nex.IDEUNI
                LEFT JOIN E000CIM cim
                    ON cim.CODINT = cix.CODINT
                   AND cim.IDEINT = cix.IDEINT
                LEFT JOIN E000EIS eis
                    ON eis.CODINT = cim.CODINT
                   AND eis.CODEMP = cim.CODEMP
                   AND eis.CODFIL = cim.CODFIL
                   AND eis.IDTREQ = cim.IDTREQ
                WHERE nfc.TIPNFE = 1
                GROUP BY
                    nfc.CODEMP,
                    nfc.CODFIL,
                    nfc.CODFOR,
                    forx.APEFOR,
                    forx.NOMFOR,
                    nfc.NUMNFC,
                    nfc.CODSNF,
                    nfc.SITNFC,
                    nfc.INTIMP,
                    nfc.DATEMI,
                    nfc.DATENT,
                    nfc.DATGER,
                    nfc.NUMLOT,
                    nfc.VLRLIQ,
                    nfc.VLRFIN,
                    nfc.CHVNEL,
                    nex.IDEUNI,
                    edc.NUMNFC,
                    edc.CODSNF,
                    edc.TIPNFE,
                    edc.DATEMI,
                    edc.DATENT,
                    edc.CHVNEL,
                    cix.CODINT,
                    cix.IDEINT,
                    cix.SITIEX,
                    cix.MSGERR,
                    cix.INDEXP,
                    cix.DATEXP,
                    cix.HOREXP,
                    cix.REGINT,
                    cix.VERREG,
                    cim.IDTREQ,
                    cim.CHVREQ,
                    cim.DATREQ,
                    cim.HORREQ,
                    eis.TIPEIS,
                    eis.CODMOT,
                    eis.DESMOT,
                    eis.DATGER,
                    eis.HORGER
            ) ERP
        )
    """

    where_parts = ["BASE.codigo_empresa = ?"]
    params_where = [EMPRESA_PADRAO]

    if tipo_nota in ('ENTRADA', 'SAIDA'):
        where_parts.append("BASE.tipo_nota = ?")
        params_where.append(tipo_nota)

    if numero_nf:
        where_parts.append("CAST(BASE.numero_nf AS VARCHAR(20)) LIKE ?")
        params_where.append(f"%{numero_nf}%")

    if serie_nf:
        where_parts.append("BASE.serie_nf LIKE ?")
        params_where.append(f"%{serie_nf}%")

    if codigo_filial:
        where_parts.append("CAST(BASE.codigo_filial AS VARCHAR(20)) LIKE ?")
        params_where.append(f"%{codigo_filial}%")

    if codigo_pessoa:
        where_parts.append("CAST(BASE.codigo_pessoa AS VARCHAR(20)) LIKE ?")
        params_where.append(f"%{codigo_pessoa}%")

    if nome_pessoa:
        where_parts.append("BASE.nome_pessoa LIKE ?")
        params_where.append(f"%{nome_pessoa}%")

    if numero_lote:
        where_parts.append("CAST(BASE.numero_lote AS VARCHAR(20)) LIKE ?")
        params_where.append(f"%{numero_lote}%")

    if situacao_erp:
        situacao_erp = str(situacao_erp).strip()
        where_parts.append("(COALESCE(BASE.situacao_erp, '') = ? OR COALESCE(BASE.situacao_erp_normalizada, '') = ?)")
        params_where.extend([situacao_erp, situacao_erp.upper()])

    if situacao_edocs:
        situacao_edocs = str(situacao_edocs).strip()
        where_parts.append("(COALESCE(BASE.situacao_edocs, '') = ? OR COALESCE(BASE.situacao_edocs_normalizada, '') = ?)")
        params_where.extend([situacao_edocs, situacao_edocs.upper()])

    if status_conciliacao != 'TODOS':
        where_parts.append("BASE.status_conciliacao = ?")
        params_where.append(status_conciliacao)

    if data_ini:
        where_parts.append("CAST(BASE.data_documento AS DATE) >= ?")
        params_where.append(data_ini)

    if data_fim:
        where_parts.append("CAST(BASE.data_documento AS DATE) <= ?")
        params_where.append(data_fim)

    if somente_divergencia:
        where_parts.append("BASE.status_conciliacao IN ('SEM_EDOCS', 'ERRO_EDOCS', 'DIVERGENCIA_SITUACAO', 'CHAVE_DIVERGENTE', 'NUMERO_DIVERGENTE', 'SERIE_DIVERGENTE')")

    if somente_sem_edocs:
        where_parts.append("BASE.status_conciliacao = 'SEM_EDOCS'")

    if somente_com_erro:
        where_parts.append("BASE.status_conciliacao = 'ERRO_EDOCS'")

    where_sql = " AND ".join(where_parts)

    sql_resumo = cte_sql + f"""
        SELECT
            COUNT(*) AS total_registros,
            SUM(CASE WHEN BASE.status_conciliacao = 'OK' THEN 1 ELSE 0 END) AS total_ok,
            SUM(CASE WHEN BASE.status_conciliacao = 'SEM_EDOCS' THEN 1 ELSE 0 END) AS total_sem_edocs,
            SUM(CASE WHEN BASE.status_conciliacao = 'ERRO_EDOCS' THEN 1 ELSE 0 END) AS total_com_erro,
            SUM(CASE WHEN BASE.status_conciliacao = 'DIVERGENCIA_SITUACAO' THEN 1 ELSE 0 END) AS total_divergencia_situacao,
            SUM(CASE WHEN BASE.status_conciliacao = 'CHAVE_DIVERGENTE' THEN 1 ELSE 0 END) AS total_chave_divergente,
            SUM(CASE WHEN BASE.status_conciliacao = 'NUMERO_DIVERGENTE' THEN 1 ELSE 0 END) AS total_numero_divergente,
            SUM(CASE WHEN BASE.status_conciliacao = 'SERIE_DIVERGENTE' THEN 1 ELSE 0 END) AS total_serie_divergente
        FROM BASE
        WHERE {where_sql}
    """

    sql_dados = cte_sql + f"""
        SELECT *
        FROM BASE
        WHERE {where_sql}
        ORDER BY
            CASE
                WHEN BASE.status_conciliacao = 'SEM_EDOCS' THEN 0
                WHEN BASE.status_conciliacao = 'ERRO_EDOCS' THEN 1
                WHEN BASE.status_conciliacao = 'CHAVE_DIVERGENTE' THEN 2
                WHEN BASE.status_conciliacao = 'NUMERO_DIVERGENTE' THEN 3
                WHEN BASE.status_conciliacao = 'SERIE_DIVERGENTE' THEN 4
                WHEN BASE.status_conciliacao = 'DIVERGENCIA_SITUACAO' THEN 5
                ELSE 6
            END,
            BASE.data_documento DESC,
            BASE.numero_nf DESC
        OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
    """

    try:
        cursor.execute(sql_resumo, params_where)
        row = cursor.fetchone()
        resumo = {
            'total_registros': int(row[0] or 0),
            'total_ok': int(row[1] or 0),
            'total_sem_edocs': int(row[2] or 0),
            'total_com_erro': int(row[3] or 0),
            'total_divergencia_situacao': int(row[4] or 0),
            'total_chave_divergente': int(row[5] or 0),
            'total_numero_divergente': int(row[6] or 0),
            'total_serie_divergente': int(row[7] or 0),
        }

        cursor.execute(sql_dados, params_where + [offset, tamanho_pagina])
        rows = cursor.fetchall()
        columns = [col[0] for col in cursor.description]
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erro SQL na conciliação ERP x EDocs: {str(e)}")
    finally:
        conn.close()

    dados = []
    for row in rows:
        item = {}
        for i, col in enumerate(columns):
            valor = row[i]
            if isinstance(valor, str):
                valor = valor.strip()
            item[col] = valor
        dados.append(item)

    total_registros = resumo['total_registros']
    total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros > 0 else 1

    return {
        'pagina': pagina,
        'tamanho_pagina': tamanho_pagina,
        'total_registros': total_registros,
        'total_paginas': total_paginas,
        'resumo': resumo,
        'dados': dados,
        'observacao': 'A conciliação compara a situação do ERP com a situação do EDocs, usando normalização de status para identificar casos como ERP cancelada x EDocs autorizada, ERP autorizada x EDocs cancelada e demais incompatibilidades operacionais.'
    }


