@app.get('/api/contas-pagar')
def consultar_contas_pagar(
    fornecedor: Optional[str] = None,
    numero_titulo: Optional[str] = None,
    tipo_titulo: Optional[str] = None,
    codigo_filial: Optional[str] = None,
    numero_projeto: Optional[str] = None,
    centro_custo: Optional[str] = None,
    status_titulo: str = 'TODOS',
    somente_vencidos: bool = False,
    somente_saldo_aberto: bool = False,
    somente_cheques: bool = False,
    data_emissao_ini: Optional[str] = None,
    data_emissao_fim: Optional[str] = None,
    data_vencimento_ini: Optional[str] = None,
    data_vencimento_fim: Optional[str] = None,
    data_movimento_ini: Optional[str] = None,
    data_movimento_fim: Optional[str] = None,
    valor_min: Optional[float] = None,
    valor_max: Optional[float] = None,
    agrupar_por_fornecedor: bool = False,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token)
):
    if pagina < 1: pagina = 1
    if tamanho_pagina < 1: tamanho_pagina = 100
    if tamanho_pagina > 100: tamanho_pagina = 100
    offset = (pagina - 1) * tamanho_pagina
    status_titulo = normalizar_status_conta_pagar(status_titulo)
    conn = get_connection(); cursor = conn.cursor()
    cte_sql = _montar_cte_contas_pagar()
    where_parts = ["BASE.codigo_empresa = ?"]; params_where = [EMPRESA_PADRAO]
    _where_contas(
        where_parts, params_where,
        cliente=fornecedor,
        numero_titulo=numero_titulo,
        tipo_titulo=tipo_titulo,
        codigo_filial=codigo_filial,
        numero_projeto=numero_projeto,
        centro_custo=centro_custo,
        status_titulo=status_titulo,
        somente_vencidos=somente_vencidos,
        somente_saldo_aberto=somente_saldo_aberto,
        somente_cheques=somente_cheques,
        data_emissao_ini=data_emissao_ini,
        data_emissao_fim=data_emissao_fim,
        data_vencimento_ini=data_vencimento_ini,
        data_vencimento_fim=data_vencimento_fim,
        data_movimento_ini=data_movimento_ini,
        data_movimento_fim=data_movimento_fim,
        valor_min=valor_min,
        valor_max=valor_max,
        entidade='fornecedor'
    )
    where_sql = " AND ".join(where_parts)
    try:
        if agrupar_por_fornecedor:
            sql_total = cte_sql + f"SELECT COUNT(*) FROM (SELECT BASE.codigo_fornecedor FROM BASE WHERE {where_sql} GROUP BY BASE.codigo_fornecedor) X"
            sql_dados = cte_sql + f"""
                SELECT CAST(BASE.codigo_fornecedor AS INT) AS codigo_fornecedor,
                       MAX(BASE.nome_fornecedor) AS nome_fornecedor, MAX(BASE.fantasia_fornecedor) AS fantasia_fornecedor,
                       COUNT(*) AS quantidade_titulos,
                       SUM(CASE WHEN COALESCE(BASE.valor_aberto,0)>0 THEN 1 ELSE 0 END) AS titulos_em_aberto,
                       SUM(CASE WHEN BASE.status_titulo='VENCIDO' THEN 1 ELSE 0 END) AS titulos_vencidos,
                       CAST(SUM(COALESCE(BASE.valor_original,0)) AS FLOAT) AS valor_original_total,
                       CAST(SUM(COALESCE(BASE.valor_aberto,0)) AS FLOAT) AS valor_aberto_total,
                       CAST(SUM(COALESCE(BASE.valor_pago,0)) AS FLOAT) AS valor_pago_total,
                       MAX(COALESCE(BASE.dias_atraso,0)) AS maior_atraso_dias,
                       MIN(BASE.data_vencimento) AS primeiro_vencimento, MAX(BASE.data_vencimento) AS ultimo_vencimento
                FROM BASE WHERE {where_sql}
                GROUP BY BASE.codigo_fornecedor
                ORDER BY MAX(BASE.nome_fornecedor), CAST(BASE.codigo_fornecedor AS INT)
                OFFSET ? ROWS FETCH NEXT ? ROWS ONLY"""
        else:
            sql_total = cte_sql + f"SELECT COUNT(*) FROM BASE WHERE {where_sql}"
            sql_dados = cte_sql + f"""
                SELECT BASE.codigo_empresa, BASE.codigo_filial, BASE.tipo_titulo, BASE.numero_titulo,
                       BASE.codigo_fornecedor, BASE.nome_fornecedor, BASE.fantasia_fornecedor,
                       BASE.numero_projeto, BASE.codigo_centro_custo, BASE.descricao_centro_custo,
                       BASE.data_emissao, BASE.data_vencimento, BASE.data_ultimo_movimento,
                       BASE.valor_original, BASE.valor_aberto, BASE.valor_movimentado,
                       BASE.valor_pago, BASE.quantidade_movimentos, BASE.status_titulo, BASE.dias_atraso
                FROM BASE WHERE {where_sql}
                ORDER BY CASE WHEN BASE.status_titulo='VENCIDO' THEN 0 ELSE 1 END,
                         BASE.data_vencimento ASC, BASE.numero_titulo ASC
                OFFSET ? ROWS FETCH NEXT ? ROWS ONLY"""
        cursor.execute(sql_total, params_where)
        total_registros = cursor.fetchone()[0]
        cursor.execute(sql_dados, params_where + [offset, tamanho_pagina])
        rows = cursor.fetchall(); columns = [col[0] for col in cursor.description]
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erro SQL em Contas a Pagar: {str(e)}")
    finally:
        conn.close()
    dados = [dict(zip(columns,[v.strip() if isinstance(v,str) else v for v in row])) for row in rows]
    total_paginas = max(1,(total_registros+tamanho_pagina-1)//tamanho_pagina)
    return {'pagina':pagina,'tamanho_pagina':tamanho_pagina,'total_registros':total_registros,
            'total_paginas':total_paginas,'agrupar_por_fornecedor':agrupar_por_fornecedor,'dados':dados}


