# =========================================
# CONTAS A RECEBER / PAGAR - ÁRVORE (BOM)
# =========================================

def _buscar_rateios_receber_real(cursor, titulo: dict) -> list:
    """Rateio real do contas a receber via E140RAT (chave: empresa/filial/serie_nf/numero_nf)."""
    sql = """
        SELECT
            CAST(COALESCE(R.NUMPRJ, 0) AS INT) AS numero_projeto,
            CAST(COALESCE(R.CODFPJ, 0) AS INT) AS codigo_fase_projeto,
            COALESCE(R.CODCCU, '') AS codigo_centro_custo,
            COALESCE(CC.DESCCU, '') AS descricao_centro_custo,
            CAST(COALESCE(R.PERRAT, 0) AS FLOAT) AS percentual_rateio,
            CAST(COALESCE(R.VLRRAT, 0) AS FLOAT) AS valor_rateado,
            CAST(COALESCE(R.SEQRAT, 0) AS INT) AS sequencia_rateio,
            'E140RAT' AS origem_rateio
        FROM E140RAT R
        LEFT JOIN E044CCU CC
               ON CC.CODEMP = R.CODEMP
              AND CC.CODCCU = R.CODCCU
        WHERE R.CODEMP = ?
          AND R.CODFIL = ?
          AND R.CODSNF = ?
          AND R.NUMNFV = ?
        ORDER BY R.SEQRAT, R.CODCCU
    """
    params = [
        int(titulo.get('codigo_empresa') or 0),
        int(titulo.get('codigo_filial') or 0),
        (titulo.get('serie_nf') or '').strip(),
        int(titulo.get('numero_nf') or 0),
    ]
    try:
        cursor.execute(sql, params)
        rows = cursor.fetchall()
        cols = [c[0] for c in cursor.description]
        return [dict(zip(cols, [v.strip() if isinstance(v, str) else v for v in row])) for row in rows]
    except Exception:
        return []


def _buscar_rateios_pagar_real(cursor, titulo: dict) -> list:
    """
    Rateio real do Contas a Pagar via E501RAT.
    Chave principal: CodEmp + CodFil + NumTit.
    Quando disponíveis, também filtra CodTpt e CodFor para evitar duplicidade.
    """
    codigo_empresa = int(titulo.get('codigo_empresa') or 0)
    codigo_filial = int(titulo.get('codigo_filial') or 0)
    numero_titulo = (titulo.get('numero_titulo') or '').strip()
    tipo_titulo = (titulo.get('tipo_titulo') or '').strip()
    codigo_fornecedor = int(titulo.get('codigo_fornecedor') or 0)

    if not codigo_empresa or not codigo_filial or not numero_titulo:
        return []

    try:
        cursor.execute("""
            SELECT UPPER(COLUMN_NAME)
            FROM INFORMATION_SCHEMA.COLUMNS
            WHERE TABLE_NAME = 'E501RAT'
        """)
        cols_existentes = {str(row[0]).upper() for row in cursor.fetchall()}
    except Exception:
        return []

    if not cols_existentes:
        return []

    where = ["R.CodEmp = ?", "R.CodFil = ?", "R.NumTit = ?"]
    params = [codigo_empresa, codigo_filial, numero_titulo]

    if "CODTPT" in cols_existentes and tipo_titulo:
        where.append("R.CodTpt = ?")
        params.append(tipo_titulo)

    if "CODFOR" in cols_existentes and codigo_fornecedor > 0:
        where.append("R.CodFor = ?")
        params.append(codigo_fornecedor)

    if "NUMPRJ" in cols_existentes:
        projeto_expr = "CAST(COALESCE(R.NumPrj, 0) AS INT) AS numero_projeto"
    elif "CODPRJ" in cols_existentes:
        projeto_expr = "CAST(COALESCE(R.CodPrj, 0) AS INT) AS numero_projeto"
    else:
        projeto_expr = "CAST(0 AS INT) AS numero_projeto"

    if "CODFPJ" in cols_existentes:
        fase_expr = "CAST(COALESCE(R.CodFpj, 0) AS INT) AS codigo_fase_projeto"
    else:
        fase_expr = "CAST(0 AS INT) AS codigo_fase_projeto"

    sql = f"""
        SELECT
            ROW_NUMBER() OVER (
                ORDER BY X.codigo_centro_custo, X.percentual_rateio, X.valor_rateado
            ) AS sequencia_rateio,
            X.numero_projeto,
            X.codigo_fase_projeto,
            X.codigo_centro_custo,
            COALESCE(CC.DesCcu, '') AS descricao_centro_custo,
            X.percentual_rateio,
            X.valor_rateado,
            'E501RAT' AS origem_rateio
        FROM (
            SELECT DISTINCT
                R.CodEmp AS codigo_empresa,
                R.CodFil AS codigo_filial,
                {projeto_expr},
                {fase_expr},
                COALESCE(R.CodCcu, '') AS codigo_centro_custo,
                CAST(COALESCE(R.PerRat, 0) AS FLOAT) AS percentual_rateio,
                CAST(COALESCE(R.VlrRat, 0) AS FLOAT) AS valor_rateado
            FROM E501RAT R
            WHERE {" AND ".join(where)}
        ) X
        LEFT JOIN E044CCU CC
               ON CC.CodEmp = X.codigo_empresa
              AND CC.CodCcu = X.codigo_centro_custo
        ORDER BY sequencia_rateio
    """

    try:
        cursor.execute(sql, params)
        rows = cursor.fetchall()
        columns = [col[0] for col in cursor.description]
        return [
            dict(zip(columns, [v.strip() if isinstance(v, str) else v for v in row]))
            for row in rows
        ]
    except Exception:
        return []


def _montar_linhas_arvore_rateio_real(cursor, titulos: list, entidade: str):
    """
    Gera estrutura hierárquica estilo BOM com rateio real:
    - nível 0 = título
    - nível 1 = linhas de rateio (E140RAT para CR, E501RAT para CP)
    Fallback: usa CCU/Projeto do próprio título se não houver rateio real.
    """
    resultado = []

    for item in titulos:
        tipo_titulo = (item.get('tipo_titulo') or '').strip()
        numero_titulo = (item.get('numero_titulo') or '').strip()
        codigo_filial = item.get('codigo_filial') or 0
        codigo_empresa = item.get('codigo_empresa') or 0

        id_pai = f"{codigo_empresa}-{codigo_filial}-{tipo_titulo}-{numero_titulo}"

        if entidade == 'cliente':
            label_pessoa = item.get('nome_cliente') or item.get('fantasia_cliente') or ''
        else:
            label_pessoa = item.get('nome_fornecedor') or item.get('fantasia_fornecedor') or ''

        pai = dict(item)
        pai['tipo_linha'] = 'TITULO'
        pai['id_linha'] = id_pai
        pai['codigo_pai'] = ''
        pai['descricao_pai'] = ''
        pai['nivel'] = 0
        pai['caminho'] = id_pai
        pai['possui_filhos'] = False
        pai['descricao_resumida'] = f"{tipo_titulo}/{numero_titulo} - {label_pessoa}".strip(' -')

        # 1) rateio real
        if entidade == 'cliente':
            rateios = _buscar_rateios_receber_real(cursor, item)
        else:
            rateios = _buscar_rateios_pagar_real(cursor, item)

        # 2) fallback: usa CCU/Projeto do próprio título
        if not rateios:
            codigo_ccu = (item.get('codigo_centro_custo') or '').strip()
            descricao_ccu = (item.get('descricao_centro_custo') or '').strip()
            numero_projeto = item.get('numero_projeto') or 0
            if codigo_ccu or descricao_ccu or numero_projeto:
                rateios = [{
                    'numero_projeto': numero_projeto,
                    'codigo_fase_projeto': 0,
                    'codigo_centro_custo': codigo_ccu,
                    'descricao_centro_custo': descricao_ccu,
                    'percentual_rateio': 100.0,
                    'valor_rateado': float(item.get('valor_original') or 0),
                    'sequencia_rateio': 1,
                    'origem_rateio': 'TITULO'
                }]

        filhos = []
        for idx, r in enumerate(rateios, start=1):
            codigo_ccu_r = (r.get('codigo_centro_custo') or '').strip()
            descricao_ccu_r = (r.get('descricao_centro_custo') or '').strip()
            filhos.append({
                'tipo_linha': 'RATEIO',
                'id_linha': f"{id_pai}-R{idx}",
                'codigo_pai': id_pai,
                'descricao_pai': pai['descricao_resumida'],
                'nivel': 1,
                'caminho': f"{id_pai} > {codigo_ccu_r or 'SEM_CCU'}",
                'possui_filhos': False,

                'codigo_empresa': codigo_empresa,
                'codigo_filial': codigo_filial,
                'tipo_titulo': tipo_titulo,
                'numero_titulo': numero_titulo,

                'numero_projeto': r.get('numero_projeto') or 0,
                'codigo_fase_projeto': r.get('codigo_fase_projeto') or 0,
                'codigo_centro_custo': codigo_ccu_r,
                'descricao_centro_custo': descricao_ccu_r,
                'sequencia_rateio': r.get('sequencia_rateio') or idx,
                'percentual_rateio': float(r.get('percentual_rateio') or 0),
                'valor_rateado': float(r.get('valor_rateado') or 0),
                'origem_rateio': r.get('origem_rateio') or '',
                'descricao_resumida': f"{codigo_ccu_r} - {descricao_ccu_r}".strip(' -'),
            })

        pai['possui_filhos'] = len(filhos) > 0
        resultado.append(pai)
        resultado.extend(filhos)

    return resultado


@app.get('/api/contas-receber-arvore')
def consultar_contas_receber_arvore(
    cliente: Optional[str] = None,
    numero_titulo: Optional[str] = None,
    tipo_titulo: Optional[str] = None,
    numero_nf: Optional[str] = None,
    serie_nf: Optional[str] = None,
    codigo_filial: Optional[str] = None,
    numero_projeto: Optional[str] = None,
    centro_custo: Optional[str] = None,
    status_titulo: str = 'TODOS',
    somente_vencidos: bool = False,
    somente_saldo_aberto: bool = False,
    somente_cheques: bool = False,
    data_emissao_ini: Optional[str] = None,
    data_emissao_fim: Optional[str] = None,
    data_vencimento_ini: Optional[str] = None,
    data_vencimento_fim: Optional[str] = None,
    data_movimento_ini: Optional[str] = None,
    data_movimento_fim: Optional[str] = None,
    valor_min: Optional[float] = None,
    valor_max: Optional[float] = None,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token)
):
    if pagina < 1: pagina = 1
    if tamanho_pagina < 1: tamanho_pagina = 100
    if tamanho_pagina > 100: tamanho_pagina = 100
    offset = (pagina - 1) * tamanho_pagina

    status_titulo = normalizar_status_conta_receber(status_titulo)
    conn = get_connection()
    cursor = conn.cursor()
    cte_sql = _montar_cte_contas_receber()

    where_parts = ["BASE.codigo_empresa = ?"]
    params_where = [EMPRESA_PADRAO]

    _where_contas(
        where_parts, params_where,
        cliente=cliente,
        numero_titulo=numero_titulo,
        tipo_titulo=tipo_titulo,
        numero_nf=numero_nf,
        serie_nf=serie_nf,
        codigo_filial=codigo_filial,
        numero_projeto=numero_projeto,
        centro_custo=centro_custo,
        status_titulo=status_titulo,
        somente_vencidos=somente_vencidos,
        somente_saldo_aberto=somente_saldo_aberto,
        somente_cheques=somente_cheques,
        data_emissao_ini=data_emissao_ini,
        data_emissao_fim=data_emissao_fim,
        data_vencimento_ini=data_vencimento_ini,
        data_vencimento_fim=data_vencimento_fim,
        data_movimento_ini=data_movimento_ini,
        data_movimento_fim=data_movimento_fim,
        valor_min=valor_min,
        valor_max=valor_max,
        entidade='cliente'
    )

    where_sql = " AND ".join(where_parts)
    sql_total = cte_sql + f"SELECT COUNT(*) FROM BASE WHERE {where_sql}"
    sql_dados = cte_sql + f"""
        SELECT
            BASE.codigo_empresa, BASE.codigo_filial, BASE.tipo_titulo, BASE.numero_titulo,
            BASE.codigo_cliente, BASE.nome_cliente, BASE.fantasia_cliente,
            BASE.serie_nf, BASE.numero_nf,
            BASE.numero_projeto, BASE.codigo_centro_custo, BASE.descricao_centro_custo,
            BASE.data_emissao, BASE.data_vencimento, BASE.data_ultimo_movimento,
            BASE.valor_original, BASE.valor_aberto, BASE.valor_movimentado,
            BASE.valor_recebido, BASE.valor_comissao, BASE.base_comissao,
            BASE.quantidade_movimentos, BASE.status_titulo, BASE.dias_atraso
        FROM BASE
        WHERE {where_sql}
        ORDER BY
            CASE WHEN BASE.status_titulo='VENCIDO' THEN 0 ELSE 1 END,
            BASE.data_vencimento ASC, BASE.numero_titulo ASC
        OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
    """

    try:
        cursor.execute(sql_total, params_where)
        total_registros = cursor.fetchone()[0]
        cursor.execute(sql_dados, params_where + [offset, tamanho_pagina])
        rows = cursor.fetchall()
        columns = [col[0] for col in cursor.description]
        titulos = [dict(zip(columns, [v.strip() if isinstance(v, str) else v for v in row])) for row in rows]
        dados = _montar_linhas_arvore_rateio_real(cursor, titulos, entidade='cliente')
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erro SQL em Contas a Receber Árvore: {str(e)}")
    finally:
        conn.close()

    total_paginas = max(1, (total_registros + tamanho_pagina - 1) // tamanho_pagina)
    return {
        'pagina': pagina,
        'tamanho_pagina': tamanho_pagina,
        'total_registros': total_registros,
        'total_paginas': total_paginas,
        'modo_exibicao': 'ARVORE',
        'dados': dados
    }


