@app.get('/api/apontamentos-producao')
def consultar_apontamentos_producao(
    data_ini: Optional[str] = None,
    data_fim: Optional[str] = None,
    numero_op: Optional[str] = None,
    origem: Optional[str] = None,
    codigo_produto: Optional[str] = None,
    operador: Optional[str] = None,
    status_op: str = 'TODOS',
    status_movimento: str = 'TODOS',
    numorp: Optional[int] = None,
    codori: Optional[int] = None,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token)
):
    """
    Consulta apontamentos de produção Genius com filtros opcionais.
    Filtros: data_ini, data_fim, numero_op, origem, codigo_produto, operador, status_op, status_movimento.
    """
    # Aliases vindos do Lovable: numorp -> numero_op, codori -> origem
    if numorp is not None and not numero_op:
        numero_op = str(numorp)
    if codori is not None and not origem:
        origem = str(codori)

    if pagina < 1:
        pagina = 1
    if tamanho_pagina < 1:
        tamanho_pagina = 100
    if tamanho_pagina > 200:
        tamanho_pagina = 200

    offset = (pagina - 1) * tamanho_pagina

    conn = get_connection()
    cursor = conn.cursor()
    rows = []
    columns = []
    resumo = {}
    total_registros = 0

    # Consultas por filtros (numero_op, origem, data, operador, etc.)
    origens_sql = GENIUS_ORIGENS_SQL

    cte_sql = f"""
        WITH OPS AS (
                SELECT
                    C.CODEMP AS codigo_empresa,
                    C.CODFIL AS codigo_filial,
                    C.CODORI AS origem,
                    C.NUMORP AS numero_op,
                    C.CODPRO AS codigo_produto,
                    COALESCE(P.DESPRO, '') AS descricao_produto,
                    COALESCE(C.SITORP, '') AS sitorp,
                    C.DATGER AS data_geracao_op,
                    C.DTPINI AS data_prevista_inicio,
                    C.DTPFIM AS data_prevista_fim,
                    COALESCE(O.CODETG, 0) AS estagio,
                    COALESCE(O.SEQROT, 0) AS seqrot,
                    COALESCE(O.CODOPR, '') AS codigo_operacao,
                    CASE
                        WHEN COALESCE(C.SITORP, '') IN ('E','L','A','R') THEN 'EM_ANDAMENTO'
                        WHEN COALESCE(C.SITORP, '') IN ('F','B','C') THEN 'FINALIZADO'
                        ELSE 'SEM_STATUS'
                    END AS status_op
                FROM E900COP C
                LEFT JOIN E900OOP O
                    ON O.CODEMP = C.CODEMP
                   AND O.CODORI = C.CODORI
                   AND O.NUMORP = C.NUMORP
                LEFT JOIN E075PRO P
                    ON P.CODEMP = C.CODEMP
                   AND P.CODPRO = C.CODPRO
                WHERE C.CODEMP = ?
                  AND COALESCE(C.CODORI, '') IN ({origens_sql})
            ),
            MOV AS (
                SELECT
                    E.CODEMP AS codigo_empresa,
                    E.CODORI AS origem,
                    E.NUMORP AS numero_op,
                    COALESCE(E.CODETG, 0) AS estagio,
                    COALESCE(E.SEQROT, 0) AS seqrot,
                    COALESCE(E.CODOPR, '') AS codigo_operacao,
                    E.SEQEOQ AS seq_movimento,
                    E.DATREA AS data_movimento,
                    COALESCE(E.HORREA, 0) AS hora_movimento,
                    E.DATINI AS data_inicio,
                    COALESCE(E.HORINI, 0) AS hora_inicio,
                    CAST(COALESCE(E.QTDHRR, 0) AS FLOAT) AS horas_realizadas,
                    CAST(COALESCE(E.QTDRE1, 0) AS FLOAT) AS qtd_real_1,
                    CAST(COALESCE(E.QTDRE2, 0) AS FLOAT) AS qtd_real_2,
                    CAST(COALESCE(E.QTDRE3, 0) AS FLOAT) AS qtd_real_3,
                    COALESCE(E.FIMORP, '') AS fimorp,
                    COALESCE(E.NUMCAD, 0) AS numcad,
                    COALESCE(OPE.NOMOPE, '') AS nome_operador,
                    COALESCE(E.TURTRB, OPE.TURTRB, 0) AS turno
                FROM E900EOQ E
                LEFT JOIN E906OPE OPE
                    ON OPE.CODEMP = E.CODEMP
                   AND OPE.NUMCAD = E.NUMCAD
                WHERE E.CODEMP = ?
                  AND COALESCE(E.CODORI, '') IN ({origens_sql})
            ),
            BASE AS (
                SELECT
                    OPS.codigo_empresa,
                    OPS.codigo_filial,
                    OPS.origem,
                    OPS.numero_op,
                    OPS.codigo_produto,
                    OPS.descricao_produto,
                    OPS.sitorp,
                    OPS.status_op,
                    OPS.data_geracao_op,
                    OPS.data_prevista_inicio,
                    OPS.data_prevista_fim,
                    OPS.estagio,
                    OPS.seqrot,
                    OPS.codigo_operacao,
                    MOV.seq_movimento,
                    MOV.data_movimento,
                    MOV.hora_movimento,
                    MOV.data_inicio,
                    MOV.hora_inicio,
                    MOV.horas_realizadas,
                    MOV.qtd_real_1,
                    MOV.qtd_real_2,
                    MOV.qtd_real_3,
                    MOV.fimorp,
                    MOV.numcad,
                    MOV.nome_operador,
                    MOV.turno,
                    CASE
                        WHEN MOV.seq_movimento IS NULL THEN 'SEM_MOVIMENTO'
                        WHEN COALESCE(MOV.fimorp, '') = 'S' THEN 'MOVIMENTO_FINAL'
                        ELSE 'COM_MOVIMENTO'
                    END AS status_movimento
                FROM OPS
                LEFT JOIN MOV
                    ON MOV.codigo_empresa = OPS.codigo_empresa
                   AND MOV.origem = OPS.origem
                   AND MOV.numero_op = OPS.numero_op
                   AND COALESCE(MOV.estagio, 0) = COALESCE(OPS.estagio, 0)
                   AND COALESCE(MOV.seqrot, 0) = COALESCE(OPS.seqrot, 0)
            )
        """

    where_parts = ["1 = 1"]
    params_where = [EMPRESA_PADRAO, EMPRESA_PADRAO]

    if numero_op:
        where_parts.append("CAST(BASE.numero_op AS VARCHAR(20)) LIKE ?")
        params_where.append(f"%{numero_op}%")

    if origem:
        lista_origens = [x.strip() for x in re.split(r'[;,\\s]+', origem) if x.strip()]
        if lista_origens:
            sub = []
            for item in lista_origens:
                sub.append("BASE.origem = ?")
                params_where.append(item)
            where_parts.append("(" + " OR ".join(sub) + ")")

    if codigo_produto:
        where_parts.append("BASE.codigo_produto LIKE ?")
        params_where.append(f"%{codigo_produto}%")

    if operador:
        where_parts.append("(BASE.nome_operador LIKE ? OR CAST(BASE.numcad AS VARCHAR(20)) LIKE ?)")
        params_where.extend([f"%{operador}%", f"%{operador}%"])

    if data_ini:
        where_parts.append("CAST(COALESCE(BASE.data_movimento, BASE.data_geracao_op) AS DATE) >= ?")
        params_where.append(data_ini)

    if data_fim:
        where_parts.append("CAST(COALESCE(BASE.data_movimento, BASE.data_geracao_op) AS DATE) <= ?")
        params_where.append(data_fim)

    if status_op != 'TODOS':
        where_parts.append("BASE.status_op = ?")
        params_where.append(status_op)

    if status_movimento != 'TODOS':
        where_parts.append("BASE.status_movimento = ?")
        params_where.append(status_movimento)

    where_sql = " AND ".join(where_parts)

    sql_resumo = cte_sql + f"""
        SELECT
            COUNT(*) AS total_registros,
            COUNT(DISTINCT CAST(BASE.codigo_empresa AS VARCHAR(10)) + '|' + BASE.origem + '|' + CAST(BASE.numero_op AS VARCHAR(20))) AS total_ops,
            SUM(CASE WHEN BASE.status_op = 'EM_ANDAMENTO' THEN 1 ELSE 0 END) AS total_ops_andamento,
            SUM(CASE WHEN BASE.status_op = 'FINALIZADO' THEN 1 ELSE 0 END) AS total_ops_finalizadas,
            SUM(CASE WHEN BASE.status_movimento = 'COM_MOVIMENTO' THEN 1 ELSE 0 END) AS total_com_movimento,
            SUM(CASE WHEN BASE.status_movimento = 'MOVIMENTO_FINAL' THEN 1 ELSE 0 END) AS total_movimento_final,
            SUM(CASE WHEN BASE.status_movimento = 'SEM_MOVIMENTO' THEN 1 ELSE 0 END) AS total_sem_movimento,
            CAST(SUM(COALESCE(BASE.horas_realizadas, 0)) AS FLOAT) AS horas_realizadas_total
        FROM BASE
        WHERE {where_sql}
    """

    sql_total = cte_sql + f"""
        SELECT COUNT(*)
        FROM BASE
        WHERE {where_sql}
    """

    sql_dados = cte_sql + f"""
        SELECT
            BASE.codigo_empresa,
            BASE.codigo_filial,
            BASE.origem,
            BASE.numero_op,
            BASE.codigo_produto,
            BASE.descricao_produto,
            BASE.sitorp,
            BASE.status_op,
            BASE.estagio,
            BASE.seqrot,
            BASE.codigo_operacao,
            BASE.seq_movimento,
            BASE.data_movimento,
            BASE.hora_movimento,
            BASE.data_inicio,
            BASE.hora_inicio,
            BASE.horas_realizadas,
            BASE.qtd_real_1,
            BASE.qtd_real_2,
            BASE.qtd_real_3,
            BASE.fimorp,
            BASE.numcad,
            BASE.nome_operador,
            BASE.turno,
            BASE.status_movimento
        FROM BASE
        WHERE {where_sql}
        ORDER BY
            BASE.origem,
            BASE.numero_op,
            BASE.estagio,
            BASE.seqrot,
            COALESCE(BASE.data_movimento, BASE.data_geracao_op) DESC,
            BASE.hora_movimento DESC
        OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
    """

    try:
        cursor.execute(sql_resumo, params_where)
        row = cursor.fetchone()
        resumo = {
            'total_registros': int(row[0] or 0),
            'total_ops': int(row[1] or 0),
            'total_ops_andamento': int(row[2] or 0),
            'total_ops_finalizadas': int(row[3] or 0),
            'total_com_movimento': int(row[4] or 0),
            'total_movimento_final': int(row[5] or 0),
            'total_sem_movimento': int(row[6] or 0),
            'horas_realizadas_total': float(row[7] or 0),
        }

        cursor.execute(sql_total, params_where)
        total_registros = int(cursor.fetchone()[0] or 0)

        cursor.execute(sql_dados, params_where + [offset, tamanho_pagina])
        rows = cursor.fetchall()
        columns = [col[0] for col in cursor.description]
    except Exception as e:
        conn.close()
        raise HTTPException(status_code=500, detail=f'Erro SQL em apontamentos de producao: {str(e)}')

    # formatação comum de horários
    def _fmt_hhmm(valor):
        try:
            n = int(valor or 0)
        except Exception:
            return ''
        if n <= 0:
            return ''
        s = str(n).rjust(4, '0')
        return f'{s[:2]}:{s[2:]}'

    dados = []
    for row in rows:
        item = {}
        for i, col in enumerate(columns):
            valor = row[i]
            if isinstance(valor, str):
                valor = valor.strip()
            item[col] = valor

        if 'hora_inicio' in item:
            item['hora_inicio'] = _fmt_hhmm(item.get('hora_inicio'))
        if 'hora_movimento' in item:
            item['hora_movimento'] = _fmt_hhmm(item.get('hora_movimento'))
        if 'horini' in item:
            item['horini'] = _fmt_hhmm(item.get('horini'))
        if 'horfim' in item:
            item['horfim'] = _fmt_hhmm(item.get('horfim'))

        dados.append(item)

    total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros > 0 else 1

    conn.close()

    return {
        'pagina': pagina,
        'tamanho_pagina': tamanho_pagina,
        'total_registros': total_registros,
        'total_paginas': total_paginas,
        'resumo': resumo,
        'dados': dados,
        'observacao': 'Consulta de apontamentos de produção com filtros opcionais.'
    }


