@app.get('/api/status-op-genius')
def consultar_status_op_genius(
    numero_op: Optional[str] = None,
    origem: Optional[str] = None,
    status_op: str = 'TODOS',
    status_apontamento: str = 'TODOS',
    data_ini: Optional[str] = None,
    data_fim: Optional[str] = None,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token)
):
    """
    Consulta OPs Genius com status NATIVO baseado em E900COP.SITORP.
    
    Movimentos/Apontamentos: Usa E900EOQ (tabela primária para execução operacional).
    Base de dados da OP: E900COP (cabeçalho) + E900OOP (operações) + E900EOQ (movimentação/execução).
    Recurso/Centro de Custo: E725CRE via E900EOQ.CODCRE.
    
    Status OP: EM_ANDAMENTO (SITORP in E,L), FINALIZADO (SITORP in F,B,C), SEM_STATUS
    Status Apontamento: APONTAMENTO_ABERTO, APONTAMENTO_FECHADO, SEM_APONTAMENTO
    """
    if pagina < 1:
        pagina = 1
    if tamanho_pagina < 1:
        tamanho_pagina = 100
    if tamanho_pagina > 200:
        tamanho_pagina = 200

    status_op = (status_op or 'TODOS').strip().upper()
    if status_op not in ('TODOS', 'EM_ANDAMENTO', 'FINALIZADO', 'SEM_STATUS'):
        status_op = 'TODOS'

    status_apontamento = (status_apontamento or 'TODOS').strip().upper()
    if status_apontamento not in ('TODOS', 'APONTAMENTO_ABERTO', 'APONTAMENTO_FECHADO', 'SEM_APONTAMENTO'):
        status_apontamento = 'TODOS'

    offset = (pagina - 1) * tamanho_pagina

    conn = get_connection()
    cursor = conn.cursor()

    origens_sql = GENIUS_ORIGENS_SQL

    # CTE APONT: usa E900EOQ como fonte primária para movimentação/execução operacional
    apont_cte = f"""
    APONT AS (
        SELECT
            Q.CODEMP AS codigo_empresa,
            Q.CODORI AS origem,
            Q.NUMORP AS numero_op,
            Q.CODETG AS estagio,
            CAST(COALESCE(Q.HORINI, 0) AS INT) AS horini,
            CAST(COALESCE(Q.HORREA, 0) AS INT) AS horfim,
            COALESCE(OPE.NOMOPE, '') AS nome_operador,
            Q.NUMCAD AS codigo_operador,
            Q.SEQROT AS seqrot,
            Q.CODOPR AS codigo_operacao,
            Q.CODPRO AS codigo_produto,
            Q.CODDER AS derivacao,
            Q.CODEQP AS equipamento,
            CAST(COALESCE(Q.QTDRE1, 0) AS FLOAT) AS qtde_1_qual,
            CAST(COALESCE(Q.QTDRFG, 0) AS FLOAT) AS qtde_refugo,
            CAST(COALESCE(Q.QTDIQL, 0) AS FLOAT) AS qtde_inspecao,
            Q.DATINI AS data_inicio,
            Q.DATREA AS data_movimento,
            CAST(COALESCE(Q.TMPBRU, 0) AS FLOAT) AS tempo_bruto_min,
            Q.CODCRE AS centro_recurso,
            COALESCE(CRE.CODCCU, '') AS centro_custo,
            CASE
                WHEN COALESCE(Q.HORINI, 0) = 0 THEN 'SEM_INICIO'
                WHEN COALESCE(Q.HORINI, 0) > 0 AND COALESCE(Q.HORREA, 0) = 0 THEN 'ABERTO'
                ELSE 'FECHADO'
            END AS status_movimento_eoq
        FROM E900EOQ Q
        LEFT JOIN E906OPE OPE
            ON OPE.CODEMP = Q.CODEMP
           AND OPE.NUMCAD = Q.NUMCAD
        LEFT JOIN E725CRE CRE
            ON CRE.CODEMP = Q.CODEMP
           AND CRE.CODCRE = Q.CODCRE
        WHERE Q.CODEMP = ?
          AND COALESCE(Q.CODORI, '') IN ({origens_sql})
    )"""

    cte_sql = f"""
        WITH OPS AS (
            SELECT
                C.CODEMP AS codigo_empresa,
                C.CODORI AS origem,
                C.NUMORP AS numero_op,
                C.CODPRO AS codigo_produto,
                C.SITORP AS sitorp,
                C.DATEMI AS data_emissao,
                C.DATPRE AS data_prevista,
                COALESCE(O.CODETG, 0) AS estagio,
                COALESCE(O.SEQROT, 0) AS seqrot,
                COALESCE(O.CODOPR, '') AS codigo_operacao,
                COALESCE(P.DESPRO, '') AS descricao_produto,
                CASE
                    WHEN COALESCE(C.SITORP, '') IN ('E', 'L') THEN 'EM_ANDAMENTO'
                    WHEN COALESCE(C.SITORP, '') IN ('F', 'B', 'C') THEN 'FINALIZADO'
                    ELSE 'SEM_STATUS'
                END AS status_op,
                ROW_NUMBER() OVER (PARTITION BY C.CODEMP, C.CODORI, C.NUMORP ORDER BY O.SEQROT) AS rn_ops
            FROM E900COP C
            LEFT JOIN E900OOP O
                ON O.CODEMP = C.CODEMP
               AND O.CODORI = C.CODORI
               AND O.NUMORP = C.NUMORP
            LEFT JOIN E075PRO P
                ON P.CODEMP = C.CODEMP
               AND P.CODPRO = C.CODPRO
            WHERE C.CODEMP = ?
              AND COALESCE(C.CODORI, '') IN ({origens_sql})
        ),
        OPS_DISTINCT AS (
            SELECT DISTINCT
                O.codigo_empresa,
                O.origem,
                O.numero_op,
                O.codigo_produto,
                O.descricao_produto,
                O.sitorp,
                O.status_op,
                O.data_emissao,
                O.data_prevista
            FROM OPS O
        ),
        {apont_cte}
    """

    where_parts = ["1 = 1"]
    params_where = [EMPRESA_PADRAO, EMPRESA_PADRAO]

    if numero_op:
        where_parts.append("CAST(OD.numero_op AS VARCHAR(20)) LIKE ?")
        params_where.append(f"%{numero_op}%")

    if origem:
        lista_origens = [x.strip() for x in re.split(r'[;,\s]+', origem) if x.strip()]
        if lista_origens:
            clausulas = []
            for item in lista_origens:
                clausulas.append("OD.origem = ?")
                params_where.append(item)
            where_parts.append("(" + " OR ".join(clausulas) + ")")

    if data_ini:
        where_parts.append("CAST(OD.data_emissao AS date) >= ?")
        params_where.append(data_ini)

    if data_fim:
        where_parts.append("CAST(OD.data_emissao AS date) <= ?")
        params_where.append(data_fim)

    if status_op != 'TODOS':
        where_parts.append("OD.status_op = ?")
        params_where.append(status_op)

    where_clause = " AND ".join(where_parts)

    sql_resumo = cte_sql + f"""
        SELECT
            COUNT(DISTINCT OD.numero_op) AS total_ops,
            SUM(CASE WHEN OD.status_op = 'EM_ANDAMENTO' THEN 1 ELSE 0 END) AS total_em_andamento,
            SUM(CASE WHEN OD.status_op = 'FINALIZADO' THEN 1 ELSE 0 END) AS total_finalizado,
            SUM(CASE WHEN APONT.horini > 0 AND APONT.horfim > 0 THEN 1 ELSE 0 END) AS total_apontamento_fechado,
            SUM(CASE WHEN APONT.horini > 0 AND APONT.horfim = 0 THEN 1 ELSE 0 END) AS total_apontamento_aberto,
            SUM(CASE WHEN APONT.horini = 0 THEN 1 ELSE 0 END) AS total_sem_apontamento
        FROM OPS_DISTINCT OD
        LEFT JOIN APONT
            ON APONT.codigo_empresa = OD.codigo_empresa
           AND APONT.origem = OD.origem
           AND APONT.numero_op = OD.numero_op
        WHERE {where_clause}
    """

    sql_total = cte_sql + f"""
        SELECT COUNT(DISTINCT OD.numero_op)
        FROM OPS_DISTINCT OD
        LEFT JOIN APONT
            ON APONT.codigo_empresa = OD.codigo_empresa
           AND APONT.origem = OD.origem
           AND APONT.numero_op = OD.numero_op
        WHERE {where_clause}
    """

    sql_dados = cte_sql + f"""
        SELECT DISTINCT
            OD.codigo_empresa,
            OD.origem,
            OD.numero_op,
            OD.codigo_produto,
            OD.descricao_produto,
            OD.sitorp,
            OD.status_op,
            OD.data_emissao,
            OD.data_prevista,
            COALESCE(APONT.horini, 0) AS horini,
            COALESCE(APONT.horfim, 0) AS horfim,
            COALESCE(APONT.nome_operador, '') AS nome_operador,
            COALESCE(APONT.seqrot, 0) AS seqrot,
            COALESCE(APONT.codigo_operacao, '') AS codigo_operacao,
            COALESCE(APONT.codigo_produto, OD.codigo_produto) AS codigo_produto_apont,
            COALESCE(APONT.derivacao, '') AS derivacao,
            COALESCE(APONT.equipamento, '') AS equipamento,
            COALESCE(APONT.qtde_1_qual, 0) AS qtde_1_qual,
            COALESCE(APONT.qtde_refugo, 0) AS qtde_refugo,
            COALESCE(APONT.qtde_inspecao, 0) AS qtde_inspecao,
            APONT.data_inicio,
            APONT.data_movimento,
            COALESCE(APONT.tempo_bruto_min, 0) AS tempo_bruto_min,
            COALESCE(APONT.centro_recurso, '') AS centro_recurso,
            COALESCE(APONT.centro_custo, '') AS centro_custo,
            COALESCE(APONT.status_movimento_eoq, CASE
                WHEN APONT.horini > 0 AND COALESCE(APONT.horfim, 0) = 0 THEN 'APONTAMENTO_ABERTO'
                WHEN APONT.horini > 0 AND APONT.horfim > 0 THEN 'APONTAMENTO_FECHADO'
                ELSE 'SEM_APONTAMENTO'
            END) AS status_apontamento
        FROM OPS_DISTINCT OD
        LEFT JOIN APONT
            ON APONT.codigo_empresa = OD.codigo_empresa
           AND APONT.origem = OD.origem
           AND APONT.numero_op = OD.numero_op
        WHERE {where_clause}
        ORDER BY OD.data_prevista DESC, OD.origem, OD.numero_op
        OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
    """

    try:
        cursor.execute(sql_resumo, params_where)
        row_resumo = cursor.fetchone()
        resumo = {
            'total_ops': int(row_resumo[0] or 0),
            'total_em_andamento': int(row_resumo[1] or 0),
            'total_finalizado': int(row_resumo[2] or 0),
            'total_apontamento_fechado': int(row_resumo[3] or 0),
            'total_apontamento_aberto': int(row_resumo[4] or 0),
            'total_sem_apontamento': int(row_resumo[5] or 0),
        }

        cursor.execute(sql_total, params_where)
        total_registros = int(cursor.fetchone()[0] or 0)

        params_dados = params_where + [offset, tamanho_pagina]
        cursor.execute(sql_dados, params_dados)
        rows = cursor.fetchall()
        columns = [col[0] for col in cursor.description]

        def _fmt_hhmm(valor):
            """Formata hora em HHMM para HH:MM."""
            try:
                n = int(valor or 0)
            except Exception:
                return ''
            if n <= 0:
                return ''
            s = str(n).rjust(4, '0')
            return f'{s[:2]}:{s[2:]}'

        dados = []
        for row in rows:
            item = {}
            for i, col in enumerate(columns):
                valor = row[i]
                if isinstance(valor, str):
                    valor = valor.strip()
                item[col] = valor
            
            # Formatar horas (E900EOQ sempre fornece dados de hora/minuto)
            item['horini'] = _fmt_hhmm(item.get('horini'))
            item['horfim'] = _fmt_hhmm(item.get('horfim'))
            
            dados.append(item)

        if status_apontamento != 'TODOS':
            dados = [d for d in dados if d.get('status_apontamento') == status_apontamento]

    except Exception as e:
        raise HTTPException(status_code=500, detail=f'Erro SQL em status-op-genius: {str(e)}')
    finally:
        conn.close()

    total_filtrado = len(dados)
    total_paginas = (total_filtrado + tamanho_pagina - 1) // tamanho_pagina if total_filtrado > 0 else 1

    obs = 'Consulta nativa de status de OP Genius: E900COP.SITORP + E900OOP + E900EOQ (movimentação/execução) + E906OPE (operador) + E725CRE (recurso/centro custo).'

    return {
        'pagina': pagina,
        'tamanho_pagina': tamanho_pagina,
        'total_registros': total_filtrado,
        'total_paginas': total_paginas,
        'resumo': resumo,
        'dados': dados,
        'observacao': obs
    }


