def _from_patio(
    numero_projeto: Optional[str] = None,
    numero_desenho: Optional[str] = None,
    revisao: Optional[str] = None,
    cliente: Optional[str] = None,
    cidade: Optional[str] = None,
):
    return _from_producao_consolidada(numero_projeto, numero_desenho, revisao, cliente, cidade)


@app.get("/api/producao/patio")
def consultar_producao_patio(
    numero_projeto: Optional[str] = None,
    numero_desenho: Optional[str] = None,
    revisao: Optional[str] = None,
    cliente: Optional[str] = None,
    cidade: Optional[str] = None,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token),
):
    from_sql, params = _from_patio(numero_projeto, numero_desenho, revisao, cliente, cidade)

    # Resumo GLOBAL — agrega kg/qtd da base filtrada inteira (sem paginação).
    resumo_sql = """
        SELECT
            CAST(COALESCE(SUM(COALESCE(base.kg_engenharia, 0)), 0)              AS FLOAT) AS kg_engenharia,
            CAST(COALESCE(SUM(COALESCE(base.kg_produzido, 0)), 0)               AS FLOAT) AS kg_produzido,
            CAST(COALESCE(SUM(COALESCE(base.kg_expedido, 0)), 0)                AS FLOAT) AS kg_expedido,
            CAST(COALESCE(SUM(COALESCE(base.kg_patio, 0)), 0)                   AS FLOAT) AS kg_patio,
            CAST(COALESCE(SUM(COALESCE(base.qtd_produzida, 0)), 0)              AS FLOAT) AS qtd_produzida,
            CAST(COALESCE(SUM(COALESCE(base.qtd_expedida, 0)), 0)               AS FLOAT) AS qtd_expedida,
            CAST(COALESCE(SUM(COALESCE(base.qtd_patio, 0)), 0)                  AS FLOAT) AS qtd_patio,
            CAST(COALESCE(SUM(COALESCE(base.qtd_itens_nao_carregados, 0)), 0)   AS FLOAT) AS qtd_itens_nao_carregados,
            CAST(COALESCE(SUM(COALESCE(base.qtd_codbar_nao_carregados, 0)), 0)  AS FLOAT) AS qtd_codbar_nao_carregados,
            COUNT(*) AS total_linhas,
            SUM(CASE
                WHEN COALESCE(base.kg_expedido, 0) >= COALESCE(base.kg_produzido, 0)
                 AND COALESCE(base.kg_produzido, 0) > 0
                THEN 1 ELSE 0
            END) AS itens_totalmente_expedidos,
            SUM(CASE
                WHEN COALESCE(base.kg_expedido, 0) > 0
                 AND COALESCE(base.kg_expedido, 0) < COALESCE(base.kg_produzido, 0)
                THEN 1 ELSE 0
            END) AS itens_parcialmente_expedidos,
            SUM(CASE
                WHEN COALESCE(base.kg_expedido, 0) = 0
                 AND COALESCE(base.kg_produzido, 0) > 0
                THEN 1 ELSE 0
            END) AS itens_em_patio,
            SUM(CASE
                WHEN COALESCE(base.kg_produzido, 0) = 0
                THEN 1 ELSE 0
            END) AS itens_sem_producao
    """
    resumo_lista = executar_lista(resumo_sql, from_sql, "", params)
    resumo = resumo_lista[0] if resumo_lista else {}

    select_sql = """
        SELECT
            base.numero_projeto,
            base.numero_desenho,
            base.revisao,
            base.codigo_cliente,
            base.cliente,
            base.cidade,
            base.kg_engenharia,
            base.kg_estrutura,
            base.kg_fabricacao_cadastrado,
            base.kg_recebido_cadastro,
            base.kg_produzido_etq_ree,
            base.kg_produzido_mvf,
            base.kg_entrada_estoque_eep,
            base.kg_produzido,
            base.kg_expedido,
            base.kg_patio,
            base.qtd_produzida_etq_ree,
            base.qtd_movimentada_mvf,
            base.qtd_entrada_estoque_eep,
            base.qtd_produzida,
            base.qtd_expedida,
            base.qtd_patio,
            base.qtd_itens_nao_carregados,
            base.qtd_codbar_nao_carregados,
            base.perc_atendimento_producao,
            base.perc_expedido,
            base.primeira_producao,
            base.ultima_producao,
            base.primeira_expedicao,
            base.ultima_expedicao,
            CASE
                WHEN COALESCE(base.kg_expedido, 0) >= COALESCE(base.kg_produzido, 0) AND COALESCE(base.kg_produzido, 0) > 0 THEN 'TOTALMENTE EXPEDIDO'
                WHEN COALESCE(base.kg_expedido, 0) > 0 THEN 'PARCIALMENTE EXPEDIDO'
                WHEN COALESCE(base.kg_produzido, 0) > 0 THEN 'EM PÁTIO'
                ELSE 'SEM PRODUÇÃO'
            END AS status_patio
    """
    order_sql = "ORDER BY base.kg_patio DESC, base.numero_projeto DESC, base.numero_desenho DESC"
    retorno = executar_paginado_sem_count(select_sql, from_sql, order_sql, params, pagina, tamanho_pagina)
    retorno["resumo"] = resumo
    retorno["observacao"] = "Saldo em pátio usando base consolidada otimizada: PRJ/QDO/COP/MVF/EEP + ETQ/REE/CONTOBR."
    return retorno


