# ============================================================
# IMPRESSÃO DE ORDEM DE PRODUÇÃO (MCAP700.GER)
# ============================================================

def _json_value(value):
    """Converte tipos do SQL Server (Decimal, datetime, date) para JSON-safe."""
    if isinstance(value, Decimal):
        return float(value)
    if isinstance(value, (datetime, date)):
        return value.isoformat()
    return value


def _fetch_all_dict(cursor):
    """Devolve todas as linhas do cursor como lista de dicts (cols->valores)."""
    columns = [col[0] for col in cursor.description]
    rows = cursor.fetchall()
    return [
        {columns[i]: _json_value(row[i]) for i in range(len(columns))}
        for row in rows
    ]


def _fetch_one_dict(cursor):
    """Devolve a primeira linha do cursor como dict, ou None se vazio."""
    columns = [col[0] for col in cursor.description]
    row = cursor.fetchone()
    if not row:
        return None
    return {columns[i]: _json_value(row[i]) for i in range(len(columns))}


def _to_int_or_none(valor, nome_campo: str, default: Optional[int] = None) -> Optional[int]:
    """Converte querystring -> int de forma tolerante.
    - None ou string vazia -> retorna ``default``
    - "123" / " 123 " -> 123
    - inteiro -> retorna como int
    - qualquer outra coisa -> HTTPException(422) com mensagem clara
    """
    if valor is None:
        return default
    if isinstance(valor, bool):
        return int(valor)
    if isinstance(valor, int):
        return valor
    s = str(valor).strip()
    if s == "":
        return default
    # tolera milhar com ponto: "1.234"
    s_norm = s.replace(".", "") if s.count(".") and s.replace(".", "").isdigit() else s
    try:
        return int(s_norm)
    except (ValueError, TypeError):
        raise HTTPException(
            status_code=422,
            detail=f"Filtro '{nome_campo}' inválido: '{valor}'. Esperado número inteiro.",
        )


FORMATOS_DESENHO_PERMITIDOS = {
    ".jpg": "JPG",
    ".jpeg": "JPG",
    ".png": "PNG",
    ".pdf": "PDF",
}


def _normalizar_formatos_desenho(formatos):
    """Converte uma string como 'JPG,PNG,PDF' em set de extensoes ('.jpg','.png','.pdf').

    Aceita ',' ou ';' como separador. Vazio/None -> aceita todos.
    """
    if not formatos:
        return set(FORMATOS_DESENHO_PERMITIDOS.keys())

    mapa = {
        "JPG": [".jpg", ".jpeg"],
        "JPEG": [".jpg", ".jpeg"],
        "PNG": [".png"],
        "PDF": [".pdf"],
    }

    permitidos = set()
    for item in str(formatos).replace(";", ",").split(","):
        chave = item.strip().upper()
        for ext in mapa.get(chave, []):
            permitidos.add(ext)

    return permitidos or set(FORMATOS_DESENHO_PERMITIDOS.keys())


def _metadata_arquivo_desenho(caminho: Path):
    """Lê dimensoes/paginas/orientacao do desenho.

    - Imagens (.jpg/.jpeg/.png) via Pillow (se instalado).
    - PDFs via pypdf (se instalado) — usa apenas a primeira pagina.

    Se a biblioteca nao estiver instalada ou o arquivo nao puder ser lido,
    devolve metadata neutra (orientacao=DESCONHECIDA, rotacao=0).
    """
    ext = caminho.suffix.lower()
    largura = None
    altura = None
    paginas = None
    orientacao = "DESCONHECIDA"
    rotacao_recomendada = 0

    try:
        if ext in [".jpg", ".jpeg", ".png"] and Image is not None:
            with Image.open(caminho) as img:
                # exif_transpose corrige fotos que tem orientacao via EXIF
                # (camera/celular) — assim largura/altura refletem o que
                # de fato sera renderizado.
                if ImageOps is not None:
                    img = ImageOps.exif_transpose(img)
                largura, altura = img.size
        elif ext == ".pdf" and PdfReader is not None:
            reader = PdfReader(str(caminho))
            paginas = len(reader.pages)
            if paginas > 0:
                box = reader.pages[0].mediabox
                largura = float(box.width)
                altura = float(box.height)
    except Exception:
        pass

    if largura and altura:
        if largura > altura:
            orientacao = "PAISAGEM"
            rotacao_recomendada = 90
        else:
            orientacao = "RETRATO"
            rotacao_recomendada = 0

    rotacionar_para_retrato = rotacao_recomendada == 90

    return {
        "largura": largura,
        "altura": altura,
        "paginas": paginas,
        "orientacao": orientacao,
        "rotacao_recomendada": rotacao_recomendada,
        "rotacionar_para_retrato": rotacionar_para_retrato,
        "a4_layout": "RETRATO",
    }


def formatar_numero_op_exibicao(num_orp):
    """Numero da OP para exibicao no relatorio (sem zeros a esquerda).

    Exemplos:
      69072       -> "69072"
      "000069072" -> "69072"
      0 / "" / None -> "0"
    """
    try:
        return str(int(num_orp))
    except Exception:
        valor = str(num_orp or "").strip().lstrip("0")
        return valor or "0"


def formatar_numero_op_barcode(num_orp):
    """Numero da OP para o codigo de barras (9 digitos com zeros a esquerda).

    Exemplos:
      69072       -> "000069072"
      "1112"      -> "000001112"
      None / ""   -> "000000000"
    """
    try:
        return str(int(num_orp)).zfill(9)
    except Exception:
        return str(num_orp or "").strip().zfill(9)


# Alias retrocompativel — algum codigo antigo pode ainda chamar formatar_numero_op.
# Aponta para a versao barcode (9 digitos), que era o comportamento anterior.
formatar_numero_op = formatar_numero_op_barcode


def formatar_codigo_barras_op(cod_ori, num_orp):
    """Monta o codigo de barras da OP: origem + OP de 9 digitos.

    Exemplo: cod_ori="210", num_orp=69072 -> "210000069072"
    """
    origem = str(cod_ori or "").strip()
    op_barcode = formatar_numero_op_barcode(num_orp)
    return f"{origem}{op_barcode}"


def numero_para_decimal(valor):
    """Converte um valor heterogeneo em Decimal de forma tolerante.

    Aceita None, int, float, Decimal, string com virgula ou ponto.
    Retorna Decimal("0") quando nao consegue interpretar.
    """
    if valor is None:
        return Decimal("0")
    if isinstance(valor, Decimal):
        return valor
    try:
        return Decimal(str(valor).replace(",", "."))
    except Exception:
        return Decimal("0")


def tempo_para_minutos(valor):
    """Trata o valor de tempo unitario como JA estando em minutos.

    Regra atual (alinhada ao MCAP700 / planilha de operacao):
    - tmp_unit do banco vem em minutos. Nao multiplicar por 60.
    - Exemplos: 5 -> 5 min, 90 -> 90 min, 0.5 -> 1 min (arredonda).

    Devolve int (minutos arredondados para o mais proximo).
    """
    minutos = numero_para_decimal(valor)
    return int(minutos.quantize(Decimal("1"), rounding=ROUND_HALF_UP))


def formatar_minutos(minutos):
    """Formata minutos como string. Ex: 60 -> "60 min", 0 -> "0 min"."""
    try:
        minutos_int = int(minutos or 0)
    except Exception:
        minutos_int = 0
    return f"{minutos_int} min"


def calcular_tempos_operacao_em_minutos(tmp_unit, quantidade_op):
    """Calcula tmp_unit_min, tmp_total_min e seus formatados.

    Formula:
      tmp_total_min = tmp_unit_min * quantidade_op
    """
    tmp_unit_min = tempo_para_minutos(tmp_unit)
    quantidade = numero_para_decimal(quantidade_op)

    tmp_total_decimal = (Decimal(tmp_unit_min) * quantidade).quantize(
        Decimal("1"),
        rounding=ROUND_HALF_UP,
    )
    tmp_total_min = int(tmp_total_decimal)

    return {
        "tmp_unit_min": tmp_unit_min,
        "tmp_total_min": tmp_total_min,
        "tmp_unit_formatado": formatar_minutos(tmp_unit_min),
        "tmp_total_formatado": formatar_minutos(tmp_total_min),
    }


# Alias retrocompativel — algum codigo antigo pode chamar formatar_tempo_decimal_horas.
# Aponta para o formatador novo (minutos). A regra mudou: tmp_unit vem em minutos,
# nao mais em horas decimais.
def formatar_tempo_decimal_horas(valor):
    return formatar_minutos(tempo_para_minutos(valor))


def localizar_desenhos_produto(cod_pro):
    """Localiza desenhos JPG/JPEG/PNG/PDF do produto na pasta fixa da API.

    A pasta vem de ``PASTA_DESENHOS_OP_PADRAO`` (configurada por env var
    PASTA_DESENHOS_OP ou hardcoded para o share UNC da Senior). O caller
    NAO informa pasta — assim evita o front mandar paths invalidos.

    Padroes procurados (nesta ordem de prioridade):
    - <COD_PRO>-1.<ext> ... <COD_PRO>-9.<ext>
    - <COD_PRO>.<ext>

    Onde <ext> ∈ {.jpg, .jpeg, .png, .pdf}. Busca case-insensitive
    (varre o diretorio uma vez e compara em uppercase).

    Cada item retornado inclui metadata de impressao (dimensoes,
    orientacao, rotacao_recomendada) — Lovable pode usar para
    rotacao automatica de paisagem ou ignorar.
    """
    cod_pro = str(cod_pro or "").strip()
    if not cod_pro:
        return []

    try:
        pasta = Path(PASTA_DESENHOS_OP_PADRAO)
    except Exception:
        return []

    if not pasta.exists() or not pasta.is_dir():
        return []

    # Lista de nomes base na ordem de prioridade
    nomes_base = [f"{cod_pro}-{i}" for i in range(1, 10)]
    nomes_base.append(cod_pro)

    # Varre a pasta uma vez (case-insensitive via .upper())
    try:
        arquivos = [
            arq for arq in pasta.iterdir()
            if arq.is_file() and arq.suffix.lower() in FORMATOS_DESENHO_PERMITIDOS
        ]
    except Exception:
        return []

    desenhos: list = []
    ja_adicionados = set()

    for nome_base in nomes_base:
        nb_upper = nome_base.upper()
        for arquivo in arquivos:
            if arquivo.stem.upper() != nb_upper:
                continue
            if arquivo.name in ja_adicionados:
                continue
            ja_adicionados.add(arquivo.name)

            ext = arquivo.suffix.lower()
            tipo = FORMATOS_DESENHO_PERMITIDOS.get(ext, ext.replace(".", "").upper())
            metadata = _metadata_arquivo_desenho(arquivo)

            # stat() pode falhar se o share cair entre o iterdir e este ponto.
            # Caimos para None/0 em vez de quebrar — Lovable trata como "sem cache_key".
            try:
                stat = arquivo.stat()
                tamanho_bytes = int(stat.st_size)
                modificado_em = int(stat.st_mtime)
            except Exception:
                tamanho_bytes = None
                modificado_em = None

            # Sufixo :autorotate-v2 -> invalida cache local do front quando
            # mudamos a logica de rotacao (forca re-download da versao nova).
            cache_key = (
                f"{arquivo.name}:{tamanho_bytes or 0}:{modificado_em or 0}:autorotate-v2"
                if tamanho_bytes is not None and modificado_em is not None
                else f"{arquivo.name}:autorotate-v2"
            )

            arquivo_encoded = quote(arquivo.name, safe="")
            # &v={mtime} forca o browser a nao reaproveitar imagem antiga.
            versao_cache = modificado_em if modificado_em is not None else 0

            desenhos.append({
                "ordem": len(desenhos) + 1,
                "nome_arquivo": arquivo.name,
                "tipo": tipo,
                "extensao": ext,
                "mime_type": mimetypes.guess_type(str(arquivo))[0] or "application/octet-stream",
                "tamanho_bytes": tamanho_bytes,
                "modificado_em": modificado_em,
                "cache_key": cache_key,
                "url": (
                    "/api/producao/ordem-producao/desenho"
                    f"?arquivo={arquivo_encoded}"
                ),
                # url_impressao: fallback simples (pagina 1 normalizada).
                # Front prefere usar url_manifest_a4 para descobrir o numero
                # real de paginas (PDF pode ter 2+ paginas).
                "url_impressao": (
                    "/api/producao/ordem-producao/desenho/impressao-a4/pagina"
                    f"?arquivo={arquivo_encoded}&pagina=1&v={versao_cache}"
                ),
                "url_manifest_a4": (
                    "/api/producao/ordem-producao/desenho/impressao-a4/manifest"
                    f"?arquivo={arquivo_encoded}&v={versao_cache}"
                ),
                # Thumbnail para preview/grid — pequeno, cacheado, leve.
                # Use loading="lazy" + IntersectionObserver no front.
                # NUNCA usar para impressao (resolucao baixa de proposito).
                "url_thumbnail": (
                    "/api/producao/ordem-producao/desenho/thumbnail"
                    f"?arquivo={arquivo_encoded}&v={versao_cache}"
                ),
                # Mantidos como legados (retrocompat) — front nao precisa usar.
                "url_impressao_a4_inteiro": (
                    "/api/producao/ordem-producao/desenho/impressao-a4"
                    f"?arquivo={arquivo_encoded}&v={versao_cache}"
                ),
                "url_impressao_legado": (
                    "/api/producao/ordem-producao/desenho/impressao"
                    f"?arquivo={arquivo_encoded}&auto_rotate=S&v={versao_cache}"
                ),
                "usar_paginas_a4_normalizadas": True,
                "layout_impressao": "A4_RETRATO_NORMALIZADO",
                "rotacao_automatica": True,
                "normalizacao_a4": True,
                "imprimir_em_nova_pagina": True,
                "iniciar_apos_op": True,
                **metadata,
            })

    return desenhos


@app.get("/api/producao/ordem-producao/desenho")
def obter_desenho_ordem_producao(
    arquivo: str,
    usuario=Depends(validar_token),
):
    """Retorna um desenho (JPG/JPEG/PNG/PDF) da pasta FIXA da API.

    Sem parametro `pasta` — sempre usa ``PASTA_DESENHOS_OP_PADRAO``.
    Bloqueia path traversal (``os.path.basename`` no nome do arquivo)
    e formatos nao permitidos.
    """
    nome_arquivo = os.path.basename(str(arquivo or "").strip())
    if not nome_arquivo:
        raise HTTPException(status_code=422, detail="Arquivo não informado.")

    try:
        pasta = Path(PASTA_DESENHOS_OP_PADRAO)
    except Exception:
        raise HTTPException(
            status_code=500,
            detail=f"Pasta de desenhos configurada eh invalida: {PASTA_DESENHOS_OP_PADRAO}",
        )

    if not pasta.exists() or not pasta.is_dir():
        raise HTTPException(
            status_code=404,
            detail=(
                "Pasta de desenhos não encontrada ou inacessível pela API: "
                f"{str(pasta)}"
            ),
        )

    caminho = pasta / nome_arquivo

    if not caminho.exists() or not caminho.is_file():
        raise HTTPException(
            status_code=404,
            detail=f"Desenho não encontrado: {nome_arquivo}",
        )

    if caminho.suffix.lower() not in [".jpg", ".jpeg", ".png", ".pdf"]:
        raise HTTPException(
            status_code=422,
            detail="Formato não permitido. Use JPG, JPEG, PNG ou PDF.",
        )

    media_type = mimetypes.guess_type(str(caminho))[0] or "application/octet-stream"

    # Metadados para cache no browser e cache local do Lovable.
    # Cache-Control: 1 dia (desenhos quase nunca mudam; se atualizar, mtime
    # muda e a cache_key no /opcoes invalida automaticamente no front).
    headers = {
        "Cache-Control": "public, max-age=86400",
        "X-File-Name": caminho.name,
    }
    try:
        st = caminho.stat()
        headers["X-File-Size"] = str(st.st_size)
        headers["X-File-MTime"] = str(int(st.st_mtime))
    except Exception:
        pass

    return FileResponse(
        str(caminho),
        media_type=media_type,
        filename=caminho.name,
        headers=headers,
    )


def _resolver_arquivo_desenho(arquivo: str) -> Path:
    """Resolve e valida o caminho de um desenho na pasta FIXA da API.

    Reaproveitado por /desenho/impressao. Bloqueia path traversal
    (os.path.basename), pasta inacessivel, arquivo inexistente e
    formato nao permitido — sempre com HTTPException apropriada.
    """
    nome_arquivo = os.path.basename(str(arquivo or "").strip())
    if not nome_arquivo:
        raise HTTPException(status_code=422, detail="Arquivo não informado.")

    pasta = Path(PASTA_DESENHOS_OP_PADRAO)
    if not pasta.exists() or not pasta.is_dir():
        raise HTTPException(
            status_code=404,
            detail=(
                "Pasta de desenhos não encontrada ou inacessível pela API: "
                f"{str(pasta)}"
            ),
        )

    caminho = pasta / nome_arquivo
    if not caminho.exists() or not caminho.is_file():
        raise HTTPException(
            status_code=404,
            detail=f"Desenho não encontrado: {nome_arquivo}",
        )

    if caminho.suffix.lower() not in [".jpg", ".jpeg", ".png", ".pdf"]:
        raise HTTPException(
            status_code=422,
            detail="Formato não permitido. Use JPG, JPEG, PNG ou PDF.",
        )

    return caminho


@app.get("/api/producao/ordem-producao/desenho/impressao")
def obter_desenho_ordem_producao_impressao(
    arquivo: str,
    auto_rotate: str = "S",
    usuario=Depends(validar_token),
):
    """Serve o desenho JA PREPARADO para impressao A4.

    Para JPG/JPEG/PNG em paisagem (largura > altura) e auto_rotate=S, a
    imagem e fisicamente rotacionada 90deg via Pillow (rotate expand=True)
    — assim o Lovable nao precisa de `transform: rotate(90deg)` no CSS,
    que so gira visualmente mas mantem a caixa em paisagem na impressao.

    PDFs sao servidos como estao (rotacao de PDF e tratada no front).
    Se Pillow nao estiver instalado, cai no arquivo original sem rotacao.
    """
    caminho = _resolver_arquivo_desenho(arquivo)
    ext = caminho.suffix.lower()

    # PDF: rotaciona paginas em paisagem (largura > altura) para retrato
    # quando auto_rotate=S, devolvendo um PDF em A4 retrato pronto para
    # imprimir. Se pypdf/PdfWriter nao estiver instalado, devolve o
    # original como fallback.
    if ext == ".pdf":
        auto_rotate_pdf = str(auto_rotate or "S").upper().strip() == "S"
        if not auto_rotate_pdf or PdfReader is None or PdfWriter is None:
            return FileResponse(
                str(caminho),
                media_type="application/pdf",
                filename=caminho.name,
                headers={
                    "Cache-Control": "no-store",
                    "X-Auto-Rotate": "PDF-ORIGINAL",
                },
            )

        try:
            reader = PdfReader(str(caminho))
            writer = PdfWriter()
            paginas_rotacionadas = 0
            for page in reader.pages:
                try:
                    box = page.mediabox
                    largura = float(box.width)
                    altura = float(box.height)
                    if largura > altura:
                        page.rotate(90)
                        paginas_rotacionadas += 1
                except Exception:
                    pass
                writer.add_page(page)

            saida = io.BytesIO()
            writer.write(saida)
            saida.seek(0)
            return StreamingResponse(
                saida,
                media_type="application/pdf",
                headers={
                    "Cache-Control": "no-store",
                    "X-Original-File": caminho.name,
                    "X-Auto-Rotate": "S" if paginas_rotacionadas > 0 else "N",
                    "X-Pages-Rotated": str(paginas_rotacionadas),
                    "X-Total-Pages": str(len(reader.pages)),
                    "X-A4-Layout": "RETRATO",
                },
            )
        except Exception:
            return FileResponse(
                str(caminho),
                media_type="application/pdf",
                filename=caminho.name,
                headers={
                    "Cache-Control": "no-store",
                    "X-Auto-Rotate": "PDF-ORIGINAL",
                    "X-Rotate-Skip": "erro-pypdf",
                },
            )

    # Sem Pillow no servidor -> fallback: devolve o arquivo original.
    if Image is None:
        media_type = mimetypes.guess_type(str(caminho))[0] or "application/octet-stream"
        return FileResponse(
            str(caminho),
            media_type=media_type,
            filename=caminho.name,
            headers={
                "Cache-Control": "no-store",
                "X-Auto-Rotate": "N",
                "X-Rotate-Skip": "pillow-indisponivel",
            },
        )

    try:
        with Image.open(caminho) as img:
            if ImageOps is not None:
                img = ImageOps.exif_transpose(img)

            largura, altura = img.size
            deve_rotacionar = (
                str(auto_rotate or "S").upper().strip() == "S"
                and largura > altura
            )

            if deve_rotacionar:
                img = img.rotate(90, expand=True)

            largura_final, altura_final = img.size

            saida = io.BytesIO()
            if ext == ".png":
                media_type = "image/png"
                img.save(saida, format="PNG", optimize=True)
            else:
                media_type = "image/jpeg"
                if img.mode in ("RGBA", "P", "LA"):
                    img = img.convert("RGB")
                img.save(saida, format="JPEG", quality=95, optimize=True)
            saida.seek(0)

        return StreamingResponse(
            saida,
            media_type=media_type,
            headers={
                # no-store: a versao rotacionada nunca deve ser servida de
                # cache antigo do browser. Reuso entre operacoes/OPs fica
                # no cache em memoria do Lovable (Map por cache_key).
                "Cache-Control": "no-store",
                "X-Original-File": caminho.name,
                "X-Auto-Rotate": "S" if deve_rotacionar else "N",
                "X-Original-Width": str(largura),
                "X-Original-Height": str(altura),
                "X-Final-Width": str(largura_final),
                "X-Final-Height": str(altura_final),
            },
        )

    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Erro ao preparar desenho para impressão: {str(exc)}",
        )


# ============================================================================
# Normalizacao definitiva A4 retrato (substitui /desenho/impressao no front).
#
# - JPG/PNG: abre, corrige EXIF, rotaciona se paisagem, redimensiona
#   proporcionalmente dentro da area util e centraliza numa folha A4 branca.
# - PDF: percorre pagina a pagina, rotaciona paisagens, escala e centraliza
#   sobre uma pagina A4 retrato em branco. Frente/verso saem como duas
#   paginas A4 retrato distintas.
# ============================================================================

# A4 em pontos PDF (1pt = 1/72 polegada) — usado pelo pypdf
A4_WIDTH_PT = 595.2756
A4_HEIGHT_PT = 841.8898
A4_MARGIN_PT = 18  # ~0.25 polegada de margem segura

# A4 em pixels — usado para imagens (Pillow / fitz).
# 200 DPI eh um compromisso entre nitidez e tamanho do JPEG enviado pro front.
DESENHO_A4_DPI = 200
A4_WIDTH_PX = int(8.27 * DESENHO_A4_DPI)   # 1654 px @ 200 DPI
A4_HEIGHT_PX = int(11.69 * DESENHO_A4_DPI)  # 2338 px @ 200 DPI
A4_MARGIN_PX = int(0.25 * DESENHO_A4_DPI)   # ~50 px de margem segura

# Recorte de margem branca antes de encaixar em A4.
# - WHITE_TOLERANCE: pixels com luminancia < deste valor sao considerados
#   "diferentes de branco" e entram na bounding box do conteudo util.
# - CROP_PADDING_PX: respiro adicionado em volta da bbox para nao colar o
#   desenho na borda da folha A4 final.
WHITE_TOLERANCE = 14
CROP_PADDING_PX = 20

# Miniatura para PREVIEW (tela). Nunca usada na impressao.
# - 600px no maior lado eh suficiente para preview legivel.
# - DPI baixo para PDF (96 dpi rasterizado) — economiza memoria/tempo.
# - WEBP quando suportado (Pillow tem desde 9.x); JPEG como fallback.
DESENHO_THUMB_MAX_PX = 600
DESENHO_THUMB_QUALITY = 70
DESENHO_THUMB_PDF_DPI = 96


def _normalizar_imagem_para_a4(caminho: Path):
    """Gera uma imagem A4 retrato (JPEG) com o desenho centralizado e escalado.

    Se a imagem original estiver em paisagem (largura > altura), eh rotacionada
    90deg antes de ser encaixada. EXIF eh corrigido para que orientacoes
    vindas de camera/celular nao saiam tortas.
    """
    if Image is None:
        raise HTTPException(
            status_code=500,
            detail="Pillow nao esta instalado. Instale pillow para normalizar imagens.",
        )

    try:
        with Image.open(caminho) as img:
            if ImageOps is not None:
                img = ImageOps.exif_transpose(img)

            img = img.convert("RGB")

            largura, altura = img.size
            rotacionou = False
            if largura > altura:
                img = img.rotate(90, expand=True)
                rotacionou = True

            area_largura = A4_WIDTH_PX - (A4_MARGIN_PX * 2)
            area_altura = A4_HEIGHT_PX - (A4_MARGIN_PX * 2)

            escala = min(
                area_largura / img.width,
                area_altura / img.height,
            )
            # Nunca ampliar acima do tamanho original (evita perda de qualidade
            # em desenhos pequenos virem borrados ao serem esticados ate A4).
            if escala > 1.0:
                escala = 1.0

            nova_largura = max(1, int(img.width * escala))
            nova_altura = max(1, int(img.height * escala))

            img_redimensionada = img.resize(
                (nova_largura, nova_altura),
                Image.LANCZOS,
            )

            folha = Image.new("RGB", (A4_WIDTH_PX, A4_HEIGHT_PX), "white")
            pos_x = (A4_WIDTH_PX - nova_largura) // 2
            pos_y = (A4_HEIGHT_PX - nova_altura) // 2
            folha.paste(img_redimensionada, (pos_x, pos_y))

            saida = io.BytesIO()
            folha.save(saida, format="JPEG", quality=95, optimize=True)
            saida.seek(0)

        return StreamingResponse(
            saida,
            media_type="image/jpeg",
            headers={
                "Cache-Control": "no-store",
                "X-Original-File": caminho.name,
                "X-A4-Normalized": "S",
                "X-A4-Orientation": "PORTRAIT",
                "X-A4-Rotated": "S" if rotacionou else "N",
                "X-Original-Width": str(largura),
                "X-Original-Height": str(altura),
            },
        )
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Erro ao normalizar imagem para A4: {str(exc)}",
        )


def _normalizar_pdf_para_a4(caminho: Path):
    """Gera um PDF A4 retrato com cada pagina do PDF original encaixada.

    Para cada pagina:
    - Detecta se eh paisagem (largura > altura).
    - Rotaciona 90deg se necessario.
    - Escala proporcionalmente para caber dentro da area util.
    - Centraliza sobre uma pagina A4 retrato em branco.

    O resultado final eh um PDF com a mesma quantidade de paginas do original,
    todas em A4 retrato.
    """
    if PdfReader is None or PdfWriter is None or Transformation is None:
        raise HTTPException(
            status_code=500,
            detail="pypdf nao esta instalado. Instale pypdf para normalizar PDFs.",
        )

    try:
        reader = PdfReader(str(caminho))
        writer = PdfWriter()

        area_w = A4_WIDTH_PT - (A4_MARGIN_PT * 2)
        area_h = A4_HEIGHT_PT - (A4_MARGIN_PT * 2)

        paginas_rotacionadas = 0

        for pagina_original in reader.pages:
            src_w = float(pagina_original.mediabox.width)
            src_h = float(pagina_original.mediabox.height)
            if src_w <= 0 or src_h <= 0:
                # Pagina degenerada — copia sem transformacao
                writer.add_page(pagina_original)
                continue

            deve_rotacionar = src_w > src_h

            if deve_rotacionar:
                content_w = src_h
                content_h = src_w
                paginas_rotacionadas += 1
            else:
                content_w = src_w
                content_h = src_h

            escala = min(area_w / content_w, area_h / content_h)
            # Nao ampliar conteudo pequeno acima do tamanho real
            if escala > 1.0:
                escala = 1.0

            final_w = content_w * escala
            final_h = content_h * escala
            offset_x = (A4_WIDTH_PT - final_w) / 2.0
            offset_y = (A4_HEIGHT_PT - final_h) / 2.0

            # Cria pagina A4 retrato em branco
            pagina_a4 = writer.add_blank_page(
                width=A4_WIDTH_PT,
                height=A4_HEIGHT_PT,
            )

            transform = Transformation()
            if deve_rotacionar:
                transform = (
                    Transformation()
                    .translate(tx=offset_x, ty=offset_y)  # 4º: centraliza na A4
                    .scale(escala)                          # 3º: escala
                    .translate(tx=src_h, ty=0)             # 2º: corrige pós-rotação
                    .rotate(90)                             # 1º: rotaciona (executado primeiro)
                )
            else:
                transform = (
                    Transformation()
                    .translate(tx=offset_x, ty=offset_y)  # 2º: centraliza
                    .scale(escala)                          # 1º: escala (executado primeiro)
                )

            pagina_original.add_transformation(transform)
            pagina_a4.merge_page(pagina_original)

        saida = io.BytesIO()
        writer.write(saida)
        saida.seek(0)

        return StreamingResponse(
            saida,
            media_type="application/pdf",
            headers={
                "Cache-Control": "no-store",
                "X-Original-File": caminho.name,
                "X-A4-Normalized": "S",
                "X-A4-Orientation": "PORTRAIT",
                "X-Pages-Rotated": str(paginas_rotacionadas),
                "X-Total-Pages": str(len(reader.pages)),
            },
        )
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Erro ao normalizar PDF para A4: {str(exc)}",
        )


@app.get("/api/producao/ordem-producao/desenho/impressao-a4")
def obter_desenho_ordem_producao_impressao_a4(
    arquivo: str,
    usuario=Depends(validar_token),
):
    """Devolve o desenho JA NORMALIZADO em A4 retrato, pronto para impressao.

    Diferente de /desenho/impressao (que so rotaciona JPG/PNG e devolvia PDF
    quase original), este endpoint sempre entrega:
    - JPG/PNG: um JPEG A4 retrato com o desenho centralizado e escalado.
    - PDF: um PDF onde toda pagina eh A4 retrato com o conteudo original
      centralizado, rotacionando paisagens automaticamente.

    O Lovable deve usar exclusivamente este endpoint para impressao —
    nao aplicar transform/rotate no CSS, nao redimensionar manualmente
    no front, nao imprimir o arquivo original.
    """
    caminho = _resolver_arquivo_desenho(arquivo)
    ext = caminho.suffix.lower()

    if ext in (".jpg", ".jpeg", ".png"):
        return _normalizar_imagem_para_a4(caminho)

    if ext == ".pdf":
        return _normalizar_pdf_para_a4(caminho)

    raise HTTPException(
        status_code=422,
        detail="Formato nao permitido. Use JPG, JPEG, PNG ou PDF.",
    )


# ============================================================================
# Normalizacao A4 v2 — pipeline imagem-unica (JPG/PNG/PDF).
#
# Diferente de /desenho/impressao-a4 (que devolve JPEG p/ imagem e PDF p/ PDF),
# este pipeline rasteriza tudo (inclusive PDFs) em JPEG A4 retrato, com
# recorte automatico de margem branca interna. Resolve dois problemas:
#
# 1) Desenhos que vinham pequenos no centro com bastante area branca.
# 2) PDFs cujas paginas em paisagem nao encaixavam corretamente.
#
# O front passa a renderizar SEMPRE como <img> dentro de .op-drawing-page
# 196mm x 283mm — sem PDF embed, sem CSS rotate, sem object/iframe.
# ============================================================================


def _recortar_margem_branca(img):
    """Remove margens brancas/quase-brancas externas do desenho.

    Resolve o caso em que o desenho vem cercado de area branca dentro do
    arquivo (PDF com pouco conteudo no centro, JPG escaneado com bordas
    grandes), o que fazia o resultado final ficar pequeno mesmo com escala
    proporcional.
    """
    if Image is None or ImageChops is None:
        return img

    rgb = img.convert("RGB")

    fundo = Image.new("RGB", rgb.size, (255, 255, 255))
    diff = ImageChops.difference(rgb, fundo).convert("L")

    # Mascara de pixels "nao brancos" (luminancia da diferenca > tolerancia)
    mask = diff.point(lambda p: 255 if p > WHITE_TOLERANCE else 0)

    bbox = mask.getbbox()
    if not bbox:
        # Imagem totalmente branca — devolve original p/ nao quebrar
        return rgb

    left, top, right, bottom = bbox
    left = max(0, left - CROP_PADDING_PX)
    top = max(0, top - CROP_PADDING_PX)
    right = min(rgb.width, right + CROP_PADDING_PX)
    bottom = min(rgb.height, bottom + CROP_PADDING_PX)

    return rgb.crop((left, top, right, bottom))


def _encaixar_em_a4_retrato(img):
    """Encaixa uma imagem (ja recortada) em uma folha A4 retrato branca.

    - Rotaciona 90deg se a imagem ainda estiver em paisagem.
    - Escala proporcionalmente para caber na area util (descontada a margem).
    - Centraliza e pinta sobre fundo branco A4.
    """
    if Image is None:
        raise HTTPException(
            status_code=500,
            detail="Pillow nao esta instalado. Instale Pillow para normalizar desenhos.",
        )

    img = img.convert("RGB")

    if img.width > img.height:
        img = img.rotate(90, expand=True)

    area_w = A4_WIDTH_PX - (A4_MARGIN_PX * 2)
    area_h = A4_HEIGHT_PX - (A4_MARGIN_PX * 2)

    escala = min(area_w / img.width, area_h / img.height)
    nova_w = max(1, int(img.width * escala))
    nova_h = max(1, int(img.height * escala))

    img_redim = img.resize((nova_w, nova_h), Image.LANCZOS)

    folha = Image.new("RGB", (A4_WIDTH_PX, A4_HEIGHT_PX), "white")
    pos_x = (A4_WIDTH_PX - nova_w) // 2
    pos_y = (A4_HEIGHT_PX - nova_h) // 2
    folha.paste(img_redim, (pos_x, pos_y))

    return folha


def _contar_paginas_desenho(caminho: Path) -> int:
    """Retorna o total de paginas do desenho.

    - JPG/PNG: sempre 1.
    - PDF: usa fitz quando disponivel, senao pypdf.
    - Outros: levanta 422.
    """
    ext = caminho.suffix.lower()

    if ext in (".jpg", ".jpeg", ".png"):
        return 1

    if ext == ".pdf":
        if fitz is not None:
            doc = fitz.open(str(caminho))
            try:
                return len(doc)
            finally:
                doc.close()
        if PdfReader is not None:
            try:
                return len(PdfReader(str(caminho)).pages)
            except Exception:
                return 1
        # Sem nenhuma biblioteca de PDF -> trata como 1 pagina e o /pagina
        # devolvera erro 500 explicando o que falta instalar.
        return 1

    raise HTTPException(
        status_code=422,
        detail="Formato nao permitido. Use JPG, JPEG, PNG ou PDF.",
    )


def _carregar_desenho_como_imagem(caminho: Path, pagina: int = 1):
    """Carrega uma pagina do desenho como Pillow.Image RGB.

    - JPG/PNG: lê direto (com correcao EXIF). Apenas pagina=1 e valida.
    - PDF: rasteriza via PyMuPDF (fitz) em DESENHO_A4_DPI.
    """
    if Image is None:
        raise HTTPException(
            status_code=500,
            detail="Pillow nao esta instalado. Instale Pillow para normalizar desenhos.",
        )

    ext = caminho.suffix.lower()

    if ext in (".jpg", ".jpeg", ".png"):
        if pagina != 1:
            raise HTTPException(
                status_code=404,
                detail="Imagem possui somente uma pagina.",
            )
        with Image.open(caminho) as img:
            if ImageOps is not None:
                img = ImageOps.exif_transpose(img)
            return img.convert("RGB")

    if ext == ".pdf":
        if fitz is None:
            raise HTTPException(
                status_code=500,
                detail="PyMuPDF (fitz) nao esta instalado. Instale pymupdf para rasterizar PDFs.",
            )

        doc = fitz.open(str(caminho))
        try:
            total = len(doc)
            if pagina < 1 or pagina > total:
                raise HTTPException(
                    status_code=404,
                    detail=f"Pagina {pagina} nao existe no PDF. Total: {total}.",
                )

            page = doc[pagina - 1]
            zoom = DESENHO_A4_DPI / 72.0
            matrix = fitz.Matrix(zoom, zoom)
            pix = page.get_pixmap(matrix=matrix, alpha=False)
            img_bytes = pix.tobytes("png")
            with Image.open(io.BytesIO(img_bytes)) as img:
                return img.convert("RGB")
        finally:
            doc.close()

    raise HTTPException(
        status_code=422,
        detail="Formato nao permitido. Use JPG, JPEG, PNG ou PDF.",
    )


@app.get("/api/producao/ordem-producao/desenho/impressao-a4/pagina")
def obter_desenho_ordem_producao_impressao_a4_pagina(
    arquivo: str,
    pagina: int = 1,
    usuario=Depends(validar_token),
):
    """Devolve UMA pagina do desenho ja como JPEG A4 retrato pronta para impressao.

    Pipeline:
      1) Carrega a pagina como imagem (rasteriza se for PDF).
      2) Recorta margens brancas externas (resolve o caso "desenho pequeno no
         centro da folha").
      3) Rotaciona se a area util sair em paisagem.
      4) Escala proporcionalmente e centraliza em uma folha A4 retrato branca.
      5) Serializa em JPEG e devolve via StreamingResponse.

    O front deve renderizar a resposta como <img> dentro de uma folha A4 fixa.
    """
    caminho = _resolver_arquivo_desenho(arquivo)

    # Checagem antecipada de Pillow — sem Pillow nao da pra fazer nada.
    # Pega o erro cedo com mensagem clara em vez de estourar la dentro.
    if Image is None:
        raise HTTPException(
            status_code=500,
            detail={
                "mensagem": "Pillow nao esta instalado na API. Instale Pillow>=10.0.0.",
                "arquivo": caminho.name,
                "pagina": pagina,
                "pillow_disponivel": False,
                "pymupdf_disponivel": fitz is not None,
            },
        )

    try:
        img_original = _carregar_desenho_como_imagem(caminho, pagina=pagina)
        img_cortada = _recortar_margem_branca(img_original)
        img_a4 = _encaixar_em_a4_retrato(img_cortada)

        saida = io.BytesIO()
        img_a4.save(saida, format="JPEG", quality=92, optimize=True)
        saida.seek(0)

        return StreamingResponse(
            saida,
            media_type="image/jpeg",
            headers={
                "Cache-Control": "no-store",
                "X-Original-File": caminho.name,
                "X-A4-Normalized": "S",
                "X-A4-Page": str(pagina),
                "X-A4-Width": str(A4_WIDTH_PX),
                "X-A4-Height": str(A4_HEIGHT_PX),
                "X-A4-DPI": str(DESENHO_A4_DPI),
            },
        )
    except HTTPException:
        raise
    except Exception as exc:
        # Erro estruturado: o front consegue extrair "erro" e ler as flags
        # de disponibilidade sem precisar chamar /diagnostico de novo.
        raise HTTPException(
            status_code=500,
            detail={
                "mensagem": "Erro ao normalizar desenho para A4.",
                "arquivo": caminho.name,
                "pagina": pagina,
                "erro": str(exc),
                "pillow_disponivel": Image is not None,
                "pymupdf_disponivel": fitz is not None,
            },
        )


@app.get("/api/producao/ordem-producao/desenho/impressao-a4/diagnostico")
def diagnosticar_desenho_impressao_a4(
    arquivo: str,
    usuario=Depends(validar_token),
):
    """Diagnostico individual de UM desenho para o pipeline /impressao-a4.

    Use este endpoint quando /pagina ou /manifest falharem para descobrir
    a causa exata:
    - pillow_disponivel=False -> falta instalar Pillow.
    - pymupdf_disponivel=False e arquivo .pdf -> falta instalar pymupdf.
    - existe=False -> arquivo nao esta na pasta de desenhos.
    - extensao desconhecida -> formato nao permitido.

    NAO levanta excecao: sempre devolve 200 com { ok: bool, ... }.
    """
    try:
        caminho = _resolver_arquivo_desenho(arquivo)
        existe = caminho.exists() and caminho.is_file()
        tamanho_bytes = None
        modificado_em = None
        if existe:
            try:
                stat = caminho.stat()
                tamanho_bytes = int(stat.st_size)
                modificado_em = int(stat.st_mtime)
            except Exception:
                pass

        return {
            "ok": True,
            "arquivo": caminho.name,
            "caminho": str(caminho),
            "existe": existe,
            "extensao": caminho.suffix.lower(),
            "tamanho_bytes": tamanho_bytes,
            "modificado_em": modificado_em,
            "pillow_disponivel": Image is not None,
            "pymupdf_disponivel": fitz is not None,
            "pypdf_disponivel": PdfReader is not None,
            "dpi_normalizacao": DESENHO_A4_DPI,
            "a4_largura_px": A4_WIDTH_PX,
            "a4_altura_px": A4_HEIGHT_PX,
            "pasta_configurada": str(Path(PASTA_DESENHOS_OP_PADRAO)),
        }
    except HTTPException as exc:
        # Erros conhecidos do resolver (404/422) viram diagnostico, nao excecao.
        detalhe = exc.detail if isinstance(exc.detail, str) else str(exc.detail)
        return {
            "ok": False,
            "arquivo_solicitado": arquivo,
            "status_resolver": exc.status_code,
            "erro": detalhe,
            "pillow_disponivel": Image is not None,
            "pymupdf_disponivel": fitz is not None,
            "pypdf_disponivel": PdfReader is not None,
            "pasta_configurada": str(Path(PASTA_DESENHOS_OP_PADRAO)),
        }
    except Exception as exc:
        return {
            "ok": False,
            "arquivo_solicitado": arquivo,
            "erro": str(exc),
            "pillow_disponivel": Image is not None,
            "pymupdf_disponivel": fitz is not None,
            "pypdf_disponivel": PdfReader is not None,
            "pasta_configurada": str(Path(PASTA_DESENHOS_OP_PADRAO)),
        }


@app.get("/api/producao/ordem-producao/desenho/impressao-a4/manifest")
def obter_manifest_desenho_ordem_producao_impressao_a4(
    arquivo: str,
    usuario=Depends(validar_token),
):
    """Lista as paginas normalizadas A4 disponiveis para um desenho.

    - JPG/PNG: 1 pagina.
    - PDF: total de paginas do arquivo (cada pagina vira uma folha A4).

    O front usa este endpoint para descobrir quantos <img> precisa renderizar
    e qual URL chamar para cada folha.
    """
    caminho = _resolver_arquivo_desenho(arquivo)
    ext = caminho.suffix.lower()
    arquivo_encoded = quote(caminho.name, safe="")

    if ext in (".jpg", ".jpeg", ".png"):
        tipo = "IMAGEM"
    elif ext == ".pdf":
        tipo = "PDF"
    else:
        raise HTTPException(
            status_code=422,
            detail="Formato nao permitido. Use JPG, JPEG, PNG ou PDF.",
        )

    total_paginas = _contar_paginas_desenho(caminho)

    try:
        stat = caminho.stat()
        versao_cache = int(stat.st_mtime)
    except Exception:
        versao_cache = 0

    paginas = []
    for pag in range(1, total_paginas + 1):
        paginas.append({
            "pagina": pag,
            "mime_type": "image/jpeg",
            "url": (
                "/api/producao/ordem-producao/desenho/impressao-a4/pagina"
                f"?arquivo={arquivo_encoded}&pagina={pag}&v={versao_cache}"
            ),
        })

    return {
        "arquivo": caminho.name,
        "tipo": tipo,
        "total_paginas": total_paginas,
        "layout": "A4_RETRATO_NORMALIZADO",
        "dpi": DESENHO_A4_DPI,
        "largura_px": A4_WIDTH_PX,
        "altura_px": A4_HEIGHT_PX,
        "paginas": paginas,
    }


# ============================================================================
# Miniatura (thumbnail) para preview na tela.
#
# Diferente de /impressao-a4/pagina (que entrega A4 retrato pronto para
# impressao, ~1654x2338px), este endpoint devolve uma versao reduzida
# (~600px no maior lado, WEBP/JPEG 70%) que pode ser cacheada agressivamente
# pelo browser. O Lovable usa para o preview/grid, e so baixa o A4 completo
# no momento de imprimir.
# ============================================================================


def _gerar_thumbnail_desenho(caminho: Path, formato: str = "WEBP"):
    """Gera uma miniatura do desenho (~DESENHO_THUMB_MAX_PX no maior lado).

    - JPG/PNG: redimensiona com Pillow.
    - PDF: rasteriza apenas a primeira pagina via fitz em DESENHO_THUMB_PDF_DPI.

    Retorna (bytes, media_type). Se WEBP nao for suportado pelo Pillow
    instalado, faz fallback para JPEG.
    """
    if Image is None:
        raise HTTPException(
            status_code=500,
            detail="Pillow nao esta instalado na API. Instale Pillow>=10.0.0.",
        )

    ext = caminho.suffix.lower()
    img = None

    if ext in (".jpg", ".jpeg", ".png"):
        img = Image.open(caminho)
        if ImageOps is not None:
            img = ImageOps.exif_transpose(img)
        img = img.convert("RGB")

    elif ext == ".pdf":
        if fitz is None:
            # Sem fitz nao da pra rasterizar PDF — devolve erro claro.
            raise HTTPException(
                status_code=500,
                detail=(
                    "PyMuPDF (fitz) nao esta instalado. Instale pymupdf para "
                    "gerar thumbnails de PDF."
                ),
            )
        doc = fitz.open(str(caminho))
        try:
            if len(doc) == 0:
                raise HTTPException(
                    status_code=422,
                    detail="PDF nao tem paginas.",
                )
            page = doc[0]
            zoom = DESENHO_THUMB_PDF_DPI / 72.0
            matrix = fitz.Matrix(zoom, zoom)
            pix = page.get_pixmap(matrix=matrix, alpha=False)
            img_bytes = pix.tobytes("png")
            img = Image.open(io.BytesIO(img_bytes)).convert("RGB")
        finally:
            doc.close()
    else:
        raise HTTPException(
            status_code=422,
            detail="Formato nao permitido. Use JPG, JPEG, PNG ou PDF.",
        )

    # Redimensiona preservando proporcao: maior lado <= DESENHO_THUMB_MAX_PX.
    largura, altura = img.size
    maior = max(largura, altura)
    if maior > DESENHO_THUMB_MAX_PX:
        escala = DESENHO_THUMB_MAX_PX / float(maior)
        nova_w = max(1, int(largura * escala))
        nova_h = max(1, int(altura * escala))
        img = img.resize((nova_w, nova_h), Image.LANCZOS)

    saida = io.BytesIO()
    formato_upper = (formato or "WEBP").upper().strip()

    if formato_upper == "WEBP":
        try:
            img.save(saida, format="WEBP", quality=DESENHO_THUMB_QUALITY, method=4)
            media_type = "image/webp"
        except Exception:
            # Pillow sem suporte a WEBP -> fallback JPEG
            saida = io.BytesIO()
            img.save(saida, format="JPEG", quality=DESENHO_THUMB_QUALITY, optimize=True)
            media_type = "image/jpeg"
            formato_upper = "JPEG"
    else:
        img.save(saida, format="JPEG", quality=DESENHO_THUMB_QUALITY, optimize=True)
        media_type = "image/jpeg"
        formato_upper = "JPEG"

    saida.seek(0)
    return saida, media_type, formato_upper, img.size


@app.get("/api/producao/ordem-producao/desenho/thumbnail")
def obter_desenho_ordem_producao_thumbnail(
    arquivo: str,
    formato: str = "WEBP",
    usuario=Depends(validar_token),
):
    """Devolve uma miniatura do desenho para PREVIEW (nao usar para impressao).

    Tamanho: ~600px no maior lado.
    Formato: WEBP por padrao (fallback JPEG se Pillow nao suportar).
    Qualidade: 70%.

    Cache-Control: public, max-age=86400 (1 dia). Como a URL inclui ?v={mtime},
    qualquer atualizacao do arquivo invalida o cache automaticamente.
    """
    caminho = _resolver_arquivo_desenho(arquivo)

    try:
        saida, media_type, formato_final, dimensoes = _gerar_thumbnail_desenho(
            caminho, formato=formato
        )
        return StreamingResponse(
            saida,
            media_type=media_type,
            headers={
                # Thumbnails sao estaveis por (arquivo, mtime) — pode cachear
                # bem agressivamente. O versionador ?v={mtime} no link da API
                # garante invalidacao quando o desenho original muda.
                "Cache-Control": "public, max-age=86400, immutable",
                "X-Original-File": caminho.name,
                "X-Thumbnail": "S",
                "X-Thumbnail-Format": formato_final,
                "X-Thumbnail-Width": str(dimensoes[0]),
                "X-Thumbnail-Height": str(dimensoes[1]),
            },
        )
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail={
                "mensagem": "Erro ao gerar thumbnail do desenho.",
                "arquivo": caminho.name,
                "erro": str(exc),
                "pillow_disponivel": Image is not None,
                "pymupdf_disponivel": fitz is not None,
            },
        )


@app.get("/api/producao/ordem-producao/desenhos/diagnostico")
def diagnosticar_desenhos_op(
    cod_emp: Optional[str] = "1",
    cod_ori: Optional[str] = None,
    num_orp: Optional[str] = None,
    cod_pro: Optional[str] = None,
    usuario=Depends(validar_token),
):
    """Diagnostico de acesso aa pasta de desenhos da OP.

    Pode ser chamado de 2 formas:
    - Direto pelo produto:  ?cod_pro=110001466
    - Pela OP (resolve CodPro via E900COP): ?cod_emp=1&cod_ori=250&num_orp=1112

    Devolve:
    - pasta configurada (UNC ou mount Linux)
    - se a pasta existe / eh diretorio
    - lista de nomes/extensoes que a API tentaria casar
    - amostra dos arquivos efetivamente na pasta
    - lista do que o helper localizar_desenhos_produto retorna
    """
    try:
        pasta = Path(PASTA_DESENHOS_OP_PADRAO)
        pasta_existe = pasta.exists()
        pasta_dir = pasta.is_dir() if pasta_existe else False
    except Exception:
        pasta = None
        pasta_existe = False
        pasta_dir = False

    # Normaliza inputs
    cod_emp_int = _to_int_or_none(cod_emp, "cod_emp", default=1) or 1
    num_orp_int = _to_int_or_none(num_orp, "num_orp", default=None)
    cod_ori_s = (str(cod_ori).strip() if cod_ori is not None else "") or None
    cod_pro_s = (str(cod_pro).strip() if cod_pro is not None else "")

    # Se nao veio cod_pro mas veio (cod_ori + num_orp), busca o CodPro da OP
    cod_pro_resolvido_via_op = False
    erro_resolucao_op = None
    if not cod_pro_s and cod_ori_s and num_orp_int:
        try:
            conn = get_connection()
            cursor = conn.cursor()
            try:
                cursor.execute(
                    """
                    SELECT CodPro
                    FROM E900COP
                    WHERE CodEmp = ?
                      AND CodOri = ?
                      AND NumOrp = ?
                      AND CodOri <> '100'
                      AND SitOrp <> 'C'
                    """,
                    [cod_emp_int, cod_ori_s, num_orp_int],
                )
                row = cursor.fetchone()
                if row and row[0]:
                    cod_pro_s = str(row[0]).strip()
                    cod_pro_resolvido_via_op = True
            finally:
                try:
                    conn.close()
                except Exception:
                    pass
        except Exception as exc:
            erro_resolucao_op = str(exc)

    candidatos = []
    if cod_pro_s:
        nomes = [f"{cod_pro_s}-{i}" for i in range(1, 10)] + [cod_pro_s]
        for nome in nomes:
            for ext in [".jpg", ".jpeg", ".png", ".pdf",
                        ".JPG", ".JPEG", ".PNG", ".PDF"]:
                candidatos.append(f"{nome}{ext}")

    desenhos = []
    arquivos_na_pasta = []
    if pasta_existe and pasta_dir:
        try:
            arquivos_na_pasta = sorted(
                arq.name for arq in pasta.iterdir() if arq.is_file()
            )[:200]
        except Exception:
            arquivos_na_pasta = []
        if cod_pro_s:
            desenhos = localizar_desenhos_produto(cod_pro_s)

    return {
        "cod_emp": cod_emp_int,
        "cod_ori": cod_ori_s,
        "num_orp": num_orp_int,
        "cod_pro": cod_pro_s or None,
        "cod_pro_resolvido_via_op": cod_pro_resolvido_via_op,
        "erro_resolucao_op": erro_resolucao_op,
        "pasta_configurada": str(pasta) if pasta is not None else None,
        "pasta_existe": pasta_existe,
        "pasta_eh_diretorio": pasta_dir,
        "total_arquivos_na_pasta": len(arquivos_na_pasta),
        "amostra_arquivos_na_pasta": arquivos_na_pasta[:50],
        "candidatos_testados": candidatos,
        "desenhos_encontrados": desenhos,
        "observacao": (
            "Se pasta_existe=false, problema esta no acesso da API ao share "
            "(monte o UNC em /mnt/desenhos_op em Linux/Docker e setar env "
            "PASTA_DESENHOS_OP). Se pasta_existe=true mas desenhos_encontrados=[], "
            "veja amostra_arquivos_na_pasta para conferir se o cod_pro casa com "
            "algum nome no padrao CODPRO ou CODPRO-N. Se cod_pro_resolvido_via_op=false "
            "e voce passou cod_ori+num_orp, a OP nao existe ou esta cancelada/origem 100."
        ),
    }


@app.get("/api/producao/ordem-producao/observacoes")
def consultar_observacoes_ordem_producao(
    cod_emp: Optional[str] = "1",
    cod_ori: Optional[str] = None,
    num_orp: Optional[str] = None,
    usuario=Depends(validar_token),
):
    """Lista as observacoes (E900OBS) de uma OP.

    Endpoint de consulta sob demanda — usado pelo Lovable para abrir
    um modal/drawer com as observacoes da OP, sem polui-las dentro da
    impressao do MCAP700.
    """
    cod_emp_int = _to_int_or_none(cod_emp, "cod_emp", default=1) or 1
    num_orp_int = _to_int_or_none(num_orp, "num_orp", default=None)
    cod_ori_s = (str(cod_ori).strip() if cod_ori is not None else "") or None

    if not cod_ori_s or not num_orp_int:
        raise HTTPException(
            status_code=422,
            detail="Informe origem (cod_ori) e número da OP (num_orp).",
        )

    conn = get_connection()
    cursor = conn.cursor()
    try:
        cursor.execute(
            """
            SELECT
                OBS.CodEmp AS cod_emp,
                OBS.CodOri AS cod_ori,
                OBS.NumOrp AS num_orp,
                OBS.TipObs AS tipo_observacao,
                OBS.SeqObs AS sequencia,
                OBS.DesObs AS observacao
            FROM E900OBS OBS
            WHERE OBS.CodEmp = ?
              AND OBS.CodOri = ?
              AND OBS.NumOrp = ?
            ORDER BY
                OBS.TipObs,
                OBS.SeqObs
            """,
            [cod_emp_int, cod_ori_s, num_orp_int],
        )
        observacoes = _fetch_all_dict(cursor)
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Erro ao consultar observações da OP: {str(exc)}",
        )
    finally:
        try:
            conn.close()
        except Exception:
            pass

    return {
        "cod_emp": cod_emp_int,
        "cod_ori": cod_ori_s,
        "num_orp": num_orp_int,
        "qtd_observacoes": len(observacoes),
        "tem_observacao": "S" if len(observacoes) > 0 else "N",
        "observacoes": observacoes,
    }


def _consultar_dados_impressao_op(
    cod_emp,
    cod_ori,
    num_orp,
    listar_componentes,
    listar_desenho,
    cod_etg,
    cod_cre,
    conn,
    incluir_desenhos: str = "N",
    quebrar_por_operacao: str = "N",
    imprimir_observacoes: str = "N",
):
    """Coleta os dados de UMA OP no formato MCAP700.

    Reutilizado pelo endpoint individual /impressao e pelo endpoint em lote
    /impressao/lote — por isso recebe ``conn`` aberta e NAO gerencia
    o ciclo de vida da conexao.

    Retorna o dict da OP ou ``None`` se a OP nao existe (ou e cancelada/origem 100,
    bloqueadas no proprio SELECT do cabecalho).
    """
    cursor = conn.cursor()

    try:
        # ============================================================
        # 1) Cabeçalho da OP
        # ============================================================

        sql_cabecalho = """
            SELECT
                COP.CodEmp AS cod_emp,
                COP.CodOri AS cod_ori,
                COP.NumOrp AS num_orp,

                RIGHT('000000000' + CAST(COP.NumOrp AS VARCHAR(9)), 9) AS num_orp_formatado,
                COP.CodOri + RIGHT('000000000' + CAST(COP.NumOrp AS VARCHAR(9)), 9) AS codigo_barras_op,

                COP.CodPro AS produto,
                ISNULL(PRO.DesPro, '') AS descricao,
                ISNULL(PRO.DesPro, '') AS descricao_produto,
                COP.CodPro + ' - ' + ISNULL(PRO.DesPro, '') AS produto_descricao,

                COP.QtdPrv AS quantidade,
                ISNULL(PRO.UniMed, '') AS unidade_medida,

                COP.NumPed AS pedido,
                COP.DatGer AS data_geracao,
                COP.DtpIni AS inicio_previsto,

                RIGHT('0' + CAST(MONTH(COP.DatGer) AS VARCHAR(2)), 2)
                    + '/'
                    + CAST(YEAR(COP.DatGer) AS VARCHAR(4)) AS periodo,

                COP.SitOrp AS situacao,
                CASE CAST(COP.SitOrp AS VARCHAR(10))
                    WHEN 'L' THEN 'Liberada'
                    WHEN 'A' THEN 'Aberta'
                    WHEN 'F' THEN 'Finalizada'
                    WHEN 'C' THEN 'Cancelada'
                    WHEN 'E' THEN 'Encerrada'
                    ELSE CAST(COP.SitOrp AS VARCHAR(20))
                END AS situacao_descricao,

                COP.CodRot AS cod_rot,
                ISNULL(COP.RelPrd, '') AS agrupamento,
                ISNULL(REVOP.revisao, '') AS revisao,
                ISNULL(DEROP.derivacao, '') AS derivacao,

                -- Revisao do MODELO (produto): prioridade COP.VerMod -> versao
                -- corrente (E700VMO) -> ultima do modelo (E700MOD) -> "-".
                COALESCE(
                    NULLIF(LTRIM(RTRIM(COP.VerMod)), ''),
                    NULLIF(LTRIM(RTRIM(VMOD.VerMod)), ''),
                    NULLIF(LTRIM(RTRIM(MMOD.VerMod)), ''),
                    '-'
                ) AS revisao_modelo,

                -- Revisao do ROTEIRO: prioridade COP.VerRot -> versao corrente
                -- (E710VRO) -> ultima do roteiro (E710ROT) -> "-".
                COALESCE(
                    NULLIF(LTRIM(RTRIM(COP.VerRot)), ''),
                    NULLIF(LTRIM(RTRIM(VROT.VerRot)), ''),
                    NULLIF(LTRIM(RTRIM(MROT.VerRot)), ''),
                    '-'
                ) AS revisao_roteiro,

                ISNULL(COP.ObsOrp, '') AS observacao_1,
                ISNULL(COP.ObsOr2, '') AS observacao_2

            FROM E900COP COP
            LEFT JOIN E075PRO PRO
                ON PRO.CodEmp = COP.CodEmp
               AND PRO.CodPro = COP.CodPro

            -- Revisao do desenho associada a OP (tabela customizada Senior)
            OUTER APPLY (
                SELECT TOP 1
                    CONVERT(VARCHAR(20), COALESCE(UC.usu_revdes, '')) AS revisao
                FROM usu_t900cop UC
                WHERE UC.usu_codemp = COP.CodEmp
                  AND UC.usu_codori = COP.CodOri
                  AND UC.usu_numorp = COP.NumOrp
                  AND COALESCE(UC.usu_revdes, '') <> ''
                ORDER BY UC.usu_revdes DESC
            ) REVOP

            -- Derivacao da OP (E900QDO -> CodDer do produto principal)
            OUTER APPLY (
                SELECT TOP 1
                    ISNULL(Q.CodDer, '') AS derivacao
                FROM E900QDO Q
                WHERE Q.CodEmp = COP.CodEmp
                  AND Q.CodOri = COP.CodOri
                  AND Q.NumOrp = COP.NumOrp
                  AND Q.CodPro = COP.CodPro
                ORDER BY Q.CodDer
            ) DEROP

            -- Versao corrente do MODELO (tabela de historico E700VMO).
            -- Usado quando COP.VerMod nao esta preenchido.
            OUTER APPLY (
                SELECT TOP 1 V.VerMod
                FROM E700VMO V
                WHERE V.CodEmp = COP.CodEmp
                  AND V.CodMod = COP.CodPro
                  AND NULLIF(LTRIM(RTRIM(V.VerMod)), '') IS NOT NULL
                ORDER BY V.VerMod DESC
            ) VMOD

            -- Ultimo registro do MODELO em E700MOD (fallback final do modelo).
            OUTER APPLY (
                SELECT TOP 1 M.VerMod
                FROM E700MOD M
                WHERE M.CodEmp = COP.CodEmp
                  AND M.CodMod = COP.CodPro
                  AND NULLIF(LTRIM(RTRIM(M.VerMod)), '') IS NOT NULL
            ) MMOD

            -- Versao corrente do ROTEIRO (tabela de historico E710VRO).
            -- Usado quando COP.VerRot nao esta preenchido.
            OUTER APPLY (
                SELECT TOP 1 V.VerRot
                FROM E710VRO V
                WHERE V.CodEmp = COP.CodEmp
                  AND V.CodRot = COP.CodRot
                  AND NULLIF(LTRIM(RTRIM(V.VerRot)), '') IS NOT NULL
                ORDER BY V.VerRot DESC
            ) VROT

            -- Ultimo registro do ROTEIRO em E710ROT (fallback final do roteiro).
            OUTER APPLY (
                SELECT TOP 1 R.VerRot
                FROM E710ROT R
                WHERE R.CodEmp = COP.CodEmp
                  AND R.CodRot = COP.CodRot
                  AND NULLIF(LTRIM(RTRIM(R.VerRot)), '') IS NOT NULL
            ) MROT

            WHERE COP.CodEmp = ?
              AND COP.CodOri = ?
              AND COP.NumOrp = ?
              AND COP.CodOri <> '100'
              AND COP.SitOrp <> 'C'
        """

        cursor.execute(sql_cabecalho, [cod_emp, cod_ori, num_orp])
        cabecalho = _fetch_one_dict(cursor)

        if not cabecalho:
            # OP nao encontrada, cancelada ou origem 100 -> caller decide o que fazer
            return None

        # Padronizacao das revisoes (modelo/roteiro). O SQL ja devolve "-" como
        # ultimo fallback via COALESCE, mas reaplicamos em Python para tratar
        # o caso da string vir literalmente vazia/whitespace ou None (defesa
        # contra mudancas na query). Tambem montamos o label combinado usado
        # na caixa "REV" do relatorio.
        def _norm_rev(valor):
            if valor is None:
                return "-"
            texto = str(valor).strip()
            return texto if texto else "-"

        cabecalho["revisao_modelo"] = _norm_rev(cabecalho.get("revisao_modelo"))
        cabecalho["revisao_roteiro"] = _norm_rev(cabecalho.get("revisao_roteiro"))
        cabecalho["revisao_label"] = (
            f"MOD {cabecalho['revisao_modelo']} / ROT {cabecalho['revisao_roteiro']}"
        )

        # Padronizacao dos zeros da OP:
        # - num_orp_exibicao: para o campo visual "O.P.:" no relatorio
        #   (sem zeros a esquerda — "69072" em vez de "000069072").
        # - num_orp_formatado: ALIAS para num_orp_exibicao. O Lovable ja
        #   usa este campo para exibir, entao mantemos o nome mas com o
        #   conteudo limpo (sem zeros) — atende a regra nova sem precisar
        #   alterar o front imediatamente.
        # - codigo_barras_op: continua com 9 digitos zero-padded (origem +
        #   OP formatada), porque o codigo de barras depende desse padrao.
        num_orp_exibicao = formatar_numero_op_exibicao(cabecalho.get("num_orp"))
        cabecalho["num_orp_exibicao"] = num_orp_exibicao
        cabecalho["num_orp_formatado"] = num_orp_exibicao
        cabecalho["num_orp_barcode"] = formatar_numero_op_barcode(cabecalho.get("num_orp"))
        cabecalho["codigo_barras_op"] = formatar_codigo_barras_op(
            cabecalho.get("cod_ori"),
            cabecalho.get("num_orp"),
        )

        # ============================================================
        # 2) Componentes
        # ============================================================

        componentes = []

        if listar_componentes == "S":
            filtros_componentes = ""
            params_componentes = [cod_emp, cod_ori, num_orp]

            if cod_etg is not None:
                filtros_componentes += " AND CMO.CodEtg = ?"
                params_componentes.append(cod_etg)

            sql_componentes = f"""
                SELECT
                    CMO.CodEmp AS cod_emp,
                    CMO.CodOri AS cod_ori,
                    CMO.NumOrp AS num_orp,
                    CMO.CodEtg AS cod_etg,
                    CMO.SeqCmp AS seq_cmp,

                    RIGHT('0000' + CAST(CMO.CodEtg AS VARCHAR(4)), 4)
                      + RIGHT('0000' + CAST(CMO.SeqCmp AS VARCHAR(4)), 4) AS codigo_barras_componente,

                    CMO.CodCmp AS codigo_componente,
                    CMO.CodDer AS derivacao_componente,
                    ISNULL(PRO.DesPro, '') AS descricao_componente,

                    CMO.QtdPrv AS quantidade_prevista,
                    CMO.UniMed AS unidade_medida,
                    CMO.CodDep AS deposito,
                    CAST('' AS VARCHAR(100)) AS endereco

                FROM E900CMO CMO
                LEFT JOIN E075PRO PRO
                    ON PRO.CodEmp = CMO.CodEmp
                   AND PRO.CodPro = CMO.CodCmp
                WHERE CMO.CodEmp = ?
                  AND CMO.CodOri = ?
                  AND CMO.NumOrp = ?
                  {filtros_componentes}
                ORDER BY
                    CMO.CodEtg,
                    CMO.SeqCmp
            """

            cursor.execute(sql_componentes, params_componentes)
            componentes = _fetch_all_dict(cursor)

        # ============================================================
        # 3) Operações
        # ============================================================

        filtros_operacoes = ""
        params_operacoes = [cod_emp, cod_ori, num_orp]

        if cod_etg is not None:
            filtros_operacoes += " AND OOP.CodEtg = ?"
            params_operacoes.append(cod_etg)

        if cod_cre:
            filtros_operacoes += " AND OOP.CodCre = ?"
            params_operacoes.append(str(cod_cre).strip())

        sql_operacoes = f"""
            SELECT
                OOP.CodEmp AS cod_emp,
                OOP.CodOri AS cod_ori,
                OOP.NumOrp AS num_orp,

                OOP.CodEtg AS cod_etg,
                OOP.SeqRot AS seq_rot,
                OOP.CodCre AS cod_cre,
                OOP.CodOpr AS cod_opr,

                ISNULL(OPR.DesOpr, '') AS descricao_operacao,

                OOP.CodFor AS fornecedor,
                ISNULL(FORN.NomFor, '') AS nome_fornecedor,

                OOP.CodSer AS servico,
                ISNULL(SER.DesSer, '') AS descricao_servico,

                OOP.TmpPrp AS tmp_unit,
                OOP.TmpTpr AS tmp_total,

                ISNULL(QDO.CodDer, '') AS derivacao_op,
                ISNULL(QDO.UniMed, '') AS unidade_medida,

                RIGHT('0000' + CAST(OOP.CodEtg AS VARCHAR(4)), 4)
                  + RIGHT('0000' + CAST(OOP.SeqRot AS VARCHAR(4)), 4)
                  + ISNULL(QDO.CodDer, '') AS codigo_barras_operacao,

                ISNULL(OOP.ObsOop, '') AS observacao_operacao,

                -- Proxima operacao na OP COMPLETA (ignora filtro de cod_cre/cod_etg).
                -- Quando o usuario filtra por centro de recurso, a grid pode mostrar
                -- so 1 operacao, mas a "proxima" deve continuar sendo a real do roteiro.
                ISNULL(CAST(PROX.CodOpr AS VARCHAR(20)), '') AS proxima_operacao_codigo,
                ISNULL(OPR_PROX.DesOpr, '') AS proxima_operacao_descricao_sql,
                CASE
                    WHEN PROX.CodOpr IS NOT NULL
                    THEN CAST(PROX.CodOpr AS VARCHAR(20)) + ' - ' + ISNULL(OPR_PROX.DesOpr, '')
                    ELSE ''
                END AS proxima_operacao_label

            FROM E900OOP OOP
            INNER JOIN E900COP COP
                ON COP.CodEmp = OOP.CodEmp
               AND COP.CodOri = OOP.CodOri
               AND COP.NumOrp = OOP.NumOrp

            LEFT JOIN E720OPR OPR
                ON OPR.CodEmp = OOP.CodEmp
               AND OPR.CodOpr = OOP.CodOpr

            LEFT JOIN E095FOR FORN
                ON FORN.CodFor = OOP.CodFor

            LEFT JOIN E080SER SER
                ON SER.CodEmp = OOP.CodEmp
               AND SER.CodSer = OOP.CodSer

            OUTER APPLY (
                SELECT TOP 1
                    Q.CodDer,
                    Q.UniMed
                FROM E900QDO Q
                WHERE Q.CodEmp = OOP.CodEmp
                  AND Q.CodOri = OOP.CodOri
                  AND Q.NumOrp = OOP.NumOrp
                  AND Q.CodPro = COP.CodPro
                ORDER BY
                    Q.CodDer
            ) QDO

            OUTER APPLY (
                SELECT TOP 1
                    NX.CodOpr,
                    NX.CodEtg,
                    NX.SeqRot
                FROM E900OOP NX
                WHERE NX.CodEmp = OOP.CodEmp
                  AND NX.CodOri = OOP.CodOri
                  AND NX.NumOrp = OOP.NumOrp
                  AND (
                        NX.CodEtg > OOP.CodEtg
                        OR (
                            NX.CodEtg = OOP.CodEtg
                            AND NX.SeqRot > OOP.SeqRot
                        )
                  )
                ORDER BY
                    NX.CodEtg,
                    NX.SeqRot
            ) PROX

            LEFT JOIN E720OPR OPR_PROX
                ON OPR_PROX.CodEmp = OOP.CodEmp
               AND OPR_PROX.CodOpr = PROX.CodOpr

            WHERE OOP.CodEmp = ?
              AND OOP.CodOri = ?
              AND OOP.NumOrp = ?
              {filtros_operacoes}

            ORDER BY
                OOP.CodEtg,
                OOP.SeqRot
        """

        cursor.execute(sql_operacoes, params_operacoes)
        operacoes = _fetch_all_dict(cursor)

        # A proxima operacao agora vem direto do SQL (OUTER APPLY na OP completa),
        # entao o codigo Python so normaliza os nomes finais usados pelo Lovable
        # e inicializa o array de narrativas que sera populado depois.
        # Quantidade da OP usada para calcular tmp_total = tmp_unit * qtd.
        quantidade_op_cab = (
            cabecalho.get("quantidade")
            or cabecalho.get("quantidade_prevista")
            or cabecalho.get("qtd_prv")
            or 1
        )
        for operacao in operacoes:
            proxima_cod = operacao.get("proxima_operacao_codigo") or ""
            proxima_desc = operacao.get("proxima_operacao_descricao_sql") or ""
            operacao["proxima_operacao"] = proxima_cod
            operacao["proxima_operacao_codigo"] = proxima_cod
            operacao["proxima_operacao_descricao"] = proxima_desc
            # proxima_operacao_label ja veio do SQL ("CODIGO - DESCRICAO" ou "")
            operacao["proxima_operacao_label"] = operacao.get("proxima_operacao_label") or ""
            # Remove o nome interno usado so para evitar conflito com a chave antiga
            operacao.pop("proxima_operacao_descricao_sql", None)
            operacao["narrativas"] = []

            # Tempos sempre em MINUTOS:
            # - tmp_unit_min: vem do banco em minutos (TmpPrp do Senior Sapiens).
            # - tmp_total_min: tmp_unit_min * quantidade_op (regra do MCAP700).
            # tmp_total do banco (OOP.TmpTpr) e ignorado de proposito — a regra
            # correta no relatorio e recalcular pela quantidade da OP, e nao
            # confiar no campo persistido que pode estar desatualizado.
            tempos = calcular_tempos_operacao_em_minutos(
                tmp_unit=operacao.get("tmp_unit"),
                quantidade_op=quantidade_op_cab,
            )
            operacao["tmp_unit_min"] = tempos["tmp_unit_min"]
            operacao["tmp_total_min"] = tempos["tmp_total_min"]
            operacao["tmp_unit_formatado"] = tempos["tmp_unit_formatado"]
            operacao["tmp_total_formatado"] = tempos["tmp_total_formatado"]

        # ============================================================
        # 4) Narrativas
        # ============================================================

        sql_narrativas = """
            SELECT
                NSR.CodEmp AS cod_emp,
                NSR.CodOri AS cod_ori,
                NSR.NumOrp AS num_orp,
                NSR.CodEtg AS cod_etg,
                NSR.SeqRot AS seq_rot,
                NSR.SeqNsr AS seq_nsr,
                NSR.DesNsr AS narrativa
            FROM E900NSR NSR
            WHERE NSR.CodEmp = ?
              AND NSR.CodOri = ?
              AND NSR.NumOrp = ?
            ORDER BY
                NSR.CodEtg,
                NSR.SeqRot,
                NSR.SeqNsr
        """

        cursor.execute(sql_narrativas, [cod_emp, cod_ori, num_orp])
        narrativas = _fetch_all_dict(cursor)

        narrativas_por_operacao = {}
        for narrativa in narrativas:
            chave = f"{narrativa.get('cod_etg')}|{narrativa.get('seq_rot')}"
            narrativas_por_operacao.setdefault(chave, []).append(narrativa.get("narrativa") or "")

        for operacao in operacoes:
            chave = f"{operacao.get('cod_etg')}|{operacao.get('seq_rot')}"
            operacao["narrativas"] = narrativas_por_operacao.get(chave, [])

        # ============================================================
        # 5) Observações da OP
        # ============================================================

        sql_observacoes = """
            SELECT
                OBS.CodEmp AS cod_emp,
                OBS.CodOri AS cod_ori,
                OBS.NumOrp AS num_orp,
                OBS.TipObs AS tipo_observacao,
                OBS.SeqObs AS sequencia,
                OBS.DesObs AS observacao
            FROM E900OBS OBS
            WHERE OBS.CodEmp = ?
              AND OBS.CodOri = ?
              AND OBS.NumOrp = ?
            ORDER BY
                OBS.TipObs,
                OBS.SeqObs
        """

        cursor.execute(sql_observacoes, [cod_emp, cod_ori, num_orp])
        observacoes = _fetch_all_dict(cursor)

        mensagem_responsabilidade = (
            "Ao finalizar o apontamento o operador estará se responsabilizando pela quantidade "
            "e qualidade dos produtos informados."
        )

        # ============================================================
        # 6) Desenhos (opcional)
        # ============================================================
        desenhos = []
        if str(incluir_desenhos or "N").upper().strip() == "S":
            desenhos = localizar_desenhos_produto(
                cod_pro=cabecalho.get("produto"),
            )

        quebrar_op_flag = str(quebrar_por_operacao or "N").upper().strip() == "S"
        imprimir_obs_flag = str(imprimir_observacoes or "N").upper().strip() == "S"

        # Layout dos componentes: se houver mais de LIMITE itens, o Lovable
        # deve renderizar a Relacao de Componentes Necessarios em pagina
        # separada (com cabecalho da OP repetido). API so devolve a flag —
        # a quebra fisica e responsabilidade do front (CSS @media print).
        LIMITE_COMPONENTES_PRIMEIRA_PAGINA = 7
        total_componentes = len(componentes or [])
        quebrar_componentes_flag = total_componentes > LIMITE_COMPONENTES_PRIMEIRA_PAGINA

        total_observacoes = len(observacoes or [])

        return {
            "cabecalho": cabecalho,
            "componentes": componentes,
            "operacoes": operacoes,
            "observacoes": observacoes,
            "desenhos": desenhos,
            "mensagem_responsabilidade": mensagem_responsabilidade,
            "layout_referencia": "MCAP700.GER - GENIUS - Ordem de Produção p/ Operações",
            "modo_impressao": {
                "quebrar_por_operacao": quebrar_op_flag,
                "desenhos_apos_op": True,
                "desenhos_um_por_pagina": True,
                "imprimir_observacoes": imprimir_obs_flag,
                "a4": True,
            },
            "layout_componentes": {
                "total_componentes": total_componentes,
                "limite_componentes_primeira_pagina": LIMITE_COMPONENTES_PRIMEIRA_PAGINA,
                "quebrar_componentes_em_pagina_separada": quebrar_componentes_flag,
                "posicao_componentes_quando_quebrar": "APOS_OPERACOES",
            },
            "layout_observacoes": {
                "total_observacoes": total_observacoes,
                "tem_observacao": total_observacoes > 0,
            },
            "parametros": {
                "cod_emp": cod_emp,
                "cod_ori": cod_ori,
                "num_orp": num_orp,
                "listar_componentes": listar_componentes,
                "listar_desenho": listar_desenho,
                "cod_etg": cod_etg,
                "cod_cre": cod_cre,
                "incluir_desenhos": (incluir_desenhos or "N").upper().strip() or "N",
                "pasta_desenhos_servidor": str(Path(PASTA_DESENHOS_OP_PADRAO)),
                "quebrar_por_operacao": "S" if quebrar_op_flag else "N",
                "imprimir_observacoes": "S" if imprimir_obs_flag else "N",
            },
        }
    except HTTPException:
        raise


@app.get("/api/producao/ordem-producao/impressao")
def consultar_ordem_producao_impressao(
    cod_emp: Optional[str] = "1",
    cod_ori: Optional[str] = "210",
    num_orp: Optional[str] = None,
    listar_componentes: Optional[str] = "S",
    listar_desenho: Optional[str] = "N",
    cod_etg: Optional[str] = None,
    cod_cre: Optional[str] = None,
    incluir_desenhos: Optional[str] = "N",
    quebrar_por_operacao: Optional[str] = "N",
    imprimir_observacoes: Optional[str] = "N",
    usuario=Depends(validar_token),
):
    """
    Retorna os dados de UMA Ordem de Produção no padrão do relatório MCAP700.GER.
    Usado pelo Lovable para visualizar, imprimir e gerar PDF da OP.

    Regras (MCAP700):
    - Origem 100 nao eh impressa (422).
    - OP cancelada (SitOrp = 'C') nao eh impressa (retorna 404).
    """

    # Conversao tolerante de querystring (aceita "", " ", None)
    cod_emp = _to_int_or_none(cod_emp, "cod_emp", default=1) or 1
    num_orp = _to_int_or_none(num_orp, "num_orp", default=None)
    cod_etg = _to_int_or_none(cod_etg, "cod_etg", default=None)

    if not num_orp:
        raise HTTPException(status_code=422, detail="Informe o número da O.P.")

    cod_ori = str(cod_ori or "").strip()
    if not cod_ori:
        raise HTTPException(status_code=422, detail="Informe a Origem (cod_ori).")

    if cod_ori == "100":
        raise HTTPException(
            status_code=422,
            detail="Origem 100 não deve ser usada na impressão de Ordem de Produção.",
        )

    listar_componentes = (listar_componentes or "S").upper().strip() or "S"
    listar_desenho = (listar_desenho or "N").upper().strip() or "N"
    incluir_desenhos = (incluir_desenhos or "N").upper().strip() or "N"
    quebrar_por_operacao = (quebrar_por_operacao or "N").upper().strip() or "N"
    imprimir_observacoes = (imprimir_observacoes or "N").upper().strip() or "N"
    if cod_cre is not None:
        cod_cre = str(cod_cre).strip() or None

    conn = get_connection()
    try:
        dados = _consultar_dados_impressao_op(
            cod_emp=cod_emp,
            cod_ori=cod_ori,
            num_orp=num_orp,
            listar_componentes=listar_componentes,
            listar_desenho=listar_desenho,
            cod_etg=cod_etg,
            cod_cre=cod_cre,
            conn=conn,
            incluir_desenhos=incluir_desenhos,
            quebrar_por_operacao=quebrar_por_operacao,
            imprimir_observacoes=imprimir_observacoes,
        )
    except HTTPException:
        raise
    except Exception as exc:
        try:
            conn.close()
        except Exception:
            pass
        raise HTTPException(
            status_code=500,
            detail=f"Erro ao consultar impressão da Ordem de Produção: {str(exc)}",
        )
    finally:
        try:
            conn.close()
        except Exception:
            pass

    if not dados:
        raise HTTPException(
            status_code=404,
            detail=(
                f"O.P. não encontrada, cancelada ou em origem bloqueada. "
                f"Empresa={cod_emp}, Origem={cod_ori}, OP={num_orp}"
            ),
        )

    return {
        "atualizado_em": datetime.now().isoformat(),
        **dados,
    }


@app.get("/api/producao/ordem-producao/impressao/lote")
def consultar_ordens_producao_impressao_lote(
    cod_emp: Optional[str] = "1",
    num_ped: Optional[str] = None,
    rel_prd: Optional[str] = None,
    cod_pro: Optional[str] = None,
    sit_orp: Optional[str] = None,
    cod_etg: Optional[str] = None,
    cod_cre: Optional[str] = None,
    listar_componentes: Optional[str] = "S",
    listar_desenho: Optional[str] = "N",
    incluir_desenhos: Optional[str] = "N",
    quebrar_por_operacao: Optional[str] = "N",
    imprimir_observacoes: Optional[str] = "N",
    usuario=Depends(validar_token),
):
    """
    Retorna varias OPs para impressao em lote.
    Usar Pedido OU Relatorio de Producao (alternativos).
    Nunca retorna OP cancelada nem origem 100.
    """

    cod_emp_int = _to_int_or_none(cod_emp, "cod_emp", default=1) or 1
    num_ped_int = _to_int_or_none(num_ped, "num_ped", default=None)
    cod_etg_int = _to_int_or_none(cod_etg, "cod_etg", default=None)

    if rel_prd is not None:
        rel_prd = str(rel_prd).strip() or None
    if cod_pro is not None:
        cod_pro = str(cod_pro).strip() or None
    if sit_orp is not None:
        sit_orp = str(sit_orp).strip().upper() or None
    if cod_cre is not None:
        cod_cre = str(cod_cre).strip() or None

    listar_componentes = (listar_componentes or "S").upper().strip() or "S"
    listar_desenho = (listar_desenho or "N").upper().strip() or "N"
    incluir_desenhos = (incluir_desenhos or "N").upper().strip() or "N"
    quebrar_por_operacao = (quebrar_por_operacao or "N").upper().strip() or "N"
    imprimir_observacoes = (imprimir_observacoes or "N").upper().strip() or "N"

    tem_pedido = num_ped_int is not None and num_ped_int > 0
    tem_relprd = bool(rel_prd)
    tem_produto = bool(cod_pro)
    tem_estagio = cod_etg_int is not None
    tem_centro = bool(cod_cre)

    # Exige pelo menos um filtro especifico (alem de cod_emp) para evitar
    # imprimir TODA a base por engano. Aceitos: Pedido, Relatorio de Producao,
    # Produto, Estagio ou Centro de Recurso (combinados a vontade, salvo
    # Pedido + RelPrd que continuam mutuamente exclusivos).
    if not (tem_pedido or tem_relprd or tem_produto or tem_estagio or tem_centro):
        raise HTTPException(
            status_code=422,
            detail=(
                "Informe pelo menos um filtro para impressão em lote: "
                "Pedido, Relatório de Produção, Produto, Estágio ou Centro de Recurso."
            ),
        )

    if tem_pedido and tem_relprd:
        raise HTTPException(
            status_code=422,
            detail="Use Pedido ou Relatório de Produção, não os dois ao mesmo tempo.",
        )

    if sit_orp == "C":
        raise HTTPException(
            status_code=422,
            detail="OP cancelada não deve ser impressa.",
        )

    conn = get_connection()
    cursor = conn.cursor()

    try:
        where = [
            "COP.CodEmp = ?",
            "COP.CodOri <> '100'",
            "COP.SitOrp <> 'C'",
        ]
        params: list = [cod_emp_int]

        if tem_pedido:
            where.append("COP.NumPed = ?")
            params.append(num_ped_int)

        if tem_relprd:
            where.append("COP.RelPrd = ?")
            params.append(rel_prd)

        if tem_produto:
            where.append("COP.CodPro = ?")
            params.append(cod_pro)

        if sit_orp:
            where.append("COP.SitOrp = ?")
            params.append(sit_orp)

        # Refinamento por Estagio e/ou Centro de Recurso via EXISTS na
        # E900OOP — mantem coerencia com a grid do /opcoes e com o relatorio
        # Senior MCAP700.
        if cod_etg_int is not None or (cod_cre and str(cod_cre).strip()):
            exists_clauses = [
                "OOPF.CodEmp = COP.CodEmp",
                "OOPF.CodOri = COP.CodOri",
                "OOPF.NumOrp = COP.NumOrp",
            ]
            if cod_etg_int is not None:
                exists_clauses.append("OOPF.CodEtg = ?")
                params.append(int(cod_etg_int))
            if cod_cre and str(cod_cre).strip():
                exists_clauses.append("OOPF.CodCre = ?")
                params.append(str(cod_cre).strip())
            where.append(
                "EXISTS (SELECT 1 FROM E900OOP OOPF WHERE "
                + " AND ".join(exists_clauses)
                + ")"
            )

        sql_ops = f"""
            SELECT
                COP.CodEmp,
                COP.CodOri,
                COP.NumOrp
            FROM E900COP COP
            WHERE {" AND ".join(where)}
            ORDER BY
                COP.CodOri,
                COP.NumOrp
        """

        cursor.execute(sql_ops, params)
        ops_basicas = cursor.fetchall()

        ordens = []
        for row in ops_basicas:
            cod_emp_op = row[0]
            cod_ori_op = (row[1] or "").strip() if isinstance(row[1], str) else row[1]
            num_orp_op = row[2]

            dados_op = _consultar_dados_impressao_op(
                cod_emp=int(cod_emp_op) if cod_emp_op is not None else cod_emp_int,
                cod_ori=str(cod_ori_op),
                num_orp=int(num_orp_op),
                listar_componentes=listar_componentes,
                listar_desenho=listar_desenho,
                cod_etg=cod_etg_int,
                cod_cre=cod_cre,
                conn=conn,
                incluir_desenhos=incluir_desenhos,
                quebrar_por_operacao=quebrar_por_operacao,
                imprimir_observacoes=imprimir_observacoes,
            )

            if dados_op:
                ordens.append(dados_op)

        return {
            "atualizado_em": datetime.now().isoformat(),
            "quantidade_ops": len(ordens),
            "modo_impressao": {
                "quebrar_por_operacao": quebrar_por_operacao == "S",
                "desenhos_apos_op": True,
                "desenhos_um_por_pagina": True,
                "imprimir_observacoes": imprimir_observacoes == "S",
                "a4": True,
            },
            "filtros_aplicados": {
                "cod_emp": cod_emp_int,
                "num_ped": num_ped_int,
                "rel_prd": rel_prd,
                "cod_pro": cod_pro,
                "sit_orp": sit_orp,
                "cod_etg": cod_etg_int,
                "cod_cre": cod_cre,
                "listar_componentes": listar_componentes,
                "listar_desenho": listar_desenho,
                "incluir_desenhos": incluir_desenhos,
                "pasta_desenhos_servidor": str(Path(PASTA_DESENHOS_OP_PADRAO)),
                "quebrar_por_operacao": quebrar_por_operacao,
                "imprimir_observacoes": imprimir_observacoes,
            },
            "ordens": ordens,
        }

    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Erro ao gerar impressão em lote das OPs: {str(exc)}",
        )
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ============================================================
# IMPRESSÃO POR SELEÇÃO MANUAL (checkbox na grid)
# ============================================================

class _OPSelecionadaPayload(BaseModel):
    """Item do payload de /impressao/selecionadas — uma OP marcada na grid."""
    cod_emp: int = Field(default=1)
    cod_ori: str
    num_orp: int


class _ImpressaoSelecionadasPayload(BaseModel):
    """Payload de /impressao/selecionadas — lista de OPs + opcoes globais.

    Cada OP do array eh resolvida individualmente via _consultar_dados_impressao_op.
    OPs com CodOri='100' ou SitOrp='C' (cancelada) sao descartadas silenciosamente
    (a regra MCAP700 ja eh aplicada no SELECT do cabecalho dentro do helper).
    """
    ops: List[_OPSelecionadaPayload] = Field(default_factory=list)
    listar_componentes: str = "S"
    listar_desenho: str = "N"
    incluir_desenhos: str = "N"
    quebrar_por_operacao: str = "N"
    imprimir_observacoes: str = "N"
    cod_etg: Optional[int] = None
    cod_cre: Optional[str] = None


@app.post("/api/producao/ordem-producao/impressao/selecionadas")
def consultar_ordens_producao_impressao_selecionadas(
    payload: _ImpressaoSelecionadasPayload,
    usuario=Depends(validar_token),
):
    """
    Retorna varias OPs para impressao, escolhidas manualmente pelo usuario
    via checkbox na grid. Diferente de /impressao/lote (que filtra por
    Pedido/Rel.Prod/Estagio/CRE), aqui o front envia a lista exata de OPs.

    OPs invalidas (CodOri=100, canceladas, inexistentes) sao silenciosamente
    descartadas — o `quantidade_ops` no retorno reflete o que efetivamente
    foi gerado.
    """
    if not payload.ops:
        raise HTTPException(
            status_code=422,
            detail="Selecione ao menos uma OP para visualizar.",
        )

    if len(payload.ops) > 100:
        raise HTTPException(
            status_code=422,
            detail="Limite máximo de 100 OPs por visualização.",
        )

    listar_componentes = (payload.listar_componentes or "S").upper().strip() or "S"
    listar_desenho = (payload.listar_desenho or "N").upper().strip() or "N"
    incluir_desenhos = (payload.incluir_desenhos or "N").upper().strip() or "N"
    quebrar_por_operacao = (payload.quebrar_por_operacao or "N").upper().strip() or "N"
    imprimir_observacoes = (payload.imprimir_observacoes or "N").upper().strip() or "N"
    cod_cre = (payload.cod_cre or "").strip() or None if payload.cod_cre else None
    cod_etg = payload.cod_etg

    conn = get_connection()

    try:
        ordens = []
        descartadas = []

        for op in payload.ops:
            cod_ori = str(op.cod_ori or "").strip()
            if not cod_ori or not op.num_orp:
                descartadas.append({
                    "cod_emp": op.cod_emp,
                    "cod_ori": op.cod_ori,
                    "num_orp": op.num_orp,
                    "motivo": "Origem ou número da OP vazio",
                })
                continue
            if cod_ori == "100":
                descartadas.append({
                    "cod_emp": op.cod_emp,
                    "cod_ori": cod_ori,
                    "num_orp": op.num_orp,
                    "motivo": "Origem 100 não é impressa",
                })
                continue

            try:
                dados_op = _consultar_dados_impressao_op(
                    cod_emp=int(op.cod_emp),
                    cod_ori=cod_ori,
                    num_orp=int(op.num_orp),
                    listar_componentes=listar_componentes,
                    listar_desenho=listar_desenho,
                    cod_etg=cod_etg,
                    cod_cre=cod_cre,
                    conn=conn,
                    incluir_desenhos=incluir_desenhos,
                    quebrar_por_operacao=quebrar_por_operacao,
                    imprimir_observacoes=imprimir_observacoes,
                )
            except Exception as exc:
                descartadas.append({
                    "cod_emp": op.cod_emp,
                    "cod_ori": cod_ori,
                    "num_orp": op.num_orp,
                    "motivo": f"Erro ao consultar: {str(exc)}",
                })
                continue

            if dados_op:
                ordens.append(dados_op)
            else:
                descartadas.append({
                    "cod_emp": op.cod_emp,
                    "cod_ori": cod_ori,
                    "num_orp": op.num_orp,
                    "motivo": "OP não encontrada ou cancelada",
                })

        return {
            "atualizado_em": datetime.now().isoformat(),
            "quantidade_ops_solicitadas": len(payload.ops),
            "quantidade_ops": len(ordens),
            "quantidade_descartadas": len(descartadas),
            "descartadas": descartadas,
            "modo_impressao": {
                "quebrar_por_operacao": quebrar_por_operacao == "S",
                "desenhos_apos_op": True,
                "desenhos_um_por_pagina": True,
                "imprimir_observacoes": imprimir_observacoes == "S",
                "a4": True,
            },
            "parametros": {
                "listar_componentes": listar_componentes,
                "listar_desenho": listar_desenho,
                "incluir_desenhos": incluir_desenhos,
                "quebrar_por_operacao": quebrar_por_operacao,
                "imprimir_observacoes": imprimir_observacoes,
                "cod_etg": cod_etg,
                "cod_cre": cod_cre,
                "pasta_desenhos_servidor": str(Path(PASTA_DESENHOS_OP_PADRAO)),
            },
            "ordens": ordens,
        }

    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Erro ao carregar OPs selecionadas para impressão: {str(exc)}",
        )
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ============================================================
# OPÇÕES PARA FILTROS DA IMPRESSÃO DE OP (autocomplete/combo)
# ============================================================

@app.get("/api/producao/ordem-producao/opcoes")
def listar_opcoes_impressao_ordem_producao(
    cod_emp: Optional[str] = None,
    cod_ori: Optional[str] = None,
    num_orp: Optional[str] = None,
    num_ped: Optional[str] = None,
    rel_prd: Optional[str] = None,
    cod_pro: Optional[str] = None,
    sit_orp: Optional[str] = None,
    cod_etg: Optional[str] = None,
    cod_cre: Optional[str] = None,
    q: Optional[str] = None,
    limite_ops: Optional[str] = "80",
    usuario=Depends(validar_token),
):
    """
    Opções para alimentar os filtros/autocomplete da tela:
    Produção > Impressão de Ordem de Produção.

    Regras (MCAP700):
    - Nunca listar CodOri = '100'.
    - Nunca listar OP cancelada (SitOrp = 'C').
    - Permite buscar OPs por Pedido (E900COP.NumPed) OU
      Relatório de Produção (E900COP.RelPrd) — alternativos,
      não podem vir juntos.

    Retorna:
    - empresas
    - origens
    - pedidos
    - relatorios_producao
    - situacoes
    - ordens_producao
    - estagios
    - centros_recurso
    """

    # Conversao tolerante de querystring (aceita "", " ", None)
    cod_emp = _to_int_or_none(cod_emp, "cod_emp", default=None)
    num_orp = _to_int_or_none(num_orp, "num_orp", default=None)
    num_ped = _to_int_or_none(num_ped, "num_ped", default=None)
    cod_etg = _to_int_or_none(cod_etg, "cod_etg", default=None)
    limite_ops_int = _to_int_or_none(limite_ops, "limite_ops", default=80) or 80
    limite_ops = max(1, min(limite_ops_int, 200))

    if cod_ori is not None:
        cod_ori = str(cod_ori).strip() or None
    if cod_cre is not None:
        cod_cre = str(cod_cre).strip() or None
    if rel_prd is not None:
        rel_prd = str(rel_prd).strip() or None
    if cod_pro is not None:
        cod_pro = str(cod_pro).strip() or None
    if sit_orp is not None:
        sit_orp = str(sit_orp).strip().upper() or None
    if q is not None:
        q = str(q).strip() or None

    # Regra fixa do MCAP700: bloqueia origem 100
    if cod_ori == "100":
        raise HTTPException(
            status_code=422,
            detail="Origem 100 não deve ser usada na impressão de Ordem de Produção.",
        )

    # OP cancelada nunca eh impressa
    if sit_orp == "C":
        raise HTTPException(
            status_code=422,
            detail="OP cancelada não deve ser exibida na Impressão de Ordem de Produção.",
        )

    # Pedido e Relatório de Produção são alternativos
    if num_ped is not None and int(num_ped) > 0 and rel_prd:
        raise HTTPException(
            status_code=422,
            detail="Use Pedido ou Relatório de Produção, não os dois ao mesmo tempo.",
        )

    conn = get_connection()
    cursor = conn.cursor()

    try:
        def rows_to_dict():
            cols = [c[0] for c in cursor.description]
            dados = []
            for row in cursor.fetchall():
                item = {}
                for i, col in enumerate(cols):
                    valor = row[i]
                    if isinstance(valor, str):
                        valor = valor.strip()
                    elif isinstance(valor, Decimal):
                        valor = float(valor)
                    elif isinstance(valor, (datetime, date)):
                        valor = valor.isoformat()
                    item[col] = valor
                dados.append(item)
            return dados

        def montar_where(alias_cop="COP", usar_q=False):
            where = []
            params = []

            # Regras fixas do MCAP700:
            # - nunca listar origem 100
            # - nunca listar OP cancelada
            where.append(f"{alias_cop}.CodOri <> '100'")
            where.append(f"{alias_cop}.SitOrp <> 'C'")

            if cod_emp is not None:
                where.append(f"{alias_cop}.CodEmp = ?")
                params.append(int(cod_emp))

            if cod_ori:
                origem = str(cod_ori).strip()
                # Defesa em profundidade: barra origem 100 mesmo que algum
                # caller interno futuro chame montar_where sem passar pela
                # validacao do topo do endpoint.
                if origem == "100":
                    raise HTTPException(
                        status_code=422,
                        detail="Origem 100 não deve ser usada na Impressão de Ordem de Produção.",
                    )
                where.append(f"{alias_cop}.CodOri = ?")
                params.append(origem)

            if num_orp is not None and int(num_orp) > 0:
                where.append(f"{alias_cop}.NumOrp = ?")
                params.append(int(num_orp))

            if num_ped is not None and int(num_ped) > 0:
                where.append(f"{alias_cop}.NumPed = ?")
                params.append(int(num_ped))

            if rel_prd:
                where.append(f"{alias_cop}.RelPrd = ?")
                params.append(str(rel_prd).strip())

            if cod_pro and str(cod_pro).strip():
                where.append(f"{alias_cop}.CodPro = ?")
                params.append(str(cod_pro).strip())

            if sit_orp:
                where.append(f"{alias_cop}.SitOrp = ?")
                params.append(sit_orp)

            # Refinamento por Estagio e/ou Centro de Recurso via EXISTS na
            # E900OOP. Faz a OP aparecer somente se possuir uma operacao com
            # esse Estagio/Centro de Recurso — espelha o comportamento do
            # relatorio Senior MCAP700.
            if cod_etg is not None or (cod_cre and str(cod_cre).strip()):
                exists_clauses = [
                    f"OOPF.CodEmp = {alias_cop}.CodEmp",
                    f"OOPF.CodOri = {alias_cop}.CodOri",
                    f"OOPF.NumOrp = {alias_cop}.NumOrp",
                ]
                if cod_etg is not None:
                    exists_clauses.append("OOPF.CodEtg = ?")
                    params.append(int(cod_etg))
                if cod_cre and str(cod_cre).strip():
                    exists_clauses.append("OOPF.CodCre = ?")
                    params.append(str(cod_cre).strip())
                where.append(
                    "EXISTS (\n"
                    "                SELECT 1\n"
                    "                FROM E900OOP OOPF\n"
                    "                WHERE " + "\n                  AND ".join(exists_clauses) + "\n"
                    "            )"
                )

            if usar_q and q and str(q).strip():
                termo = f"%{str(q).strip()}%"
                where.append(f"""
                    (
                        CAST({alias_cop}.NumOrp AS VARCHAR(20)) LIKE ?
                        OR CAST({alias_cop}.NumPed AS VARCHAR(20)) LIKE ?
                        OR ISNULL({alias_cop}.RelPrd, '') LIKE ?
                        OR {alias_cop}.CodOri LIKE ?
                        OR {alias_cop}.CodPro LIKE ?
                        OR ISNULL(PRO.DesPro, '') LIKE ?
                    )
                """)
                params.extend([termo, termo, termo, termo, termo, termo])

            sql_where = " WHERE " + " AND ".join(where)
            return sql_where, params

        # ============================================================
        # Empresas
        # ============================================================

        cursor.execute("""
            SELECT DISTINCT
                COP.CodEmp AS codigo,
                CAST(COP.CodEmp AS VARCHAR(20)) AS value,
                'Empresa ' + CAST(COP.CodEmp AS VARCHAR(20)) AS descricao,
                CAST(COP.CodEmp AS VARCHAR(20)) + ' - Empresa ' + CAST(COP.CodEmp AS VARCHAR(20)) AS label
            FROM E900COP COP
            WHERE COP.CodOri <> '100'
              AND COP.SitOrp <> 'C'
            ORDER BY COP.CodEmp
        """)
        empresas = rows_to_dict()

        # ============================================================
        # Origens
        # ============================================================

        where_origens, params_origens = montar_where("COP", usar_q=False)

        cursor.execute(f"""
            SELECT DISTINCT
                COP.CodOri AS codigo,
                COP.CodOri AS value,
                'Origem ' + COP.CodOri AS descricao,
                COP.CodOri + ' - Origem ' + COP.CodOri AS label
            FROM E900COP COP
            {where_origens}
            ORDER BY COP.CodOri
        """, params_origens)
        origens = rows_to_dict()

        # ============================================================
        # Pedidos
        # ============================================================

        where_pedidos, params_pedidos = montar_where("COP", usar_q=False)

        cursor.execute(f"""
            SELECT
                COP.NumPed AS codigo,
                CAST(COP.NumPed AS VARCHAR(20)) AS value,
                'Pedido ' + CAST(COP.NumPed AS VARCHAR(20)) AS descricao,
                'Pedido ' + CAST(COP.NumPed AS VARCHAR(20))
                    + ' - ' + CAST(COUNT(*) AS VARCHAR(20)) + ' OP(s)' AS label,
                COUNT(*) AS qtd_ops
            FROM E900COP COP
            {where_pedidos}
              AND ISNULL(COP.NumPed, 0) > 0
            GROUP BY
                COP.NumPed
            ORDER BY
                COP.NumPed DESC
        """, params_pedidos)
        pedidos = rows_to_dict()

        # ============================================================
        # Relatórios de Produção / Agrupamentos
        # ============================================================

        where_relatorios, params_relatorios = montar_where("COP", usar_q=False)

        cursor.execute(f"""
            SELECT
                COP.RelPrd AS codigo,
                COP.RelPrd AS value,
                'Relatório Produção ' + COP.RelPrd AS descricao,
                'Relatório Produção ' + COP.RelPrd
                    + ' - ' + CAST(COUNT(*) AS VARCHAR(20)) + ' OP(s)' AS label,
                COUNT(*) AS qtd_ops
            FROM E900COP COP
            {where_relatorios}
              AND ISNULL(COP.RelPrd, '') <> ''
            GROUP BY
                COP.RelPrd
            ORDER BY
                COP.RelPrd DESC
        """, params_relatorios)
        relatorios_producao = rows_to_dict()

        # ============================================================
        # Produtos (lista de CodPro distintos nas OPs filtradas)
        # ============================================================

        where_produtos, params_produtos = montar_where("COP", usar_q=False)

        cursor.execute(f"""
            SELECT TOP 200
                COP.CodPro AS codigo,
                COP.CodPro AS value,
                ISNULL(MAX(PRO.DesPro), '') AS descricao,
                COP.CodPro
                    + CASE
                        WHEN ISNULL(MAX(PRO.DesPro), '') <> ''
                        THEN ' - ' + ISNULL(MAX(PRO.DesPro), '')
                        ELSE ''
                      END AS label,
                COUNT(*) AS qtd_ops
            FROM E900COP COP
            LEFT JOIN E075PRO PRO
                ON PRO.CodEmp = COP.CodEmp
               AND PRO.CodPro = COP.CodPro
            {where_produtos}
            GROUP BY
                COP.CodPro
            ORDER BY
                COP.CodPro
        """, params_produtos)
        produtos = rows_to_dict()

        # ============================================================
        # Situações (somente as não canceladas)
        # ============================================================

        where_situacoes, params_situacoes = montar_where("COP", usar_q=False)

        cursor.execute(f"""
            SELECT
                COP.SitOrp AS codigo,
                COP.SitOrp AS value,
                CASE CAST(COP.SitOrp AS VARCHAR(10))
                    WHEN 'L' THEN 'Liberada'
                    WHEN 'A' THEN 'Aberta'
                    WHEN 'F' THEN 'Finalizada'
                    WHEN 'E' THEN 'Encerrada'
                    ELSE CAST(COP.SitOrp AS VARCHAR(20))
                END AS descricao,
                COP.SitOrp + ' - ' +
                CASE CAST(COP.SitOrp AS VARCHAR(10))
                    WHEN 'L' THEN 'Liberada'
                    WHEN 'A' THEN 'Aberta'
                    WHEN 'F' THEN 'Finalizada'
                    WHEN 'E' THEN 'Encerrada'
                    ELSE CAST(COP.SitOrp AS VARCHAR(20))
                END AS label,
                COUNT(*) AS qtd_ops
            FROM E900COP COP
            {where_situacoes}
            GROUP BY
                COP.SitOrp
            ORDER BY
                COP.SitOrp
        """, params_situacoes)
        situacoes = rows_to_dict()

        # ============================================================
        # Ordens de Produção
        # ============================================================

        where_ops, params_ops = montar_where("COP", usar_q=True)

        cursor.execute(f"""
            SELECT TOP {limite_ops}
                COP.CodEmp AS cod_emp,
                COP.CodOri AS cod_ori,
                COP.NumOrp AS num_orp,

                COP.NumPed AS num_ped,
                ISNULL(COP.RelPrd, '') AS rel_prd,

                -- Campos diretos para a grid do Lovable
                COP.CodPro AS produto,
                ISNULL(PRO.DesPro, '') AS descricao,
                COP.QtdPrv AS qtde,
                ISNULL(PRO.UniMed, '') AS un,
                COP.SitOrp AS situacao,

                CASE CAST(COP.SitOrp AS VARCHAR(10))
                    WHEN 'L' THEN 'Liberada'
                    WHEN 'A' THEN 'Aberta'
                    WHEN 'F' THEN 'Finalizada'
                    WHEN 'E' THEN 'Encerrada'
                    ELSE CAST(COP.SitOrp AS VARCHAR(20))
                END AS situacao_descricao,

                -- Mantém compatibilidade com campos antigos (legado)
                COP.CodPro AS cod_pro,
                ISNULL(PRO.DesPro, '') AS des_pro,
                COP.QtdPrv AS qtd_prevista,
                ISNULL(PRO.UniMed, '') AS unidade_medida,
                COP.SitOrp AS sit_orp,

                -- Indicador de observações (botão "Ver observações" na grid)
                ISNULL(OBSINFO.qtd_observacoes, 0) AS qtd_observacoes,
                CASE
                    WHEN ISNULL(OBSINFO.qtd_observacoes, 0) > 0 THEN 'S'
                    ELSE 'N'
                END AS tem_observacao,

                COP.DatGer AS data_geracao,
                COP.DtpIni AS inicio_previsto,
                ISNULL(COP.RelPrd, '') AS agrupamento,

                CAST(COP.NumOrp AS VARCHAR(20)) AS value,

                COP.CodOri
                    + ' / OP ' + CAST(COP.NumOrp AS VARCHAR(20))
                    + CASE
                        WHEN ISNULL(COP.NumPed, 0) > 0
                        THEN ' - Pedido ' + CAST(COP.NumPed AS VARCHAR(20))
                        ELSE ''
                      END
                    + CASE
                        WHEN ISNULL(COP.RelPrd, '') <> ''
                        THEN ' - Rel. Prod. ' + ISNULL(COP.RelPrd, '')
                        ELSE ''
                      END
                    + ' - ' + COP.CodPro
                    + CASE
                        WHEN ISNULL(PRO.DesPro, '') <> ''
                        THEN ' - ' + ISNULL(PRO.DesPro, '')
                        ELSE ''
                      END AS label

            FROM E900COP COP
            LEFT JOIN E075PRO PRO
                ON PRO.CodEmp = COP.CodEmp
               AND PRO.CodPro = COP.CodPro
            OUTER APPLY (
                SELECT COUNT(*) AS qtd_observacoes
                FROM E900OBS OBS
                WHERE OBS.CodEmp = COP.CodEmp
                  AND OBS.CodOri = COP.CodOri
                  AND OBS.NumOrp = COP.NumOrp
            ) OBSINFO
            {where_ops}
            ORDER BY
                COP.DatGer DESC,
                COP.NumOrp DESC
        """, params_ops)
        ordens_producao = rows_to_dict()

        # ============================================================
        # Estágios
        # ============================================================

        where_estagios, params_estagios = montar_where("COP", usar_q=False)

        filtros_estagios_extra = ""
        if cod_cre:
            filtros_estagios_extra += " AND OOP.CodCre = ?"
            params_estagios.append(str(cod_cre).strip())

        cursor.execute(f"""
            SELECT
                OOP.CodEtg AS codigo,
                CAST(OOP.CodEtg AS VARCHAR(20)) AS value,
                'Estágio ' + CAST(OOP.CodEtg AS VARCHAR(20)) AS descricao,
                CAST(OOP.CodEtg AS VARCHAR(20)) + ' - Estágio ' + CAST(OOP.CodEtg AS VARCHAR(20)) AS label,
                COUNT(DISTINCT CAST(OOP.CodOri AS VARCHAR(10)) + '-' + CAST(OOP.NumOrp AS VARCHAR(20))) AS qtd_ops
            FROM E900OOP OOP
            INNER JOIN E900COP COP
                ON COP.CodEmp = OOP.CodEmp
               AND COP.CodOri = OOP.CodOri
               AND COP.NumOrp = OOP.NumOrp
            {where_estagios}
            {filtros_estagios_extra}
            GROUP BY
                OOP.CodEtg
            ORDER BY
                OOP.CodEtg
        """, params_estagios)
        estagios = rows_to_dict()

        # ============================================================
        # Centros de Recurso
        # ============================================================

        where_cre, params_cre = montar_where("COP", usar_q=False)

        filtros_cre_extra = ""
        if cod_etg is not None:
            filtros_cre_extra += " AND OOP.CodEtg = ?"
            params_cre.append(int(cod_etg))

        # Tenta usar E725CRE se existir. Se não existir, usa descrição da operação como apoio.
        cursor.execute("""
            SELECT CASE
                     WHEN OBJECT_ID('E725CRE', 'U') IS NOT NULL THEN 1
                     WHEN OBJECT_ID('dbo.E725CRE', 'U') IS NOT NULL THEN 1
                     ELSE 0
                   END AS existe
        """)
        usa_e725cre = bool(cursor.fetchone()[0])

        if usa_e725cre:
            sql_centros = f"""
                SELECT
                    OOP.CodCre AS codigo,
                    OOP.CodCre AS value,
                    ISNULL(MAX(CRE.DesCre), ISNULL(MAX(OPR.DesOpr), '')) AS descricao,
                    OOP.CodCre
                        + CASE
                            WHEN ISNULL(MAX(CRE.DesCre), ISNULL(MAX(OPR.DesOpr), '')) <> ''
                            THEN ' - ' + ISNULL(MAX(CRE.DesCre), ISNULL(MAX(OPR.DesOpr), ''))
                            ELSE ''
                          END AS label,
                    COUNT(DISTINCT CAST(OOP.CodOri AS VARCHAR(10)) + '-' + CAST(OOP.NumOrp AS VARCHAR(20))) AS qtd_ops
                FROM E900OOP OOP
                INNER JOIN E900COP COP
                    ON COP.CodEmp = OOP.CodEmp
                   AND COP.CodOri = OOP.CodOri
                   AND COP.NumOrp = OOP.NumOrp
                LEFT JOIN E725CRE CRE
                    ON CRE.CodEmp = OOP.CodEmp
                   AND CRE.CodCre = OOP.CodCre
                LEFT JOIN E720OPR OPR
                    ON OPR.CodEmp = OOP.CodEmp
                   AND OPR.CodOpr = OOP.CodOpr
                {where_cre}
                {filtros_cre_extra}
                GROUP BY
                    OOP.CodCre
                ORDER BY
                    OOP.CodCre
            """
        else:
            sql_centros = f"""
                SELECT
                    OOP.CodCre AS codigo,
                    OOP.CodCre AS value,
                    ISNULL(MAX(OPR.DesOpr), '') AS descricao,
                    OOP.CodCre
                        + CASE
                            WHEN ISNULL(MAX(OPR.DesOpr), '') <> ''
                            THEN ' - ' + ISNULL(MAX(OPR.DesOpr), '')
                            ELSE ''
                          END AS label,
                    COUNT(DISTINCT CAST(OOP.CodOri AS VARCHAR(10)) + '-' + CAST(OOP.NumOrp AS VARCHAR(20))) AS qtd_ops
                FROM E900OOP OOP
                INNER JOIN E900COP COP
                    ON COP.CodEmp = OOP.CodEmp
                   AND COP.CodOri = OOP.CodOri
                   AND COP.NumOrp = OOP.NumOrp
                LEFT JOIN E720OPR OPR
                    ON OPR.CodEmp = OOP.CodEmp
                   AND OPR.CodOpr = OOP.CodOpr
                {where_cre}
                {filtros_cre_extra}
                GROUP BY
                    OOP.CodCre
                ORDER BY
                    OOP.CodCre
            """

        cursor.execute(sql_centros, params_cre)
        centros_recurso = rows_to_dict()

        return {
            "empresas": empresas,
            "origens": origens,
            "pedidos": pedidos,
            "relatorios_producao": relatorios_producao,
            "produtos": produtos,
            "situacoes": situacoes,
            "ordens_producao": ordens_producao,
            "estagios": estagios,
            "centros_recurso": centros_recurso,
            "filtros_aplicados": {
                "cod_emp": cod_emp,
                "cod_ori": cod_ori,
                "num_orp": num_orp,
                "num_ped": num_ped,
                "rel_prd": rel_prd,
                "cod_pro": cod_pro,
                "sit_orp": sit_orp,
                "cod_etg": cod_etg,
                "cod_cre": cod_cre,
                "q": q,
                "limite_ops": limite_ops,
            },
        }

    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Erro ao carregar opções da impressão da OP: {str(exc)}",
        )
    finally:
        try:
            conn.close()
        except Exception:
            pass


