@app.get("/api/producao/dashboard")
def consultar_producao_dashboard(
    numero_projeto: Optional[str] = None,
    numero_desenho: Optional[str] = None,
    revisao: Optional[str] = None,
    cliente: Optional[str] = None,
    cidade: Optional[str] = None,
    usuario=Depends(validar_token),
):
    from_sql, params = _from_producao_consolidada(numero_projeto, numero_desenho, revisao, cliente, cidade)

    resumo_sql = """
        SELECT
            CAST(COALESCE(SUM(base.kg_engenharia), 0) AS FLOAT) AS kg_engenharia,
            CAST(COALESCE(SUM(base.kg_produzido), 0) AS FLOAT) AS kg_produzido,
            CAST(COALESCE(SUM(base.kg_expedido), 0) AS FLOAT) AS kg_expedido,
            CAST(COALESCE(SUM(base.kg_patio), 0) AS FLOAT) AS kg_patio,
            CAST(COALESCE(SUM(base.qtd_itens_nao_carregados), 0) AS INT) AS itens_nao_carregados,
            SUM(CASE WHEN COALESCE(base.status_fluxo, '') = 'AGUARDANDO PRODUÇÃO' THEN 1 ELSE 0 END) AS projetos_aguardando_producao,
            SUM(CASE WHEN COALESCE(base.status_fluxo, '') = 'EM PRODUÇÃO' THEN 1 ELSE 0 END) AS projetos_em_producao,
            SUM(CASE WHEN COALESCE(base.status_fluxo, '') = 'PARCIALMENTE EXPEDIDO' THEN 1 ELSE 0 END) AS projetos_parcialmente_expedidos,
            SUM(CASE WHEN COALESCE(base.status_fluxo, '') = 'EXPEDIDO' THEN 1 ELSE 0 END) AS projetos_expedidos,
            CAST(AVG(CAST(base.dias_engenharia_ate_producao AS FLOAT)) AS FLOAT) AS leadtime_medio_engenharia_producao,
            CAST(AVG(CAST(base.dias_producao_ate_expedicao AS FLOAT)) AS FLOAT) AS leadtime_medio_producao_expedicao,
            CAST(AVG(CAST(base.dias_total_ate_expedicao AS FLOAT)) AS FLOAT) AS leadtime_medio_total,
            CAST(COALESCE(SUM(CASE WHEN COALESCE(base.qtd_expedida, 0) > 0 THEN 1 ELSE 0 END), 0) AS INT) AS quantidade_cargas
    """
    resumo_lista = executar_lista(resumo_sql, from_sql, "", params)
    resumo = resumo_lista[0] if resumo_lista else {}

    top_sql = """
        SELECT TOP 10
            base.numero_projeto,
            base.numero_desenho,
            base.revisao,
            base.codigo_cliente,
            base.cliente,
            base.cidade,
            base.descricao_projeto,
            base.descricao_desenho,
            base.data_liberacao_engenharia,
            base.kg_engenharia,
            base.kg_produzido,
            base.kg_expedido,
            base.kg_patio,
            base.qtd_itens_nao_carregados,
            base.status_fluxo
    """
    top_order = "ORDER BY base.kg_patio DESC, base.numero_projeto DESC, base.numero_desenho DESC"
    top_projetos = executar_lista(top_sql, from_sql, top_order, params)

    return {
        "resumo": {
            "kg_engenharia": round(float(resumo.get("kg_engenharia") or 0), 2),
            "kg_produzido": round(float(resumo.get("kg_produzido") or 0), 2),
            "kg_expedido": round(float(resumo.get("kg_expedido") or 0), 2),
            "kg_patio": round(float(resumo.get("kg_patio") or 0), 2),
            "itens_nao_carregados": int(resumo.get("itens_nao_carregados") or 0),
            "projetos_aguardando_producao": int(resumo.get("projetos_aguardando_producao") or 0),
            "projetos_em_producao": int(resumo.get("projetos_em_producao") or 0),
            "projetos_parcialmente_expedidos": int(resumo.get("projetos_parcialmente_expedidos") or 0),
            "projetos_expedidos": int(resumo.get("projetos_expedidos") or 0),
            "leadtime_medio_engenharia_producao": round(float(resumo.get("leadtime_medio_engenharia_producao") or 0), 2),
            "leadtime_medio_producao_expedicao": round(float(resumo.get("leadtime_medio_producao_expedicao") or 0), 2),
            "leadtime_medio_total": round(float(resumo.get("leadtime_medio_total") or 0), 2),
            "quantidade_cargas": int(resumo.get("quantidade_cargas") or 0),
        },
        "top_projetos_patio": top_projetos,
        "cargas_por_mes": [],
        "observacao": "Dashboard gerencial otimizado da produção/expedição usando base consolidada com agregação SQL.",
    }


