        cursor.execute("UPDATE dbo.USU_REQ_CAB SET USU_STATUS='CANCELADA' WHERE USU_IDREQ=?", [idreq])
        _req_log_status(cursor, idreq, status_ant, 'CANCELADA', usuario,
                        body.obs if body else None)
