# --- Catálogo de itens (busca para nova requisição) ---

@app.get('/api/catalogo-itens')
def req_catalogo_itens(
    q:              Optional[str] = None,
    codpro:         Optional[str] = None,
    codfam:         Optional[str] = None,
    codori:         Optional[str] = None,
    somente_ativos: bool          = True,
    com_saldo:      bool          = False,
    limite:         int           = 50,
    usuario=Depends(validar_token),
):
    limite = max(1, min(limite, 200))
    conn = get_connection()
    cursor = conn.cursor()

    try:
        where = "WHERE P.CODEMP = ?"
        params = [EMPRESA_PADRAO]

        if somente_ativos:
            where += " AND COALESCE(P.SITPRO,'A') = 'A'"

        if q:
            where += " AND (P.CODPRO LIKE ? OR P.DESPRO LIKE ?)"
            params.extend([f"%{q.strip()}%", f"%{q.strip()}%"])

        if codpro:
            where += " AND P.CODPRO LIKE ?"
            params.append(f"%{codpro.strip()}%")

        if codfam:
            where += " AND P.CODFAM = ?"
            params.append(codfam.strip())

        if codori:
            where += " AND P.CODORI = ?"
            params.append(codori.strip())

        if com_saldo:
            where += """
                AND EXISTS (
                    SELECT 1
                    FROM E210EST E
                    WHERE E.CODEMP = P.CODEMP
                      AND E.CODPRO = P.CODPRO
                      AND COALESCE(E.QTDEST, 0) > 0
                )
            """

        sql = f"""
            SELECT TOP {limite}
                P.CODPRO AS codigo,
                P.DESPRO AS descricao,
                COALESCE(P.CODFAM,'') AS familia,
                COALESCE(P.CODORI,'') AS origem,
                COALESCE(P.UNIMED,'') AS unidade_medida,
                COALESCE(P.TIPPRO,'') AS tipo,
                COALESCE(P.SITPRO,'A') AS situacao,
                COALESCE((
                    SELECT SUM(CAST(E.QTDEST AS FLOAT))
                    FROM E210EST E
                    WHERE E.CODEMP = P.CODEMP
                      AND E.CODPRO = P.CODPRO
                ), 0.0) AS saldo_total
            FROM E075PRO P
            {where}
            ORDER BY P.CODPRO
        """

        cursor.execute(sql, params)
        rows = cursor.fetchall()
        dados = [_req_row(cursor, r) for r in rows]

        return {"total": len(dados), "dados": dados}

    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erro ao buscar catálogo: {str(e)}")
    finally:
        conn.close()


