# ============================================================
# FATURAMENTO GENIUS
# ============================================================

def _normalizar_anomes(valor: Optional[str], padrao: Optional[str] = None) -> str:
    texto = re.sub(r"\D", "", str(valor or ""))
    if len(texto) >= 6:
        return texto[:6]
    if padrao:
        return padrao
    hoje = datetime.now()
    return f"{hoje.year}{str(hoje.month).zfill(2)}"


def _rows_dict_faturamento(cursor, rows):
    cols = [col[0] for col in cursor.description]
    dados = []
    for row in rows:
        item = {}
        for i, col in enumerate(cols):
            valor = row[i]
            if isinstance(valor, str):
                valor = valor.strip()
            item[col] = valor
        dados.append(item)
    return dados


# Transações (E001TNS.CODTNS) consideradas devolução no Faturamento Genius.
# TITNOT não existe em E001TNS, então identificamos devolução pelo código da transação.
GENIUS_TNS_DEVOLUCAO = (
    '90270',
)
GENIUS_TNS_DEVOLUCAO_SQL = ", ".join(f"'{x}'" for x in GENIUS_TNS_DEVOLUCAO)

# Transações não-operacionais: zeram o valor bruto na visão canônica USU_VMBRUTANFE.
GENIUS_TNS_NAO_OPERACIONAL = (
    '5949A', '6949A',
    '5949D', '6949D',
    '5101A',
)
GENIUS_TNS_NAO_OPERACIONAL_SQL = ", ".join(f"'{x}'" for x in GENIUS_TNS_NAO_OPERACIONAL)

# Transações que zeram impostos na visão canônica (não-operacional + bonificações/garantias/outros).
GENIUS_TNS_IMPOSTO_ZERO = (
    '5949A', '6949A',
    '5949D', '6949D',
    '5101A',
    '5949G', '6949G',
    '5949N', '6949N',
    '5949O', '6949O',
)
GENIUS_TNS_IMPOSTO_ZERO_SQL = ", ".join(f"'{x}'" for x in GENIUS_TNS_IMPOSTO_ZERO)

# Naturezas de operação (NATOPE) de remessa que também zeram impostos.
GENIUS_NATOPE_REMESSA = (
    '5910', '6910',
    '5912', '6912',
)
GENIUS_NATOPE_REMESSA_SQL = ", ".join(f"'{x}'" for x in GENIUS_NATOPE_REMESSA)


def _fg_from_join() -> str:
    """
    FROM/JOIN do Faturamento Genius usando tabelas nativas do ERP Senior.

    Tabelas:
        NFV = E140NFV — cabeçalho da nota fiscal de saída
        IPV = E140IPV — itens da nota fiscal de saída
        TNS = E001TNS — transação (devolução por TNSPRO; natureza via COMNAT)
        PRO = E075PRO — cadastro de produto (família via CODFAM)
        DER = E075DER — derivação (custo via PREMED)
        IPD = E120IPD — item do pedido (revenda via USU_REVPED)
        CLI = E085CLI — cadastro de cliente
    """
    return """
        FROM dbo.E140NFV NFV
        INNER JOIN dbo.E140IPV IPV
            ON  IPV.CODEMP = NFV.CODEMP
            AND IPV.CODFIL = NFV.CODFIL
            AND IPV.CODSNF = NFV.CODSNF
            AND IPV.NUMNFV = NFV.NUMNFV
        INNER JOIN dbo.E001TNS TNS
            ON  TNS.CODEMP = IPV.CODEMP
            AND TNS.CODTNS = IPV.TNSPRO
        INNER JOIN dbo.E075PRO PRO
            ON  PRO.CODEMP = IPV.CODEMP
            AND PRO.CODPRO = IPV.CODPRO
        LEFT JOIN dbo.E075DER DER
            ON  DER.CODEMP = IPV.CODEMP
            AND DER.CODPRO = IPV.CODPRO
            AND COALESCE(DER.CODDER, '') = COALESCE(IPV.CODDER, '')
        LEFT JOIN dbo.E120IPD IPD
            ON  IPD.CODEMP = IPV.CODEMP
            AND IPD.CODFIL = IPV.FILPED
            AND IPD.NUMPED = IPV.NUMPED
            AND IPD.SEQIPD = IPV.SEQIPD
        LEFT JOIN dbo.E085CLI CLI
            ON  CLI.CODCLI = NFV.CODCLI
    """


def _where_faturamento_genius(
    anomes_ini: Optional[str] = None,
    anomes_fim: Optional[str] = None,
    revenda: Optional[str] = None,
    origem: Optional[str] = None,
    tipo_movimento: str = "TODOS",
    cliente: Optional[str] = None,
    representante: Optional[str] = None,
    produto: Optional[str] = None,
    pedido: Optional[str] = None,
    nf: Optional[str] = None,
    somente_com_revenda: bool = False,
):
    """
    Monta o WHERE para consultas do Faturamento Genius nas tabelas nativas
    (E140NFV / E140IPV / E001TNS / E075PRO / E120IPD).
    """
    hoje = datetime.now()
    anomes_padrao = f"{hoje.year}{str(hoje.month).zfill(2)}"

    anomes_ini = _normalizar_anomes(anomes_ini, anomes_padrao)
    anomes_fim = _normalizar_anomes(anomes_fim, anomes_ini)

    where = f"""
        WHERE NFV.CODEMP = ?
          AND COALESCE(NFV.SITNFV, '') <> '3'
          AND FORMAT(NFV.DATEMI, 'yyyyMM') BETWEEN ? AND ?
          AND (
                TNS.VENFAT = 'S'
                OR IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL})
              )
    """
    params = [EMPRESA_PADRAO, anomes_ini, anomes_fim]

    revenda       = (revenda       or "").strip()
    origem        = (origem        or "").strip()
    tipo_movimento = (tipo_movimento or "TODOS").strip().upper()
    cliente       = (cliente       or "").strip()
    representante = (representante or "").strip()
    produto       = (produto       or "").strip()
    pedido        = (pedido        or "").strip()
    nf            = (nf            or "").strip()

    if revenda:
        where += " AND COALESCE(NULLIF(LTRIM(RTRIM(IPD.USU_REVPED)), ''), 'OUTROS') LIKE ?"
        params.append(f"%{revenda}%")
    if origem:
        where += " AND COALESCE(PRO.CODFAM, '') LIKE ?"
        params.append(f"%{origem}%")

    if cliente:
        where += " AND CAST(NFV.CODCLI AS VARCHAR) LIKE ?"
        params.append(f"%{cliente}%")

    if representante:
        where += " AND CAST(NFV.CODREP AS VARCHAR) LIKE ?"
        params.append(f"%{representante}%")

    if produto:
        where += " AND IPV.CODPRO LIKE ?"
        params.append(f"%{produto}%")

    if pedido:
        where += " AND CAST(IPV.NUMPED AS VARCHAR) LIKE ?"
        params.append(f"%{pedido}%")

    if nf:
        where += " AND CAST(NFV.NUMNFV AS VARCHAR) LIKE ?"
        params.append(f"%{nf}%")

    if somente_com_revenda:
        where += " AND COALESCE(NULLIF(LTRIM(RTRIM(IPD.USU_REVPED)), ''), 'OUTROS') NOT IN ('OUTROS', 'LANCTO MANUAL')"

    return where, params, anomes_ini, anomes_fim


@app.get("/api/faturamento-genius-dashboard")
def consultar_faturamento_genius_dashboard(
    anomes_ini: Optional[str] = None,
    anomes_fim: Optional[str] = None,
    revenda: Optional[str] = None,
    origem: Optional[str] = None,
    tipo_movimento: str = "TODOS",
    cliente: Optional[str] = None,
    representante: Optional[str] = None,
    produto: Optional[str] = None,
    pedido: Optional[str] = None,
    nf: Optional[str] = None,
    somente_com_revenda: bool = False,
    usuario=Depends(validar_token),
):
    where_sql, params, anomes_ini, anomes_fim = _where_faturamento_genius(
        anomes_ini=anomes_ini,
        anomes_fim=anomes_fim,
        revenda=revenda,
        origem=origem,
        tipo_movimento=tipo_movimento,
        cliente=cliente,
        representante=representante,
        produto=produto,
        pedido=pedido,
        nf=nf,
        somente_com_revenda=somente_com_revenda,
    )

    fg_join = _fg_from_join()

    conn = get_connection()
    cursor = conn.cursor()

    try:
        sql_kpis = f"""
            SELECT
                COUNT(*) AS quantidade_linhas,
                COUNT(DISTINCT NFV.NUMNFV) AS quantidade_notas,
                COUNT(DISTINCT IPV.NUMPED) AS quantidade_pedidos,
                COUNT(DISTINCT COALESCE(CLI.CGCCPF, CAST(NFV.CODCLI AS VARCHAR(30)))) AS quantidade_clientes,
                COUNT(DISTINCT IPD.USU_REVPED) AS quantidade_revendas,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) OR IPV.TNSPRO IN ({GENIUS_TNS_NAO_OPERACIONAL_SQL}) THEN 0 ELSE COALESCE(IPV.VLRBRU, 0) END) AS FLOAT) AS valor_bruto,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END) AS FLOAT) AS valor_total,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN COALESCE(IPV.VLRLIQ, 0) ELSE 0 END) AS FLOAT) AS valor_devolucao,
                CAST(SUM(COALESCE(DER.PREMED, 0) * COALESCE(IPV.QTDFAT, 0) * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END) AS FLOAT) AS valor_custo,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 0 ELSE COALESCE(IPV.VLRCOM, 0) END) AS FLOAT) AS valor_comissao,
                CAST(SUM(COALESCE(IPV.QTDFAT, 0) * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END) AS FLOAT) AS quantidade_produtos,
                CAST(SUM(
                    CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_IMPOSTO_ZERO_SQL}) THEN 0
                         ELSE (COALESCE(IPV.VLRICM, 0) + COALESCE(IPV.VLRIPI, 0) + COALESCE(IPV.VLRPIS, 0) + COALESCE(IPV.VLRCOR, 0))
                    END
                    * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END
                ) AS FLOAT) AS valor_impostos,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 0 ELSE COALESCE(IPV.VLRDSC, 0) END) AS FLOAT) AS valor_desconto
            {fg_join}
            {where_sql}
        """
        cursor.execute(sql_kpis, params)
        row = cursor.fetchone()

        valor_total = float(row[6] or 0)
        valor_custo = float(row[8] or 0)
        valor_impostos = float(row[11] or 0)
        valor_desconto = float(row[12] or 0)
        valor_liquido = valor_total - valor_impostos - valor_desconto
        margem_bruta = valor_total - valor_custo
        margem_percentual = (margem_bruta / valor_total * 100) if valor_total else 0

        kpis = {
            "quantidade_linhas": int(row[0] or 0),
            "quantidade_notas": int(row[1] or 0),
            "quantidade_pedidos": int(row[2] or 0),
            "quantidade_clientes": int(row[3] or 0),
            "quantidade_revendas": int(row[4] or 0),
            "valor_bruto": float(row[5] or 0),
            "valor_total": valor_total,
            "valor_devolucao": float(row[7] or 0),
            "valor_custo": valor_custo,
            "valor_comissao": float(row[9] or 0),
            "quantidade_produtos": float(row[10] or 0),
            "valor_impostos": valor_impostos,
            "valor_desconto": valor_desconto,
            "valor_liquido": valor_liquido,
            "margem_bruta": margem_bruta,
            "margem_percentual": margem_percentual,
        }

        sql_revendas = f"""
            SELECT TOP 100
                COALESCE(NULLIF(LTRIM(RTRIM(IPD.USU_REVPED)), ''), 'OUTROS') AS revenda,
                COUNT(DISTINCT NFV.NUMNFV) AS quantidade_notas,
                COUNT(DISTINCT COALESCE(CLI.CGCCPF, CAST(NFV.CODCLI AS VARCHAR(30)))) AS quantidade_clientes,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) OR IPV.TNSPRO IN ({GENIUS_TNS_NAO_OPERACIONAL_SQL}) THEN 0 ELSE COALESCE(IPV.VLRBRU, 0) END) AS FLOAT) AS valor_bruto,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END) AS FLOAT) AS valor_total,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN COALESCE(IPV.VLRLIQ, 0) ELSE 0 END) AS FLOAT) AS valor_devolucao,
                CAST(SUM(COALESCE(DER.PREMED, 0) * COALESCE(IPV.QTDFAT, 0) * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END) AS FLOAT) AS valor_custo,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 0 ELSE COALESCE(IPV.VLRCOM, 0) END) AS FLOAT) AS valor_comissao,
                CAST(SUM(COALESCE(IPV.QTDFAT, 0) * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END) AS FLOAT) AS quantidade_produtos,
                CAST(SUM(
                    CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_IMPOSTO_ZERO_SQL}) THEN 0
                         ELSE (COALESCE(IPV.VLRICM, 0) + COALESCE(IPV.VLRIPI, 0) + COALESCE(IPV.VLRPIS, 0) + COALESCE(IPV.VLRCOR, 0))
                    END
                    * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END
                ) AS FLOAT) AS valor_impostos,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 0 ELSE COALESCE(IPV.VLRDSC, 0) END) AS FLOAT) AS valor_desconto,
                CAST(
                    SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END)
                    - SUM(
                        CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_IMPOSTO_ZERO_SQL}) THEN 0
                             ELSE (COALESCE(IPV.VLRICM, 0) + COALESCE(IPV.VLRIPI, 0) + COALESCE(IPV.VLRPIS, 0) + COALESCE(IPV.VLRCOR, 0))
                        END
                        * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END
                    )
                    - SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 0 ELSE COALESCE(IPV.VLRDSC, 0) END)
                AS FLOAT) AS valor_liquido
            {fg_join}
            {where_sql}
            GROUP BY COALESCE(NULLIF(LTRIM(RTRIM(IPD.USU_REVPED)), ''), 'OUTROS')
            ORDER BY SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END) DESC
        """
        cursor.execute(sql_revendas, params)
        por_revenda = _rows_dict_faturamento(cursor, cursor.fetchall())

        sql_origens = f"""
            SELECT
                COALESCE(NULLIF(LTRIM(RTRIM(PRO.CODFAM)), ''), 'SEM_ORIGEM') AS origem,
                COUNT(DISTINCT NFV.NUMNFV) AS quantidade_notas,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END) AS FLOAT) AS valor_total,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN COALESCE(IPV.VLRLIQ, 0) ELSE 0 END) AS FLOAT) AS valor_devolucao,
                CAST(SUM(COALESCE(DER.PREMED, 0) * COALESCE(IPV.QTDFAT, 0) * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END) AS FLOAT) AS valor_custo,
                CAST(SUM(
                    CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_IMPOSTO_ZERO_SQL}) THEN 0
                         ELSE (COALESCE(IPV.VLRICM, 0) + COALESCE(IPV.VLRIPI, 0) + COALESCE(IPV.VLRPIS, 0) + COALESCE(IPV.VLRCOR, 0))
                    END
                    * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END
                ) AS FLOAT) AS valor_impostos,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 0 ELSE COALESCE(IPV.VLRDSC, 0) END) AS FLOAT) AS valor_desconto,
                CAST(
                    SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END)
                    - SUM(
                        CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_IMPOSTO_ZERO_SQL}) THEN 0
                             ELSE (COALESCE(IPV.VLRICM, 0) + COALESCE(IPV.VLRIPI, 0) + COALESCE(IPV.VLRPIS, 0) + COALESCE(IPV.VLRCOR, 0))
                        END
                        * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END
                    )
                    - SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 0 ELSE COALESCE(IPV.VLRDSC, 0) END)
                AS FLOAT) AS valor_liquido
            {fg_join}
            {where_sql}
            GROUP BY COALESCE(NULLIF(LTRIM(RTRIM(PRO.CODFAM)), ''), 'SEM_ORIGEM')
            ORDER BY SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END) DESC
        """
        cursor.execute(sql_origens, params)
        por_origem = _rows_dict_faturamento(cursor, cursor.fetchall())

        sql_meses = f"""
            SELECT
                FORMAT(NFV.DATEMI, 'yyyyMM') AS anomes,
                COUNT(DISTINCT NFV.NUMNFV) AS quantidade_notas,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END) AS FLOAT) AS valor_total,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN COALESCE(IPV.VLRLIQ, 0) ELSE 0 END) AS FLOAT) AS valor_devolucao,
                CAST(SUM(COALESCE(DER.PREMED, 0) * COALESCE(IPV.QTDFAT, 0) * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END) AS FLOAT) AS valor_custo,
                CAST(SUM(
                    CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_IMPOSTO_ZERO_SQL}) THEN 0
                         ELSE (COALESCE(IPV.VLRICM, 0) + COALESCE(IPV.VLRIPI, 0) + COALESCE(IPV.VLRPIS, 0) + COALESCE(IPV.VLRCOR, 0))
                    END
                    * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END
                ) AS FLOAT) AS valor_impostos,
                CAST(SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 0 ELSE COALESCE(IPV.VLRDSC, 0) END) AS FLOAT) AS valor_desconto,
                CAST(
                    SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END)
                    - SUM(
                        CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_IMPOSTO_ZERO_SQL}) THEN 0
                             ELSE (COALESCE(IPV.VLRICM, 0) + COALESCE(IPV.VLRIPI, 0) + COALESCE(IPV.VLRPIS, 0) + COALESCE(IPV.VLRCOR, 0))
                        END
                        * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END
                    )
                    - SUM(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 0 ELSE COALESCE(IPV.VLRDSC, 0) END)
                AS FLOAT) AS valor_liquido
            {fg_join}
            {where_sql}
            GROUP BY FORMAT(NFV.DATEMI, 'yyyyMM')
            ORDER BY FORMAT(NFV.DATEMI, 'yyyyMM')
        """
        cursor.execute(sql_meses, params)
        por_mes = _rows_dict_faturamento(cursor, cursor.fetchall())

    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erro SQL em Faturamento Genius Dashboard: {str(e)}")
    finally:
        conn.close()

    return {
        "periodo": {
            "anomes_ini": anomes_ini,
            "anomes_fim": anomes_fim,
        },
        "kpis": kpis,
        "por_revenda": por_revenda,
        "por_origem": por_origem,
        "por_mes": por_mes,
        "observacao": "Faturamento lido das tabelas E140NFV/E140IPV/E120IPD do ERP Senior. Revenda via E120IPD.USU_REVPED.",
    }


@app.get("/api/faturamento-genius")
def consultar_faturamento_genius(
    anomes_ini: Optional[str] = None,
    anomes_fim: Optional[str] = None,
    revenda: Optional[str] = None,
    origem: Optional[str] = None,
    tipo_movimento: str = "TODOS",
    cliente: Optional[str] = None,
    representante: Optional[str] = None,
    produto: Optional[str] = None,
    pedido: Optional[str] = None,
    nf: Optional[str] = None,
    somente_com_revenda: bool = False,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token),
):
    if pagina < 1:
        pagina = 1
    if tamanho_pagina < 1:
        tamanho_pagina = 100
    if tamanho_pagina > 500:
        tamanho_pagina = 500

    offset = (pagina - 1) * tamanho_pagina

    where_sql, params, anomes_ini, anomes_fim = _where_faturamento_genius(
        anomes_ini=anomes_ini,
        anomes_fim=anomes_fim,
        revenda=revenda,
        origem=origem,
        tipo_movimento=tipo_movimento,
        cliente=cliente,
        representante=representante,
        produto=produto,
        pedido=pedido,
        nf=nf,
        somente_com_revenda=somente_com_revenda,
    )

    fg_join = _fg_from_join()

    conn = get_connection()
    cursor = conn.cursor()

    try:
        sql_total = f"""
            SELECT COUNT(*)
            {fg_join}
            {where_sql}
        """
        cursor.execute(sql_total, params)
        total_registros = int(cursor.fetchone()[0] or 0)

        sql_dados = f"""
            SELECT
                CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN 'DEVOLUCAO' ELSE 'VENDA' END AS tipo_movimento,
                COALESCE(PRO.CODFAM, '')                                          AS origem,
                NFV.CODEMP                                                        AS empresa,
                NFV.CODFIL                                                        AS filial,
                CAST(NFV.NUMNFV AS VARCHAR(30))                                   AS id_nf,
                CAST(NFV.NUMNFV AS VARCHAR(30))                                   AS numero_nf,
                COALESCE(NFV.CODSNF, '')                                          AS serie_nf,
                NFV.DATEMI                                                        AS data_emissao,
                FORMAT(NFV.DATEMI, 'yyyyMM')                                      AS anomes_emissao,
                COALESCE(NULLIF(LTRIM(RTRIM(IPD.USU_REVPED)), ''), 'OUTROS')      AS revenda,
                CAST(COALESCE(NFV.CODREP, 0) AS VARCHAR(30))                      AS representante,
                CAST('' AS VARCHAR(30))                                           AS grupo_cliente,
                CAST(NFV.CODCLI AS VARCHAR(30))                                   AS cliente,
                COALESCE(CLI.SIGUFS, '')                                          AS estado,
                COALESCE(CLI.CIDCLI, '')                                          AS cidade,
                COALESCE(IPV.TNSPRO, '')                                          AS transacao,
                COALESCE(TNS.COMNAT, '')                                          AS natureza,
                ''                                                                AS centro_custos,
                ''                                                                AS centro_custos_3,
                ''                                                                AS projeto,
                ''                                                                AS descricao_projeto,
                CAST(COALESCE(IPV.NUMPED, 0) AS VARCHAR(30))                      AS pedido,
                COALESCE(PRO.CODFAM, '')                                          AS familia,
                ''                                                                AS agrupamento,
                IPV.CODPRO                                                        AS produto,
                COALESCE(IPV.CODDER, '')                                          AS derivacao,
                COALESCE(IPV.UNIMED, '')                                          AS unidade_medida,
                CAST(COALESCE(IPV.QTDFAT, 0) * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END AS FLOAT) AS quantidade,
                CAST(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) OR IPV.TNSPRO IN ({GENIUS_TNS_NAO_OPERACIONAL_SQL}) THEN 0 ELSE COALESCE(IPV.VLRBRU, 0) END AS FLOAT) AS valor_bruto,
                CAST(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -COALESCE(IPV.VLRLIQ, 0) ELSE COALESCE(IPV.VLRLIQ, 0) END AS FLOAT) AS valor_total,
                CAST(CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN COALESCE(IPV.VLRLIQ, 0) ELSE 0 END AS FLOAT) AS valor_devolucao,
                CAST(COALESCE(DER.PREMED, 0) * COALESCE(IPV.QTDFAT, 0) * CASE WHEN IPV.TNSPRO IN ({GENIUS_TNS_DEVOLUCAO_SQL}) THEN -1 ELSE 1 END AS FLOAT) AS valor_custo,
                CAST(COALESCE(IPV.VLRCOM, 0) AS FLOAT)                            AS valor_comissao,
                CAST(COALESCE(IPV.VLRDSC, 0) AS FLOAT)                            AS valor_desconto,
                CAST(COALESCE(IPV.VLRICM, 0) AS FLOAT)                            AS valor_icms,
                CAST(COALESCE(IPV.VLRIPI, 0) AS FLOAT)                            AS valor_ipi,
                CAST(COALESCE(IPV.VLRPIS, 0) AS FLOAT)                            AS valor_pis,
                CAST(COALESCE(IPV.VLRCOR, 0) AS FLOAT)                            AS valor_cofins,
                CAST(0 AS FLOAT)                                                  AS valor_frete
            {fg_join}
            {where_sql}
            ORDER BY
                NFV.DATEMI DESC,
                IPD.USU_REVPED,
                NFV.NUMNFV,
                IPV.CODPRO
            OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
        """

        cursor.execute(sql_dados, params + [offset, tamanho_pagina])
        dados = _rows_dict_faturamento(cursor, cursor.fetchall())

    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erro SQL em Faturamento Genius: {str(e)}")
    finally:
        conn.close()

    total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros > 0 else 1

    return {
        "pagina": pagina,
        "tamanho_pagina": tamanho_pagina,
        "total_registros": total_registros,
        "total_paginas": total_paginas,
        "dados": dados,
    }


@app.post("/api/faturamento-genius/atualizar")
def atualizar_faturamento_genius(
    anomes_ini: str = Body(..., embed=True),
    anomes_fim: str = Body(..., embed=True),
    usuario=Depends(validar_token),
):
    """
    Atualização automática desabilitada neste ambiente.
    O relatório lê diretamente a view USU_VMBRUTANFE do ERP (somente leitura).
    Para habilitar, configure OBJ_V_FATURAMENTO_META e PROC_ATU_COMERCIAL
    com os objetos corretos do seu ambiente.
    """
    anomes_ini = _normalizar_anomes(anomes_ini)
    anomes_fim = _normalizar_anomes(anomes_fim, anomes_ini)
    return {
        "mensagem": (
            "Atualizacao automatica nao aplicada neste ambiente. "
            "O relatorio le diretamente a view USU_VMBRUTANFE do ERP."
        ),
        "anomes_ini": anomes_ini,
        "anomes_fim": anomes_fim,
        "usuario": usuario,
    }


