@app.post("/api/sgu/usuarios/comparar")
def comparar_usuarios_sgu(
    body: SGUPreviewCamposPayload,
    usuario=Depends(validar_token),
):
    usuario_api = _normalizar_usuario_api_sgu(usuario)
    _somente_admin_sgu(usuario_api)

    tabelas = [_validar_tabela_sgu(t) for t in (body.tabelas or SGU_TABELAS_PARAMETROS)]

    conn = get_connection()
    try:
        cursor = conn.cursor()

        origem = _validar_usuario_sgu(cursor, body.usuario_origem)
        destino = _validar_usuario_sgu(cursor, body.usuario_destino)
        if not origem["valido"]:
            raise HTTPException(status_code=400, detail="Usuário origem não localizado em R910USU/R999USU.")
        if not destino["valido"]:
            raise HTTPException(status_code=400, detail="Usuário destino não localizado em R910USU/R999USU.")

        comparacao = []
        for tabela in tabelas:
            cursor.execute(f"""
                SELECT
                    SUM(CASE WHEN CODUSU = ? THEN 1 ELSE 0 END) AS qtd_origem,
                    SUM(CASE WHEN CODUSU = ? THEN 1 ELSE 0 END) AS qtd_destino
                FROM dbo.{tabela}
                WHERE CODUSU IN (?, ?)
            """, [body.usuario_origem, body.usuario_destino,
                  body.usuario_origem, body.usuario_destino])
            row = cursor.fetchone()
            comparacao.append({
                "tabela": tabela,
                "qtd_origem": int(row[0] or 0),
                "qtd_destino": int(row[1] or 0),
            })

        return {
            "usuario_origem": origem,
            "usuario_destino": destino,
            "comparacao": comparacao,
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.post("/api/sgu/usuarios/duplicar-preview-campos")
def duplicar_preview_campos_sgu(
    body: SGUPreviewCamposPayload,
    request: Request,
    usuario=Depends(validar_token),
):
    """Diff campo a campo entre origem e destino. Não altera nada — só
    registra evento de PREVIEW na auditoria com o resumo do diff."""
    usuario_api = _normalizar_usuario_api_sgu(usuario)
    _somente_admin_sgu(usuario_api)

    ip = request.client.host if request.client else None
    tabelas = [_validar_tabela_sgu(t) for t in (body.tabelas or SGU_TABELAS_PARAMETROS)]

    conn = get_connection()
    cursor = conn.cursor()
    try:
        origem = _validar_usuario_sgu(cursor, body.usuario_origem)
        destino = _validar_usuario_sgu(cursor, body.usuario_destino)
        if not origem["valido"]:
            raise HTTPException(status_code=400, detail="Usuário origem não localizado em R910USU/R999USU.")
        if not destino["valido"]:
            raise HTTPException(status_code=400, detail="Usuário destino não localizado em R910USU/R999USU.")

        diferencas: list = []
        resumo_tabelas: list = []

        for tabela in tabelas:
            columns = _get_columns_sgu(cursor, tabela)
            if "codusu" not in columns or "codemp" not in columns:
                continue

            cursor.execute(
                f"SELECT * FROM dbo.{tabela} WHERE CODUSU = ? ORDER BY CODEMP",
                [body.usuario_origem],
            )
            origem_rows = _rows_to_dict_sgu(cursor, cursor.fetchall())

            cursor.execute(
                f"SELECT * FROM dbo.{tabela} WHERE CODUSU = ? ORDER BY CODEMP",
                [body.usuario_destino],
            )
            destino_rows = _rows_to_dict_sgu(cursor, cursor.fetchall())

            destino_por_empresa = {
                int(row.get("codemp")): row
                for row in destino_rows
                if row.get("codemp") is not None
            }

            qtd_dif_tabela = 0
            for row_origem in origem_rows:
                codemp = int(row_origem.get("codemp"))
                row_destino = destino_por_empresa.get(codemp)

                if not row_destino:
                    diferencas.append({
                        "tabela": tabela,
                        "codemp": codemp,
                        "campo": "*REGISTRO*",
                        "valor_origem": "EXISTE",
                        "valor_destino": "NAO_EXISTE",
                        "acao_planejada": "INSERIR",
                        "motivo": "Destino não possui registro para a empresa.",
                    })
                    qtd_dif_tabela += 1
                    continue

                for campo in columns:
                    campo_lower = campo.lower()
                    if campo_lower in SGU_CAMPOS_CHAVE_PADRAO:
                        continue

                    valor_origem = row_origem.get(campo_lower)
                    valor_destino = row_destino.get(campo_lower)

                    if str(valor_origem or "").strip() == str(valor_destino or "").strip():
                        if body.mostrar_campos_iguais:
                            diferencas.append({
                                "tabela": tabela,
                                "codemp": codemp,
                                "campo": campo_lower.upper(),
                                "valor_origem": valor_origem,
                                "valor_destino": valor_destino,
                                "acao_planejada": "MANTER",
                                "motivo": "Valores iguais.",
                            })
                        continue

                    if tabela == "E099USU" and campo_lower in SGU_CAMPOS_PRESERVAR_E099USU:
                        diferencas.append({
                            "tabela": tabela,
                            "codemp": codemp,
                            "campo": campo_lower.upper(),
                            "valor_origem": valor_origem,
                            "valor_destino": valor_destino,
                            "acao_planejada": "MANTER",
                            "motivo": "Campo preservado do usuário destino.",
                        })
                        continue

                    diferencas.append({
                        "tabela": tabela,
                        "codemp": codemp,
                        "campo": campo_lower.upper(),
                        "valor_origem": valor_origem,
                        "valor_destino": valor_destino,
                        "acao_planejada": "ALTERAR",
                        "motivo": "Campo diferente entre origem e destino.",
                    })
                    qtd_dif_tabela += 1

            resumo_tabelas.append({
                "tabela": tabela,
                "registros_origem": len(origem_rows),
                "registros_destino": len(destino_rows),
                "diferencas_alteraveis": qtd_dif_tabela,
            })

        resultado = {
            "usuario_origem": origem,
            "usuario_destino": destino,
            "total_diferencas": len(diferencas),
            "resumo_tabelas": resumo_tabelas,
            "diferencas": diferencas,
        }

        _registrar_log_sgu(
            cursor=cursor,
            usuario_api=usuario_api,
            acao="DUPLICAR_PREVIEW_CAMPOS",
            usuario_origem=body.usuario_origem,
            usuario_destino=body.usuario_destino,
            detalhe=body.model_dump(),
            resultado={
                "total_diferencas": len(diferencas),
                "resumo_tabelas": resumo_tabelas,
            },
            ip=ip,
        )
        conn.commit()

        return resultado

    except HTTPException:
        try:
            conn.rollback()
        except Exception:
            pass
        raise
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        raise HTTPException(status_code=500, detail=f"Erro no preview SGU por campo: {str(e)}")
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.post("/api/sgu/usuarios/duplicar-parametros")
def duplicar_parametros_sgu(
    body: SGUDuplicarParametrosPayload,
    request: Request,
    usuario=Depends(validar_token),
):
    """Aplica a duplicação de parâmetros em transação única.
    Pré-requisitos: confirmar=True + motivo não-vazio + ambos usuários
    válidos. Para cada tabela: snapshot do destino em USU_BKP_SGU_PARAM,
    UPDATE dos campos não-chave/não-preservados, INSERT quando o destino
    não tinha registro para a empresa. Em E099USU, campos cadastrais e
    de bloqueio em SGU_CAMPOS_PRESERVAR_E099USU NÃO são alterados."""
    usuario_api = _normalizar_usuario_api_sgu(usuario)
    _somente_admin_sgu(usuario_api)

    ip = request.client.host if request.client else None

    if not body.confirmar:
        raise HTTPException(
            status_code=400,
            detail="Confirmação obrigatória. Envie confirmar=true somente após validar o preview.",
        )

    motivo = (body.motivo or "").strip()
    if not motivo:
        raise HTTPException(status_code=400, detail="Informe o motivo da duplicação.")

    tabelas = [_validar_tabela_sgu(t) for t in (body.tabelas or SGU_TABELAS_PARAMETROS)]

    conn = get_connection()
    cursor = conn.cursor()
    try:
        origem = _validar_usuario_sgu(cursor, body.usuario_origem)
        destino = _validar_usuario_sgu(cursor, body.usuario_destino)
        if not origem["valido"]:
            raise HTTPException(status_code=400, detail="Usuário origem não localizado em R910USU/R999USU.")
        if not destino["valido"]:
            raise HTTPException(status_code=400, detail="Usuário destino não localizado em R910USU/R999USU.")

        resultado_tabelas: list = []

        for tabela in tabelas:
            columns = _get_columns_sgu(cursor, tabela)
            if "codusu" not in columns or "codemp" not in columns:
                continue

            # snapshot do destino antes de mexer
            cursor.execute(
                f"SELECT * FROM dbo.{tabela} WHERE CODUSU = ?",
                [body.usuario_destino],
            )
            dados_destino_atuais = _rows_to_dict_sgu(cursor, cursor.fetchall())

            cursor.execute("""
                INSERT INTO dbo.USU_BKP_SGU_PARAM
                    (USUARIO_API, USUARIO_ORIGEM, USUARIO_DESTINO,
                     TABELA, CODEMP, DADOS_JSON, MOTIVO)
                VALUES (?, ?, ?, ?, NULL, ?, ?)
            """, [
                usuario_api,
                body.usuario_origem,
                body.usuario_destino,
                tabela,
                json.dumps(dados_destino_atuais, ensure_ascii=False, default=str),
                motivo,
            ])

            cursor.execute(
                f"SELECT * FROM dbo.{tabela} WHERE CODUSU = ? ORDER BY CODEMP",
                [body.usuario_origem],
            )
            origem_rows = _rows_to_dict_sgu(cursor, cursor.fetchall())

            atualizados = 0
            inseridos = 0

            # Define quais campos podem ser sobrescritos
            if tabela == "E099USU":
                campos_copiaveis = [
                    c for c in columns
                    if c not in SGU_CAMPOS_CHAVE_PADRAO
                    and c not in SGU_CAMPOS_PRESERVAR_E099USU
                ]
            else:
                campos_copiaveis = [c for c in columns if c not in SGU_CAMPOS_CHAVE_PADRAO]

            for row_origem in origem_rows:
                codemp = row_origem.get("codemp")

                cursor.execute(
                    f"SELECT COUNT(*) FROM dbo.{tabela} WHERE CODUSU = ? AND CODEMP = ?",
                    [body.usuario_destino, codemp],
                )
                existe_destino = int(cursor.fetchone()[0] or 0) > 0

                if existe_destino and campos_copiaveis:
                    sets = ", ".join(f"{c.upper()} = ?" for c in campos_copiaveis)
                    params_upd = [row_origem.get(c) for c in campos_copiaveis]
                    params_upd.extend([body.usuario_destino, codemp])
                    cursor.execute(
                        f"UPDATE dbo.{tabela} SET {sets} WHERE CODUSU = ? AND CODEMP = ?",
                        params_upd,
                    )
                    atualizados += cursor.rowcount or 0
                elif not existe_destino:
                    valores: list = []
                    for c in columns:
                        if c == "codusu":
                            valores.append(body.usuario_destino)
                        else:
                            valores.append(row_origem.get(c))
                    campos_sql = ", ".join(c.upper() for c in columns)
                    placeholders = ", ".join("?" for _ in columns)
                    cursor.execute(
                        f"INSERT INTO dbo.{tabela} ({campos_sql}) VALUES ({placeholders})",
                        valores,
                    )
                    inseridos += cursor.rowcount or 0

            resultado_tabelas.append({
                "tabela": tabela,
                "registros_origem": len(origem_rows),
                "atualizados": atualizados,
                "inseridos": inseridos,
            })

        _registrar_log_sgu(
            cursor=cursor,
            usuario_api=usuario_api,
            acao="DUPLICAR_PARAMETROS_APLICADO",
            usuario_origem=body.usuario_origem,
            usuario_destino=body.usuario_destino,
            detalhe=body.model_dump(),
            resultado=resultado_tabelas,
            ip=ip,
        )
        conn.commit()

        return {
            "mensagem": "Parâmetros SGU duplicados com sucesso.",
            "usuario_origem": origem,
            "usuario_destino": destino,
            "resultado_tabelas": resultado_tabelas,
        }

    except HTTPException:
        try:
            conn.rollback()
        except Exception:
            pass
        raise
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        # Best-effort: registra a falha em log separado (fora da transação)
        try:
            conn2 = get_connection()
            try:
                cur2 = conn2.cursor()
                _registrar_log_sgu(
                    cursor=cur2,
                    usuario_api=usuario_api,
                    acao="DUPLICAR_PARAMETROS_ERRO",
                    usuario_origem=body.usuario_origem,
                    usuario_destino=body.usuario_destino,
                    detalhe=body.model_dump(),
                    resultado={"erro": str(e)[:900]},
                    ip=ip,
                )
                conn2.commit()
            finally:
                conn2.close()
        except Exception:
            pass
        raise HTTPException(status_code=500, detail=f"Erro ao duplicar parâmetros SGU: {str(e)}")
    finally:
        try:
            conn.close()
        except Exception:
            pass


class SGURestaurarBackupPayload(BaseModel):
    motivo: str
    confirmar: bool = False
    remover_extras: bool = False   # se True, DELETE rows que não estão no snapshot
                                    # (revert completo); se False, só UPDATE/INSERT (aditivo)


@app.get("/api/sgu/usuarios/backups")
def listar_backups_sgu(
    usuario_destino: Optional[int] = None,
    tabela: Optional[str] = None,
    data_ini: Optional[str] = None,
    data_fim: Optional[str] = None,
    pagina: int = 1,
    tamanho_pagina: int = 50,
    usuario=Depends(validar_token),
):
    """Lista entradas em USU_BKP_SGU_PARAM com filtros opcionais. Os
    metadados retornam SEM o `dados_json` (que pode ser grande); para ver
    o conteúdo do snapshot, use GET /api/sgu/usuarios/backups/{id_bkp}."""
    usuario_api = _normalizar_usuario_api_sgu(usuario)
    _somente_admin_sgu(usuario_api)

    pagina = max(1, int(pagina or 1))
    tamanho_pagina = max(1, min(int(tamanho_pagina or 50), 200))
    offset = (pagina - 1) * tamanho_pagina

    where = ["1=1"]
    params: list = []
    if usuario_destino:
        where.append("USUARIO_DESTINO = ?")
        params.append(int(usuario_destino))
    if tabela:
        where.append("TABELA = ?")
        params.append(_validar_tabela_sgu(tabela))
    if data_ini:
        where.append("DATA_HORA >= ?")
        params.append(data_ini.strip())
    if data_fim:
        where.append("DATA_HORA <= ?")
        params.append(data_fim.strip())
    where_sql = " AND ".join(where)

    conn = get_connection()
    try:
        cursor = conn.cursor()
        cursor.execute(
            f"SELECT COUNT(*) FROM dbo.USU_BKP_SGU_PARAM WHERE {where_sql}",
            params,
        )
        total = int(cursor.fetchone()[0] or 0)
        total_paginas = (total + tamanho_pagina - 1) // tamanho_pagina if total else 0

        sql = f"""
            SELECT
                ID_BKP                                           AS id_bkp,
                CONVERT(VARCHAR(19), DATA_HORA, 120)             AS data_hora,
                USUARIO_API                                      AS usuario_api,
                USUARIO_ORIGEM                                   AS usuario_origem,
                USUARIO_DESTINO                                  AS usuario_destino,
                TABELA                                           AS tabela,
                CODEMP                                           AS codemp,
                MOTIVO                                           AS motivo,
                DATALENGTH(DADOS_JSON)                           AS tamanho_json_bytes
            FROM dbo.USU_BKP_SGU_PARAM
            WHERE {where_sql}
            ORDER BY DATA_HORA DESC, ID_BKP DESC
            OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
        """
        cursor.execute(sql, params + [offset, tamanho_pagina])
        dados = _rows_to_dict_sgu(cursor, cursor.fetchall())

        return {
            "total": total,
            "total_paginas": total_paginas,
            "pagina": pagina,
            "tamanho_pagina": tamanho_pagina,
            "dados": dados,
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.get("/api/sgu/usuarios/backups/{id_bkp}")
def detalhar_backup_sgu(
    id_bkp: int,
    usuario=Depends(validar_token),
):
    """Retorna metadados + JSON desserializado do snapshot. Usar antes
    de chamar restaurar-backup para conferir o que será reescrito."""
    usuario_api = _normalizar_usuario_api_sgu(usuario)
    _somente_admin_sgu(usuario_api)

    conn = get_connection()
    try:
        cursor = conn.cursor()
        cursor.execute("""
            SELECT
                ID_BKP,
                DATA_HORA,
                USUARIO_API,
                USUARIO_ORIGEM,
                USUARIO_DESTINO,
                TABELA,
                CODEMP,
                MOTIVO,
                DADOS_JSON
            FROM dbo.USU_BKP_SGU_PARAM
            WHERE ID_BKP = ?
        """, [id_bkp])
        row = cursor.fetchone()
        if not row:
            raise HTTPException(status_code=404, detail="Backup não localizado.")

        dados_json_raw = row[8] or ""
        try:
            dados_json = json.loads(dados_json_raw) if dados_json_raw else []
        except Exception as exc:
            dados_json = None
            json_erro = str(exc)[:200]
        else:
            json_erro = None

        data_hora_str = row[1].strftime("%Y-%m-%d %H:%M:%S") if row[1] else None

        return {
            "id_bkp": int(row[0]),
            "data_hora": data_hora_str,
            "usuario_api": (row[2] or "").strip() if isinstance(row[2], str) else row[2],
            "usuario_origem": int(row[3]) if row[3] is not None else None,
            "usuario_destino": int(row[4]) if row[4] is not None else None,
            "tabela": (row[5] or "").strip() if isinstance(row[5], str) else row[5],
            "codemp": int(row[6]) if row[6] is not None else None,
            "motivo": (row[7] or "").strip() if isinstance(row[7], str) else row[7],
            "qtd_registros": len(dados_json) if isinstance(dados_json, list) else 0,
            "dados_json": dados_json,
            "json_erro": json_erro,
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.post("/api/sgu/usuarios/restaurar-backup/{id_bkp}")
def restaurar_backup_sgu(
    id_bkp: int,
    body: SGURestaurarBackupPayload,
    request: Request,
    usuario=Depends(validar_token),
):
    """Restaura o snapshot ID_BKP de USU_BKP_SGU_PARAM para o destino
    original. Atenção: a restauração é EXATA — não preserva campos
    cadastrais (diferente de duplicar-parametros). Se o usuário destino
    teve alterações legítimas após o backup, elas serão sobrescritas.

    Política sobre rows extras (existentes hoje no destino mas não no
    snapshot):
      - ``remover_extras=False`` (default, seguro): aditivo. Só UPDATE
        e INSERT. Rows extras permanecem.
      - ``remover_extras=True``: revert completo. DELETE de qualquer row
        do destino na tabela cuja `codemp` não esteja no snapshot.

    Camadas de segurança:
      1. Auth: ADMIN/RENATO.
      2. confirmar=True + motivo não-vazio.
      3. Backup existe (404 se não).
      4. Tabela está em SGU_TABELAS_PARAMETROS.
      5. Snapshot é JSON válido (lista de dicts).
      6. Tudo em transação única; falha → rollback.
      7. Audit log INICIADO/FINALIZADO/ERRO."""
    usuario_api = _normalizar_usuario_api_sgu(usuario)
    _somente_admin_sgu(usuario_api)

    ip = request.client.host if request.client else None

    if not body.confirmar:
        raise HTTPException(
            status_code=400,
            detail="Confirmação obrigatória. Envie confirmar=true após validar o conteúdo do backup.",
        )

    motivo = (body.motivo or "").strip()
    if not motivo:
        raise HTTPException(status_code=400, detail="Informe o motivo da restauração.")

    conn = get_connection()
    cursor = conn.cursor()
    try:
        cursor.execute("""
            SELECT USUARIO_ORIGEM, USUARIO_DESTINO, TABELA, MOTIVO, DADOS_JSON
            FROM dbo.USU_BKP_SGU_PARAM
            WHERE ID_BKP = ?
        """, [id_bkp])
        row = cursor.fetchone()
        if not row:
            raise HTTPException(status_code=404, detail="Backup não localizado.")

        usuario_origem = int(row[0]) if row[0] is not None else None
        usuario_destino = int(row[1]) if row[1] is not None else None
        tabela = (row[2] or "").strip().upper()
        motivo_original = (row[3] or "").strip() if isinstance(row[3], str) else None
        dados_json_raw = row[4] or ""

        if not usuario_destino:
            raise HTTPException(
                status_code=400,
                detail="Backup sem usuario_destino — não é possível restaurar.",
            )

        tabela = _validar_tabela_sgu(tabela)

        try:
            snapshot_rows = json.loads(dados_json_raw) if dados_json_raw else []
        except Exception as exc:
            raise HTTPException(
                status_code=400,
                detail=f"Backup com JSON inválido: {exc}",
            )
        if not isinstance(snapshot_rows, list):
            raise HTTPException(
                status_code=400,
                detail="Backup não é uma lista de registros.",
            )

        # Log INICIADO (best-effort dentro da transação)
        _registrar_log_sgu(
            cursor=cursor,
            usuario_api=usuario_api,
            acao="RESTAURAR_BACKUP_INICIADO",
            usuario_origem=usuario_origem,
            usuario_destino=usuario_destino,
            tabela=tabela,
            detalhe={
                "id_bkp": id_bkp,
                "motivo_restauracao": motivo,
                "motivo_original_backup": motivo_original,
                "remover_extras": body.remover_extras,
                "qtd_registros_snapshot": len(snapshot_rows),
            },
            ip=ip,
        )

        columns = _get_columns_sgu(cursor, tabela)
        if "codusu" not in columns or "codemp" not in columns:
            raise HTTPException(
                status_code=400,
                detail=f"Tabela {tabela} não tem CODUSU/CODEMP.",
            )

        # Snapshot do estado atual antes de restaurar — para que a
        # restauração também seja reversível.
        cursor.execute(
            f"SELECT * FROM dbo.{tabela} WHERE CODUSU = ?",
            [usuario_destino],
        )
        estado_atual = _rows_to_dict_sgu(cursor, cursor.fetchall())
        cursor.execute("""
            INSERT INTO dbo.USU_BKP_SGU_PARAM
                (USUARIO_API, USUARIO_ORIGEM, USUARIO_DESTINO,
                 TABELA, CODEMP, DADOS_JSON, MOTIVO)
            VALUES (?, ?, ?, ?, NULL, ?, ?)
        """, [
            usuario_api,
            usuario_origem,
            usuario_destino,
            tabela,
            json.dumps(estado_atual, ensure_ascii=False, default=str),
            f"PRE_RESTAURACAO id_bkp={id_bkp} motivo={motivo[:300]}",
        ])

        atualizados = 0
        inseridos = 0
        removidos = 0

        # Filtrar campos que existem hoje no schema (defesa contra schema drift)
        campos_validos = [c for c in columns]   # mantém ordem do schema atual
        codemps_no_snapshot: set = set()

        for snap_row in snapshot_rows:
            if not isinstance(snap_row, dict):
                continue
            # Acesso case-insensitive — _rows_to_dict_sgu salvou em lowercase
            snap_lower = {(k or "").lower(): v for k, v in snap_row.items()}
            codemp_val = snap_lower.get("codemp")
            if codemp_val is None:
                continue
            try:
                codemp_int = int(codemp_val)
            except (TypeError, ValueError):
                continue
            codemps_no_snapshot.add(codemp_int)

            cursor.execute(
                f"SELECT COUNT(*) FROM dbo.{tabela} WHERE CODUSU = ? AND CODEMP = ?",
                [usuario_destino, codemp_int],
            )
            existe = int(cursor.fetchone()[0] or 0) > 0

            campos_set = [c for c in campos_validos if c not in SGU_CAMPOS_CHAVE_PADRAO]
            if existe and campos_set:
                sets = ", ".join(f"{c.upper()} = ?" for c in campos_set)
                params_upd = [snap_lower.get(c) for c in campos_set]
                params_upd.extend([usuario_destino, codemp_int])
                cursor.execute(
                    f"UPDATE dbo.{tabela} SET {sets} WHERE CODUSU = ? AND CODEMP = ?",
                    params_upd,
                )
                atualizados += cursor.rowcount or 0
            elif not existe:
                valores: list = []
                for c in campos_validos:
                    if c == "codusu":
                        valores.append(usuario_destino)
                    elif c == "codemp":
                        valores.append(codemp_int)
                    else:
                        valores.append(snap_lower.get(c))
                campos_sql = ", ".join(c.upper() for c in campos_validos)
                placeholders = ", ".join("?" for _ in campos_validos)
                cursor.execute(
                    f"INSERT INTO dbo.{tabela} ({campos_sql}) VALUES ({placeholders})",
                    valores,
                )
                inseridos += cursor.rowcount or 0

        if body.remover_extras:
            # Apaga rows do destino cuja codemp não estava no snapshot
            cursor.execute(
                f"SELECT CODEMP FROM dbo.{tabela} WHERE CODUSU = ?",
                [usuario_destino],
            )
            codemps_atuais = [int(r[0]) for r in cursor.fetchall() if r[0] is not None]
            extras = [c for c in codemps_atuais if c not in codemps_no_snapshot]
            for codemp_extra in extras:
                cursor.execute(
                    f"DELETE FROM dbo.{tabela} WHERE CODUSU = ? AND CODEMP = ?",
                    [usuario_destino, codemp_extra],
                )
                removidos += cursor.rowcount or 0

        resultado = {
            "id_bkp_restaurado": id_bkp,
            "tabela": tabela,
            "registros_snapshot": len(snapshot_rows),
            "atualizados": atualizados,
            "inseridos": inseridos,
            "removidos": removidos,
            "remover_extras": body.remover_extras,
        }

        _registrar_log_sgu(
            cursor=cursor,
            usuario_api=usuario_api,
            acao="RESTAURAR_BACKUP_FINALIZADO",
            usuario_origem=usuario_origem,
            usuario_destino=usuario_destino,
            tabela=tabela,
            detalhe={"id_bkp": id_bkp, "motivo_restauracao": motivo},
            resultado=resultado,
            ip=ip,
        )
        conn.commit()

        return {
            "mensagem": "Backup restaurado com sucesso.",
            **resultado,
        }

    except HTTPException:
        try:
            conn.rollback()
        except Exception:
            pass
        raise
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        # Log de erro fora da transação
        try:
            conn2 = get_connection()
            try:
                cur2 = conn2.cursor()
                _registrar_log_sgu(
                    cursor=cur2,
                    usuario_api=usuario_api,
                    acao="RESTAURAR_BACKUP_ERRO",
                    detalhe={"id_bkp": id_bkp, "motivo": motivo},
                    resultado={"erro": str(e)[:900]},
                    ip=ip,
                )
                conn2.commit()
            finally:
                conn2.close()
        except Exception:
            pass
        raise HTTPException(status_code=500, detail=f"Erro ao restaurar backup SGU: {str(e)}")
    finally:
        try:
            conn.close()
        except Exception:
            pass


# ============================================================
# ETL BI — Pipeline ERP Senior → Supabase
# ============================================================
# Tarefas:
#   ATU_COMPRAS       → bi_compras
#   ATU_RECEBIMENTOS  → bi_recebimentos
# Endpoints:
#   POST /api/etl/executar    — síncrono, V1
#   POST /api/etl/reprocessar — enfileira em etl_fila_integrador
#   GET  /api/etl/execucoes   — lista últimas execuções
# V2 (não implementado ainda):
#   - watermark incremental (hoje é full refresh)
#   - worker assíncrono que drena etl_fila_integrador
# ============================================================

import hashlib as _hashlib

ETL_TAREFAS_VALIDAS = ("ATU_COMPRAS", "ATU_RECEBIMENTOS")
ETL_BATCH_UPSERT = 500

TIPO_DESPESA_LABELS = {
    "MATERIA_PRIMA":   "Matéria-prima",
    "USO_CONSUMO":     "Uso e consumo",
    "DESPESAS_GERAIS": "Despesas gerais",
    "SERVICOS":        "Serviços",
    "TODOS":           "Todos",
}

SITUACAO_OC_LABELS = {
    1: "Aberto Total",
    2: "Aberto Parcial",
    3: "Suspenso",
    4: "Liquidado",
    5: "Cancelado",
    6: "Aguardando Integração WMS",
    7: "Em Transmissão",
    8: "Preparação Análise ou NF",
    9: "Não Fechado",
}

SITUACAO_NF_LABELS = {
    "1": "Normal",
    "2": "Em digitação",
    "3": "Cancelada",
    "4": "Devolvida",
    "5": "Inutilizada",
}


class EtlExecutarPayload(BaseModel):
    tarefa: str
    acionado_por: Optional[str] = "MANUAL"
    data_ini: Optional[str] = None
    data_fim: Optional[str] = None


class EtlReprocessarPayload(BaseModel):
    tarefa: str
    data_ini: Optional[str] = None
    data_fim: Optional[str] = None


def _supabase_required():
    if not SUPABASE_URL or not SUPABASE_SERVICE_ROLE_KEY:
        raise HTTPException(
            status_code=500,
            detail="Supabase não configurado. Defina SUPABASE_URL e SUPABASE_SERVICE_ROLE_KEY.",
        )


def _supabase_headers(prefer: str = "return=minimal") -> dict:
    return {
        "apikey": SUPABASE_SERVICE_ROLE_KEY,
        "Authorization": f"Bearer {SUPABASE_SERVICE_ROLE_KEY}",
        "Content-Type": "application/json",
        "Prefer": prefer,
    }


def _supabase_upsert(table: str, rows: list, on_conflict: list) -> int:
    """POST batch para Supabase REST com `resolution=merge-duplicates`.
    Retorna número de linhas enviadas (não o número de inserts vs updates,
    que o REST não distingue sem ?count=exact)."""
    if not rows:
        return 0
    url = f"{SUPABASE_URL}/rest/v1/{table}?on_conflict={','.join(on_conflict)}"
    resp = requests.post(
        url, json=rows,
        headers=_supabase_headers("return=minimal,resolution=merge-duplicates"),
        timeout=120,
    )
    if resp.status_code not in (200, 201, 204):
        raise RuntimeError(
            f"Supabase upsert {table} HTTP {resp.status_code}: {(resp.text or '')[:300]}"
        )
    return len(rows)


def _supabase_iniciar_execucao(tarefa: str, acionado_por: str,
                                parametros: Optional[dict] = None) -> Optional[Any]:
    payload = {
        "tarefa": tarefa,
        "status": "RUNNING",
        "acionado_por": (acionado_por or "MANUAL")[:80],
        "parametros_json": json.dumps(parametros or {}, ensure_ascii=False, default=str),
        "iniciado_em": datetime.utcnow().isoformat() + "Z",
    }
    resp = requests.post(
        f"{SUPABASE_URL}/rest/v1/etl_execucoes",
        json=payload, headers=_supabase_headers("return=representation"),
        timeout=15,
    )
    if resp.status_code not in (200, 201):
        raise RuntimeError(
            f"etl_execucoes insert HTTP {resp.status_code}: {(resp.text or '')[:300]}"
        )
    body = resp.json()
    if isinstance(body, list) and body:
        return body[0].get("id")
    if isinstance(body, dict):
        return body.get("id")
    return None


def _supabase_finalizar_execucao(execucao_id, status: str, *,
                                  linhas_lidas=0, linhas_inseridas=0,
                                  linhas_atualizadas=0, erro_resumo=None):
    if not execucao_id:
        return
    payload = {
        "status": status,
        "terminado_em": datetime.utcnow().isoformat() + "Z",
        "linhas_lidas": int(linhas_lidas or 0),
        "linhas_inseridas": int(linhas_inseridas or 0),
        "linhas_atualizadas": int(linhas_atualizadas or 0),
    }
    if erro_resumo:
        payload["erro_resumo"] = str(erro_resumo)[:1000]
    try:
        requests.patch(
            f"{SUPABASE_URL}/rest/v1/etl_execucoes?id=eq.{execucao_id}",
            json=payload, headers=_supabase_headers(),
            timeout=15,
        )
    except Exception as exc:
        print(f"[ETL] falha ao finalizar execucao {execucao_id}: {exc}")


def _supabase_log(execucao_id, mensagem: str, nivel: str = "INFO",
                   detalhe: Optional[Any] = None):
    """Insere uma linha em etl_logs. Best-effort — nunca derruba a tarefa."""
    try:
        payload = {
            "execucao_id": execucao_id,
            "nivel": (nivel or "INFO")[:20].upper(),
            "mensagem": (mensagem or "")[:1000],
            "detalhe": (json.dumps(detalhe, ensure_ascii=False, default=str)[:4000]
                        if detalhe is not None else None),
            "data_hora": datetime.utcnow().isoformat() + "Z",
        }
        requests.post(
            f"{SUPABASE_URL}/rest/v1/etl_logs",
            json=payload, headers=_supabase_headers(),
            timeout=10,
        )
    except Exception as exc:
        print(f"[ETL_LOG] falha: {exc}")


def _hash_etl(*partes) -> str:
    raw = "|".join(("" if p is None else str(p)) for p in partes)
    return _hashlib.sha1(raw.encode("utf-8")).hexdigest()


def _mes_competencia(valor) -> str:
    """Extrai 'YYYY-MM' de uma data (datetime ou string ISO)."""
    if not valor:
        return ""
    if isinstance(valor, datetime):
        return valor.strftime("%Y-%m")
    s = str(valor)
    return s[:7] if len(s) >= 7 else s


def _status_recebimento_oc(qtd_pedida, qtd_recebida) -> str:
    qp = float(qtd_pedida or 0)
    qr = float(qtd_recebida or 0)
    if qp <= 0:
        return "INDEFINIDO"
    if qr <= 0:
        return "PENDENTE"
    if qr >= qp:
        return "TOTAL"
    return "PARCIAL"


def _executar_atu_compras(execucao_id, usuario_api: str,
                           data_ini=None, data_fim=None) -> dict:
    _supabase_log(execucao_id, "ATU_COMPRAS iniciado", "INFO",
                  {"data_ini": data_ini, "data_fim": data_fim})

    # 1) Coleta TODA a base via paginação interna (sem cap arbitrário)
    dados = _collect_paginated_data(
        consultar_painel_compras,
        usuario_api or "ETL",
        batch_size=500,
        max_pages=10000,
        data_emissao_ini=data_ini,
        data_emissao_fim=data_fim,
        somente_pendentes=False,
        agrupar_por_fornecedor=False,
    )
    linhas_lidas = len(dados)
    _supabase_log(execucao_id, f"Lidas {linhas_lidas} linhas do ERP (E420OCP/IPO/ISO)",
                  "INFO")

    # 2) Transforma + classifica
    rows_bi: list = []
    now_iso = datetime.utcnow().isoformat() + "Z"
    for it in dados:
        valor_liquido = float(it.get("valor_liquido") or 0)
        valor_pendente = float(it.get("valor_pendente_estimado") or 0)
        valor_recebido = round(valor_liquido - valor_pendente, 2)
        qtd_pedida = float(it.get("quantidade_pedida") or 0)
        qtd_recebida = float(it.get("quantidade_recebida") or 0)
        qtd_pendente = float(it.get("saldo_pendente") or max(0, qtd_pedida - qtd_recebida))

        tipo_despesa = (it.get("tipo_despesa")
                        or classificar_tipo_despesa(it)
                        or "DESPESAS_GERAIS")
        projeto_macro = _projeto_macro(
            it.get("nome_projeto"),
            it.get("numero_projeto"),
            it.get("origem_material"),
        )
        situacao_oc_int = int(it.get("situacao_oc") or 0)

        codemp = int(it.get("codigo_empresa") or EMPRESA_PADRAO)
        codfil = int(it.get("codigo_filial") or 0)
        numero_oc = int(it.get("numero_oc") or 0)
        seq_item = int(it.get("sequencia_item") or 0)

        h = _hash_etl(
            codemp, codfil, numero_oc, seq_item,
            valor_liquido, valor_pendente, qtd_pedida, qtd_recebida,
            situacao_oc_int, tipo_despesa, projeto_macro,
        )

        rows_bi.append({
            "codemp": codemp,
            "codfil": codfil,
            "numero_oc": numero_oc,
            "sequencia_item": seq_item,
            "codigo_fornecedor": it.get("codigo_fornecedor"),
            "nome_fornecedor": (it.get("nome_fornecedor") or "")[:200],
            "codigo_item": (it.get("codigo_item") or "")[:50],
            "descricao_item": (it.get("descricao_item") or "")[:300],
            "codigo_familia": (it.get("codigo_familia") or "")[:30],
            "origem_material": (it.get("origem_material") or "")[:30],
            "transacao": (it.get("transacao") or "")[:30],
            "numero_projeto": int(it.get("numero_projeto") or 0) or None,
            "nome_projeto": (it.get("nome_projeto") or "")[:200],
            "projeto_macro": projeto_macro,
            "centro_custo": (it.get("codigo_centro_custo") or "")[:30],
            "descricao_centro_custo": (it.get("descricao_centro_custo") or "")[:200],
            "tipo_despesa": tipo_despesa,
            "tipo_despesa_label": TIPO_DESPESA_LABELS.get(tipo_despesa, tipo_despesa),
            # V2: enriquecer condicao_pagamento via JOIN E028CPG no CTE
            "condicao_pagamento": "",
            "descricao_condicao_pagamento": "",
            "situacao_oc": situacao_oc_int,
            "situacao_oc_label": SITUACAO_OC_LABELS.get(situacao_oc_int, ""),
            "data_emissao": str(it.get("data_emissao") or "")[:19] or None,
            "data_entrega": str(it.get("data_entrega") or "")[:19] or None,
            "mes_competencia": _mes_competencia(it.get("data_emissao")),
            "quantidade_pedida": qtd_pedida,
            "quantidade_recebida": qtd_recebida,
            "quantidade_pendente": qtd_pendente,
            "valor_bruto": float(it.get("valor_bruto") or 0),
            "valor_liquido": valor_liquido,
            "valor_recebido": valor_recebido,
            "valor_pendente": valor_pendente,
            "status_recebimento": _status_recebimento_oc(qtd_pedida, qtd_recebida),
            # V2: cruzar com bi_recebimentos por (numero_oc_origem)
            "tem_nf_vinculada": False,
            "hash_registro": h,
            "atualizado_em": now_iso,
        })

    _supabase_log(execucao_id, f"Transformadas {len(rows_bi)} linhas", "INFO")

    # 3) Upsert em batches
    inseridos = 0
    for i in range(0, len(rows_bi), ETL_BATCH_UPSERT):
        batch = rows_bi[i:i + ETL_BATCH_UPSERT]
        try:
            _supabase_upsert(
                "bi_compras", batch,
                on_conflict=["codemp", "codfil", "numero_oc", "sequencia_item"],
            )
            inseridos += len(batch)
            _supabase_log(execucao_id,
                          f"Upsert bi_compras batch {i}-{i + len(batch)} OK",
                          "INFO")
        except Exception as exc:
            _supabase_log(execucao_id, f"Erro no batch {i}: {exc}", "ERROR")
            raise

    return {
        "linhas_lidas": linhas_lidas,
        "linhas_inseridas": inseridos,
        "linhas_atualizadas": 0,
    }


def _executar_atu_recebimentos(execucao_id, usuario_api: str,
                                data_ini=None, data_fim=None) -> dict:
    _supabase_log(execucao_id, "ATU_RECEBIMENTOS iniciado", "INFO",
                  {"data_ini": data_ini, "data_fim": data_fim})

    dados = _collect_paginated_data(
        consultar_notas_recebimento,
        usuario_api or "ETL",
        batch_size=500,
        max_pages=10000,
        data_recebimento_ini=data_ini,
        data_recebimento_fim=data_fim,
    )
    linhas_lidas = len(dados)
    _supabase_log(execucao_id, f"Lidas {linhas_lidas} linhas do ERP (E140NFV/IPV/ISV)",
                  "INFO")

    rows_bi: list = []
    now_iso = datetime.utcnow().isoformat() + "Z"
    for it in dados:
        # Já vem enriquecido com tipo_movimento_nf/sinal/líquido pelo
        # _enriquecer_item_movimento_nf dentro do endpoint base.
        tipo_mov = it.get("tipo_movimento_nf") or "RECEBIMENTO"
        sinal = int(it.get("sinal_movimento") or 1)
        valor_liquido = float(it.get("valor_liquido") or 0)
        valor_recebido_liquido = float(
            it.get("valor_recebido_liquido", valor_liquido * sinal) or 0
        )

        tipo_despesa = classificar_tipo_despesa(it) or "DESPESAS_GERAIS"
        projeto_macro = _projeto_macro(
            it.get("nome_projeto"),
            it.get("numero_projeto"),
            it.get("origem_material"),
        )
        situacao_nf_str = str(it.get("situacao_nf") or "").strip()

        codemp = int(it.get("codigo_empresa") or EMPRESA_PADRAO)
        codfil = int(it.get("codigo_filial") or 0)
        numero_nf = int(it.get("numero_nf") or 0)
        serie_nf = (it.get("serie_nf") or "")[:10]
        seq_item = int(it.get("sequencia_item") or it.get("seqipv") or 0)
        numero_oc_origem = int(it.get("numero_oc_origem") or 0) or None

        h = _hash_etl(
            codemp, codfil, numero_nf, serie_nf, seq_item,
            valor_liquido, tipo_mov, sinal, situacao_nf_str,
            tipo_despesa, projeto_macro,
        )

        rows_bi.append({
            "codemp": codemp,
            "codfil": codfil,
            "numero_nf": numero_nf,
            "serie_nf": serie_nf,
            "sequencia_item": seq_item,
            "codigo_fornecedor": it.get("codigo_fornecedor"),
            "nome_fornecedor": (it.get("nome_fornecedor") or "")[:200],
            "codigo_item": (it.get("codigo_item") or "")[:50],
            "descricao_item": (it.get("descricao_item") or "")[:300],
            "codigo_familia": (it.get("codigo_familia") or "")[:30],
            "origem_material": (it.get("origem_material") or "")[:30],
            "transacao_nf": (it.get("transacao") or "")[:30],
            "numero_oc_origem": numero_oc_origem,
            "sequencia_oc_origem": int(it.get("sequencia_oc_origem") or 0) or None,
            "tem_oc_origem": bool(numero_oc_origem),
            "numero_projeto": int(it.get("numero_projeto") or 0) or None,
            "nome_projeto": (it.get("nome_projeto") or "")[:200],
            "projeto_macro": projeto_macro,
            "centro_custo": (it.get("codigo_centro_custo") or "")[:30],
            "descricao_centro_custo": (it.get("descricao_centro_custo") or "")[:200],
            "tipo_despesa": tipo_despesa,
            "tipo_despesa_label": TIPO_DESPESA_LABELS.get(tipo_despesa, tipo_despesa),
            "condicao_pagamento": "",
            "descricao_condicao_pagamento": "",
            "situacao_nf": situacao_nf_str,
            "situacao_nf_label": SITUACAO_NF_LABELS.get(situacao_nf_str, ""),
            "tipo_movimento_nf": tipo_mov,
            "sinal_movimento": sinal,
            "data_emissao": str(it.get("data_emissao") or "")[:19] or None,
            "data_recebimento": str(it.get("data_recebimento") or "")[:19] or None,
            "mes_competencia": _mes_competencia(
                it.get("data_recebimento") or it.get("data_emissao")
            ),
            "quantidade_recebida": float(it.get("quantidade_pedida") or 0),
            "valor_bruto": float(it.get("valor_bruto") or 0),
            "valor_liquido": valor_liquido,
            "valor_recebido_liquido": valor_recebido_liquido,
            "hash_registro": h,
            "atualizado_em": now_iso,
        })

    _supabase_log(execucao_id, f"Transformadas {len(rows_bi)} linhas", "INFO")

    inseridos = 0
    for i in range(0, len(rows_bi), ETL_BATCH_UPSERT):
        batch = rows_bi[i:i + ETL_BATCH_UPSERT]
        try:
            _supabase_upsert(
                "bi_recebimentos", batch,
                on_conflict=["codemp", "codfil", "numero_nf", "serie_nf", "sequencia_item"],
            )
            inseridos += len(batch)
            _supabase_log(execucao_id,
                          f"Upsert bi_recebimentos batch {i}-{i + len(batch)} OK",
                          "INFO")
        except Exception as exc:
            _supabase_log(execucao_id, f"Erro no batch {i}: {exc}", "ERROR")
            raise

    return {
        "linhas_lidas": linhas_lidas,
        "linhas_inseridas": inseridos,
        "linhas_atualizadas": 0,
    }


@app.post("/api/etl/executar")
def etl_executar(body: EtlExecutarPayload, usuario=Depends(validar_token)):
    """Executa uma tarefa ETL síncronamente. V1 = full refresh (sem
    watermark incremental). Retorna 200 com contadores em sucesso, 500
    em falha, 422 se tarefa inválida ou Supabase mal configurado."""
    _supabase_required()

    tarefa = (body.tarefa or "").upper().strip()
    if tarefa not in ETL_TAREFAS_VALIDAS:
        raise HTTPException(
            status_code=422,
            detail=f"Tarefa inválida. Use uma de: {', '.join(ETL_TAREFAS_VALIDAS)}",
        )

    usuario_api = str(usuario or "").upper().strip()
    parametros = {
        "data_ini": body.data_ini,
        "data_fim": body.data_fim,
        "acionado_por": body.acionado_por,
        "usuario_api": usuario_api,
    }

    try:
        execucao_id = _supabase_iniciar_execucao(
            tarefa, body.acionado_por, parametros,
        )
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Falha ao registrar etl_execucoes: {exc}",
        )

    try:
        if tarefa == "ATU_COMPRAS":
            resultado = _executar_atu_compras(
                execucao_id, usuario_api, body.data_ini, body.data_fim,
            )
        else:  # ATU_RECEBIMENTOS
            resultado = _executar_atu_recebimentos(
                execucao_id, usuario_api, body.data_ini, body.data_fim,
            )
        _supabase_log(execucao_id, "Tarefa concluída com sucesso", "INFO", resultado)
        _supabase_finalizar_execucao(execucao_id, "SUCCESS", **resultado)
        return {
            "execucao_id": execucao_id,
            "tarefa": tarefa,
            "status": "SUCCESS",
            **resultado,
        }
    except HTTPException:
        _supabase_finalizar_execucao(execucao_id, "ERROR", erro_resumo="HTTPException")
        raise
    except Exception as exc:
        msg = str(exc)[:500]
        _supabase_log(execucao_id, f"Falha fatal: {msg}", "ERROR")
        _supabase_finalizar_execucao(execucao_id, "ERROR", erro_resumo=msg)
        raise HTTPException(
            status_code=500,
            detail=f"ETL {tarefa} falhou: {msg}",
        )


@app.post("/api/etl/reprocessar")
def etl_reprocessar(body: EtlReprocessarPayload, usuario=Depends(validar_token)):
    """Enfileira pedido de reprocessamento em etl_fila_integrador.
    V1: apenas insere PENDENTE — V2 implementa worker que drena a fila."""
    _supabase_required()

    tarefa = (body.tarefa or "").upper().strip()
    if tarefa not in ETL_TAREFAS_VALIDAS:
        raise HTTPException(
            status_code=422,
            detail=f"Tarefa inválida. Use uma de: {', '.join(ETL_TAREFAS_VALIDAS)}",
        )

    usuario_api = str(usuario or "").upper().strip()
    payload = {
        "tarefa": tarefa,
        "data_ini": body.data_ini,
        "data_fim": body.data_fim,
        "status": "PENDENTE",
        "acionado_por": usuario_api,
        "criado_em": datetime.utcnow().isoformat() + "Z",
    }

    try:
        resp = requests.post(
            f"{SUPABASE_URL}/rest/v1/etl_fila_integrador",
            json=payload, headers=_supabase_headers("return=representation"),
            timeout=15,
        )
        if resp.status_code not in (200, 201):
            raise RuntimeError(
                f"HTTP {resp.status_code}: {(resp.text or '')[:300]}"
            )
        body_resp = resp.json()
        item_id = (body_resp[0].get("id") if isinstance(body_resp, list) and body_resp
                   else body_resp.get("id") if isinstance(body_resp, dict) else None)
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Falha ao enfileirar em etl_fila_integrador: {exc}",
        )

    return {
        "status": "ENFILEIRADO",
        "id": item_id,
        "tarefa": tarefa,
        "data_ini": body.data_ini,
        "data_fim": body.data_fim,
        "observacao": "V2: implementar worker que drena etl_fila_integrador.",
    }


@app.get("/api/etl/execucoes")
def etl_listar_execucoes(
    tarefa: Optional[str] = None,
    status: Optional[str] = None,
    limite: int = 50,
    usuario=Depends(validar_token),
):
    """Lista as últimas execuções. Útil para diagnóstico no frontend."""
    _supabase_required()
    limite = max(1, min(int(limite or 50), 200))
    params = {
        "select": "*",
        "order": "iniciado_em.desc",
        "limit": str(limite),
    }
    if tarefa:
        params["tarefa"] = f"eq.{tarefa.upper().strip()}"
    if status:
        params["status"] = f"eq.{status.upper().strip()}"
    try:
        resp = requests.get(
            f"{SUPABASE_URL}/rest/v1/etl_execucoes",
            params=params, headers=_supabase_headers(),
            timeout=15,
        )
        if resp.status_code != 200:
            raise RuntimeError(
                f"HTTP {resp.status_code}: {(resp.text or '')[:300]}"
            )
        return {"total": len(resp.json()), "dados": resp.json()}
    except Exception as exc:
        raise HTTPException(
            status_code=500,
            detail=f"Falha ao consultar etl_execucoes: {exc}",
        )


# ============================================================
# BI SHADOW MODE — endpoints paralelos lendo bi_compras / bi_recebimentos
# ============================================================
# Estratégia:
#   - Endpoints `/api/bi/...` lêem do Supabase (analítico)
#   - Endpoints originais `/api/painel-compras*` e `/api/notas-recebimento*`
#     continuam lendo do ERP Senior intactos
#   - Frontend pode comparar ERP vs BI antes de trocar a fonte
#   - Quando dados validarem, ativar feature flag USE_BI_ANALYTICS=true
# Limitações V1:
#   - Sem `/api/export/bi/*` (próxima iteração)
#   - Aggregations em Python pós-fetch (Supabase REST não tem SUM/COUNT
#     nativo sem RPC; bi_compras é tabela analítica achatada → aceitável)
# ============================================================


def _bi_supabase_get(table: str, *, params: Optional[dict] = None,
                     prefer: str = "count=exact",
                     limit: Optional[int] = None,
                     offset: Optional[int] = None,
                     order: Optional[str] = None) -> tuple[list, int]:
    """GET genérico no Supabase REST. Retorna (rows, total_count).

    `params` é um dict com filtros já no formato PostgREST
    (ex.: {'numero_projeto': 'eq.123', 'data_emissao': 'gte.2026-01-01'}).
    `prefer='count=exact'` força o header Prefer para Supabase devolver
    Content-Range com total — usamos para saber `total_registros` sem
    fazer query separada."""
    _supabase_required()
    url = f"{SUPABASE_URL}/rest/v1/{table}"
    qp = dict(params or {})
    if order:
        qp["order"] = order
    if limit is not None:
        qp["limit"] = str(limit)
    if offset is not None:
        qp["offset"] = str(offset)

    headers = _supabase_headers(prefer)
    resp = requests.get(url, params=qp, headers=headers, timeout=60)
    if resp.status_code not in (200, 206):
        raise RuntimeError(
            f"Supabase GET {table} HTTP {resp.status_code}: {(resp.text or '')[:300]}"
        )
    rows = resp.json() if resp.text else []
    # Content-Range vem como '0-99/1234' — pegamos o total após '/'
    total = len(rows)
    cr = resp.headers.get("Content-Range", "")
    if "/" in cr:
        try:
            total = int(cr.split("/")[-1])
        except (TypeError, ValueError):
            pass
    return rows, total


def _bi_filtros_compras(*, numero_projeto=None, centro_custo=None,
                         tipo_despesa=None, projeto_macro=None,
                         mes_competencia=None, fornecedor=None,
                         descricao_item=None, numero_oc=None,
                         data_emissao_ini=None, data_emissao_fim=None,
                         situacao_oc=None, somente_pendentes=False,
                         familia=None, origem_material=None,
                         transacao=None) -> dict:
    """Monta dict PostgREST a partir dos filtros canônicos."""
    f: dict = {"codemp": f"eq.{EMPRESA_PADRAO}"}

    if numero_projeto:
        try:
            f["numero_projeto"] = f"eq.{int(numero_projeto)}"
        except (TypeError, ValueError):
            pass
    if centro_custo:
        f["centro_custo"] = f"ilike.*{centro_custo}*"
    if tipo_despesa:
        td = normalizar_tipo_despesa(tipo_despesa)
        if td != "TODOS":
            f["tipo_despesa"] = f"eq.{td}"
    if projeto_macro:
        f["projeto_macro"] = f"eq.{projeto_macro.upper().strip()}"
    if mes_competencia:
        f["mes_competencia"] = f"eq.{mes_competencia.strip()}"
    if fornecedor:
        # Cliente pode mandar código numérico ou nome
        try:
            cod = int(str(fornecedor).strip())
            f["codigo_fornecedor"] = f"eq.{cod}"
        except (TypeError, ValueError):
            f["nome_fornecedor"] = f"ilike.*{fornecedor}*"
    if descricao_item:
        f["descricao_item"] = f"ilike.*{descricao_item}*"
    if numero_oc:
        try:
            f["numero_oc"] = f"eq.{int(numero_oc)}"
        except (TypeError, ValueError):
            pass
    if data_emissao_ini:
        f["data_emissao"] = f"gte.{data_emissao_ini}"
    if data_emissao_fim:
        # Append-style — PostgREST aceita repetir mas via dict precisamos
        # combinar OR ranged. Workaround: usar dois params com nomes
        # diferentes via lista de tuplas. Simplifico aqui usando .and.
        f.setdefault("and", "")
        existing_and = f.get("and") or ""
        novo = f"data_emissao.lte.{data_emissao_fim}"
        f["and"] = f"({existing_and},{novo})" if existing_and else f"({novo})"
    if situacao_oc:
        valores = parse_csv_int_param(situacao_oc, "situacao_oc")
        if valores:
            f["situacao_oc"] = "in.(" + ",".join(str(v) for v in valores) + ")"
    if somente_pendentes:
        f["valor_pendente"] = "gt.0"
    if familia:
        f["codigo_familia"] = f"ilike.*{familia}*"
    if origem_material:
        f["origem_material"] = f"ilike.*{origem_material}*"
    if transacao:
        f["transacao"] = f"ilike.*{transacao}*"
    return f


def _bi_filtros_recebimentos(*, numero_projeto=None, centro_custo=None,
                              tipo_despesa=None, projeto_macro=None,
                              mes_competencia=None, fornecedor=None,
                              descricao_item=None, numero_nf=None,
                              serie_nf=None, numero_oc_origem=None,
                              data_recebimento_ini=None,
                              data_recebimento_fim=None,
                              situacao=None, transacao=None,
                              familia=None, origem_material=None,
                              tipo_movimento=None) -> dict:
    f: dict = {"codemp": f"eq.{EMPRESA_PADRAO}"}

    if numero_projeto:
        try:
            f["numero_projeto"] = f"eq.{int(numero_projeto)}"
        except (TypeError, ValueError):
            pass
    if centro_custo:
        f["centro_custo"] = f"ilike.*{centro_custo}*"
    if tipo_despesa:
        td = normalizar_tipo_despesa(tipo_despesa)
        if td != "TODOS":
            f["tipo_despesa"] = f"eq.{td}"
    if projeto_macro:
        f["projeto_macro"] = f"eq.{projeto_macro.upper().strip()}"
    if mes_competencia:
        f["mes_competencia"] = f"eq.{mes_competencia.strip()}"
    if fornecedor:
        try:
            f["codigo_fornecedor"] = f"eq.{int(fornecedor)}"
        except (TypeError, ValueError):
            f["nome_fornecedor"] = f"ilike.*{fornecedor}*"
    if descricao_item:
        f["descricao_item"] = f"ilike.*{descricao_item}*"
    if numero_nf:
        try:
            f["numero_nf"] = f"eq.{int(numero_nf)}"
        except (TypeError, ValueError):
            pass
    if serie_nf:
        f["serie_nf"] = f"eq.{serie_nf.strip()}"
    if numero_oc_origem:
        try:
            f["numero_oc_origem"] = f"eq.{int(numero_oc_origem)}"
        except (TypeError, ValueError):
            pass
    if data_recebimento_ini:
        f["data_recebimento"] = f"gte.{data_recebimento_ini}"
    if data_recebimento_fim:
        existing_and = f.get("and") or ""
        novo = f"data_recebimento.lte.{data_recebimento_fim}"
        f["and"] = f"({existing_and},{novo})" if existing_and else f"({novo})"
    if situacao:
        f["situacao_nf"] = f"eq.{situacao.strip()}"
    if transacao:
        f["transacao_nf"] = f"ilike.*{transacao}*"
    if familia:
        f["codigo_familia"] = f"ilike.*{familia}*"
    if origem_material:
        f["origem_material"] = f"ilike.*{origem_material}*"
    if tipo_movimento:
        f["tipo_movimento_nf"] = f"eq.{tipo_movimento.upper().strip()}"
    return f


def _bi_kpis_compras(rows: list) -> dict:
    fornecedores = {r.get("codigo_fornecedor") for r in rows if r.get("codigo_fornecedor")}
    ocs = {(r.get("codemp"), r.get("codfil"), r.get("numero_oc"))
           for r in rows if r.get("numero_oc")}
    valor_bruto = sum(float(r.get("valor_bruto") or 0) for r in rows)
    valor_liquido = sum(float(r.get("valor_liquido") or 0) for r in rows)
    valor_pendente = sum(float(r.get("valor_pendente") or 0) for r in rows)
    valor_recebido = sum(float(r.get("valor_recebido") or 0) for r in rows)
    return {
        "valor_bruto": round(valor_bruto, 2),
        "valor_liquido": round(valor_liquido, 2),
        "valor_pendente": round(valor_pendente, 2),
        "valor_recebido": round(valor_recebido, 2),
        "qtd_ocs": len(ocs),
        "qtd_itens": len(rows),
        "qtd_fornecedores": len(fornecedores),
        "ticket_medio_oc": round(valor_liquido / len(ocs), 2) if ocs else 0.0,
        "percentual_recebido": round(valor_recebido / valor_liquido * 100, 2) if valor_liquido else 0.0,
    }


def _bi_kpis_recebimentos(rows: list) -> dict:
    fornecedores = {r.get("codigo_fornecedor") for r in rows if r.get("codigo_fornecedor")}
    nfs = {(r.get("codemp"), r.get("codfil"), r.get("numero_nf"), r.get("serie_nf"))
           for r in rows if r.get("numero_nf")}
    valor_recebido_liquido = sum(float(r.get("valor_recebido_liquido") or 0) for r in rows)
    valor_bruto = sum(float(r.get("valor_bruto") or 0) for r in rows)
    valor_liquido = sum(float(r.get("valor_liquido") or 0) for r in rows)
    return {
        "valor_bruto": round(valor_bruto, 2),
        "valor_liquido": round(valor_liquido, 2),
        "valor_recebido_liquido": round(valor_recebido_liquido, 2),
        "qtd_nfs": len(nfs),
        "qtd_itens": len(rows),
        "qtd_fornecedores": len(fornecedores),
    }


def _bi_agrupar(rows: list, campo: str, label_field: Optional[str] = None,
                 valor_field: str = "valor_liquido", top: Optional[int] = None) -> list:
    grupos: dict = {}
    for r in rows:
        chave = r.get(campo)
        if chave is None or chave == "":
            chave = "NÃO INFORMADO"
        chave_str = str(chave)
        g = grupos.setdefault(chave_str, {
            "chave": chave_str, "label": chave_str,
            "valor": 0.0, "quantidade": 0,
        })
        if label_field:
            lv = r.get(label_field)
            if lv:
                g["label"] = str(lv).strip()
        g["valor"] += float(r.get(valor_field) or 0)
        g["quantidade"] += 1
    for g in grupos.values():
        g["valor"] = round(g["valor"], 2)
    out = sorted(grupos.values(), key=lambda x: x["valor"], reverse=True)
    return out[:top] if top else out


