@app.get("/api/bi/painel-compras")
def bi_painel_compras(
    numero_projeto: Optional[str] = None,
    centro_custo: Optional[str] = None,
    tipo_despesa: Optional[str] = None,
    projeto_macro: Optional[str] = None,
    mes_competencia: Optional[str] = None,
    fornecedor: Optional[str] = None,
    descricao_item: Optional[str] = None,
    numero_oc: Optional[str] = None,
    data_emissao_ini: Optional[str] = None,
    data_emissao_fim: Optional[str] = None,
    situacao_oc: Optional[str] = None,
    somente_pendentes: bool = False,
    familia: Optional[str] = None,
    origem_material: Optional[str] = None,
    transacao: Optional[str] = None,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token),
):
    """Lista paginada lendo de bi_compras (Supabase). Espelha o shape do
    /api/painel-compras (ERP) para o frontend não precisar mudar."""
    _supabase_required()
    pagina = max(1, int(pagina or 1))
    tamanho_pagina = max(1, min(int(tamanho_pagina or 100), 500))
    offset = (pagina - 1) * tamanho_pagina

    filtros = _bi_filtros_compras(
        numero_projeto=numero_projeto, centro_custo=centro_custo,
        tipo_despesa=tipo_despesa, projeto_macro=projeto_macro,
        mes_competencia=mes_competencia, fornecedor=fornecedor,
        descricao_item=descricao_item, numero_oc=numero_oc,
        data_emissao_ini=data_emissao_ini, data_emissao_fim=data_emissao_fim,
        situacao_oc=situacao_oc, somente_pendentes=somente_pendentes,
        familia=familia, origem_material=origem_material, transacao=transacao,
    )

    rows, total_registros = _bi_supabase_get(
        "bi_compras",
        params=filtros,
        order="data_emissao.desc,numero_oc.desc,sequencia_item.asc",
        limit=tamanho_pagina,
        offset=offset,
    )
    total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros else 1

    return {
        "fonte": "BI (bi_compras)",
        "pagina": pagina,
        "tamanho_pagina": tamanho_pagina,
        "total_registros": total_registros,
        "total_paginas": total_paginas,
        "dados": rows,
    }


@app.get("/api/bi/painel-compras-dashboard")
def bi_painel_compras_dashboard(
    numero_projeto: Optional[str] = None,
    centro_custo: Optional[str] = None,
    tipo_despesa: Optional[str] = None,
    projeto_macro: Optional[str] = None,
    mes_competencia: Optional[str] = None,
    fornecedor: Optional[str] = None,
    descricao_item: Optional[str] = None,
    numero_oc: Optional[str] = None,
    data_emissao_ini: Optional[str] = None,
    data_emissao_fim: Optional[str] = None,
    situacao_oc: Optional[str] = None,
    somente_pendentes: bool = False,
    familia: Optional[str] = None,
    origem_material: Optional[str] = None,
    transacao: Optional[str] = None,
    usuario=Depends(validar_token),
):
    """KPIs e gráficos agregados de bi_compras. Sem paginação — pega
    TODA a base filtrada e agrega em Python (em bi_compras o volume é
    achatado, então isso é OK para o tamanho típico)."""
    _supabase_required()
    filtros = _bi_filtros_compras(
        numero_projeto=numero_projeto, centro_custo=centro_custo,
        tipo_despesa=tipo_despesa, projeto_macro=projeto_macro,
        mes_competencia=mes_competencia, fornecedor=fornecedor,
        descricao_item=descricao_item, numero_oc=numero_oc,
        data_emissao_ini=data_emissao_ini, data_emissao_fim=data_emissao_fim,
        situacao_oc=situacao_oc, somente_pendentes=somente_pendentes,
        familia=familia, origem_material=origem_material, transacao=transacao,
    )

    # Pagina internamente para evitar timeout em datasets grandes
    BATCH = 1000
    todas: list = []
    offset = 0
    while True:
        rows, _ = _bi_supabase_get("bi_compras", params=filtros,
                                    limit=BATCH, offset=offset)
        if not rows:
            break
        todas.extend(rows)
        if len(rows) < BATCH:
            break
        offset += BATCH
        if len(todas) >= 50000:  # safety cap V1
            break

    return {
        "fonte": "BI (bi_compras)",
        "kpis": _bi_kpis_compras(todas),
        "graficos": {
            "por_mes":           _bi_agrupar(todas, "mes_competencia"),
            "por_tipo_despesa":  _bi_agrupar(todas, "tipo_despesa", "tipo_despesa_label"),
            "por_projeto_macro": _bi_agrupar(todas, "projeto_macro"),
            "por_centro_custo":  _bi_agrupar(todas, "centro_custo", "descricao_centro_custo", top=15),
            "por_projeto":       _bi_agrupar(todas, "numero_projeto", "nome_projeto", top=15),
            "por_fornecedor":    _bi_agrupar(todas, "codigo_fornecedor", "nome_fornecedor", top=10),
        },
        "linhas_processadas": len(todas),
    }


