# ----- VALIDAÇÃO ERP × BI -----

def _normalizar_kpi_compras_erp(dashboard_response: dict) -> dict:
    """Achata o shape do /api/painel-compras-dashboard (ERP) para o
    shape canônico de comparação."""
    kpis = dashboard_response.get("kpis_dashboard") or {}
    kpis_legado = dashboard_response.get("kpis") or {}
    return {
        "valor_bruto": float(kpis_legado.get("valor_bruto_total") or 0),
        "valor_liquido": float(kpis.get("valor_comprado")
                                or kpis_legado.get("valor_liquido_total") or 0),
        "valor_pendente": float(kpis.get("valor_pendente")
                                 or kpis_legado.get("valor_pendente_total") or 0),
        "qtd_ocs": int(kpis.get("quantidade_ocs")
                       or kpis_legado.get("total_ocs") or 0),
        "qtd_itens": int(kpis.get("quantidade_itens")
                         or kpis_legado.get("total_linhas") or 0),
        "qtd_fornecedores": int(kpis.get("quantidade_fornecedores")
                                 or kpis_legado.get("total_fornecedores") or 0),
    }


def _normalizar_kpi_compras_bi(dashboard_response: dict) -> dict:
    kpis = dashboard_response.get("kpis") or {}
    return {
        "valor_bruto": float(kpis.get("valor_bruto") or 0),
        "valor_liquido": float(kpis.get("valor_liquido") or 0),
        "valor_pendente": float(kpis.get("valor_pendente") or 0),
        "qtd_ocs": int(kpis.get("qtd_ocs") or 0),
        "qtd_itens": int(kpis.get("qtd_itens") or 0),
        "qtd_fornecedores": int(kpis.get("qtd_fornecedores") or 0),
    }


def _diff_kpis(erp: dict, bi: dict) -> dict:
    out: dict = {}
    for k, ev in erp.items():
        bv = bi.get(k, 0)
        if isinstance(ev, float) or isinstance(bv, float):
            out[k] = round(float(bv) - float(ev), 2)
        else:
            out[k] = int(bv) - int(ev)
    return out


@app.get("/api/bi/validar-painel-compras")
def bi_validar_painel_compras(
    numero_projeto: Optional[str] = None,
    centro_custo: Optional[str] = None,
    tipo_despesa: Optional[str] = None,
    mes_competencia: Optional[str] = None,
    fornecedor: Optional[str] = None,
    data_emissao_ini: Optional[str] = None,
    data_emissao_fim: Optional[str] = None,
    situacao_oc: Optional[str] = None,
    somente_pendentes: bool = False,
    usuario=Depends(validar_token),
):
    """Compara KPIs ERP (painel-compras-dashboard) × BI (bi/painel-compras-dashboard)
    com os mesmos filtros. Usado para validar paridade antes de trocar a fonte."""
    _supabase_required()

    # ERP
    erp_dashboard = consultar_painel_compras_dashboard(
        numero_projeto=numero_projeto,
        centro_custo=centro_custo,
        tipo_despesa=tipo_despesa or "TODOS",
        mes_competencia=mes_competencia,
        fornecedor=fornecedor,
        data_emissao_ini=data_emissao_ini,
        data_emissao_fim=data_emissao_fim,
        situacao_oc=situacao_oc,
        somente_pendentes=somente_pendentes,
        usuario=usuario,
    )
    bi_dashboard = bi_painel_compras_dashboard(
        numero_projeto=numero_projeto,
        centro_custo=centro_custo,
        tipo_despesa=tipo_despesa,
        mes_competencia=mes_competencia,
        fornecedor=fornecedor,
        data_emissao_ini=data_emissao_ini,
        data_emissao_fim=data_emissao_fim,
        situacao_oc=situacao_oc,
        somente_pendentes=somente_pendentes,
        usuario=usuario,
    )

    erp_kpis = _normalizar_kpi_compras_erp(erp_dashboard)
    bi_kpis = _normalizar_kpi_compras_bi(bi_dashboard)
    diferencas = _diff_kpis(erp_kpis, bi_kpis)

    return {
        "filtros_aplicados": {
            "numero_projeto": numero_projeto,
            "centro_custo": centro_custo,
            "tipo_despesa": tipo_despesa,
            "mes_competencia": mes_competencia,
            "fornecedor": fornecedor,
            "data_emissao_ini": data_emissao_ini,
            "data_emissao_fim": data_emissao_fim,
            "situacao_oc": situacao_oc,
            "somente_pendentes": somente_pendentes,
        },
        "erp": erp_kpis,
        "bi": bi_kpis,
        "diferencas": diferencas,
        "observacao": (
            "diferencas = bi - erp. Zero em todas as linhas ⇒ paridade. "
            "Diferenças pequenas em valores (centavos) podem ser de "
            "arredondamento. Diferenças em qtd_* indicam ETL ainda não "
            "rodou para o período ou regra de classificação divergente."
        ),
    }


