@app.get("/api/senior/regras/clonar-de-e098reg/preview")
def senior_preview_clone_e098reg(
    codemp: int,
    modsis: str,
    idereg: str,
    codtns: str = "",
    usuario=Depends(validar_token),
):
    """Lê uma linha de E098REG e devolve um payload pronto para
    pré-preencher a modal 'Clonar para portal'. Frontend ainda precisa
    pedir o `fonte_lsp` (cola do Editor de Regras Senior) + `motivo`
    antes de fazer POST /api/senior/regras."""
    conn = get_connection()
    try:
        cursor = conn.cursor()
        row = _buscar_identificador_e098(cursor, codemp, modsis, idereg, codtns)
        if not row:
            raise HTTPException(
                status_code=404,
                detail=(
                    f"Identificador não encontrado em E098REG: "
                    f"codemp={codemp}, modsis={modsis}, idereg={idereg}, "
                    f"codtns={codtns!r}."
                ),
            )

        codreg = row.get("CODREG")
        if not codreg:
            raise HTTPException(
                status_code=409,
                detail=(
                    "Identificador sem CODREG vinculado. "
                    "Clonagem só faz sentido para identificadores com regra."
                ),
            )

        # Verifica se já existe regra no portal com esse CODREG_ERP (ou
        # com a mesma chave IDEREG/MODSIS/CODTNS) — evita duplicação.
        cursor.execute("""
            SELECT TOP 1
                ID_REGRA,
                NOME_REGRA,
                STATUS_REGRA,
                CONVERT(VARCHAR(19), DATA_CRIACAO, 120) AS DATA_CRIACAO
            FROM dbo.USU_SENIOR_REGRA
            WHERE (CODREG_ERP = ? AND ? > 0)
               OR (
                    COALESCE(MODSIS, '') = ?
                AND COALESCE(IDEREG, IDENTIFICADOR, '') = ?
                AND COALESCE(CODTNS, '') = ?
               )
            ORDER BY ID_REGRA DESC
        """, [
            int(codreg), int(codreg),
            (modsis or "").strip().upper(),
            (idereg or "").strip().upper(),
            (codtns or "").strip().upper(),
        ])
        existing = cursor.fetchone()
        existente_no_portal = None
        if existing:
            existente_no_portal = {
                "id_regra": int(existing[0]),
                "nome_regra": (existing[1] or "").strip(),
                "status_regra": (existing[2] or "").strip(),
                "data_criacao": existing[3],
            }

        modsis_clean = (row.get("MODSIS") or "").strip()
        idereg_clean = (row.get("IDEREG") or "").strip()
        nome_sugerido = f"Regra ERP {codreg} - {modsis_clean}-{idereg_clean}"

        return {
            "origem_erp": row,
            "ja_existe_no_portal": existente_no_portal is not None,
            "regra_existente_no_portal": existente_no_portal,
            "payload_sugerido": {
                "nome_regra": nome_sugerido,
                "codreg_erp": int(codreg),
                "codemp": int(row.get("CODEMP") or codemp),
                "modsis": modsis_clean,
                "idereg": idereg_clean,
                "codtns": (row.get("CODTNS") or "").strip(),
                "descricao": (row.get("DESREG") or "").strip(),
                "ambiente": "HOMOLOGACAO",
                "ticket": "",
                "motivo": "Clonada da E098REG para controle no portal",
                "fonte_lsp": "",  # frontend pede para o usuário colar
            },
            "instrucoes": (
                "1. Abra o Editor de Regras Senior. "
                "2. Localize a regra (CODREG=" + str(codreg) + "). "
                "3. Copie o fonte LSP. "
                "4. Cole no campo 'Fonte LSP' da modal. "
                "5. Confirme o motivo e clique em Clonar. "
                "A regra é criada com STATUS=RASCUNHO no portal — "
                "não altera nada no ERP."
            ),
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


# Endpoints /codigo, /importar-fonte, /fontes e /{id_regra}/codigo
# foram movidos para ANTES de /api/senior/regras/{id_regra} para
# evitar conflito de roteamento (FastAPI matcheia rotas na ordem
# de declaração — caso contrário /codigo seria interpretado como
# {id_regra: int} e falharia com 422).


# ============================================================
# AUDITORIA APONTAMENTO GENIUS — OPs Pintura/Jato com peso
# ============================================================
# Fase 1 (esta): peso calculado a partir de E900COP + E900EOQ + E900CMO + E075PRO
# Fase 2 (futura): explosão multinível para componentes produzidos Genius
# ============================================================

GENIUS_OPR_JATO = (2160, 2161)  # 2160=JATEAR AUTO, 2161=JATEAR MANUAL


def _ops_jato_peso_cte_multinivel(codemp: int, *, data_ini=None, data_fim=None,
                                   origem=None, numero_op=None,
                                   codigo_produto=None, situacao_op=None,
                                   ops_extras_where: str = "",
                                   nivel_max: int = 10) -> tuple[str, list]:
    """Constrói o CTE recursivo BOM multinível e retorna (sql_cte, params).
    O caller adiciona o SELECT final (agregado ou detalhe). Não inclui
    OPTION(MAXRECURSION) — caller anexa."""
    origens_sql = ", ".join(f"'{o}'" for o in GENIUS_ORIGENS)
    codopr_sql = ", ".join(str(c) for c in GENIUS_OPR_JATO)

    where_op: list = []
    params: list = [codemp]
    if data_ini:
        where_op.append("EOQ.DATREA >= ?")
        params.append(data_ini)
    if data_fim:
        where_op.append("EOQ.DATREA <= ?")
        params.append(data_fim)
    if origem:
        where_op.append("COP.CODORI = ?")
        params.append(str(origem).strip())
    if numero_op:
        where_op.append("COP.NUMORP = ?")
        params.append(int(numero_op))
    if codigo_produto:
        where_op.append("COP.CODPRO LIKE ?")
        params.append(f"%{codigo_produto.strip()}%")
    if situacao_op:
        where_op.append("COP.SITORP = ?")
        params.append(situacao_op.strip().upper())
    if ops_extras_where:
        where_op.append(ops_extras_where)
    where_op_sql = (" AND " + " AND ".join(where_op)) if where_op else ""

    cte = f"""
        WITH OpsJato AS (
            SELECT
                COP.CODEMP, COP.CODORI, COP.NUMORP, COP.CODPRO, COP.SITORP,
                MAX(EOQ.DATREA) AS DATA_JATO,
                COUNT(*) AS QTD_APONTAMENTOS_JATO
            FROM E900COP COP
            INNER JOIN E900EOQ EOQ
                    ON EOQ.CODEMP = COP.CODEMP
                   AND EOQ.CODORI = COP.CODORI
                   AND EOQ.NUMORP = COP.NUMORP
            WHERE COP.CODEMP = ?
              AND COP.CODORI IN ({origens_sql})
              AND EOQ.CODOPR IN ({codopr_sql})
              AND EOQ.DATREA > CONVERT(DATE, '19001231', 112)
              {where_op_sql}
            GROUP BY COP.CODEMP, COP.CODORI, COP.NUMORP, COP.CODPRO, COP.SITORP
        ),
        RaizComponentes AS (
            SELECT
                OJ.CODEMP, OJ.CODORI, OJ.NUMORP,
                OJ.CODPRO    AS CODPRO_OP,
                OJ.SITORP, OJ.DATA_JATO, OJ.QTD_APONTAMENTOS_JATO,
                1 AS NIVEL,
                CAST(OJ.CODPRO + '>' + CMO.CODCMP AS VARCHAR(1000)) AS CAMINHO,
                CMO.CODCMP   AS CODIGO_COMPONENTE,
                CMO.CODDER   AS DERIVACAO_COMPONENTE,
                CAST(CMO.QTDPRV AS FLOAT) AS QTD_NIVEL,
                CAST(CMO.QTDPRV AS FLOAT) AS QTD_ACUMULADA,
                CMO.UNIMED   AS UNIDADE,
                0 AS CICLO_DETECTADO
            FROM OpsJato OJ
            INNER JOIN E900CMO CMO
                    ON CMO.CODEMP = OJ.CODEMP
                   AND CMO.CODORI = OJ.CODORI
                   AND CMO.NUMORP = OJ.NUMORP
        ),
        BomRecursiva AS (
            SELECT
                R.CODEMP, R.CODORI, R.NUMORP, R.CODPRO_OP,
                R.SITORP, R.DATA_JATO, R.QTD_APONTAMENTOS_JATO,
                R.NIVEL, R.CAMINHO,
                R.CODIGO_COMPONENTE, R.DERIVACAO_COMPONENTE,
                R.QTD_NIVEL, R.QTD_ACUMULADA, R.UNIDADE,
                R.CICLO_DETECTADO
            FROM RaizComponentes R
            UNION ALL
            SELECT
                B.CODEMP, B.CODORI, B.NUMORP, B.CODPRO_OP,
                B.SITORP, B.DATA_JATO, B.QTD_APONTAMENTOS_JATO,
                B.NIVEL + 1 AS NIVEL,
                CAST(B.CAMINHO + '>' + CT.CODCMP AS VARCHAR(1000)) AS CAMINHO,
                CT.CODCMP AS CODIGO_COMPONENTE,
                CT.DERCMP AS DERIVACAO_COMPONENTE,
                CAST(CT.QTDUTI AS FLOAT) AS QTD_NIVEL,
                CAST(B.QTD_ACUMULADA * CT.QTDUTI AS FLOAT) AS QTD_ACUMULADA,
                CT.UNIME2 AS UNIDADE,
                CASE
                    WHEN CHARINDEX('>' + CT.CODCMP + '>', '>' + B.CAMINHO + '>') > 0
                    THEN 1 ELSE 0
                END AS CICLO_DETECTADO
            FROM BomRecursiva B
            INNER JOIN E700CTM CT
                    ON CT.CODEMP = B.CODEMP
                   AND CT.CODMOD = B.CODIGO_COMPONENTE
                   AND (
                        B.DERIVACAO_COMPONENTE IS NULL
                        OR B.DERIVACAO_COMPONENTE = ''
                        OR CT.CODDER = B.DERIVACAO_COMPONENTE
                   )
            WHERE B.NIVEL < {int(nivel_max)}
              AND B.CICLO_DETECTADO = 0
        ),
        BomEnriquecida AS (
            SELECT
                B.CODEMP, B.CODORI, B.NUMORP, B.CODPRO_OP,
                B.SITORP, B.DATA_JATO, B.QTD_APONTAMENTOS_JATO,
                B.NIVEL, B.CAMINHO,
                B.CODIGO_COMPONENTE, B.DERIVACAO_COMPONENTE,
                B.QTD_NIVEL, B.QTD_ACUMULADA, B.UNIDADE,
                B.CICLO_DETECTADO,
                PRO.DESPRO   AS DESCRICAO_COMPONENTE,
                PRO.TIPPRO   AS TIPO_PRODUTO,
                PRO.CODORI   AS ORIGEM_COMPONENTE,
                CAST(COALESCE(DER.PESLIQ, PRO.PESLIQ, 0) AS FLOAT) AS PESO_UNITARIO,
                CASE
                    WHEN PRO.CODORI IN ({origens_sql})
                     AND EXISTS (
                            SELECT 1 FROM E700CTM CTX
                            WHERE CTX.CODEMP = B.CODEMP
                              AND CTX.CODMOD = B.CODIGO_COMPONENTE
                        )
                    THEN 1 ELSE 0
                END AS DEVE_EXPANDIR
            FROM BomRecursiva B
            LEFT JOIN E075PRO PRO
                   ON PRO.CODEMP = B.CODEMP
                  AND PRO.CODPRO = B.CODIGO_COMPONENTE
            LEFT JOIN E075DER DER
                   ON DER.CODEMP = B.CODEMP
                  AND DER.CODPRO = B.CODIGO_COMPONENTE
                  AND DER.CODDER = B.DERIVACAO_COMPONENTE
        ),
        Folhas AS (
            SELECT
                B.*,
                CASE WHEN B.DEVE_EXPANDIR = 1 THEN 0 ELSE 1 END AS COMPONENTE_FINAL,
                CASE
                    WHEN B.DEVE_EXPANDIR = 1 THEN CAST(0 AS FLOAT)
                    WHEN UPPER(LTRIM(RTRIM(COALESCE(B.UNIDADE, '')))) = 'KG'
                        THEN COALESCE(B.QTD_ACUMULADA, 0)
                    ELSE COALESCE(B.QTD_ACUMULADA, 0) * COALESCE(B.PESO_UNITARIO, 0)
                END AS PESO_KG_CALCULADO
            FROM BomEnriquecida B
        )
    """
    return cte, params


@app.get("/api/auditoria-apontamento-genius/ops-jato-peso")
def auditoria_genius_ops_jato_peso(
    codemp: int = EMPRESA_PADRAO,
    data_ini: Optional[str] = None,
    data_fim: Optional[str] = None,
    origem: Optional[str] = None,
    numero_op: Optional[int] = None,
    codigo_produto: Optional[str] = None,
    situacao_op: Optional[str] = None,
    somente_com_peso: bool = False,
    somente_sem_peso: bool = False,
    somente_peso_parcial: bool = False,
    usar_multinivel: bool = False,
    nivel_maximo: int = 10,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token),
):
    """Lista OPs Genius que passaram pelo JATO/Pintura (CODOPR 2160/2161)
    e calcula o peso em KG via componentes reais da OP (E900CMO + E075PRO).

    Fase 1: peso baseado no nível imediato dos componentes em E900CMO.
            Componentes que também são produzidos Genius mostram peso 0
            quando seu PESLIQ não está cadastrado — a fase 2 explodirá
            esses subconjuntos.

    Status do peso:
      - SEM_COMPONENTES_E900CMO: OP sem componentes mapeados
      - PESO_ZERO: tem componentes, mas nenhum calculou peso
      - PESO_PARCIAL: alguns componentes sem PESLIQ
      - OK: todos os componentes calcularam peso

    Fase 2 (`usar_multinivel=true`): explode E700CTM até chegar em itens
    finais. Adiciona campos qtd_componentes_finais/expandidos, nivel_maximo,
    qtd_ciclos e peso_kg_multinivel."""
    pagina = max(1, int(pagina or 1))
    tamanho_pagina = max(1, min(int(tamanho_pagina or 100), 500))
    offset = (pagina - 1) * tamanho_pagina
    nivel_maximo = max(1, min(int(nivel_maximo or 10), 20))

    # Datas: pyodbc + SQL Server falham na conversão implícita nvarchar→datetime
    # dependendo da configuração regional. Converte para `date` no Python.
    def _parse_data(v):
        if v is None or v == "":
            return None
        if isinstance(v, date):
            return v
        return datetime.strptime(str(v)[:10], "%Y-%m-%d").date()
    data_ini = _parse_data(data_ini)
    data_fim = _parse_data(data_fim)

    # ------------------------------------------------------------------
    # Fase 2 — multinivel via CTE recursiva (E700CTM)
    # ------------------------------------------------------------------
    if usar_multinivel:
        cte_sql, params_base = _ops_jato_peso_cte_multinivel(
            codemp,
            data_ini=data_ini, data_fim=data_fim,
            origem=origem, numero_op=numero_op,
            codigo_produto=codigo_produto, situacao_op=situacao_op,
            nivel_max=nivel_maximo,
        )

        having_peso: list = []
        if somente_com_peso:
            having_peso.append("agregado.peso_kg_multinivel > 0")
        if somente_sem_peso:
            having_peso.append("agregado.peso_kg_multinivel = 0")
        if somente_peso_parcial:
            having_peso.append("agregado.status_peso = 'PESO_PARCIAL'")
        having_sql = (" WHERE " + " AND ".join(having_peso)) if having_peso else ""

        select_agregado = """
            SELECT
                F.CODEMP                                       AS CODEMP,
                F.CODORI                                       AS origem,
                F.NUMORP                                       AS numero_op,
                F.CODPRO_OP                                    AS codigo_produto,
                COALESCE(PRO_OP.DESPRO, '')                    AS descricao_produto,
                F.SITORP                                       AS situacao_op,
                CONVERT(VARCHAR(10), F.DATA_JATO, 120)         AS data_jato,
                F.QTD_APONTAMENTOS_JATO                        AS qtd_apontamentos_jato,
                COUNT(CASE WHEN F.NIVEL = 1 THEN 1 END)        AS qtd_componentes_diretos,
                COUNT(CASE WHEN F.COMPONENTE_FINAL = 1 THEN 1 END) AS qtd_componentes_finais,
                COUNT(CASE WHEN F.DEVE_EXPANDIR = 1 THEN 1 END)    AS qtd_componentes_expandidos,
                SUM(CASE WHEN F.CICLO_DETECTADO = 1 THEN 1 ELSE 0 END) AS qtd_ciclos,
                SUM(
                    CASE WHEN F.COMPONENTE_FINAL = 1
                          AND COALESCE(F.PESO_KG_CALCULADO, 0) = 0
                         THEN 1 ELSE 0 END
                ) AS qtd_componentes_sem_peso,
                MAX(F.NIVEL)                                   AS nivel_maximo_encontrado,
                CAST(SUM(
                    CASE WHEN F.COMPONENTE_FINAL = 1
                         THEN COALESCE(F.PESO_KG_CALCULADO, 0)
                         ELSE 0 END
                ) AS FLOAT)                                    AS peso_kg_multinivel,
                CASE
                    WHEN COUNT(*) = 0 THEN 'SEM_COMPONENTES_E900CMO'
                    WHEN SUM(CASE WHEN F.CICLO_DETECTADO = 1 THEN 1 ELSE 0 END) > 0
                        THEN 'CICLO_BOM'
                    WHEN SUM(
                            CASE WHEN F.COMPONENTE_FINAL = 1
                                  AND COALESCE(F.PESO_KG_CALCULADO, 0) = 0
                                 THEN 1 ELSE 0 END
                         ) > 0
                     AND SUM(
                            CASE WHEN F.COMPONENTE_FINAL = 1
                                 THEN COALESCE(F.PESO_KG_CALCULADO, 0)
                                 ELSE 0 END
                         ) > 0
                        THEN 'PESO_PARCIAL'
                    WHEN SUM(
                            CASE WHEN F.COMPONENTE_FINAL = 1
                                 THEN COALESCE(F.PESO_KG_CALCULADO, 0)
                                 ELSE 0 END
                         ) = 0
                        THEN 'PESO_ZERO'
                    ELSE 'OK'
                END AS status_peso
            FROM Folhas F
            LEFT JOIN E075PRO PRO_OP
                   ON PRO_OP.CODEMP = F.CODEMP
                  AND PRO_OP.CODPRO = F.CODPRO_OP
            GROUP BY
                F.CODEMP, F.CODORI, F.NUMORP, F.CODPRO_OP,
                PRO_OP.DESPRO, F.SITORP, F.DATA_JATO, F.QTD_APONTAMENTOS_JATO
        """

        sql_total = cte_sql + f"""
            SELECT COUNT(*) FROM (
                {select_agregado}
            ) agregado
            {having_sql}
            OPTION (MAXRECURSION {nivel_maximo})
        """
        sql_resumo = cte_sql + f"""
            SELECT
                COUNT(*) AS total_ops,
                SUM(CASE WHEN agregado.peso_kg_multinivel > 0 THEN 1 ELSE 0 END) AS ops_com_peso,
                SUM(CASE WHEN agregado.peso_kg_multinivel = 0 THEN 1 ELSE 0 END) AS ops_sem_peso,
                SUM(CASE WHEN agregado.status_peso = 'PESO_PARCIAL' THEN 1 ELSE 0 END) AS ops_peso_parcial,
                SUM(CASE WHEN agregado.qtd_ciclos > 0 THEN 1 ELSE 0 END) AS ops_com_ciclo,
                CAST(SUM(COALESCE(agregado.peso_kg_multinivel, 0)) AS FLOAT) AS peso_total_kg_multinivel,
                MAX(agregado.nivel_maximo_encontrado) AS maior_nivel_encontrado
            FROM (
                {select_agregado}
            ) agregado
            {having_sql}
            OPTION (MAXRECURSION {nivel_maximo})
        """
        sql_dados = cte_sql + f"""
            SELECT *
            FROM (
                {select_agregado}
            ) agregado
            {having_sql}
            ORDER BY agregado.origem, agregado.numero_op
            OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
            OPTION (MAXRECURSION {nivel_maximo})
        """

        conn = get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(sql_total, params_base)
            total_registros = int(cursor.fetchone()[0] or 0)

            cursor.execute(sql_resumo, params_base)
            row_r = cursor.fetchone()
            resumo = {
                "total_ops": int(row_r[0] or 0),
                "ops_com_peso": int(row_r[1] or 0),
                "ops_sem_peso": int(row_r[2] or 0),
                "ops_peso_parcial": int(row_r[3] or 0),
                "ops_com_ciclo": int(row_r[4] or 0),
                "peso_total_kg_multinivel": round(float(row_r[5] or 0), 3),
                "maior_nivel_encontrado": int(row_r[6] or 0),
            }

            cursor.execute(sql_dados, params_base + [offset, tamanho_pagina])
            cols = [c[0] for c in cursor.description]
            dados = []
            for row in cursor.fetchall():
                item = {}
                for i, c in enumerate(cols):
                    v = row[i]
                    if isinstance(v, str):
                        v = v.strip()
                    item[c] = v
                # Remove CODEMP do payload (interno)
                item.pop("CODEMP", None)
                if item.get("peso_kg_multinivel") is not None:
                    item["peso_kg_multinivel"] = round(float(item["peso_kg_multinivel"]), 3)
                # Compat com Fase 1: peso_kg_direto fica None
                item["peso_kg_direto"] = None
                dados.append(item)

            total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros else 0
            return {
                "modo": "MULTINIVEL",
                "nivel_maximo": nivel_maximo,
                "pagina": pagina,
                "tamanho_pagina": tamanho_pagina,
                "total_registros": total_registros,
                "total_paginas": total_paginas,
                "dados": dados,
                "resumo": resumo,
                "filtros_aplicados": {
                    "codemp": codemp,
                    "data_ini": data_ini, "data_fim": data_fim,
                    "origem": origem, "numero_op": numero_op,
                    "codigo_produto": codigo_produto, "situacao_op": situacao_op,
                    "somente_com_peso": somente_com_peso,
                    "somente_sem_peso": somente_sem_peso,
                    "somente_peso_parcial": somente_peso_parcial,
                    "usar_multinivel": True,
                    "nivel_maximo": nivel_maximo,
                },
                "observacao": (
                    "Peso via CTE recursiva (E900CMO → E700CTM). Subconjuntos "
                    "produzidos Genius são EXPANDIDOS até chegar em itens "
                    "finais (TIPPRO='C' OU origem fora Genius OU sem modelo). "
                    f"MAXRECURSION={nivel_maximo}. Ciclos detectados via "
                    "CHARINDEX no caminho."
                ),
            }
        finally:
            try:
                conn.close()
            except Exception:
                pass

    # ------------------------------------------------------------------
    # Fase 1 — peso direto (default — `usar_multinivel=false`)
    # ------------------------------------------------------------------

    # WHERE dinâmico da CTE OpsJato (origens fixas + filtros opcionais)
    origens_sql = ", ".join(f"'{o}'" for o in GENIUS_ORIGENS)
    where_op: list = []
    params_base: list = [codemp]

    if data_ini:
        where_op.append("EOQ.DATREA >= ?")
        params_base.append(data_ini)
    if data_fim:
        where_op.append("EOQ.DATREA <= ?")
        params_base.append(data_fim)
    if origem:
        where_op.append("COP.CODORI = ?")
        params_base.append(str(origem).strip())
    if numero_op:
        where_op.append("COP.NUMORP = ?")
        params_base.append(int(numero_op))
    if codigo_produto:
        where_op.append("COP.CODPRO LIKE ?")
        params_base.append(f"%{codigo_produto.strip()}%")
    if situacao_op:
        where_op.append("COP.SITORP = ?")
        params_base.append(situacao_op.strip().upper())

    where_op_sql = (" AND " + " AND ".join(where_op)) if where_op else ""

    # Filtros pós-agregação por peso
    having_peso: list = []
    if somente_com_peso:
        having_peso.append("COALESCE(P.PESO_KG_COMPONENTES, 0) > 0")
    if somente_sem_peso:
        having_peso.append("COALESCE(P.PESO_KG_COMPONENTES, 0) = 0")
    where_peso_sql = (" AND " + " AND ".join(having_peso)) if having_peso else ""

    cte_sql = f"""
        WITH OpsJato AS (
            SELECT
                COP.CODEMP,
                COP.CODORI,
                COP.NUMORP,
                COP.CODPRO,
                COP.SITORP,
                MAX(EOQ.DATREA) AS DATA_JATO,
                COUNT(*) AS QTD_APONTAMENTOS_JATO
            FROM E900COP COP
            INNER JOIN E900EOQ EOQ
                    ON EOQ.CODEMP = COP.CODEMP
                   AND EOQ.CODORI = COP.CODORI
                   AND EOQ.NUMORP = COP.NUMORP
            WHERE COP.CODEMP = ?
              AND COP.CODORI IN ({origens_sql})
              AND EOQ.CODOPR IN ({", ".join(str(c) for c in GENIUS_OPR_JATO)})
              AND EOQ.DATREA > CONVERT(DATE, '19001231', 112)
              {where_op_sql}
            GROUP BY
                COP.CODEMP, COP.CODORI, COP.NUMORP, COP.CODPRO, COP.SITORP
        ),
        ComponentesOP AS (
            SELECT
                OJ.CODEMP,
                OJ.CODORI,
                OJ.NUMORP,
                OJ.CODPRO   AS CODPRO_OP,
                OJ.SITORP,
                OJ.DATA_JATO,
                OJ.QTD_APONTAMENTOS_JATO,
                CMO.CODCMP  AS COMPONENTE,
                CMO.QTDPRV  AS QTD_PREVISTA,
                CMO.UNIMED  AS UNIDADE,
                PRO.DESPRO  AS DESCRICAO_COMPONENTE,
                PRO.TIPPRO  AS TIPO_PRODUTO,
                PRO.CODORI  AS ORIGEM_COMPONENTE,
                COALESCE(PRO.PESLIQ, 0) AS PESO_UNITARIO
            FROM OpsJato OJ
            LEFT JOIN E900CMO CMO
                   ON CMO.CODEMP = OJ.CODEMP
                  AND CMO.CODORI = OJ.CODORI
                  AND CMO.NUMORP = OJ.NUMORP
            LEFT JOIN E075PRO PRO
                   ON PRO.CODEMP = CMO.CODEMP
                  AND PRO.CODPRO = CMO.CODCMP
        ),
        PesoOP AS (
            SELECT
                C.CODEMP,
                C.CODORI,
                C.NUMORP,
                C.CODPRO_OP,
                C.SITORP,
                C.DATA_JATO,
                C.QTD_APONTAMENTOS_JATO,
                COUNT(C.COMPONENTE) AS QTD_COMPONENTES,
                CAST(SUM(
                    CASE
                        WHEN UPPER(LTRIM(RTRIM(COALESCE(C.UNIDADE, '')))) = 'KG'
                            THEN COALESCE(C.QTD_PREVISTA, 0)
                        ELSE COALESCE(C.QTD_PREVISTA, 0) * COALESCE(C.PESO_UNITARIO, 0)
                    END
                ) AS FLOAT) AS PESO_KG_COMPONENTES,
                SUM(CASE WHEN C.COMPONENTE IS NULL THEN 1 ELSE 0 END) AS SEM_COMPONENTE,
                SUM(
                    CASE
                        WHEN (
                            CASE
                                WHEN UPPER(LTRIM(RTRIM(COALESCE(C.UNIDADE, '')))) = 'KG'
                                    THEN COALESCE(C.QTD_PREVISTA, 0)
                                ELSE COALESCE(C.QTD_PREVISTA, 0) * COALESCE(C.PESO_UNITARIO, 0)
                            END
                        ) = 0 AND C.COMPONENTE IS NOT NULL THEN 1
                        ELSE 0
                    END
                ) AS QTD_COMPONENTES_SEM_PESO
            FROM ComponentesOP C
            -- Filtro: considera só componentes finais (comprados ou origem não-Genius)
            WHERE (
                C.TIPO_PRODUTO = 'C'
                OR C.ORIGEM_COMPONENTE NOT IN ({origens_sql})
                OR C.COMPONENTE IS NULL
            )
            GROUP BY
                C.CODEMP, C.CODORI, C.NUMORP, C.CODPRO_OP, C.SITORP,
                C.DATA_JATO, C.QTD_APONTAMENTOS_JATO
        )
    """

    # SELECT base aplicado em duas formas: COUNT (para total) e SELECT detalhado paginado
    select_dados = f"""
        SELECT
            P.CODORI                                  AS origem,
            P.NUMORP                                  AS numero_op,
            P.CODPRO_OP                               AS codigo_produto,
            COALESCE(PRO.DESPRO, '')                  AS descricao_produto,
            P.SITORP                                  AS situacao_op,
            CONVERT(VARCHAR(10), P.DATA_JATO, 120)    AS data_jato,
            P.QTD_APONTAMENTOS_JATO                   AS qtd_apontamentos_jato,
            P.QTD_COMPONENTES                         AS qtd_componentes,
            COALESCE(P.PESO_KG_COMPONENTES, 0)        AS peso_kg_componentes,
            P.QTD_COMPONENTES_SEM_PESO                AS qtd_componentes_sem_peso,
            CASE
                WHEN P.QTD_COMPONENTES = 0 THEN 'SEM_COMPONENTES_E900CMO'
                WHEN COALESCE(P.PESO_KG_COMPONENTES, 0) = 0 THEN 'PESO_ZERO'
                WHEN P.QTD_COMPONENTES_SEM_PESO > 0 THEN 'PESO_PARCIAL'
                ELSE 'OK'
            END AS status_peso
        FROM PesoOP P
        LEFT JOIN E075PRO PRO
               ON PRO.CODEMP = P.CODEMP
              AND PRO.CODPRO = P.CODPRO_OP
        WHERE 1=1 {where_peso_sql}
    """

    conn = get_connection()
    try:
        cursor = conn.cursor()

        # ---- COUNT ----
        sql_total = cte_sql + f"""
            SELECT COUNT(*)
            FROM ({select_dados}) X
        """
        cursor.execute(sql_total, params_base)
        total_registros = int(cursor.fetchone()[0] or 0)

        # ---- RESUMO ----
        sql_resumo = cte_sql + f"""
            SELECT
                COUNT(*) AS total_ops,
                SUM(CASE WHEN qtd_componentes > 0 THEN 1 ELSE 0 END)  AS ops_com_componentes,
                SUM(CASE WHEN qtd_componentes = 0 THEN 1 ELSE 0 END)  AS ops_sem_componentes,
                CAST(SUM(COALESCE(peso_kg_componentes, 0)) AS FLOAT) AS peso_total_kg,
                SUM(CASE WHEN COALESCE(peso_kg_componentes, 0) > 0 THEN 1 ELSE 0 END) AS ops_com_peso,
                SUM(CASE WHEN COALESCE(peso_kg_componentes, 0) = 0 THEN 1 ELSE 0 END) AS ops_sem_peso,
                SUM(CASE WHEN status_peso = 'PESO_PARCIAL' THEN 1 ELSE 0 END) AS ops_peso_parcial
            FROM ({select_dados}) X
        """
        cursor.execute(sql_resumo, params_base)
        row_r = cursor.fetchone()
        resumo = {
            "total_ops": int(row_r[0] or 0),
            "ops_com_componentes": int(row_r[1] or 0),
            "ops_sem_componentes": int(row_r[2] or 0),
            "peso_total_kg": round(float(row_r[3] or 0), 3),
            "ops_com_peso": int(row_r[4] or 0),
            "ops_sem_peso": int(row_r[5] or 0),
            "ops_peso_parcial": int(row_r[6] or 0),
        }

        # ---- DADOS PAGINADOS ----
        sql_dados = cte_sql + f"""
            {select_dados}
            ORDER BY P.CODORI, P.NUMORP
            OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
        """
        cursor.execute(sql_dados, params_base + [offset, tamanho_pagina])
        cols = [c[0] for c in cursor.description]
        dados = []
        for row in cursor.fetchall():
            item = {}
            for i, c in enumerate(cols):
                v = row[i]
                if isinstance(v, str):
                    v = v.strip()
                item[c] = v
            # Arredonda o peso para apresentação
            if item.get("peso_kg_componentes") is not None:
                item["peso_kg_componentes"] = round(float(item["peso_kg_componentes"]), 3)
            dados.append(item)

        total_paginas = (total_registros + tamanho_pagina - 1) // tamanho_pagina if total_registros else 0

        return {
            "pagina": pagina,
            "tamanho_pagina": tamanho_pagina,
            "total_registros": total_registros,
            "total_paginas": total_paginas,
            "dados": dados,
            "resumo": resumo,
            "filtros_aplicados": {
                "codemp": codemp,
                "data_ini": data_ini,
                "data_fim": data_fim,
                "origem": origem,
                "numero_op": numero_op,
                "codigo_produto": codigo_produto,
                "situacao_op": situacao_op,
                "somente_com_peso": somente_com_peso,
                "somente_sem_peso": somente_sem_peso,
            },
            "observacao": (
                "Peso calculado pelos componentes em E900CMO × E075PRO.PESLIQ. "
                "Não é peso de balança. Componentes que também são produzidos "
                "Genius e estão sem PESLIQ cadastrado mostram peso 0 — fase 2 "
                "explodirá esses subconjuntos multinível."
            ),
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.get("/api/auditoria-apontamento-genius/ops-jato-peso/{origem}/{numero_op}/componentes")
def auditoria_genius_ops_jato_componentes(
    origem: str,
    numero_op: int,
    codemp: int = EMPRESA_PADRAO,
    nivel_maximo: int = 10,
    incluir_expandidos: bool = True,
    usuario=Depends(validar_token),
):
    """Retorna a árvore aberta de componentes multinível de UMA OP
    específica. Frontend usa para o modal/drawer 'Ver componentes' que
    mostra a explosão da estrutura."""
    nivel_maximo = max(1, min(int(nivel_maximo or 10), 20))

    cte_sql, params_base = _ops_jato_peso_cte_multinivel(
        codemp,
        origem=origem,
        numero_op=numero_op,
        nivel_max=nivel_maximo,
    )

    sql_detalhe = cte_sql + f"""
        SELECT
            F.NIVEL                                       AS nivel,
            F.CAMINHO                                     AS caminho,
            F.CODPRO_OP                                   AS codigo_pai_op,
            F.CODIGO_COMPONENTE                           AS codigo_componente,
            F.DERIVACAO_COMPONENTE                        AS derivacao_componente,
            COALESCE(F.DESCRICAO_COMPONENTE, '')          AS descricao_componente,
            F.TIPO_PRODUTO                                AS tipo_produto,
            F.ORIGEM_COMPONENTE                           AS origem_componente,
            CAST(F.QTD_NIVEL AS FLOAT)                    AS quantidade_nivel,
            CAST(F.QTD_ACUMULADA AS FLOAT)                AS quantidade_acumulada,
            F.UNIDADE                                     AS unidade,
            CAST(F.PESO_UNITARIO AS FLOAT)                AS peso_unitario,
            CAST(F.PESO_KG_CALCULADO AS FLOAT)            AS peso_calculado,
            CASE WHEN F.DEVE_EXPANDIR = 1 THEN 1 ELSE 0 END AS foi_expandido,
            CASE WHEN F.COMPONENTE_FINAL = 1 THEN 1 ELSE 0 END AS componente_final,
            CASE WHEN F.CICLO_DETECTADO = 1 THEN 1 ELSE 0 END AS ciclo_detectado
        FROM Folhas F
        ORDER BY F.NIVEL, F.CAMINHO, F.CODIGO_COMPONENTE
        OPTION (MAXRECURSION {nivel_maximo})
    """

    conn = get_connection()
    try:
        cursor = conn.cursor()
        cursor.execute(sql_detalhe, params_base)
        cols = [c[0] for c in cursor.description]
        componentes = []
        peso_total = 0.0
        nivel_max_encontrado = 0
        for row in cursor.fetchall():
            item = {}
            for i, c in enumerate(cols):
                v = row[i]
                if isinstance(v, str):
                    v = v.strip()
                item[c] = v
            # Booleanos pra ficar mais natural no frontend
            item["foi_expandido"] = bool(item.get("foi_expandido"))
            item["componente_final"] = bool(item.get("componente_final"))
            item["ciclo_detectado"] = bool(item.get("ciclo_detectado"))
            # Rounds
            for k in ("quantidade_nivel", "quantidade_acumulada", "peso_unitario", "peso_calculado"):
                if item.get(k) is not None:
                    item[k] = round(float(item[k]), 4)
            nivel_max_encontrado = max(nivel_max_encontrado, int(item.get("nivel") or 0))
            if item["componente_final"]:
                peso_total += float(item.get("peso_calculado") or 0)
            componentes.append(item)

        if not componentes:
            raise HTTPException(
                status_code=404,
                detail=f"OP não encontrada ou sem apontamento de JATO: origem={origem} numero_op={numero_op}",
            )

        if not incluir_expandidos:
            componentes = [c for c in componentes if c["componente_final"] or c["nivel"] == 1]

        # Cabeçalho da OP (codpro, descrição) — pega da primeira linha
        primeiro = componentes[0] if componentes else {}
        produto_op = primeiro.get("codigo_pai_op")

        # Buscar descrição do produto da OP
        descricao_op = ""
        try:
            cursor.execute(
                "SELECT TOP 1 DESPRO FROM E075PRO WHERE CODEMP = ? AND CODPRO = ?",
                [codemp, produto_op],
            )
            r = cursor.fetchone()
            if r and r[0]:
                descricao_op = r[0].strip() if isinstance(r[0], str) else r[0]
        except Exception:
            pass

        return {
            "codemp": codemp,
            "origem": origem,
            "numero_op": numero_op,
            "produto_op": produto_op,
            "descricao_produto": descricao_op,
            "peso_kg_multinivel": round(peso_total, 3),
            "nivel_maximo": nivel_maximo,
            "nivel_maximo_encontrado": nivel_max_encontrado,
            "qtd_total_linhas": len(componentes),
            "qtd_componentes_finais": sum(1 for c in componentes if c["componente_final"]),
            "qtd_componentes_expandidos": sum(1 for c in componentes if c["foi_expandido"]),
            "qtd_ciclos": sum(1 for c in componentes if c["ciclo_detectado"]),
            "componentes": componentes,
            "observacao": (
                "Árvore completa de componentes da OP. Itens com "
                "foi_expandido=true são subconjuntos Genius já explodidos "
                "(não somam peso direto). Itens com componente_final=true "
                "são os que contribuem com peso_kg_multinivel."
            ),
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.get("/api/export/auditoria-apontamento-genius/ops-jato-peso")
def exportar_auditoria_genius_ops_jato_peso(
    codemp: int = EMPRESA_PADRAO,
    data_ini: Optional[str] = None,
    data_fim: Optional[str] = None,
    origem: Optional[str] = None,
    numero_op: Optional[int] = None,
    codigo_produto: Optional[str] = None,
    situacao_op: Optional[str] = None,
    somente_com_peso: bool = False,
    somente_sem_peso: bool = False,
    somente_peso_parcial: bool = False,
    usar_multinivel: bool = False,
    nivel_maximo: int = 10,
    usuario=Depends(validar_token_download),
):
    """Exporta para Excel todas as OPs (sem paginação) usando o mesmo
    filtro do endpoint principal. Aceita `usar_multinivel` para incluir
    o peso explodido via E700CTM."""
    dados = _collect_paginated_data(
        auditoria_genius_ops_jato_peso,
        usuario,
        batch_size=500,
        max_pages=5000,
        codemp=codemp,
        data_ini=data_ini,
        data_fim=data_fim,
        origem=origem,
        numero_op=numero_op,
        codigo_produto=codigo_produto,
        situacao_op=situacao_op,
        somente_com_peso=somente_com_peso,
        somente_sem_peso=somente_sem_peso,
        somente_peso_parcial=somente_peso_parcial,
        usar_multinivel=usar_multinivel,
        nivel_maximo=nivel_maximo,
    )
    if usar_multinivel:
        cabecalhos = {
            "origem": "Origem",
            "numero_op": "Número OP",
            "codigo_produto": "Cód. Produto",
            "descricao_produto": "Descrição Produto",
            "situacao_op": "Sit. OP",
            "data_jato": "Data JATO",
            "qtd_apontamentos_jato": "Qtd. Apontamentos",
            "qtd_componentes_diretos": "Qtd. Comp. Diretos",
            "qtd_componentes_finais": "Qtd. Comp. Finais",
            "qtd_componentes_expandidos": "Qtd. Comp. Expandidos",
            "qtd_componentes_sem_peso": "Componentes sem Peso",
            "qtd_ciclos": "Ciclos Detectados",
            "nivel_maximo_encontrado": "Nível Máximo",
            "peso_kg_multinivel": "Peso KG Multinível",
            "status_peso": "Status Peso",
        }
        nome = "auditoria_genius_ops_jato_peso_multinivel.xlsx"
    else:
        cabecalhos = {
            "origem": "Origem",
            "numero_op": "Número OP",
            "codigo_produto": "Cód. Produto",
            "descricao_produto": "Descrição Produto",
            "situacao_op": "Sit. OP",
            "data_jato": "Data JATO",
            "qtd_apontamentos_jato": "Qtd. Apontamentos",
            "qtd_componentes": "Qtd. Componentes",
            "peso_kg_componentes": "Peso (KG)",
            "qtd_componentes_sem_peso": "Componentes sem Peso",
            "status_peso": "Status Peso",
        }
        nome = "auditoria_genius_ops_jato_peso.xlsx"
    return _xlsx_response(nome, [("OPs JATO/Pintura", dados, cabecalhos)])


# ============================================================
# CONTABILIDADE — Balanço Patrimonial
# Módulo separado do Faturamento/Comercial. Lê V_BALANCO_PATRIMONIAL.
# ============================================================


@app.get("/api/contabilidade/balanco/colunas")
def contabilidade_balanco_colunas(usuario=Depends(validar_token)):
    """Diagnóstico: lista as colunas reais de V_BALANCO_PATRIMONIAL.
    Use para confirmar nomes antes de bater os campos do frontend."""
    conn = get_connection()
    try:
        cursor = conn.cursor()
        cursor.execute("""
            SELECT
                COLUMN_NAME, DATA_TYPE, CHARACTER_MAXIMUM_LENGTH,
                IS_NULLABLE, ORDINAL_POSITION
            FROM INFORMATION_SCHEMA.COLUMNS
            WHERE TABLE_SCHEMA = ?
              AND TABLE_NAME = 'V_BALANCO_PATRIMONIAL'
            ORDER BY ORDINAL_POSITION
        """, [SCHEMA_CONTABILIDADE])
        cols = [c[0] for c in cursor.description]
        dados = []
        for row in cursor.fetchall():
            item = {}
            for i, c in enumerate(cols):
                v = row[i]
                if isinstance(v, str):
                    v = v.strip()
                item[c.lower()] = v
            dados.append(item)
        if not dados:
            raise HTTPException(
                status_code=404,
                detail=f"View {OBJ_V_BALANCO_PATRIMONIAL} não encontrada no schema.",
            )
        return {
            "view": OBJ_V_BALANCO_PATRIMONIAL,
            "total_colunas": len(dados),
            "colunas": dados,
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.get("/api/contabilidade/balanco")
def consultar_balanco_patrimonial(
    anomes_ini: str = Query(..., description="Competência inicial YYYYMM"),
    anomes_fim: Optional[str] = Query(None, description="Competência final YYYYMM (default = anomes_ini)"),
    codigo_empresa: int = EMPRESA_PADRAO,
    codigo_filial: Optional[str] = None,
    conta: Optional[str] = None,
    grupo: Optional[str] = None,
    subgrupo: Optional[str] = None,
    pagina: int = 1,
    tamanho_pagina: int = 100,
    usuario=Depends(validar_token),
):
    """Consulta o Balanço Patrimonial (V_BALANCO_PATRIMONIAL).
    Filtros: anomes_ini/anomes_fim (YYYYMM), codigo_empresa, codigo_filial,
    conta (LIKE em código ou descrição), grupo, subgrupo."""
    anomes_ini = _normalizar_anomes(anomes_ini)
    anomes_fim = _normalizar_anomes(anomes_fim, anomes_ini)

    pagina = max(1, int(pagina or 1))
    tamanho_pagina = max(1, min(int(tamanho_pagina or 100), 500))
    offset = (pagina - 1) * tamanho_pagina

    where = ["B.ANOMES_REFERENTE BETWEEN ? AND ?"]
    params: list = [int(anomes_ini), int(anomes_fim)]

    where.append("B.CD_EMPRESA = ?")
    params.append(int(codigo_empresa))

    if codigo_filial:
        where.append("CAST(B.CD_FILIAL AS VARCHAR(30)) LIKE ?")
        params.append(f"%{codigo_filial.strip()}%")

    if conta:
        where.append("("
                     " CAST(B.CD_CONTA_CONTABIL AS VARCHAR(50)) LIKE ? "
                     " OR B.DS_CONTA_CONTABIL LIKE ? "
                     ")")
        t = f"%{conta.strip()}%"
        params.extend([t, t])

    if grupo:
        where.append("B.DS_GRUPO LIKE ?")
        params.append(f"%{grupo.strip()}%")

    if subgrupo:
        where.append("B.DS_SUBGRUPO LIKE ?")
        params.append(f"%{subgrupo.strip()}%")

    where_sql = " AND ".join(where)

    conn = get_connection()
    try:
        cursor = conn.cursor()
        try:
            cursor.execute(
                f"SELECT COUNT(1) FROM {OBJ_V_BALANCO_PATRIMONIAL} B WHERE {where_sql}",
                params,
            )
            total = int(cursor.fetchone()[0] or 0)
        except Exception as exc:
            raise HTTPException(
                status_code=500,
                detail=(
                    f"Falha ao consultar {OBJ_V_BALANCO_PATRIMONIAL}: {exc}. "
                    "Use GET /api/contabilidade/balanco/colunas para conferir "
                    "se a view existe e os nomes reais das colunas."
                ),
            )
        total_paginas = (total + tamanho_pagina - 1) // tamanho_pagina if total else 0

        cursor.execute(f"""
            SELECT B.*
            FROM {OBJ_V_BALANCO_PATRIMONIAL} B
            WHERE {where_sql}
            ORDER BY
                B.ANOMES_REFERENTE,
                B.DS_GRUPO,
                B.DS_SUBGRUPO,
                B.CD_CONTA_CONTABIL
            OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
        """, params + [offset, tamanho_pagina])
        cols = [c[0] for c in cursor.description]
        dados = []
        for row in cursor.fetchall():
            item = {}
            for i, c in enumerate(cols):
                v = row[i]
                if isinstance(v, str):
                    v = v.strip()
                item[c.lower()] = v
            dados.append(item)

        return {
            "pagina": pagina,
            "tamanho_pagina": tamanho_pagina,
            "total_registros": total,
            "total_paginas": total_paginas,
            "anomes_ini": anomes_ini,
            "anomes_fim": anomes_fim,
            "codigo_empresa": codigo_empresa,
            "dados": dados,
            "observacao": (
                f"Fonte: {OBJ_V_BALANCO_PATRIMONIAL}. Confirme os nomes das "
                "colunas com /api/contabilidade/balanco/colunas se algum "
                "campo vier ausente."
            ),
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.get("/api/export/contabilidade/balanco")
def exportar_balanco_patrimonial(
    anomes_ini: str = Query(...),
    anomes_fim: Optional[str] = None,
    codigo_empresa: int = EMPRESA_PADRAO,
    codigo_filial: Optional[str] = None,
    conta: Optional[str] = None,
    grupo: Optional[str] = None,
    subgrupo: Optional[str] = None,
    usuario=Depends(validar_token_download),
):
    """Exporta Excel completo do Balanço Patrimonial (sem paginação)."""
    dados = _collect_paginated_data(
        consultar_balanco_patrimonial,
        usuario,
        batch_size=500,
        max_pages=5000,
        anomes_ini=anomes_ini,
        anomes_fim=anomes_fim,
        codigo_empresa=codigo_empresa,
        codigo_filial=codigo_filial,
        conta=conta,
        grupo=grupo,
        subgrupo=subgrupo,
    )
    # Sem mapa fixo de cabeçalhos — _xlsx_response usa os nomes das chaves
    # diretamente (que vêm normalizados em lowercase pelo backend).
    return _xlsx_response(
        "balanco_patrimonial.xlsx",
        [("Balanço Patrimonial", dados, None)],
    )


# ============================================================
# CONTABILIDADE — Conciliação Comercial × Contábil
# Endpoint SEPARADO do Balanço (não confundir). Compara faturamento
# emitido (E140NFV/IPV/ISV + devoluções E440) com lançamentos
# contábeis (E640LCT + E045PLA por USU_MCTCTA) por NF.
# ============================================================


@app.get("/api/contabilidade/conciliacao-comercial-contabil")
def consultar_conciliacao_comercial_contabil(
    anomes_ini: str = Query(..., description="YYYYMM"),
    anomes_fim: Optional[str] = None,
    codigo_empresa: Optional[int] = None,
    cliente: Optional[str] = None,
    apenas_diferencas: bool = True,
    usuario=Depends(validar_token),
):
    """Compara COMERCIAL (E140NFV/IPV/ISV + E440 devoluções) com
    CONTÁBIL (E640LCT × E045PLA via USU_MCTCTA) por NF. Retorna uma
    linha por (CD_EMPRESA, CD_FILIAL, ANOMES_REFERENTE, CD_NF, CD_SERIE)
    com VL_*_COM, VL_*_CTB e DIF_* + STATUS_VALIDACAO."""
    anomes_ini = _normalizar_anomes(anomes_ini)
    anomes_fim = _normalizar_anomes(anomes_fim, anomes_ini)

    where_extra: list = []
    params_extra: list = []
    if codigo_empresa:
        where_extra.append(
            "COALESCE(COM.CD_EMPRESA, CTB.CD_EMPRESA) = ?"
        )
        params_extra.append(int(codigo_empresa))
    if cliente:
        where_extra.append("UPPER(ISNULL(COM.NM_CLIENTE, '')) LIKE ?")
        params_extra.append(f"%{cliente.strip().upper()}%")
    if apenas_diferencas:
        where_extra.append("""(
            COM.CD_NF IS NULL
            OR CTB.CD_NF IS NULL
            OR ABS(ISNULL(COM.VL_LIQUIDO_COM, 0) - ISNULL(CTB.VL_LIQUIDO_CTB, 0)) > 0.01
        )""")
    where_extra_sql = (" WHERE " + " AND ".join(where_extra)) if where_extra else ""

    sql = f"""
        DECLARE @ANOMES_INI INT = ?;
        DECLARE @ANOMES_FIM INT = ?;

        WITH COMERCIAL_BASE AS (
            -- PRODUTOS
            SELECT
                E140NFV.CODEMP AS CD_EMPRESA,
                CONVERT(VARCHAR, E140NFV.CODEMP) + '-' + CONVERT(VARCHAR, E140NFV.CODFIL) AS CD_FILIAL,
                CAST(YEAR(E140NFV.DATEMI) * 100 + MONTH(E140NFV.DATEMI) AS INT) AS ANOMES_REFERENTE,
                E140NFV.NUMNFV AS CD_NF,
                E140NFV.CODSNF AS CD_SERIE,
                E140NFV.CODCLI AS CD_CLIENTE,
                E085CLI.NOMCLI AS NM_CLIENTE,
                SUM(E140IPV.VLRBRU + E140IPV.VLRIPI
                    - (E140IPV.VLRDSC + E140IPV.VLRDS1 + E140IPV.VLRDS2 + E140IPV.VLRDS3 + E140IPV.VLRDS4)
                    + E140IPV.VLROUI + E140IPV.VLRICS) AS VL_BRUTO,
                SUM(E140IPV.VLRDSC + E140IPV.VLRDS1 + E140IPV.VLRDS2 + E140IPV.VLRDS3 + E140IPV.VLRDS4) AS VL_DESCONTO,
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E140IPV.VLRICM * -1 END) AS VL_ICMS,
                SUM(E140IPV.VLRDFA * -1) AS VL_DIFAL,
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E140IPV.VLRIPI * -1 END) AS VL_IPI,
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E140IPV.VLRPIF * -1 END) AS VL_PIS,
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E140IPV.VLRCFF * -1 END) AS VL_COFINS,
                0 AS VL_ISS, 0 AS VL_ICMSST, 0 AS VL_DEVOLUCAO
            FROM E140IPV
            INNER JOIN E140NFV
                ON E140NFV.CODEMP = E140IPV.CODEMP AND E140NFV.CODFIL = E140IPV.CODFIL
               AND E140NFV.NUMNFV = E140IPV.NUMNFV AND E140NFV.CODSNF = E140IPV.CODSNF
               AND E140NFV.TIPNFS <> 0
            INNER JOIN E001TNS
                ON E140IPV.CODEMP = E001TNS.CODEMP AND E140IPV.TNSPRO = E001TNS.CODTNS
               AND E001TNS.VENFAT = 'S'
            INNER JOIN E085CLI ON E085CLI.CODCLI = E140NFV.CODCLI
            LEFT JOIN E140RAT
                ON E140RAT.CODEMP = E140IPV.CODEMP AND E140RAT.CODFIL = E140IPV.CODFIL
               AND E140RAT.CODSNF = E140IPV.CODSNF AND E140RAT.NUMNFV = E140IPV.NUMNFV
               AND E140RAT.SEQIPV = E140IPV.SEQIPV
            LEFT JOIN E044CCU
                ON (E044CCU.CODEMP = E140RAT.CODEMP AND E044CCU.CODCCU = E140RAT.CODCCU)
                OR (E044CCU.CODEMP = E140IPV.CODEMP AND E044CCU.CODCCU = E140IPV.CODCCU)
            WHERE E140NFV.SITNFV = 2
              AND E140NFV.CODCLI <> 1
              AND SUBSTRING(E044CCU.CLACCU, 1, 3) IN ('503', '502')
              AND CAST(YEAR(E140NFV.DATEMI) * 100 + MONTH(E140NFV.DATEMI) AS INT) BETWEEN @ANOMES_INI AND @ANOMES_FIM
              AND E001TNS.CODTNS NOT IN ('5933O','6933O','5101A','6101A')
            GROUP BY E140NFV.CODEMP, E140NFV.CODFIL,
                     YEAR(E140NFV.DATEMI), MONTH(E140NFV.DATEMI),
                     E140NFV.NUMNFV, E140NFV.CODSNF,
                     E140NFV.CODCLI, E085CLI.NOMCLI

            UNION ALL

            -- SERVIÇOS
            SELECT
                E140NFV.CODEMP, CONVERT(VARCHAR, E140NFV.CODEMP) + '-' + CONVERT(VARCHAR, E140NFV.CODFIL),
                CAST(YEAR(E140NFV.DATEMI) * 100 + MONTH(E140NFV.DATEMI) AS INT),
                E140NFV.NUMNFV, E140NFV.CODSNF, E140NFV.CODCLI, E085CLI.NOMCLI,
                SUM(E140ISV.VLRBRU + E140ISV.VLRIPI
                    - (E140ISV.VLRDSC + E140ISV.VLRDS1 + E140ISV.VLRDS2 + E140ISV.VLRDS3 + E140ISV.VLRDS4)
                    + E140ISV.VLROUI + E140ISV.VLRICS),
                SUM(E140ISV.VLRDSC + E140ISV.VLRDS1 + E140ISV.VLRDS2 + E140ISV.VLRDS3 + E140ISV.VLRDS4),
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E140ISV.VLRICM * -1 END),
                SUM(E140ISV.VLRDFA * -1),
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E140ISV.VLRIPI * -1 END),
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E140ISV.VLRPIF * -1 END),
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E140ISV.VLRCFF * -1 END),
                SUM(E140ISV.VLRISS * -1), 0, 0
            FROM E140ISV
            INNER JOIN E140NFV
                ON E140NFV.CODEMP = E140ISV.CODEMP AND E140NFV.CODFIL = E140ISV.CODFIL
               AND E140NFV.NUMNFV = E140ISV.NUMNFV AND E140NFV.CODSNF = E140ISV.CODSNF
               AND E140NFV.TIPNFS <> 0
            INNER JOIN E001TNS
                ON E140ISV.CODEMP = E001TNS.CODEMP AND E140ISV.TNSSER = E001TNS.CODTNS
               AND E001TNS.VENFAT = 'S'
            INNER JOIN E085CLI ON E085CLI.CODCLI = E140NFV.CODCLI
            LEFT JOIN E140RAT
                ON E140RAT.CODEMP = E140ISV.CODEMP AND E140RAT.CODFIL = E140ISV.CODFIL
               AND E140RAT.CODSNF = E140ISV.CODSNF AND E140RAT.NUMNFV = E140ISV.NUMNFV
               AND E140RAT.SEQISV = E140ISV.SEQISV
            LEFT JOIN E044CCU
                ON (E044CCU.CODEMP = E140RAT.CODEMP AND E044CCU.CODCCU = E140RAT.CODCCU)
                OR (E044CCU.CODEMP = E140ISV.CODEMP AND E044CCU.CODCCU = E140ISV.CODCCU)
            WHERE E140NFV.SITNFV = 2
              AND E140NFV.CODCLI <> 1
              AND SUBSTRING(E044CCU.CLACCU, 1, 3) IN ('503', '502')
              AND CAST(YEAR(E140NFV.DATEMI) * 100 + MONTH(E140NFV.DATEMI) AS INT) BETWEEN @ANOMES_INI AND @ANOMES_FIM
              AND E001TNS.CODTNS NOT IN ('5933O','6933O','5101A','6101A')
            GROUP BY E140NFV.CODEMP, E140NFV.CODFIL,
                     YEAR(E140NFV.DATEMI), MONTH(E140NFV.DATEMI),
                     E140NFV.NUMNFV, E140NFV.CODSNF,
                     E140NFV.CODCLI, E085CLI.NOMCLI

            UNION ALL

            -- DEVOLUÇÕES (E440)
            SELECT
                E440NFC.CODEMP, CONVERT(VARCHAR, E440NFC.CODEMP) + '-' + CONVERT(VARCHAR, E440NFC.CODFIL),
                CAST(YEAR(E440NFC.DATENT) * 100 + MONTH(E440NFC.DATENT) AS INT),
                E440NFC.NUMNFC, E440NFC.CODSNF, E085CLI.CODCLI, E085CLI.NOMCLI,
                SUM((E440IPC.VLRBRU + E440IPC.VECIPI + E440IPC.VLRICS
                    - (E440IPC.VLRDSC + E440IPC.VLRDS1 + E440IPC.VLRDS2 + E440IPC.VLRDS3 + E440IPC.VLRDS4)
                    + E440IPC.VLROUI) * -1),
                SUM(E440IPC.VLRDSC + E440IPC.VLRDS1 + E440IPC.VLRDS2 + E440IPC.VLRDS3 + E440IPC.VLRDS4),
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E440IPC.VECICM END),
                SUM(E440IPC.VLRDFA),
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E440IPC.VECIPI END),
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E440IPC.VLRPIS END),
                SUM(CASE WHEN E001TNS.CODTNS IN ('5949A','6949A','5949D','6949D','5101A','5949G','6949G','5949N','6949N','5949O','6949O')
                              OR E001TNS.COMNAT IN ('6910','5910','6912','5912') THEN 0
                          ELSE E440IPC.VLRCOR END),
                0, 0,
                SUM(E440IPC.VLRBRU + E440IPC.VECIPI + E440IPC.VLRICS
                    - (E440IPC.VLRDSC + E440IPC.VLRDS1 + E440IPC.VLRDS2 + E440IPC.VLRDS3 + E440IPC.VLRDS4)
                    + E440IPC.VLROUI)
            FROM E440IPC
            INNER JOIN E440NFC
                ON E440NFC.CODEMP = E440IPC.CODEMP AND E440NFC.CODFIL = E440IPC.CODFIL
               AND E440NFC.NUMNFC = E440IPC.NUMNFC AND E440NFC.CODSNF = E440IPC.CODSNF
               AND E440NFC.CODFOR = E440IPC.CODFOR
            INNER JOIN E001TNS
                ON E440IPC.CODEMP = E001TNS.CODEMP AND E440IPC.TNSPRO = E001TNS.CODTNS
            LEFT JOIN E095FOR ON E095FOR.CODFOR = E440NFC.CODFOR
            LEFT JOIN E085CLI ON E085CLI.CODCLI = E095FOR.CODCLI
            LEFT JOIN E085HCL
                ON E085CLI.CODCLI = E085HCL.CODCLI
               AND E440NFC.CODEMP = E085HCL.CODEMP
               AND E440NFC.CODFIL = E085HCL.CODFIL
            LEFT JOIN E440RAT
                ON E440RAT.CODEMP = E440IPC.CODEMP AND E440RAT.CODFIL = E440IPC.CODFIL
               AND E440RAT.CODSNF = E440IPC.CODSNF AND E440RAT.CODFOR = E440IPC.CODFOR
               AND E440RAT.NUMNFC = E440IPC.NUMNFC AND E440RAT.SEQIPC = E440IPC.SEQIPC
            LEFT JOIN E044CCU
                ON (E044CCU.CODEMP = E440RAT.CODEMP AND E044CCU.CODCCU = E440RAT.CODCCU)
                OR (E044CCU.CODEMP = E440IPC.CODEMP AND E044CCU.CODCCU = E440IPC.CODCCU)
            WHERE E440NFC.SITNFC = 2
              AND ISNULL(E085HCL.CODCLI, 0) <> 1
              AND E001TNS.COMNAT IN ('3211','3202','3201','2411','2410','2209',
                                     '2204','2203','2202','2201','1411','1410',
                                     '1204','1203','1202','1201')
              AND SUBSTRING(E044CCU.CLACCU, 1, 3) IN ('503', '502')
              AND CAST(YEAR(E440NFC.DATENT) * 100 + MONTH(E440NFC.DATENT) AS INT) BETWEEN @ANOMES_INI AND @ANOMES_FIM
            GROUP BY E440NFC.CODEMP, E440NFC.CODFIL,
                     YEAR(E440NFC.DATENT), MONTH(E440NFC.DATENT),
                     E440NFC.NUMNFC, E440NFC.CODSNF,
                     E085CLI.CODCLI, E085CLI.NOMCLI
        ),
        COMERCIAL AS (
            SELECT CD_EMPRESA, CD_FILIAL, ANOMES_REFERENTE, CD_NF, CD_SERIE,
                   MAX(CD_CLIENTE) AS CD_CLIENTE, MAX(NM_CLIENTE) AS NM_CLIENTE,
                   SUM(VL_BRUTO) AS VL_BRUTO_COM, SUM(VL_DESCONTO) AS VL_DESCONTO_COM,
                   SUM(VL_ICMS) AS VL_ICMS_COM, SUM(VL_DIFAL) AS VL_DIFAL_COM,
                   SUM(VL_IPI) AS VL_IPI_COM, SUM(VL_PIS) AS VL_PIS_COM,
                   SUM(VL_COFINS) AS VL_COFINS_COM, SUM(VL_ISS) AS VL_ISS_COM,
                   SUM(VL_ICMSST) AS VL_ICMSST_COM, SUM(VL_DEVOLUCAO) AS VL_DEVOLUCAO_COM,
                   SUM(VL_BRUTO + VL_ICMS + VL_DIFAL + VL_IPI + VL_PIS + VL_COFINS + VL_ISS + VL_ICMSST) AS VL_LIQUIDO_COM
            FROM COMERCIAL_BASE
            GROUP BY CD_EMPRESA, CD_FILIAL, ANOMES_REFERENTE, CD_NF, CD_SERIE
        ),
        CONTABIL_BASE AS (
            -- DÉBITO
            SELECT
                L.CODEMP AS CD_EMPRESA,
                CONVERT(VARCHAR, L.CODEMP) + '-' + CONVERT(VARCHAR, L.CODFIL) AS CD_FILIAL,
                CAST(YEAR(L.DATLCT) * 100 + MONTH(L.DATLCT) AS INT) AS ANOMES_REFERENTE,
                ISNULL(E644LNF.NUMNFI, 0) AS CD_NF,
                ISNULL(E644LNF.CODSNF, '0') AS CD_SERIE,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('01','02','03') THEN L.VLRLCT * -1 ELSE 0 END) AS VL_BRUTO,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('17') THEN L.VLRLCT * -1 ELSE 0 END) AS VL_DESCONTO,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('04') THEN L.VLRLCT * -1 ELSE 0 END) AS VL_ICMS,
                0 AS VL_DIFAL,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('05') THEN L.VLRLCT * -1 ELSE 0 END) AS VL_IPI,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('06') THEN L.VLRLCT * -1 ELSE 0 END) AS VL_PIS,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('07') THEN L.VLRLCT * -1 ELSE 0 END) AS VL_COFINS,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('08') THEN L.VLRLCT * -1 ELSE 0 END) AS VL_ISS,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('16') THEN L.VLRLCT * -1 ELSE 0 END) AS VL_ICMSST,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('12') THEN L.VLRLCT * -1 ELSE 0 END) AS VL_DEVOLUCAO
            FROM E640LCT L
            INNER JOIN E045PLA ON L.CODEMP = E045PLA.CODEMP AND L.CTADEB = E045PLA.CTARED
            LEFT JOIN E644LNF ON L.CODEMP = E644LNF.CODEMP AND L.NUMLCT = E644LNF.NUMLCT
            WHERE L.SITLCT = 2
              AND ISNULL(L.CODHPD, 0) <> 712
              AND CAST(CASE WHEN ISNULL(E045PLA.USU_MCTCTA, ' ') = ' '
                              OR ISNULL(E045PLA.USU_MCTCTA, '  ') = '  '
                            THEN '0' ELSE E045PLA.USU_MCTCTA END AS INT) BETWEEN 1 AND 20
              AND CAST(YEAR(L.DATLCT) * 100 + MONTH(L.DATLCT) AS INT) BETWEEN @ANOMES_INI AND @ANOMES_FIM
            GROUP BY L.CODEMP, L.CODFIL,
                     YEAR(L.DATLCT), MONTH(L.DATLCT),
                     ISNULL(E644LNF.NUMNFI, 0), ISNULL(E644LNF.CODSNF, '0')

            UNION ALL

            -- CRÉDITO
            SELECT
                L.CODEMP, CONVERT(VARCHAR, L.CODEMP) + '-' + CONVERT(VARCHAR, L.CODFIL),
                CAST(YEAR(L.DATLCT) * 100 + MONTH(L.DATLCT) AS INT),
                ISNULL(E644LNF.NUMNFI, 0), ISNULL(E644LNF.CODSNF, '0'),
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('01','02','03','12') THEN L.VLRLCT ELSE 0 END),
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('17') THEN L.VLRLCT ELSE 0 END),
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('04') THEN L.VLRLCT ELSE 0 END),
                0,
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('05') THEN L.VLRLCT ELSE 0 END),
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('06') THEN L.VLRLCT ELSE 0 END),
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('07') THEN L.VLRLCT ELSE 0 END),
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('08') THEN L.VLRLCT ELSE 0 END),
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('16') THEN L.VLRLCT * -1 ELSE 0 END),
                SUM(CASE WHEN E045PLA.USU_MCTCTA IN ('12') THEN L.VLRLCT ELSE 0 END)
            FROM E640LCT L
            INNER JOIN E045PLA ON L.CODEMP = E045PLA.CODEMP AND L.CTACRE = E045PLA.CTARED
            LEFT JOIN E644LNF ON L.CODEMP = E644LNF.CODEMP AND L.NUMLCT = E644LNF.NUMLCT
            WHERE L.SITLCT = 2
              AND ISNULL(L.CODHPD, 0) <> 712
              AND CAST(CASE WHEN ISNULL(E045PLA.USU_MCTCTA, ' ') = ' '
                              OR ISNULL(E045PLA.USU_MCTCTA, '  ') = '  '
                            THEN '0' ELSE E045PLA.USU_MCTCTA END AS INT) BETWEEN 1 AND 20
              AND CAST(YEAR(L.DATLCT) * 100 + MONTH(L.DATLCT) AS INT) BETWEEN @ANOMES_INI AND @ANOMES_FIM
            GROUP BY L.CODEMP, L.CODFIL,
                     YEAR(L.DATLCT), MONTH(L.DATLCT),
                     ISNULL(E644LNF.NUMNFI, 0), ISNULL(E644LNF.CODSNF, '0')
        ),
        CONTABIL AS (
            SELECT CD_EMPRESA, CD_FILIAL, ANOMES_REFERENTE, CD_NF, CD_SERIE,
                   SUM(VL_BRUTO) AS VL_BRUTO_CTB, SUM(VL_DESCONTO) AS VL_DESCONTO_CTB,
                   SUM(VL_ICMS) AS VL_ICMS_CTB, SUM(VL_DIFAL) AS VL_DIFAL_CTB,
                   SUM(VL_IPI) AS VL_IPI_CTB, SUM(VL_PIS) AS VL_PIS_CTB,
                   SUM(VL_COFINS) AS VL_COFINS_CTB, SUM(VL_ISS) AS VL_ISS_CTB,
                   SUM(VL_ICMSST) AS VL_ICMSST_CTB, SUM(VL_DEVOLUCAO) AS VL_DEVOLUCAO_CTB,
                   SUM(VL_BRUTO + VL_ICMS + VL_DIFAL + VL_IPI + VL_PIS + VL_COFINS + VL_ISS + VL_ICMSST) AS VL_LIQUIDO_CTB
            FROM CONTABIL_BASE
            GROUP BY CD_EMPRESA, CD_FILIAL, ANOMES_REFERENTE, CD_NF, CD_SERIE
        )
        SELECT
            COALESCE(COM.CD_EMPRESA, CTB.CD_EMPRESA) AS cd_empresa,
            COALESCE(COM.CD_FILIAL, CTB.CD_FILIAL) AS cd_filial,
            COALESCE(COM.ANOMES_REFERENTE, CTB.ANOMES_REFERENTE) AS anomes_referente,
            COALESCE(COM.CD_NF, CTB.CD_NF) AS cd_nf,
            COALESCE(COM.CD_SERIE, CTB.CD_SERIE) AS cd_serie,
            COM.CD_CLIENTE AS cd_cliente,
            COM.NM_CLIENTE AS nm_cliente,
            ISNULL(COM.VL_BRUTO_COM, 0) AS vl_bruto_com,
            ISNULL(CTB.VL_BRUTO_CTB, 0) AS vl_bruto_ctb,
            ISNULL(COM.VL_BRUTO_COM, 0) - ISNULL(CTB.VL_BRUTO_CTB, 0) AS dif_bruto,
            ISNULL(COM.VL_ICMS_COM, 0) AS vl_icms_com, ISNULL(CTB.VL_ICMS_CTB, 0) AS vl_icms_ctb,
            ISNULL(COM.VL_ICMS_COM, 0) - ISNULL(CTB.VL_ICMS_CTB, 0) AS dif_icms,
            ISNULL(COM.VL_DIFAL_COM, 0) AS vl_difal_com, ISNULL(CTB.VL_DIFAL_CTB, 0) AS vl_difal_ctb,
            ISNULL(COM.VL_DIFAL_COM, 0) - ISNULL(CTB.VL_DIFAL_CTB, 0) AS dif_difal,
            ISNULL(COM.VL_IPI_COM, 0) AS vl_ipi_com, ISNULL(CTB.VL_IPI_CTB, 0) AS vl_ipi_ctb,
            ISNULL(COM.VL_IPI_COM, 0) - ISNULL(CTB.VL_IPI_CTB, 0) AS dif_ipi,
            ISNULL(COM.VL_PIS_COM, 0) AS vl_pis_com, ISNULL(CTB.VL_PIS_CTB, 0) AS vl_pis_ctb,
            ISNULL(COM.VL_PIS_COM, 0) - ISNULL(CTB.VL_PIS_CTB, 0) AS dif_pis,
            ISNULL(COM.VL_COFINS_COM, 0) AS vl_cofins_com, ISNULL(CTB.VL_COFINS_CTB, 0) AS vl_cofins_ctb,
            ISNULL(COM.VL_COFINS_COM, 0) - ISNULL(CTB.VL_COFINS_CTB, 0) AS dif_cofins,
            ISNULL(COM.VL_ISS_COM, 0) AS vl_iss_com, ISNULL(CTB.VL_ISS_CTB, 0) AS vl_iss_ctb,
            ISNULL(COM.VL_ISS_COM, 0) - ISNULL(CTB.VL_ISS_CTB, 0) AS dif_iss,
            ISNULL(COM.VL_ICMSST_COM, 0) AS vl_icmsst_com, ISNULL(CTB.VL_ICMSST_CTB, 0) AS vl_icmsst_ctb,
            ISNULL(COM.VL_ICMSST_COM, 0) - ISNULL(CTB.VL_ICMSST_CTB, 0) AS dif_icmsst,
            ISNULL(COM.VL_DEVOLUCAO_COM, 0) AS vl_devolucao_com,
            ISNULL(CTB.VL_DEVOLUCAO_CTB, 0) AS vl_devolucao_ctb,
            ISNULL(COM.VL_DEVOLUCAO_COM, 0) - ISNULL(CTB.VL_DEVOLUCAO_CTB, 0) AS dif_devolucao,
            ISNULL(COM.VL_LIQUIDO_COM, 0) AS vl_liquido_com,
            ISNULL(CTB.VL_LIQUIDO_CTB, 0) AS vl_liquido_ctb,
            ISNULL(COM.VL_LIQUIDO_COM, 0) - ISNULL(CTB.VL_LIQUIDO_CTB, 0) AS dif_liquido,
            CASE
                WHEN COM.CD_NF IS NULL THEN 'SOMENTE_CONTABIL'
                WHEN CTB.CD_NF IS NULL THEN 'SOMENTE_COMERCIAL'
                WHEN ABS(ISNULL(COM.VL_LIQUIDO_COM, 0) - ISNULL(CTB.VL_LIQUIDO_CTB, 0)) > 0.01 THEN 'DIFERENCA'
                ELSE 'OK'
            END AS status_validacao
        FROM COMERCIAL COM
        FULL OUTER JOIN CONTABIL CTB
            ON CTB.CD_EMPRESA = COM.CD_EMPRESA
           AND CTB.CD_FILIAL = COM.CD_FILIAL
           AND CTB.ANOMES_REFERENTE = COM.ANOMES_REFERENTE
           AND CTB.CD_NF = COM.CD_NF
           AND CTB.CD_SERIE = COM.CD_SERIE
        {where_extra_sql}
        ORDER BY
            ABS(ISNULL(COM.VL_LIQUIDO_COM, 0) - ISNULL(CTB.VL_LIQUIDO_CTB, 0)) DESC,
            COALESCE(COM.ANOMES_REFERENTE, CTB.ANOMES_REFERENTE),
            COALESCE(COM.CD_NF, CTB.CD_NF)
    """
    params: list = [int(anomes_ini), int(anomes_fim)] + params_extra

    conn = get_connection()
    try:
        cursor = conn.cursor()
        try:
            cursor.execute(sql, params)
        except Exception as exc:
            raise HTTPException(
                status_code=500,
                detail=f"Erro SQL na conciliação comercial × contábil: {exc}",
            )
        cols = [c[0] for c in cursor.description]
        dados = []
        for row in cursor.fetchall():
            item = {}
            for i, c in enumerate(cols):
                v = row[i]
                if isinstance(v, str):
                    v = v.strip()
                item[c] = v
            dados.append(item)

        # Resumo agregado
        total = len(dados)
        ok = sum(1 for d in dados if d.get("status_validacao") == "OK")
        diferenca = sum(1 for d in dados if d.get("status_validacao") == "DIFERENCA")
        somente_com = sum(1 for d in dados if d.get("status_validacao") == "SOMENTE_COMERCIAL")
        somente_ctb = sum(1 for d in dados if d.get("status_validacao") == "SOMENTE_CONTABIL")
        soma_dif_liq = round(sum(float(d.get("dif_liquido") or 0) for d in dados), 2)

        return {
            "anomes_ini": anomes_ini,
            "anomes_fim": anomes_fim,
            "apenas_diferencas": apenas_diferencas,
            "total": total,
            "resumo": {
                "ok": ok,
                "diferenca": diferenca,
                "somente_comercial": somente_com,
                "somente_contabil": somente_ctb,
                "soma_dif_liquido": soma_dif_liq,
            },
            "dados": dados,
            "observacao": (
                "Comparação por (CD_EMPRESA, CD_FILIAL, ANOMES_REFERENTE, "
                "CD_NF, CD_SERIE). Esta é a conciliação Comercial × Contábil, "
                "NÃO confunda com o Balanço Patrimonial (que vive em "
                "/api/contabilidade/balanco)."
            ),
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.get("/api/export/contabilidade/conciliacao-comercial-contabil")
def exportar_conciliacao_comercial_contabil(
    anomes_ini: str = Query(...),
    anomes_fim: Optional[str] = None,
    codigo_empresa: Optional[int] = None,
    cliente: Optional[str] = None,
    apenas_diferencas: bool = True,
    usuario=Depends(validar_token_download),
):
    """Excel da conciliação. Sem paginação interna (a query nativa já
    não pagina) — chama o endpoint direto."""
    resp = consultar_conciliacao_comercial_contabil(
        anomes_ini=anomes_ini, anomes_fim=anomes_fim,
        codigo_empresa=codigo_empresa, cliente=cliente,
        apenas_diferencas=apenas_diferencas, usuario=usuario,
    )
    dados = resp.get("dados", [])
    return _xlsx_response(
        "conciliacao_comercial_contabil.xlsx",
        [("Conciliação Com × Ctb", dados, None)],
    )


